def admin_stars_menu(call):
    if not is_admin(call.from_user.id):
        return bot.answer_callback_query(call.id, "Нема доступу", show_alert=True)
    from telebot.types import InlineKeyboardMarkup, InlineKeyboardButton
    settings = get_stars_settings() if 'get_stars_settings' in globals() else None
    status = settings and settings.get('enabled')
    rate = settings and settings.get('exchange_rate')
    min_dep = settings and settings.get('min_deposit')
    fee = settings and settings.get('admin_fee_percent', 0)
    text = (
        "🌟 <b>Telegram Stars</b>\n\n"
        f"Статус: <b>{'Увімкнено' if status else 'Вимкнено'}</b>\n"
        f"Курс: <b>{rate}</b> Stars = 1₴\n"
        f"Мін. депозит: <b>{min_dep}</b> Stars\n"
        f"Комісія адміна: <b>{fee}%</b>\n\n"
        "Кнопки нижче змінюють налаштування."
    )
    kb = InlineKeyboardMarkup(row_width=2)
    kb.add(
        InlineKeyboardButton("🔁 Тогл Stars", callback_data="stars_toggle_btn"),
        InlineKeyboardButton("💱 Курс", callback_data="stars_change_rate"),
    )
    kb.add(
        InlineKeyboardButton("📉 Мін. депозит", callback_data="stars_change_min"),
        InlineKeyboardButton("📊 Комісія %", callback_data="stars_change_fee"),
    )
    kb.add(InlineKeyboardButton("⬅️ Назад", callback_data="panel"))
    edit_or_send(call, text, reply_markup=kb, parse_mode="HTML")

def stars_toggle_btn(call):
    if not is_admin(call.from_user.id):
        return bot.answer_callback_query(call.id)
    try:
        settings = get_stars_settings()
        new_status = not settings['enabled']
        update_stars_settings(enabled=new_status)
        bot.answer_callback_query(call.id, f"✅ Stars {'увімкнено' if new_status else 'вимкнено'}")
    except Exception as e:
        bot.answer_callback_query(call.id, "❌ Помилка", show_alert=True)
    return admin_stars_menu(call)

def stars_change_params(call):
    if not is_admin(call.from_user.id):
        return bot.answer_callback_query(call.id)
    kind = call.data.split('_')[-1]
    prompts = {
        'rate': 'Введіть новий курс (ціле, напр. 95):',
        'min': 'Введіть мінімальний депозит (ціле, напр. 100):',
        'fee': 'Введіть комісію у % (напр. 5):',
    }
    msg = bot.send_message(call.message.chat.id, prompts[kind])
    bot.register_next_step_handler(msg, _apply_stars_param, kind)

def _apply_stars_param(message, kind):
    if not is_admin(message.from_user.id):
        return
    try:
        if kind == 'rate':
            val = int(str(message.text).strip())
            update_stars_settings(exchange_rate=val)
        elif kind == 'min':
            val = int(str(message.text).strip())
            update_stars_settings(min_deposit=val)
        else:
            val = float(str(message.text).replace(',', '.').strip())
            update_stars_settings(admin_fee_percent=val)
        bot.reply_to(message, "✅ Збережено")
    except Exception:
        bot.reply_to(message, "❌ Невірний ввід")
 

