def _banners_disabled() -> bool:
    """Global switch to turn off image banners.

    Checks database setting first, then falls back to env var BANNERS_DISABLED=1.
    """
    try:
        return get_banners_disabled()
    except Exception:
        # Fallback на env переменную
        try:
            val = os.environ.get("BANNERS_DISABLED", "0")
            return str(val).lower() in ("1", "true", "yes", "on")
        except Exception:
            return False


def send_menu_banner(chat_id, title, icon, subtitle=None):
    """Отправляет баннер-изображение без подписи. Учитывает глобальный флаг отключения баннеров."""
    if _banners_disabled():
        return False
    try:
        banner_img = draw_modern_banner(title, icon, subtitle)
        bot.send_photo(chat_id, banner_img)
        return True
    except Exception as e:
        print(f"[banner] error: {e}")
        return False


def send_banner_with_caption(chat_id, title, icon, caption, reply_markup=None, parse_mode="HTML", subtitle=None):
    """Отправляет баннер как фото с подписью и клавиатурой (для коротких меню).
    Если баннеры отключены, отправляет только текст.
    """
    print(f"[DEBUG] send_banner_with_caption: chat_id={chat_id}, title={title}, banners_disabled={_banners_disabled()}")
    # Если баннеры отключены — отправляем просто текст
    if _banners_disabled():
        try:
            print(f"[DEBUG] send_banner_with_caption: баннеры отключены, отправляем текст")
            bot.send_message(chat_id, caption or (title or ""), reply_markup=reply_markup, parse_mode=parse_mode)
            print(f"[DEBUG] send_banner_with_caption: текст отправлен успешно")
            return True
        except Exception as e:
            print(f"[ERROR] send_banner_with_caption: ошибка отправки текста: {e}")
            import traceback
            traceback.print_exc()
            return False
    try:
        # Если заголовок пустой — возьмём первые строки из caption без HTML, чтобы заголовок не был пустым
        if not title or not str(title).strip():
            import re
            plain = re.sub(r"<[^>]+>", "", caption or "").strip()
            title = (plain.splitlines()[0] if plain else "PALMARON BOT")[:36]
        # Используем pro-рендер, если есть ассеты, иначе — стандартный
        try:
            from banner_utils import draw_pro_banner
            assets_dir = os.path.join(os.path.dirname(__file__), 'assets')
            use_pro = os.path.exists(os.path.join(assets_dir, 'hand.png'))
        except Exception:
            use_pro = False
        print(f"[DEBUG] send_banner_with_caption: создаем баннер, use_pro={use_pro}")
        banner_img = draw_pro_banner(title, subtitle or '', width=1280, height=420) if use_pro else draw_modern_banner(title, icon, subtitle)
        print(f"[DEBUG] send_banner_with_caption: отправляем фото с баннером")
        bot.send_photo(chat_id, banner_img, caption=caption, reply_markup=reply_markup, parse_mode=parse_mode)
        print(f"[DEBUG] send_banner_with_caption: фото отправлено успешно")
        return True
    except Exception as e:
        print(f"[ERROR] send_banner_with_caption: ошибка отправки баннера: {e}")
        import traceback
        traceback.print_exc()
        try:
            print(f"[DEBUG] send_banner_with_caption: пытаемся отправить текст вместо баннера")
            bot.send_message(chat_id, caption, reply_markup=reply_markup, parse_mode=parse_mode)
            print(f"[DEBUG] send_banner_with_caption: текст отправлен успешно")
        except Exception as e2:
            print(f"[ERROR] send_banner_with_caption: ошибка отправки текста: {e2}")
            traceback.print_exc()
        return False
def build_caption_from_text(full_text: str, limit: int = 1024) -> str:
    """Safely trim long texts to fit Telegram photo caption limit.
    Keeps whole lines where possible and appends an ellipsis if truncated.
    """
    try:
        if not isinstance(full_text, str):
            full_text = str(full_text)
        if len(full_text) <= limit:
            return full_text
        lines = full_text.split("\n")
        acc = []
        for line in lines:
            candidate = ("\n".join(acc + [line])) if acc else line
            if len(candidate) > limit - 1:  # leave room for ellipsis
                break
            acc.append(line)
        result = "\n".join(acc)
        if len(result) > limit:
            result = result[:limit-1]
        result = result.rstrip()
        if not result.endswith("…"):
            if len(result) >= limit:
                result = result[:-1]
            result += "…"
        return result
    except Exception:
        # Fallback: hard cut
        s = (full_text or "")
        return (s[:limit-1] + "…") if len(s) > limit else s

def send_admin_error(call, err, where: str = ""):
    """Send user-friendly error to the admin and log a short reason."""
    try:
        where_part = f" у {where}" if where else ""
        msg = (
            f"❌ <b>Щось пішло не так{where_part}</b>\n\n"
            f"Причина: <code>{type(err).__name__}: {err}</code>\n"
            f"Якщо повторюється — зверніться до розробника."
        )
        try:
            bot.answer_callback_query(call.id, "Сталася помилка", show_alert=False)
        except Exception:
            pass
        from telebot.types import InlineKeyboardMarkup, InlineKeyboardButton
        kb = InlineKeyboardMarkup().add(InlineKeyboardButton("⬅️ Назад", callback_data="panel"))
        bot.send_message(call.message.chat.id, msg, parse_mode="HTML", reply_markup=kb)
    except Exception:
        pass

def edit_or_send(call, text: str, reply_markup=None, parse_mode="HTML"):
    """Edit message text if current message has text; otherwise send new message.
    Prevents Telegram 400 when trying to edit a photo message.
    """
    try:
        has_text = bool(getattr(call, 'message', None) and getattr(call.message, 'text', None))
        if has_text:
            return bot.edit_message_text(text, call.message.chat.id, call.message.message_id, reply_markup=reply_markup, parse_mode=parse_mode)
        return bot.send_message(call.message.chat.id, text, reply_markup=reply_markup, parse_mode=parse_mode)
    except Exception as e:
        try:
            return bot.send_message(call.message.chat.id, text, reply_markup=reply_markup, parse_mode=parse_mode)
        except Exception:
            send_admin_error(call, e, where="оновлення повідомлення")
            return None

def safe_edit_reply_markup(call, reply_markup=None):
    try:
        has_text = bool(getattr(call, 'message', None) and getattr(call.message, 'text', None))
        if has_text:
            return bot.edit_message_reply_markup(call.message.chat.id, call.message.message_id, reply_markup=reply_markup)
        return bot.send_message(call.message.chat.id, "", reply_markup=reply_markup)
    except Exception:
        return None
