# ---- Formatting helpers ----
def fmt_money(amount: float, currency_sign: str = "₴") -> str:
    try:
        return f"{float(amount):,.2f}{currency_sign}".replace(",", " ")
    except Exception:
        return f"{amount}{currency_sign}"

def fmt_date(ts: int, with_time: bool = True) -> str:
    try:
        import datetime as _dt
        dt = _dt.datetime.fromtimestamp(int(ts))
        return dt.strftime("%d.%m.%Y %H:%M") if with_time else dt.strftime("%d.%m.%Y")
    except Exception:
        return str(ts)

# ---- Safe send wrappers ----
def safe_send_message(chat_id, text: str, reply_markup=None, parse_mode="HTML"):
    try:
        if not text:
            text = "\u2060"  # invisible char to avoid Telegram errors
        # Telegram limit is 4096
        if len(text) <= 4096:
            return bot.send_message(chat_id, text, reply_markup=reply_markup, parse_mode=parse_mode)
        # split by lines
        lines = text.split("\n")
        chunk = []
        total = 0
        first_msg = None
        for ln in lines:
            if total + len(ln) + 1 > 4096:
                part = "\n".join(chunk)
                msg = bot.send_message(chat_id, part, reply_markup=None, parse_mode=parse_mode)
                if first_msg is None:
                    first_msg = msg
                chunk, total = [], 0
            chunk.append(ln)
            total += len(ln) + 1
        if chunk:
            msg = bot.send_message(chat_id, "\n".join(chunk), reply_markup=reply_markup, parse_mode=parse_mode)
            if first_msg is None:
                first_msg = msg
        return first_msg
    except Exception as e:
        try:
            return bot.send_message(chat_id, "Сталася помилка. Спробуйте ще раз пізніше.")
        except Exception:
            print("[safe_send_message]", e)
            return None

