def _broadcast_event_announcement(event: dict):
    try:
        from database import get_gaming_chats
        chats = get_gaming_chats() or []
    except Exception:
        chats = []
    etype = event.get('type')
    p = event.get('params', {})
    title_map = {
        'storm': '🌪️ БУРЯ',
        'rain': '🌧️ РЯСНИЙ ДОЩ',
        'drought': '🔥 ПОСУХА',
        'pests': '🐛 ШКІДНИКИ',
        'rush': '⚡ ТУРБО-ЗБІР',
        'market': '🕸️ ЧОРНИЙ РИНОК',
        'buyer': '🧑‍🌾 СКУПЩИК',
        'golden': '🥇 ЗОЛОТІ ЯБЛУКА',
        'goal': '🤝 СПІЛЬНА МЕТА',
    }
    btn_map = {
        'storm': ('Зібрати урожай', 'harvest_now'),
        'rain': ('Активувати дощ', 'activate'),
        'drought': ('Зібрати урожай', 'harvest_now'),
        'pests': ('Зібрати урожай', 'harvest_now'),
        'rush': ('Увімкнути турбо', 'activate'),
        'market': ('Дивитись ринок', 'open'),
        'buyer': ('Продати вигідно', 'open'),
        'golden': ('Збирати!', 'ok'),
        'goal': ('Взяти участь', 'join'),
    }
    title = title_map.get(etype, (etype or '').upper())
    dur = int(p.get('dur', p.get('duration', 0))) or 0
    msg_lines = [
        f"<b>{title}</b> • <i>{dur} хв</i>",
        "━━━━━━━━━━━━━━━━━━━━",
    ]
    if etype == 'storm':
        msg_lines.append("🌪️ <b>Вплив:</b> без укриття зменшує врожайність, з укриттям — невеликий бонус.")
        msg_lines.append("🛡️ <b>Дії:</b> натисни ‘Укриття’ або ‘Зібрати зараз’.")
        msg_lines.append("💡 <i>Порада:</i> укриття допоможе зберегти урожай.")
    elif etype == 'rain':
        msg_lines.append("🌧️ <b>Вплив:</b> тимчасово підсилює ріст і збір фруктів.")
        msg_lines.append("⚙️ <b>Дії:</b> натисни ‘Активувати дощ’.")
    elif etype == 'drought':
        msg_lines.append("🔥 <b>Вплив:</b> знижує врожайність, якщо не полити дерева.")
        msg_lines.append("💧 <b>Дії:</b> натисни ‘Полити’ або ‘Зібрати зараз’.")
    elif etype == 'pests':
        msg_lines.append("🐛 <b>Вплив:</b> частина врожаю втрачається без обробки.")
        msg_lines.append("🧪 <b>Дії:</b> натисни ‘Обробити’ або ‘Зібрати зараз’.")
    elif etype == 'rush':
        msg_lines.append("⚡ <b>Вплив:</b> учасники отримують тимчасовий множник до збору.")
        msg_lines.append("▶️ <b>Дії:</b> натисни ‘Увімкнути турбо’.")
    elif etype == 'market':
        msg_lines.append("🕸️ <b>Вплив:</b> волатильні ціни та додаткова комісія на біржі.")
        msg_lines.append("📈 <b>Дії:</b> відкрий біржу та обери вигідну угоду.")
    elif etype == 'buyer':
        msg_lines.append("🧑‍🌾 <b>Вплив:</b> трохи підвищена ціна за обмежену кількість фруктів.")
        msg_lines.append("💡 <b>Порада:</b> продай частину зараз, решту — пізніше.")
    elif etype == 'golden':
        msg_lines.append("🥇 <b>Вплив:</b> шанс на ‘золоте’ яблуко і додаткові фрукти.")
        msg_lines.append("▶️ <b>Дії:</b> активуй участь і збирай урожай.")
    elif etype == 'goal':
        msg_lines.append("🤝 <b>Вплив:</b> спільна мета — внесок усіх наближає нагороду.")
    text = "\n".join(msg_lines)
    from telebot.types import InlineKeyboardMarkup, InlineKeyboardButton
    btn_title, act = btn_map.get(etype, ('Участь', 'join'))
    kb = InlineKeyboardMarkup()
    if etype == 'storm':
        kb.add(
            InlineKeyboardButton("🛡️ Укриття", callback_data=f"event_act:{event['id']}:shelter"),
            InlineKeyboardButton("🍎 Зібрати зараз", callback_data=f"event_harvest:{event['id']}")
        )
    elif etype == 'drought':
        kb.add(
            InlineKeyboardButton("💧 Полити", callback_data=f"event_act:{event['id']}:water"),
            InlineKeyboardButton("🍎 Зібрати зараз", callback_data=f"event_harvest:{event['id']}")
        )
    elif etype == 'pests':
        kb.add(
            InlineKeyboardButton("🧪 Обробити", callback_data=f"event_act:{event['id']}:treat"),
            InlineKeyboardButton("🍎 Зібрати зараз", callback_data=f"event_harvest:{event['id']}")
        )
    elif act == 'harvest_now':
        kb.add(InlineKeyboardButton(f"{btn_title}", callback_data=f"event_harvest:{event['id']}"))
    else:
        kb.add(InlineKeyboardButton(f"{btn_title}", callback_data=f"event_act:{event['id']}:{act}"))
    if etype in ('market', 'buyer'):
        if etype == 'buyer':
            kb.add(InlineKeyboardButton("🧑‍🌾 Продати скупщику", callback_data="buyer_market"))
        kb.add(InlineKeyboardButton("📈 Відкрити біржу", callback_data="sell_fruits"))
        if etype == 'market':
            kb.add(InlineKeyboardButton("🕸️ Чорний ринок", callback_data=f"open_black_market"))
    kb.add(InlineKeyboardButton("ℹ️ Деталі", callback_data=f"event_info:{event['id']}"))
    # Кнопка "Статус" убрана по запросу пользователя
    if not chats:
        try:
            from database import get_withdraw_channel
            ch = get_withdraw_channel()
            if ch:
                bot.send_message(ch, text, reply_markup=kb)
                return
        except Exception:
            pass
        try:
            from database import get_all_admins
            admin_ids = get_all_admins() or []
            for aid in admin_ids:
                try:
                    bot.send_message(aid, text + "\n\n<i>ℹ️ Подія надіслана у приват, бо не налаштовані ігрові чати</i>", reply_markup=kb, parse_mode="HTML")
                except Exception:
                    continue
        except Exception:
            pass
        return
    for chat_id, chat_title, added_by, added_at in chats:
        try:
            bot.send_message(chat_id, text, reply_markup=kb, parse_mode="HTML")
        except Exception:
            continue


def apply_event_effects(event_id: int, user_id: int):
    """Apply event effects to a user. Supports explicit 'effects' in params or defaults per event type."""
    try:
        from database import get_event_by_id, add_balance
        import random
        row = get_event_by_id(event_id)
        if not row:
            return
        eid, etype, params_s, st, en, status, created_by, chat_id = row
        params = _json_loads_safe(params_s)

        effects = params.get('effects') if isinstance(params, dict) else None
        if effects and isinstance(effects, list):
            for eff in effects:
                try:
                    t = eff.get('type')
                    if t == 'add_balance':
                        amt = float(eff.get('amount', 0))
                        if amt != 0:
                            add_balance(user_id, amt, reason='event_bonus', details=f'Бонус за участие в событии #{event_id}')
                            try:
                                bot.send_message(user_id, f"💸 Ви отримали бонус: <b>{format_currency(amt)}₴</b> за участь у події.", parse_mode="HTML")
                            except Exception:
                                pass
                    elif t == 'send_message':
                        txt = eff.get('text') or ''
                        try:
                            bot.send_message(user_id, txt, parse_mode="HTML")
                        except Exception:
                            pass
                except Exception:
                    continue
            return

        if etype == 'golden':
            # Золотое яблоко больше не дается при активации события
            # Теперь золотые яблоки появляются при сборе урожая во время события
            try:
                bot.send_message(user_id, 
                    "🥇 <b>Золоті яблука активні!</b>\n\n"
                    "💎 <b>Під час збору урожаю є шанс знайти золоте яблуко!</b>\n"
                    "💰 <b>Золоті яблука можна продати за високу ціну</b>\n\n"
                    "🌱 <i>Збирайте урожай, щоб отримати шанс на золоте яблуко!</i>",
                    parse_mode="HTML")
            except Exception:
                pass
        elif etype == 'rush':
            try:
                bot.send_message(user_id, "⚡ Турбо активний! Збирайте фрукти швидше, поки подія активна.")
            except Exception:
                pass
        elif etype == 'buyer':
            # Скупщик больше не платит автоматически
            # Пользователь должен открыть меню скупщика и выбрать фрукты для продажи
            try:
                bot.send_message(user_id, 
                    "🧑‍🌾 <b>Скупщик прибув!</b>\n\n"
                    "💰 <b>Скупщик готовий купити ваші фрукти за підвищену ціну!</b>\n"
                    "📈 <i>Ціни вищі на 15-20% від звичайних</i>\n\n"
                    "💡 <i>Натисніть 'Відкрити біржу' щоб продати фрукти скупщику</i>",
                    parse_mode="HTML")
            except Exception:
                pass
        else:
            try:
                title = {
                    'storm': '🌪️ Буря', 'rain': '🌧️ Дощ', 'drought': '🔥 Посуха',
                    'pests': '🐛 Шкідники', 'rush': '⚡ Турбо', 'golden': '🥇 Золоте',
                    'buyer': '🧑‍🌾 Скупщик', 'market': '🕸️ Ринок'
                }.get((etype or '').lower(), etype)
                bot.send_message(user_id, f"🎉 Ви успішно взяли участь у події <b>{title}</b>!", parse_mode="HTML")
            except Exception:
                pass
    except Exception as e:
        print(f"[EVENT][ERR] apply_event_effects: {e}")


def is_cancel_step(message):
    # Якщо це команда або просто пустий текст
    if not getattr(message, 'text', None) or str(message.text).startswith('/'):
        return True
    return False

def convert_frozen_timestamp_to_int(frozen_at):
    """Конвертує frozen_at (string або int) в integer Unix timestamp"""
    import time
    import datetime
    
    # Якщо вже integer, повертаємо як є
    if isinstance(frozen_at, int):
        return frozen_at
    
    # Якщо string, парсимо SQLite TIMESTAMP формат
    if isinstance(frozen_at, str):
        try:
            # Спробуємо парсити формат "YYYY-MM-DD HH:MM:SS"
            dt = datetime.datetime.strptime(frozen_at, '%Y-%m-%d %H:%M:%S')
            return int(dt.timestamp())
        except ValueError:
            # Якщо не вдалося, спробуємо інші формати
            try:
                # Можливо формат без секунд
                dt = datetime.datetime.strptime(frozen_at, '%Y-%m-%d %H:%M')
                return int(dt.timestamp())
            except ValueError:
                # Якщо все ще не вдалося, спробуємо як число
                try:
                    return int(float(frozen_at))
                except (ValueError, TypeError):
                    # Якщо нічого не спрацювало, повертаємо поточний час як fallback
                    return int(time.time())
    
    # Fallback на поточний час
    return int(time.time())

def freeze_check(func):
    """Декоратор для перевірки заморозки акаунта"""
    def wrapper(*args, **kwargs):
        callback_data = None
        user_id = None
        # Логирование для отладки
        if args and hasattr(args[0], 'data'):
            callback_data = args[0].data
            if hasattr(args[0], 'from_user'):
                user_id = args[0].from_user.id
            
            office_callbacks = (
                "office_menu", "office_agency", "office_info", "office_top",
                "office_withdraw_profit", "office_confirm_withdraw",
                "office_employee_already_hired", "office_insufficient_funds",
            )
            is_office = (
                callback_data in office_callbacks or 
                (callback_data and callback_data.startswith(("office_employee_info:", "office_buy_employee:")))
            )
            if is_office:
                print(f"[DEBUG] freeze_check: START for {callback_data}, user: {user_id}")
        
        # Отримуємо user_id з аргументів
        if not user_id:
            if args and hasattr(args[0], 'from_user'):
                user_id = args[0].from_user.id
            elif args and hasattr(args[0], 'id'):
                user_id = args[0].id

        if user_id:
            try:
                is_frozen, freeze_info = get_user_freeze_info(user_id)
                if is_frozen and freeze_info:
                    is_office = (
                        callback_data and (
                            callback_data in ("office_menu", "office_agency", "office_info", "office_top",
                            "office_withdraw_profit", "office_confirm_withdraw",
                            "office_employee_already_hired", "office_insufficient_funds") or 
                            callback_data.startswith(("office_employee_info:", "office_buy_employee:"))
                        )
                    )
                    if is_office:
                        print(f"[DEBUG] freeze_check: account is FROZEN for {callback_data}, user: {user_id}")
                    # Форматуємо дату заморозки
                    import time
                    try:
                        frozen_timestamp = convert_frozen_timestamp_to_int(freeze_info.get('frozen_at', time.time()))
                        frozen_date = time.strftime('%d.%m.%Y %H:%M', time.localtime(frozen_timestamp))
                    except Exception as e:
                        print(f"[ERROR] freeze_check: error converting timestamp: {e}")
                        frozen_date = "Невідомо"
                    
                    freeze_message = (
                        f"🧊 <b>АККАУНТ ЗАМОРОЖЕНО</b> 🧊\n\n"
                        f"❄️ <b>Ваш акаунт тимчасово заблоковано</b>\n\n"
                        f"📅 <b>Дата заморозки:</b> {frozen_date}\n"
                        f"📝 <b>Причина:</b> {freeze_info.get('reason', 'Не вказано')}\n\n"
                        f"⚠️ <b>Доступні дії обмежено:</b>\n"
                        f"• ❌ Не можна виводити кошти\n"
                        f"• ❌ Не можна продавати фрукти\n"
                        f"• ❌ Не можна брати участь в іграх\n"
                        f"• ❌ Не можна отримувати подарунки\n\n"
                        f"💬 <b>Для розблокування зверніться до адміністратора</b>"
                    )
                    
                    # Відправляємо повідомлення про заморозку
                    try:
                        if args and hasattr(args[0], 'id') and hasattr(args[0], 'from_user'):
                            # Це callback_query
                            bot.answer_callback_query(args[0].id, text="❄️ Акаунт заморожено", show_alert=True)
                            bot.send_message(user_id, freeze_message, parse_mode="HTML")
                        elif args and hasattr(args[0], 'reply_to'):
                            args[0].reply_to(freeze_message, parse_mode="HTML")
                        else:
                            bot.send_message(user_id, freeze_message, parse_mode="HTML")
                    except Exception as e:
                        print(f"[ERROR] freeze_check: error sending freeze message: {e}")
                        import traceback
                        traceback.print_exc()
                    # Якщо акаунт заморожений, не виконуємо функцію
                    # Отвечаем на callback_query если это callback
                    if args and hasattr(args[0], 'id'):
                        try:
                            from utils import safe_answer_callback_query
                            safe_answer_callback_query(args[0], text="🧊 Акаунт заморожено", show_alert=False)
                        except:
                            try:
                                bot.answer_callback_query(args[0].id)
                            except:
                                pass
                    return None
            except Exception as e:
                print(f"[ERROR] freeze_check: error checking freeze status: {e}")
                import traceback
                traceback.print_exc()
                # У випадку помилки продовжуємо виконання
        
        # Аккаунт не заморожен - продолжаем
        is_office = (
            callback_data and (
                callback_data in ("office_menu", "office_agency", "office_info", "office_top",
                "office_withdraw_profit", "office_confirm_withdraw",
                "office_employee_already_hired", "office_insufficient_funds") or 
                callback_data.startswith(("office_employee_info:", "office_buy_employee:"))
            )
        )
        if is_office:
            print(f"[DEBUG] freeze_check: PASSED for {callback_data}, user: {user_id}, calling function")
        
        result = func(*args, **kwargs)
        
        if is_office:
            print(f"[DEBUG] freeze_check: function returned for {callback_data}, user: {user_id}")
        
        return result
    return wrapper

def admin_user_transactions(call):
    if not is_admin(call.from_user.id):
        return bot.answer_callback_query(call.id, "⛔️ Немає доступу", show_alert=True)
    try:
        user_id = int(call.data.split(":",1)[1])
    except Exception:
        return bot.answer_callback_query(call.id)
    from database import _db, get_user_balance_ledger
    rows = []
    import time
    try:
        from database import get_ref_bonus
        with _db() as con:
            # Депозиты
            for r in con.execute("SELECT amount, comment, created_at FROM deposit_tx WHERE user_id=? AND status='approved' ORDER BY created_at DESC LIMIT 50", (user_id,)).fetchall():
                rows.append((r[2] or '', '+', float(r[0] or 0), 'deposit', r[1] or ''))
            # Выводы
            for r in con.execute("SELECT amount, comment, processed_at FROM tx WHERE user_id=? AND status='done' ORDER BY processed_at DESC LIMIT 50", (user_id,)).fetchall():
                rows.append((r[2] or '', '-', float(r[0] or 0), 'withdraw', r[1] or ''))
            # Садовые транзакции
            for r in con.execute("SELECT amount, type, timestamp, comment FROM garden_transactions WHERE user_id=? ORDER BY timestamp DESC LIMIT 80", (user_id,)).fetchall():
                rows.append((int(r[2] or 0), '~', float(r[0] or 0), f"garden:{r[1] or ''}", r[3] or ''))
            # Реферальные бонусы
            try:
                ref_bonus = float(get_ref_bonus())
            except Exception:
                ref_bonus = 0.0
            try:
                for r in con.execute("SELECT user_id, invited_at FROM referral_timestamps WHERE invited_by=? ORDER BY invited_at DESC LIMIT 100", (user_id,)).fetchall():
                    ts = int(r[1] or 0)
                    rows.append((ts, '+', ref_bonus, 'referral', f"Бонус за реферала {r[0]}"))
            except Exception:
                pass
            # Логи
            for r in con.execute("SELECT action, details, timestamp FROM logs WHERE user_id=? ORDER BY timestamp DESC LIMIT 50", (user_id,)).fetchall():
                rows.append((int(r[2] or 0), '±', 0.0, f"log:{r[0] or ''}", r[1] or ''))
        
        # ВАЖНО: Добавляем ВСЕ изменения баланса из balance_ledger
        try:
            balance_ledger = get_user_balance_ledger(user_id, 200)
            for r in balance_ledger:
                delta, balance_before, balance_after, reason, details, created_at = r
                sign = '+' if float(delta) > 0 else '-' if float(delta) < 0 else '='
                rows.append((
                    int(created_at), 
                    sign, 
                    abs(float(delta)), 
                    f"balance:{reason or 'unknown'}", 
                    f"Было: {float(balance_before):.2f}₴ → Стало: {float(balance_after):.2f}₴" + (f" | {details}" if details else "")
                ))
        except Exception as e:
            print(f"[ADMIN] balance_ledger error: {e}")
            
    except Exception as e:
        print(f"[ADMIN] user tx read error: {e}")
    try:
        def _norm_ts(x):
            try:
                return int(x[0]) if isinstance(x[0], (int,float)) else int(time.mktime(time.strptime(x[0], "%Y-%m-%d %H:%M:%S")))
            except Exception:
                return 0
        rows.sort(key=_norm_ts, reverse=True)
    except Exception:
        pass
    head = f"📒 <b>Транзакції користувача</b> <code>{user_id}</code>\n"
    if not rows:
        return bot.edit_message_text(head+"\nПоки що записів немає.", call.message.chat.id, call.message.message_id, parse_mode="HTML")
    lines = [head]
    # Локалізація джерел
    def _localize_src(src: str) -> str:
        try:
            s = str(src or '')
            if s.startswith('balance:'):
                reason = s.split(':',1)[1]
                mapping = {
                    'auto': 'Автоматично',
                    'admin_chat_meta': 'Адмін (чат)',
                    'deposit': 'Депозит',
                    'withdraw': 'Вивід',
                    'referral': 'Реферальний бонус',
                    'garden_harvest': 'Сад: збір урожаю',
                    'garden_sell': 'Сад: продаж фруктів',
                    'garden_commission': 'Сад: комісія',
                    'event_bonus': 'Подія: бонус',
                    'event_golden': 'Подія: золоте яблуко',
                    'event_buyer': 'Подія: скупщик',
                    'event_market': 'Подія: чорний ринок',
                    'admin_balance': 'Адмін: зміна балансу',
                    'system': 'Система',
                    'unknown': 'Невідомо'
                }
                return mapping.get(reason, f"Баланс: {reason}")
            if s.startswith('garden:'):
                kind = s.split(':',1)[1]
                mapping = {
                    'harvest': 'Сад: збір',
                    'watering': 'Сад: полив',
                    'buy_tree': 'Сад: покупка дерева',
                    'sell_fruit': 'Сад: продаж фруктів',
                    'garden_commission': 'Сад: комісія',
                }
                return mapping.get(kind, f"Сад: {kind}")
            if s == 'withdraw':
                return 'Вивід'
            if s == 'deposit':
                return 'Депозит'
            if s == 'referral':
                return 'Реферальний бонус'
            if s.startswith('log:'):
                return f"Подія: {s.split(':',1)[1]}"
            return s
        except Exception:
            return str(src)
    for ts, sign, amt, src, cm in rows[:20]:
        try:
            if isinstance(ts, (int,float)):
                dt = time.strftime('%Y-%m-%d %H:%M:%S', time.localtime(int(ts))) if ts else '-'
            else:
                dt = str(ts)
        except Exception:
            dt = str(ts)
        amt_s = f"{sign}{amt:.2f}₴" if sign in ('+','-') else f"{amt:.2f}"
        src_ua = _localize_src(src)
        lines.append(f"• <b>{dt}</b> — <b>{src_ua}</b> — <b>{amt_s}</b>\n   {cm}".strip())
    try:
        from telebot.types import InlineKeyboardMarkup, InlineKeyboardButton
        kb = InlineKeyboardMarkup().add(InlineKeyboardButton("⬅️ Назад", callback_data=f"admin_view_profile"))
    except Exception:
        kb = None
    bot.edit_message_text("\n".join(lines), call.message.chat.id, call.message.message_id, reply_markup=kb, parse_mode="HTML")
