        lines.append(f"{emoji} <b>{html.escape(name)}</b>: ціна <b>{format_currency(price)}₴</b>, множник <b>{mult}×</b>{income_txt}{promo_txt}")
        kb.add(
            InlineKeyboardButton(f"{emoji} Ціна", callback_data=f"fruit_set_price:{ftype}"),
            InlineKeyboardButton(f"{emoji} x1/x2/x3", callback_data=f"fruit_set_mult:{ftype}")
        )
