import calendar

def _kyiv_offset_seconds_for_timestamp(ts: int) -> int:
    """Повертає зсув Києва від UTC у секундах для заданого timestamp.
    Правила літнього часу: остання неділя березня 01:00 UTC → +3; остання неділя жовтня 01:00 UTC → +2.
    """
    dt_utc = datetime.datetime.utcfromtimestamp(int(ts))
    year = dt_utc.year
    # Обчислюємо останню неділю місяця
    def last_sunday(year: int, month: int) -> int:
        last_day = calendar.monthrange(year, month)[1]
        wd = datetime.date(year, month, last_day).weekday()  # 0=Mon..6=Sun
        return last_day - ((wd + 1) % 7)
    # Межі переходів у UTC
    dst_start_utc = datetime.datetime(year, 3, last_sunday(year, 3), 1, 0, 0)  # +2 → +3
    dst_end_utc = datetime.datetime(year, 10, last_sunday(year, 10), 1, 0, 0)   # +3 → +2
    if dst_start_utc <= dt_utc < dst_end_utc:
        return 3 * 3600
    return 2 * 3600

def get_kiev_time():
    """Повертає поточний час у Києві (dd.mm.YYYY HH:MM) без зовнішніх бібліотек."""
    import time as _time
    ts = int(_time.time())
    offset = _kyiv_offset_seconds_for_timestamp(ts)
    dt = datetime.datetime.utcfromtimestamp(ts) + datetime.timedelta(seconds=offset)
    return dt.strftime('%d.%m.%Y %H:%M')

def get_kiev_time_short():
    """Поточний час Києва HH:MM:SS."""
    import time as _time
    ts = int(_time.time())
    offset = _kyiv_offset_seconds_for_timestamp(ts)
    dt = datetime.datetime.utcfromtimestamp(ts) + datetime.timedelta(seconds=offset)
    return dt.strftime('%H:%M:%S')

def format_kiev_time(timestamp):
    """Форматує UTC timestamp як час Києва (dd.mm.YYYY HH:MM)."""
    if not timestamp:
        return '—'
    ts = int(timestamp)
    offset = _kyiv_offset_seconds_for_timestamp(ts)
    dt = datetime.datetime.utcfromtimestamp(ts) + datetime.timedelta(seconds=offset)
    return dt.strftime('%d.%m.%Y %H:%M')

def get_user_timezone(user_id):
    """Отримує часовий пояс користувача з бази даних"""
    try:
        from database import get_user_timezone as db_get_timezone
        timezone = db_get_timezone(user_id)
        return timezone if timezone else 'Europe/Kiev'  # За замовчуванням Київ
    except:
        return 'Europe/Kiev'

def format_user_time(datetime_str, user_id):
    """Форматує datetime (UTC) як час Києва (dd.mm.YYYY HH:MM)."""
    if not datetime_str or datetime_str == "1970-01-01 01:00:17":
        return "—"
    try:
        from datetime import datetime as _dt
        if isinstance(datetime_str, str):
            dt_utc = _dt.strptime(datetime_str, "%Y-%m-%d %H:%M:%S")
        else:
            dt_utc = datetime_str
        # Перетворення з UTC до Києва
        ts = int((dt_utc - _dt(1970, 1, 1)).total_seconds())
        offset = _kyiv_offset_seconds_for_timestamp(ts)
        dt = datetime.datetime.utcfromtimestamp(ts) + datetime.timedelta(seconds=offset)
        return dt.strftime('%d.%m.%Y %H:%M')
    except Exception:
        try:
            return str(datetime_str)
        except Exception:
            return "—"

def get_user_current_time(user_id):
    """Повертає поточний час Києва (dd.mm.YYYY HH:MM)."""
    return get_kiev_time()

