import os

# Налаштування підключення до Telegram API
# Система автоматичного вибору режиму підключення з fallback механізмом
import requests
from requests.adapters import HTTPAdapter
from urllib3.util.retry import Retry

proxy_env_vars = ['HTTP_PROXY', 'HTTPS_PROXY', 'http_proxy', 'https_proxy', 
                  'ALL_PROXY', 'all_proxy', 'NO_PROXY', 'no_proxy']
saved_proxy_vars = {}
for var in proxy_env_vars:
    if var in os.environ:
        saved_proxy_vars[var] = os.environ[var]

# Глобальна змінна для режиму підключення
_current_proxy_mode = None  # 'direct', 'proxy', or None (auto)

def create_telegram_session(use_proxy=False):
    """Створює requests session для Telegram API з retry стратегією"""
    session = requests.Session()
    
    # Налаштовуємо retry стратегію для стійкості
    retry_strategy = Retry(
        total=3,
        backoff_factor=1,
        status_forcelist=[429, 500, 502, 503, 504],
        allowed_methods=["GET", "POST"]
    )
    adapter = HTTPAdapter(max_retries=retry_strategy)
    session.mount("http://", adapter)
    session.mount("https://", adapter)
    
    if use_proxy:
        # Використовуємо прокси з оточення
        session.trust_env = True
        # Відновлюємо змінні оточення якщо вони були збережені
        for var, value in saved_proxy_vars.items():
            os.environ[var] = value
        print("[INFO] Using proxy from environment for Telegram API")
    else:
        # Без прокси
        session.proxies = {
            'http': None,
            'https': None,
        }
        if hasattr(session, 'trust_env'):
            session.trust_env = False
        # Видаляємо змінні оточення прокси
        for var in proxy_env_vars:
            if var in os.environ:
                os.environ.pop(var)
        print("[INFO] Proxy disabled for Telegram API")
    
    return session

# Функція для створення обгорнутого request з обробкою помилок прокси та мережі
def create_wrapped_request(sess):
    """Створює обгорнутий метод request для конкретної сесії"""
    original_session_request = requests.Session.request
    
    def wrapped_request(method, url, **kwargs):
        """Обгортає request з автоматичним переключенням при помилках прокси або мережі"""
        try:
            return original_session_request(sess, method, url, **kwargs)
        except (requests.exceptions.ProxyError, requests.exceptions.ConnectionError) as e:
            error_str = str(e).lower()
            error_type = type(e).__name__
            
            # Перевіряємо помилки прокси
            proxy_errors = [
                'proxyerror',
                'remote end closed connection',
                'remote end closed connection without response',
                'unable to connect to proxy',
                'tunnel connection failed'
            ]
            
            # Перевіряємо помилки мережі
            network_errors = [
                'network is unreachable',
                'errno 101',
                'connection refused',
                'failed to establish a new connection',
                'max retries exceeded'
            ]
            
            is_proxy_error = any(err in error_str for err in proxy_errors)
            is_network_error = any(err in error_str for err in network_errors)
            
            global _current_proxy_mode, session
            
            # Якщо помилка прокси і використовуємо прокси - переключаємося на пряме підключення
            if is_proxy_error and _current_proxy_mode == 'proxy':
                print(f"[WARNING] Proxy error detected: {error_str[:100]}")
                print("[INFO] Switching to direct connection due to proxy failure...")
                try:
                    switch_connection_mode('direct')
                    # Повторюємо запит з новою сесією
                    return original_session_request(session, method, url, **kwargs)
                except Exception as e2:
                    print(f"[ERROR] Direct connection also failed: {e2}")
                    raise e
            
            # Якщо помилка мережі і використовуємо пряме підключення - спробуємо прокси
            elif is_network_error and _current_proxy_mode == 'direct' and saved_proxy_vars:
                print(f"[WARNING] Network error detected: {error_str[:100]}")
                print("[INFO] Switching to proxy connection due to network failure...")
                try:
                    switch_connection_mode('proxy')
                    # Повторюємо запит з новою сесією
                    return original_session_request(session, method, url, **kwargs)
                except Exception as e2:
                    print(f"[ERROR] Proxy connection also failed: {e2}")
                    # Повертаємося до прямого підключення
                    switch_connection_mode('direct')
                    raise e
            
            # Інші помилки - просто перекидаємо
            raise e
    
    return wrapped_request

# Створюємо сесію - спочатку пробуємо БЕЗ прокси, якщо не працює - переключимося на прокси
# Бо на деяких хостингах прокси може бути нестабільним (503 помилки)
print("[INFO] Starting with direct connection (will switch to proxy if needed)...")
session = create_telegram_session(use_proxy=False)
_current_proxy_mode = 'direct'

# Додаємо обгортку для обробки помилок прокси
try:
    session.request = create_wrapped_request(session)
except Exception as e:
    print(f"[WARNING] Could not wrap session request: {e}")

# Функція для переключення режиму підключення
def switch_connection_mode(new_mode):
    """Переключає режим підключення між direct та proxy"""
    global session, _current_proxy_mode
    if _current_proxy_mode == new_mode:
        return session
    
    print(f"[INFO] Switching connection mode: {_current_proxy_mode} -> {new_mode}")
    session = create_telegram_session(use_proxy=(new_mode == 'proxy'))
    _current_proxy_mode = new_mode
    
    # Додаємо обгортку для обробки помилок прокси
    try:
        session.request = create_wrapped_request(session)
    except Exception:
        pass
    
    # Оновлюємо функцію в telebot
    telebot.apihelper._get_req_session = lambda: session
    return session

# Налаштовуємо telebot.apihelper з обробкою помилок
try:
    telebot.apihelper.proxy = None
    
    # Встановлюємо функцію для отримання сесії
    def get_req_session_func():
        return session
    
    original_get_session = getattr(telebot.apihelper, '_get_req_session', None)
    if original_get_session:
        telebot.apihelper._get_req_session = get_req_session_func
    else:
        telebot.apihelper._get_req_session = get_req_session_func
except Exception as e:
    print(f"[WARNING] Could not configure proxy settings: {e}")
    import traceback
    traceback.print_exc()

# Зчитуємо токен з змінної середовища для безпеки
TOKEN = os.environ.get("TELEGRAM_BOT_TOKEN")
if not TOKEN:
    # ВРЕМЕННО: для локального тестирования (НЕ ИСПОЛЬЗУЙТЕ НА ПРОДАКШЕНЕ!)
    TOKEN = "7612542064:AAHj6KKNYHuJP1Jjyf06IeeJTe1XMZcsVM8"  # Замените на ваш реальный токен
    # raise RuntimeError("TELEGRAM_BOT_TOKEN env var is not set. Set it to your bot token.")

state_storage = StateMemoryStorage()
bot = telebot.TeleBot(TOKEN, parse_mode="HTML", state_storage=state_storage)

# Перевіряємо авторизацію на старті з автоматичним переключенням режимів
# Спробуємо підключитися, переключаючись між режимами при помилках
boot_success = False

# ВСЕГДА спочатку пробуємо пряме підключення (бо прокси може бути нестабільним)
print("[BOOT] Attempting direct connection first...")
try:
    # Переконаємося що використовуємо пряме підключення
    if _current_proxy_mode != 'direct':
        switch_connection_mode('direct')
    
    me = bot.get_me()
    print(f"[BOOT] Bot authorized as @{me.username} (id {me.id}) [via direct]")
    boot_success = True
except Exception as e:
    error_str = str(e).lower()
    print(f"[BOOT] Direct connection failed: {error_str[:100]}")
    
    # Перевіряємо чи це помилка мережі (network unreachable)
    network_errors = [
        'network is unreachable', 'connection refused', 'errno 101',
        'failed to establish a new connection'
    ]
    
    is_network_error = any(err in error_str for err in network_errors)
    
    # Якщо помилка мережі - спробуємо прокси (якщо є)
    if is_network_error and saved_proxy_vars:
        print("[BOOT] Network unreachable, trying proxy...")
        try:
            switch_connection_mode('proxy')
            me = bot.get_me()
            print(f"[BOOT] Bot authorized as @{me.username} (id {me.id}) [via proxy]")
            boot_success = True
        except Exception as e2:
            error_str2 = str(e2).lower()
            print(f"[BOOT] Proxy connection also failed: {error_str2[:100]}")
            
            # Якщо прокси повернув 503 - спробуємо ще раз пряме підключення
            proxy_errors = ['503', 'service unavailable', 'tunnel connection failed']
            if any(err in error_str2 for err in proxy_errors):
                print("[BOOT] Proxy returned 503, retrying direct connection...")
                try:
                    switch_connection_mode('direct')
                    me = bot.get_me()
                    print(f"[BOOT] Bot authorized as @{me.username} (id {me.id}) [via direct after proxy 503]")
                    boot_success = True
                except Exception as e3:
                    print(f"[BOOT] Direct connection failed again: {str(e3)[:100]}")
                    boot_success = False
            else:
                boot_success = False
    else:
        # Перевіряємо чи це помилка прокси (якщо вже використовували прокси)
        proxy_errors = [
            '503', 'service unavailable', 'tunnel connection failed',
            'proxyerror', 'unable to connect to proxy'
        ]
        is_proxy_error = any(err in error_str for err in proxy_errors)
        
        if is_proxy_error:
            print("[BOOT] Proxy error detected, trying direct connection...")
            try:
                switch_connection_mode('direct')
                me = bot.get_me()
                print(f"[BOOT] Bot authorized as @{me.username} (id {me.id}) [via direct after proxy error]")
                boot_success = True
            except Exception as e2:
                print(f"[BOOT] Direct connection also failed: {str(e2)[:100]}")
                boot_success = False
        else:
            # Інша помилка (401, 403, тощо) - не переключаємося, просто перекидаємо
            print(f"[BOOT] Authorization failed (not a connection error): {e}")
            raise

if not boot_success:
    print("[ERROR] Failed to connect via both proxy and direct connection")
    print("[ERROR] Please check your network connection and proxy settings")
    raise RuntimeError("Bot failed to start: unable to connect to Telegram API")

# Додаємо middleware для автоматичного переключення при помилках прокси
def proxy_error_handler(request, exception):
    """Обробник помилок прокси з автоматичним переключенням"""
    error_str = str(exception).lower()
    
    # Перевіряємо чи це помилка прокси
    proxy_errors = [
        'proxyerror',
        'remote end closed connection',
        'remote end closed connection without response',
        'unable to connect to proxy',
        'tunnel connection failed'
    ]
    
    is_proxy_error = any(err in error_str for err in proxy_errors)
    
    if is_proxy_error:
        current_mode = _current_proxy_mode
        print(f"[WARNING] Proxy error detected: {exception}")
        
        # Якщо використовуємо прокси - спробуємо переключитися на прямое підключення
        if current_mode == 'proxy':
            print("[INFO] Attempting to switch to direct connection...")
            try:
                switch_connection_mode('direct')
                # Повторюємо запит
                return telebot.apihelper._get_req_session().request(
                    request.method, request.url, 
                    params=request.params, files=request.files,
                    timeout=request.timeout, proxies=None
                )
            except Exception as e2:
                print(f"[ERROR] Direct connection also failed: {e2}")
                # Повертаємося до прокси
                switch_connection_mode('proxy')
                raise exception
        # Якщо використовуємо прямое підключення - спробуємо прокси
        elif current_mode == 'direct':
            print("[INFO] Attempting to switch to proxy...")
            try:
                switch_connection_mode('proxy')
                # Повторюємо запит
                return telebot.apihelper._get_req_session().request(
                    request.method, request.url,
                    params=request.params, files=request.files,
                    timeout=request.timeout
                )
            except Exception as e2:
                print(f"[ERROR] Proxy connection also failed: {e2}")
                # Повертаємося до прямого підключення
                switch_connection_mode('direct')
                raise exception
    
    # Якщо не помилка прокси - просто перекидаємо
    raise exception

# Реєструємо обробник помилок прокси для автоматичного переключення
try:
    # Замінюємо метод request для нашої сесії
    session.request = create_wrapped_request(session)
except Exception as e:
    print(f"[WARNING] Could not register proxy error handler: {e}")
    import traceback
    traceback.print_exc()

# --- Автозагрузка зовнішніх адмін‑хендлерів, якщо вони існують ---
def _autoload_admin_handlers():
    try:
        import importlib, glob, os as _os, sys as _sys
        base_dir = _os.path.dirname(__file__)
        pattern = _os.path.join(base_dir, "admin*_handler.py")
        for path in glob.glob(pattern):
            mod_name = _os.path.splitext(_os.path.basename(path))[0]
            if mod_name in _sys.modules:
                continue
            try:
                importlib.import_module(mod_name)
                print(f"[ADMIN] loaded handlers from {mod_name}")
            except Exception as e:
                print(f"[ADMIN] failed to load {mod_name}: {e}")
    except Exception as e:
        print(f"[ADMIN] autoload error: {e}")

_autoload_admin_handlers()

