@bot.callback_query_handler(func=lambda c: c.data.startswith("event_info:"))
def event_info_handler(call):
    try:
        _, eid_s = call.data.split(":", 1)
        eid = int(eid_s)
    except Exception:
        return bot.answer_callback_query(call.id)
    try:
        from database import get_event_by_id
        row = get_event_by_id(eid)
        if not row:
            return bot.answer_callback_query(call.id, "Подію не знайдено", show_alert=True)
        eid, etype, p, st, en, status, created_by, chat_id = row
        params = _json_loads_safe(p)
        dur = int(params.get('dur', params.get('duration', 0)) or 0)
        # Формуємо красивий опис за типом
        lines = [f"<b>ℹ️ Деталі події</b> • #{eid}", "━━━━━━━━━━━━━━━━━━━━"]
        if etype == 'storm':
            loss = int(float(params.get('damage_pct', 0.25))*100)
            bonus_cap = int(float(params.get('cap', 20)))
            lines += [
                "🌪️ <b>Буря</b>",
                f"⏳ Тривалість: {dur} хв",
                f"❌ Втрата врожайності без укриття: −{loss}%",
                f"🛡️ Бонус при укритті: до +{bonus_cap} шт",
                "💡 Порада: укрийте сад або зберіть врожай завчасно."
            ]
        elif etype == 'rain':
            gain = int(float(params.get('gain_pct', 0.10))*100)
            lines += [
                "🌧️ <b>Дощ</b>",
                f"⏳ Тривалість: {dur} хв",
                f"✅ Посилення збору: +{gain}%",
                "💡 Порада: активуйте і збирайте під час дощу."
            ]
        elif etype == 'drought':
            pen = int(abs(float(params.get('penalty', -0.05)))*100)
            lines += [
                "🔥 <b>Посуха</b>",
                f"⏳ Тривалість: {dur} хв",
                f"❌ Штраф без поливу: −{pen}%",
                "💧 Порада: полийте дерева або зберіть врожай одразу."
            ]
        elif etype == 'pests':
            loss = int(float(params.get('loss_pct', 0.15))*100)
            prot = int(float(params.get('protect_bonus', 0.03))*100)
            lines += [
                "🐛 <b>Шкідники</b>",
                f"⏳ Тривалість: {dur} хв",
                f"❌ Втрата без обробки: −{loss}%",
                f"✅ Захист після обробки: +{prot}%",
                "💡 Порада: обробіть сад або зберіть врожай."
            ]
        elif etype == 'rush':
            mult = int(float(params.get('mult', 0.15))*100)
            lines += [
                "⚡ <b>Турбо</b>",
                f"⏳ Тривалість: {dur} хв",
                f"✅ Множник для учасників: +{mult}%",
                "💡 Порада: активуйте та збирайте поки діє турбо."
            ]
        elif etype == 'buyer':
            pct = int(float(params.get('bonus_price_pct', 0.07))*100)
            limit = float(params.get('limit', 100.0))
            lines += [
                "🧑‍🌾 <b>Скупщик</b>",
                f"⏳ Тривалість: {dur} хв",
                f"💵 Надбавка до ціни: +{pct}%",
                f"📦 Ліміт за бонусною ціною: {limit:.0f} шт",
                "💡 Порада: продайте частину фруктів зараз, решту — пізніше."
            ]
        elif etype == 'market':
            vol = int(float(params.get('volatility_pct', 0.05))*100)
            fee = int(float(params.get('extra_fee_pct', 0.12))*100)
            lines += [
                "🕸️ <b>Чорний ринок</b>",
                f"⏳ Тривалість: {dur} хв",
                f"📈 Волатильність цін: ±{vol}%",
                f"📊 Додаткова комісія: {fee}%",
                "💡 Порада: ловіть вигідні піки ціни."
            ]
        elif etype == 'golden':
            ch = int(float(params.get('extra_chance', 0.05))*100)
            pct = int(float(params.get('extra_pct', 0.05))*100)
            lines += [
                "🥇 <b>Золоті яблука</b>",
                f"⏳ Тривалість: {dur} хв",
                f"🎯 Шанс додаткових фруктів: {ch}%",
                f"➕ Бонус до врожаю: {pct}%",
                "💡 Порада: збирайте частіше, щоб зловити шанс."
            ]
        else:
            lines += [f"Тип: {etype}"]
        # Показуємо коротку довідку як alert (Telegram обмежує довжину)
        text_plain = "\n".join([
            # Прибираємо HTML теги для alert
            l.replace('<b>','').replace('</b>','').replace('<i>','').replace('</i>','') for l in lines
        ])
        if len(text_plain) > 900:
            text_plain = text_plain[:900] + "…"
        try:
            bot.answer_callback_query(call.id, text_plain, show_alert=True)
        except Exception:
            # Фолбек: якщо alert не вдався — надіслати повідомлення в чат
            try:
                bot.send_message(call.message.chat.id, "\n".join(lines), parse_mode="HTML")
            except Exception:
                pass
    except Exception:
        try:
            bot.answer_callback_query(call.id)
        except Exception:
            pass

# --- ПРОСТА СИСТЕМА УПРАВЛІННЯ АДМІНІСТРАТОРАМИ (ВИСОКИЙ ПРІОРИТЕТ) ---
@bot.message_handler(func=lambda message: message.from_user.id == 6029312631 and get_user_state(message.from_user.id) == "waiting_admin_id")
def simple_add_admin_handler(message):
    """Простий обробник для додавання адміністратора"""
    print(f"[ADMIN] ===== ADD ADMIN HANDLER TRIGGERED! =====")
    print(f"[ADMIN] User: {message.from_user.id}")
    print(f"[ADMIN] Text: {message.text}")
    print(f"[ADMIN] State: {get_user_state(message.from_user.id)}")
    
    try:
        user_id = int(message.text.strip())
        
        # Перевіряємо, чи не намагається додати себе
        if user_id == message.from_user.id:
            bot.reply_to(message, "❌ Ви не можете додати себе як адміністратора!")
            clear_user_state(message.from_user.id)
            return
        
        # Перевіряємо, чи не намагається додати створювача бота
        if user_id == 6029312631:
            bot.reply_to(message, "❌ Цей користувач вже є створювачем бота!")
            clear_user_state(message.from_user.id)
            return
        
        # Додаємо адміністратора
        from database import grant_admin, is_admin
        grant_admin(user_id)
        
        # Перевіряємо, чи дійсно додався
        if is_admin(user_id):
            # Повідомлення створювачу
            bot.reply_to(message, f"✅ <b>Успішно!</b>\n\n"
                                f"👤 Користувач <code>{user_id}</code> тепер адміністратор!\n"
                                f"🛠️ У нього з'явиться кнопка 'Адмінка' в головному меню.", 
                                parse_mode="HTML")
            
            # Повідомлення новому адміністратору
            try:
                bot.send_message(user_id, "🎉 <b>Вітаємо!</b>\n\n"
                                         "🛡️ <b>Ви отримали права адміністратора!</b>\n\n"
                                         "👑 <b>Видано:</b> Створювач бота\n"
                                         "⏰ <b>Час:</b> Зараз\n"
                                         "🔧 <b>Доступ:</b> Повний доступ до адмін-панелі\n\n"
                                         "📱 Натисніть /start щоб побачити нове меню з кнопкою '🛠 Адмінка'", 
                                         parse_mode="HTML")
                print(f"[ADMIN] Message sent to new admin {user_id}")
            except Exception as e:
                print(f"[ADMIN] Failed to send message to new admin {user_id}: {e}")
        else:
            bot.reply_to(message, f"❌ Помилка: не вдалося додати користувача <code>{user_id}</code> як адміністратора!", parse_mode="HTML")
        
        clear_user_state(message.from_user.id)
        
    except ValueError:
        bot.reply_to(message, "❌ Помилка: ID має бути числом!\n\n💡 Приклад: 123456789")
    except Exception as e:
        bot.reply_to(message, f"❌ Помилка: {e}")
        clear_user_state(message.from_user.id)

