# --- ХЕЛПЕРИ ФІЛЬТРІВ ДЛЯ ПРЕ-ПЕРЕВІРКИ ---
def _should_block_message(m):
    try:
        # Пропускаємо всі slash-команди, щоб вони доходили до своїх хендлерів
        try:
            if m.text and m.text.strip().startswith('/'):
                return False
        except Exception:
            pass
        # Імпортуємо get_user_state на початку
        from database import get_user_state
        
        # СПОЧАТКУ перевіряємо P2P стан - він важливіший за все!
        try:
            user_state = get_user_state(m.from_user.id)
            if user_state and (user_state.startswith('p2p_') or user_state.startswith('p2p_waiting_') or user_state.startswith('simple_move_')):
                print(f"[DEBUG] _should_block_message: P2P/SIMPLE_MOVE state detected: {user_state}, allowing message")
                return False
        except Exception as e:
            print(f"[DEBUG] _should_block_message: error checking P2P/SIMPLE_MOVE state: {e}")
        
        # Адміни/бета — без блокування
        is_admin_result = is_admin(m.from_user.id)
        is_beta_result = is_beta(m.from_user.id)
        
        # Додаємо відладочну інформацію для створювача бота
        if m.from_user.id == 6029312631:
            print(f"[DEBUG] _should_block_message for bot creator:")
            print(f"[DEBUG] is_admin: {is_admin_result}")
            print(f"[DEBUG] is_beta: {is_beta_result}")
            print(f"[DEBUG] Message text: '{m.text}'")
            print(f"[DEBUG] User state: '{get_user_state(m.from_user.id)}'")
        
        if is_admin_result or is_beta_result:
            return False
        # Не блокуємо системні повідомлення типу контактів — їх обробляє окремий хендлер
        try:
            if getattr(m, 'content_type', None) == 'contact':
                return False
        except Exception:
            pass
        # Дозволяємо /start пройти до свого хендлера
        if m.text and m.text.strip().startswith('/start'):
            return False
        # Не дублюємо картку, якщо вже очікуємо підписку
        try:
            user_state = get_user_state(m.from_user.id)
            # Не блокуємо для P2P-операцій
            if user_state and (user_state.startswith('p2p_') or user_state.startswith('p2p_waiting_') or user_state.startswith('simple_move_')):
                return False
            # Не блокуємо якщо очікуємо підписку
            if user_state == 'waiting_subscription':
                return False
        except Exception:
            pass
        from subscription_system import check_user_subscription
        ok = check_user_subscription(m.from_user.id, bot)
        return not ok
    except Exception as e:
        print(f"[ERROR] _should_block_message: {e}")
        return False

def _should_block_callback(c):
    try:
        if is_admin(c.from_user.id) or is_beta(c.from_user.id):
            return False
        
        # Перевіряємо чи користувач заблокований
        from database import is_user_blocked
        if is_user_blocked(c.from_user.id):
            # Дозволяємо тільки verify_subscription для розблокування
            if c.data == "verify_subscription":
                return False
            # Всі інші callback'и блокуються
            print(f"[DEBUG] Blocking callback {c.data} for blocked user {c.from_user.id}")
            return True
        
        # Якщо не заблокований, перевіряємо підписку
        from subscription_system import check_user_subscription
        ok = check_user_subscription(c.from_user.id, bot)
        return not ok
    except Exception as e:
        print(f"[ERROR] _should_block_callback: {e}")
        return False

def check_user_block_before_action(call, bot):
    """Універсальна функція для перевірки блокировки користувача перед виконанням дії"""
    try:
        from database import is_user_blocked
        if is_user_blocked(call.from_user.id):
            from subscription_system import send_subscription_required_message
            try:
                bot.answer_callback_query(call.id, "🚫 Доступ заблоковано", show_alert=False)
            except Exception:
                pass
            send_subscription_required_message(call, call.from_user.id, bot)
            return True  # Користувач заблокований
        return False  # Користувач не заблокований
    except Exception as e:
        print(f"[ERROR] check_user_block_before_action: {e}")
        return False

