@bot.message_handler(func=_should_block_message)
def subscription_precheck_all_messages_early(m):
    try:
        # СПОЧАТКУ перевіряємо чи це P2P/simple_move стан - якщо так, НЕ показуємо підписку
        try:
            from database import get_user_state
            user_state = get_user_state(m.from_user.id)
            if user_state and (user_state.startswith('p2p_') or user_state.startswith('simple_move_')):
                # Це P2P операція - НЕ показуємо картку підписки, даємо обробити іншим хендлерам
                print(f"[DEBUG] P2P state detected in subscription_precheck, not showing subscription")
                return
        except Exception as e:
            print(f"[DEBUG] Error checking state in subscription_precheck: {e}")
        
        # Додаємо відладочну інформацію для створювача бота
        if m.from_user.id == 6029312631:
            print(f"[DEBUG] ===== subscription_precheck_all_messages_early TRIGGERED! =====")
            print(f"[DEBUG] User: {m.from_user.id}")
            print(f"[DEBUG] Text: '{m.text}'")
            print(f"[DEBUG] State: '{get_user_state(m.from_user.id)}'")
            print(f"[DEBUG] ========================================================")
        
        # Якщо ми вже показали картку підписки — не дублюємо
        try:
            from database import get_user_state
            if get_user_state(m.from_user.id) == 'waiting_subscription':
                return
        except Exception:
            pass
        from subscription_system import send_subscription_required_message
        send_subscription_required_message(m, m.from_user.id, bot)
    except Exception as e:
        print(f"[ERROR] precheck messages (early): {e}")
        return

