# --- Функції для розрахунку прогресу збору фруктів ---
def calculate_harvest_progress(last_harvest_time, tree_type, user_id=None):
    """Розраховує прогрес збору фруктів для дерева з урахуванням поливу"""
    import time
    from garden_models import TREE_TYPES
    from database import get_tree_watering_status
    
    now = int(time.time())
    last_harvest = last_harvest_time or now
    
    # Знаходимо інформацію про дерево
    tree_info = next((t for t in TREE_TYPES if t['type'] == tree_type), None)
    if not tree_info:
        return 0, 0, "Невідоме дерево", "❌"
    
    # Перевіряємо рівень води якщо передано user_id
    watering_blocked = False
    if user_id:
        watering_status = get_tree_watering_status(user_id, tree_type)
        water_level = watering_status.get('water_level', 100)
        is_withered = watering_status.get('is_withered', False)
        
        # Якщо дерево засохло або рівень води дуже низький, воно не росте
        if is_withered or water_level < 20:
            watering_blocked = True
    
    # Час до збору (60 хвилин = 1 година)
    harvest_interval = 60 * 60  # 1 година в секундах
    time_since_harvest = now - last_harvest
    time_until_harvest = max(0, harvest_interval - time_since_harvest)
    
    # Прогрес у відсотках
    progress_percent = min(100, (time_since_harvest / harvest_interval) * 100)
    
    # Перевіряємо чи можна збирати (як у harvest_fruits_handler)
    hours_since_harvest = time_since_harvest // 3600
    can_harvest = hours_since_harvest >= 1 and not watering_blocked
    
    # Форматування часу
    if watering_blocked:
        # Не обнуляємо прогрес — ріст зупинено, але накопичений прогрес збережено
        time_text = "💧 ПОТРЕБУЄ ПОЛИВУ!"
        status_emoji = "🌱"
    elif can_harvest:
        time_text = "✅ ГОТОВО!"
        status_emoji = "🟢"
        progress_percent = 100  # Примусово встановлюємо 100% якщо можна збирати
    elif time_until_harvest <= 300:  # 5 хвилин
        time_text = f"⏳ {time_until_harvest // 60}хв"
        status_emoji = "🟡"
    else:
        time_text = f"⏳ {time_until_harvest // 60}хв"
        status_emoji = "🔴"
    
    return progress_percent, time_until_harvest, time_text, status_emoji

def create_progress_bar(percent, width=10):
    """Створює візуальний прогрес-бар"""
    filled = int((percent / 100) * width)
    empty = width - filled
    return "█" * filled + "░" * empty

def check_button_spam(user_id: int, button_name: str) -> tuple[bool, str]:
    """
    Перевіряє чи не спамить користувач кнопками
    
    Args:
        user_id: ID користувача
        button_name: Назва кнопки
        
    Returns:
        tuple: (is_spam, funny_message)
    """
    import time
    
    now = time.time()
    
    # Ініціалізуємо словник для користувача якщо потрібно
    if user_id not in button_spam_protection:
        button_spam_protection[user_id] = {}
    
    # Перевіряємо чи недавно натискав цю кнопку
    if button_name in button_spam_protection[user_id]:
        last_click = button_spam_protection[user_id][button_name]
        if now - last_click < SPAM_COOLDOWN:
            # Кумедні повідомлення про спам
            spam_messages = [
                "🤖 Бот: 'Спокійно, я не встигаю за твоєю швидкістю!'",
                "⚡ Ти натискаєш швидше, ніж я думаю!",
                "🦘 Стрибаєш по кнопках як кенгуру!",
                "🎯 Мета - натиснути кнопку, а не розбити її!",
                "🐰 Ти швидший за білого кролика!",
                "🚀 Натискаєш з космічною швидкістю!",
                "⚡ Електрика в пальцях? Спокійніше!",
                "🎮 Це не гонка, це бот!",
                "🦋 Легко як метелик, а не як бульдозер!",
                "🎪 Цирк з кнопками? Я не встигаю!",
                "🦈 Акула кнопок? Спокійніше!",
                "🚁 Гелікоптерний палець? Приземлися!",
                "🎯 Снайперська точність, але занадто швидко!",
                "🦅 Орел нападає на кнопки!",
                "🎪 Це не кнопка, це не джойстик!"
            ]
            
            import random
            funny_message = random.choice(spam_messages)
            return True, funny_message
    
    # Оновлюємо час останнього натискання
    button_spam_protection[user_id][button_name] = now
    
    # Очищаємо старі записи (старіше 1 хвилини)
    for btn, click_time in list(button_spam_protection[user_id].items()):
        if now - click_time > 60:
            del button_spam_protection[user_id][btn]
    
    return False, ""

def create_water_progress_bar(percent, width=8):
    """Створює візуальний прогрес-бар для води з різними символами"""
    filled = int((percent / 100) * width)
    empty = width - filled
    
    # Використовуємо різні символи для води
    if percent >= 80:
        # Багато води - сині символи
        return "💧" * filled + "░" * empty
    elif percent >= 50:
        # Середній рівень - блакитні символи
        return "🌊" * filled + "░" * empty
    elif percent >= 20:
        # Мало води - жовті символи
        return "💦" * filled + "░" * empty
    else:
        # Дуже мало води - червоні символи
        return "🔥" * filled + "░" * empty

