# Функція для бану користувача
def ban_user(user_id, duration_seconds, reason, admin_id):
    """Банує користувача"""
    try:
        import time
        from datetime import datetime, timezone, timedelta
        
        now = int(time.time())
        end_time = (now + duration_seconds) if (duration_seconds and duration_seconds > 0) else None
        
        # Форматуємо термін для відображення
        if duration_seconds == 0:
            duration_text = "Назавжди"
        else:
            duration_text = format_duration(duration_seconds)
        
        # Форматуємо дату
        date = datetime.now(timezone(timedelta(hours=3))).strftime("%d.%m.%Y %H:%M")
        
        # Зберігаємо в базу даних (сумісно зі схемою users_bans)
        from database import _db
        with _db() as con:
            con.execute("""
                INSERT OR REPLACE INTO user_bans (user_id, banned_by, reason, banned_at, expires_at)
                VALUES (?, ?, ?, ?, ?)
            """, (user_id, admin_id, reason, now, end_time))
            con.commit()
        
        return {
            'success': True,
            'duration_text': duration_text,
            'date': date,
            'ban_type': "Бан в боті"
        }
        
    except Exception as e:
        print(f"[DEBUG] Error in ban_user: {e}")
        return {
            'success': False,
            'error': str(e)
        }

