# Функція для перевірки timestamp
def is_valid_timestamp(val):
    try:
        return float(val) > 0
    except (ValueError, TypeError):
        return False

# --- Декоратор перевірки номера телефону ---
def phone_required(func):
    def wrapper(message_or_call, *args, **kwargs):
        from database import is_phone_verified, is_phone_verification_enabled
        # Визначаємо user_id
        if hasattr(message_or_call, 'from_user'):
            user_id = message_or_call.from_user.id
        else:
            user_id = message_or_call.message.from_user.id if hasattr(message_or_call, 'message') else None
        
        if not user_id:
            return
            
        # Перевіряємо, чи адмін (адмінам не потрібна перевірка)
        if is_admin(user_id):
            return func(message_or_call, *args, **kwargs)
        
        # Якщо перевірка номеру вимкнена — пропускаємо
        try:
            if not is_phone_verification_enabled():
                return func(message_or_call, *args, **kwargs)
        except Exception:
            pass

        # Перевіряємо номер телефону (обов'язково, якщо увімкнено)
        if not is_phone_verified(user_id):
            # Створюємо кнопку для поділення контактом
            from telebot.types import ReplyKeyboardMarkup, KeyboardButton
            kb = ReplyKeyboardMarkup(resize_keyboard=True, one_time_keyboard=True)
            contact_btn = KeyboardButton("📱 Поділитися контактом", request_contact=True)
            kb.add(contact_btn)
            
            phone_text = (
                "📱 <b>ВЕРИФІКАЦІЯ НОМЕРА ТЕЛЕФОНУ</b>\n"
                "━━━━━━━━━━━━━━━━━━━━\n\n"
                "🇺🇦 <b>Для безпеки використовуйте ТІЛЬКИ кнопку!</b>\n\n"
                "🔐 <b>Чому через контакт?</b>\n"
                "• Неможливо підробити\n"
                "• Підтверджується Telegram\n"
                "• Тільки українські +380 номери\n\n"
                "👆 Натисніть кнопку знизу, щоб поділитися контактом 👇"
            )
            
            if hasattr(message_or_call, 'message'):  # callback
                bot.send_message(message_or_call.message.chat.id, phone_text, 
                               reply_markup=kb, parse_mode="HTML")
            else:  # message
                bot.send_message(message_or_call.chat.id, phone_text, 
                               reply_markup=kb, parse_mode="HTML")
            # Плануємо нагадування про підтвердження номера через 5 хв
            try:
                def _schedule_phone_reminder(chat_id, user_id, delay_sec=300):
                    import threading
                    if not hasattr(bot, 'phone_reminders'):
                        bot.phone_reminders = {}
                    # Скасовуємо попередній таймер
                    prev = bot.phone_reminders.get(user_id)
                    try:
                        if prev:
                            prev.cancel()
                    except Exception:
                        pass
                    def _send():
                        try:
                            from database import is_phone_verified
                            if not is_phone_verified(user_id):
                                from telebot.types import ReplyKeyboardMarkup, KeyboardButton
                                rem_kb = ReplyKeyboardMarkup(resize_keyboard=True, one_time_keyboard=True)
                                rem_kb.add(KeyboardButton("📱 Поділитися контактом", request_contact=True))
                                bot.send_message(chat_id,
                                                 "⏰ <b>Нагадування:</b> підтвердіть номер телефону, щоб продовжити.\n\n"
                                                 "Натисніть кнопку нижче.",
                                                 parse_mode="HTML",
                                                 reply_markup=rem_kb)
                        except Exception:
                            pass
                        finally:
                            try:
                                bot.phone_reminders.pop(user_id, None)
                            except Exception:
                                pass
                    t = threading.Timer(delay_sec, _send)
                    bot.phone_reminders[user_id] = t
                    try:
                        t.daemon = True
                    except Exception:
                        pass
                    t.start()
                # Визначаємо chat_id для планування
                chat_id = message_or_call.message.chat.id if hasattr(message_or_call, 'message') else message_or_call.chat.id
                _schedule_phone_reminder(chat_id, user_id, 300)
            except Exception:
                pass
            return
        
        return func(message_or_call, *args, **kwargs)
    return wrapper

# --- Декоратор для ответа на callback_query ПЕРВЫМ ---
def answer_callback_first(func):
    """Декоратор, который отвечает на callback_query ПЕРВЫМ, до всех проверок"""
    def wrapper(message_or_call, *args, **kwargs):
        callback_data = None
        user_id = None
        # Если это callback_query - отвечаем сразу
        if hasattr(message_or_call, 'id') and hasattr(message_or_call, 'data'):
            callback_data = message_or_call.data
            if hasattr(message_or_call, 'from_user'):
                user_id = message_or_call.from_user.id
            office_callbacks = ("office_menu", "office_agency", "office_info", "office_top", 
                              "office_withdraw_profit", "office_confirm_withdraw", 
                              "office_employee_already_hired", "office_insufficient_funds")
            if callback_data in office_callbacks or (callback_data and callback_data.startswith(("office_employee_info:", "office_buy_employee:"))):
                print(f"[DEBUG] answer_callback_first: START for {callback_data}, user: {user_id}")
            try:
                bot.answer_callback_query(message_or_call.id, text="", show_alert=False)
            except Exception as e:
                print(f"[DEBUG] answer_callback_first: failed to answer callback for {callback_data}: {e}")
        
        try:
            print(f"[DEBUG] answer_callback_first: calling function {func.__name__} for {callback_data}")
            result = func(message_or_call, *args, **kwargs)
            if hasattr(message_or_call, 'data'):
                callback_data = message_or_call.data
                office_callbacks = ("office_menu", "office_agency", "office_info", "office_top",
                                  "office_withdraw_profit", "office_confirm_withdraw",
                                  "office_employee_already_hired", "office_insufficient_funds")
                if callback_data in office_callbacks or (callback_data and callback_data.startswith(("office_employee_info:", "office_buy_employee:"))):
                    print(f"[DEBUG] answer_callback_first: END for {callback_data}, user: {user_id}, result={result}")
            return result
        except Exception as e:
            if callback_data:
                office_callbacks = ("office_menu", "office_agency", "office_info", "office_top",
                                  "office_withdraw_profit", "office_confirm_withdraw",
                                  "office_employee_already_hired", "office_insufficient_funds")
                if callback_data in office_callbacks or (callback_data and callback_data.startswith(("office_employee_info:", "office_buy_employee:"))):
                    print(f"[ERROR] answer_callback_first: function {func.__name__} RAISED EXCEPTION for {callback_data}, user: {user_id}, error: {e}")
                    import traceback
                    traceback.print_exc()
            raise
    return wrapper

# --- Декоратор блокування заблокованих користувачів ---
def ban_check(func):
    def wrapper(message_or_call, *args, **kwargs):
        callback_data = None
        user_id = None
        # Логирование для отладки
        if hasattr(message_or_call, 'data'):
            callback_data = message_or_call.data
            if hasattr(message_or_call, 'from_user'):
                user_id = message_or_call.from_user.id
            
            office_callbacks = (
                "office_menu", "office_agency", "office_info", "office_top",
                "office_withdraw_profit", "office_confirm_withdraw",
                "office_employee_already_hired", "office_insufficient_funds",
            )
            is_office = (
                callback_data in office_callbacks or 
                (callback_data and callback_data.startswith(("office_employee_info:", "office_buy_employee:")))
            )
            if is_office:
                print(f"[DEBUG] ban_check: START for {callback_data}, user: {user_id}")
        
        from database import is_user_banned, get_ban_info
        # Оновлюємо активність користувача
        try:
            from database import update_user_activity
        except Exception:
            update_user_activity = None
        
        # Визначаємо user_id та chat_id
        if hasattr(message_or_call, 'from_user'):
            user_id = message_or_call.from_user.id
            chat_id = message_or_call.chat.id if hasattr(message_or_call, 'chat') else None
        else:
            user_id = message_or_call.message.from_user.id if hasattr(message_or_call, 'message') else None
            chat_id = message_or_call.message.chat.id if hasattr(message_or_call, 'message') else None
        
        if not user_id:
            if hasattr(message_or_call, 'data') and message_or_call.data == "office_menu":
                print(f"[DEBUG] ban_check: no user_id found")
            return
        # touch activity
        try:
            if update_user_activity:
                update_user_activity(user_id)
        except Exception:
            pass
        
        # Адміни проходять без перевірки банів
        if is_admin(user_id):
            return func(message_or_call, *args, **kwargs)
        
        # Перевіряємо бан
        banned, ban_reason = is_user_banned(user_id)
        if banned:
            ban_info = get_ban_info(user_id)
            
            # Форматуємо повідомлення про бан
            ban_text = (
                f"🚫 <b>ПРОФІЛЬ ЗАБЛОКОВАНО</b> 🚫\n"
                f"━━━━━━━━━━━━━━━━━━━━\n\n"
                f"⛔️ <b>ДОСТУП ДО БОТА ЗАБОРОНЕНО</b>\n\n"
                f"💬 <b>Причина блокування:</b>\n"
                f"<i>{ban_reason or 'Не вказано'}</i>\n\n"
            )
            
            if ban_info:
                if ban_info['is_permanent']:
                    ban_text += f"⏳ <b>Тип бану:</b> Постійний\n\n"
                else:
                    time_left = ban_info['time_left']
                    if time_left:
                        time_left_str = format_duration(time_left)
                        ban_text += f"⏳ <b>Залишилося:</b> {time_left_str}\n\n"
            
            ban_text += (
                f"📞 <b>Для розблокування:</b>\n"
                f"Зверніться до адміністратора\n\n"
                f"🔒 <b>Всі функції бота недоступні</b>"
            )
            
            if hasattr(message_or_call, 'message'):  # callback
                bot.send_message(message_or_call.message.chat.id, ban_text, parse_mode="HTML")
            else:  # message
                bot.send_message(message_or_call.chat.id, ban_text, parse_mode="HTML")
            return
        
        # Пользователь не забанен - продолжаем
        is_office = (
            callback_data and (
                callback_data in ("office_menu", "office_agency", "office_info", "office_top",
                "office_withdraw_profit", "office_confirm_withdraw",
                "office_employee_already_hired", "office_insufficient_funds") or 
                callback_data.startswith(("office_employee_info:", "office_buy_employee:"))
            )
        )
        if is_office:
            print(f"[DEBUG] ban_check: PASSED for {callback_data}, user: {user_id}, calling function")
        
        result = func(message_or_call, *args, **kwargs)
        
        if is_office:
            print(f"[DEBUG] ban_check: function returned for {callback_data}, user: {user_id}")
        
        return result
    return wrapper

# --- Декоратор перевірки підписки (єдина узгоджена логіка) ---
def subscription_required(func):
    def wrapper(message_or_call, *args, **kwargs):
        # Логирование для отладки
        callback_data = None
        user_id = None
        if hasattr(message_or_call, 'data'):
            callback_data = message_or_call.data
            if hasattr(message_or_call, 'from_user'):
                user_id = message_or_call.from_user.id
        
        office_callbacks = (
            "office_menu", "office_agency", "office_info", "office_top",
            "office_withdraw_profit", "office_confirm_withdraw",
            "office_employee_already_hired", "office_insufficient_funds",
        )
        is_office_callback = (
            callback_data and (
                callback_data in office_callbacks or 
                str(callback_data).startswith(("office_employee_info:", "office_buy_employee:"))
            )
        )
        
        if is_office_callback:
            print(f"[DEBUG] subscription_required: office callback {callback_data}, user: {user_id}")
        
        try:
            # Використовуємо єдину перевірку з автоматичним блоком і показом картки
            # ВАЖНО: Проверяем подписку ДЛЯ ВСЕХ callback'ов, включая офисные
            from subscription_system import check_subscription_before_action
            is_ok = check_subscription_before_action(message_or_call, bot)
            
            if not is_ok:
                if is_office_callback:
                    print(f"[DEBUG] subscription_required: subscription check FAILED for office callback {callback_data}, user: {user_id}")
                # Для callback_query нужно ответить, иначе будет "загрузка"
                if hasattr(message_or_call, 'id'):
                    try:
                        from utils import safe_answer_callback_query
                        safe_answer_callback_query(message_or_call, text="⚠️ Потрібна підписка", show_alert=False)
                    except:
                        pass
                return  # доступ блокується всередині перевірки
            
            if is_office_callback:
                print(f"[DEBUG] subscription_required: subscription check PASSED for office callback {callback_data}, user: {user_id}, calling function")
            
            try:
                result = func(message_or_call, *args, **kwargs)
                if is_office_callback:
                    print(f"[DEBUG] subscription_required: function returned for office callback {callback_data}, user: {user_id}, result={result}")
                return result
            except Exception as func_error:
                if is_office_callback:
                    print(f"[ERROR] subscription_required: function RAISED EXCEPTION for office callback {callback_data}, user: {user_id}, error: {func_error}")
                    import traceback
                    traceback.print_exc()
                raise
        except Exception as e:
            print(f"[ERROR] subscription_required decorator error for callback {callback_data}, user {user_id}: {e}")
            import traceback
            traceback.print_exc()
            # В случае ошибки все равно пытаемся выполнить функцию
            try:
                return func(message_or_call, *args, **kwargs)
            except Exception as e2:
                print(f"[ERROR] subscription_required: function execution failed for callback {callback_data}, user {user_id}: {e2}")
                import traceback
                traceback.print_exc()
                return
    return wrapper

# Глобальний словник для відстеження відправлених уведомлень про нових користувачів
_notified_new_users = {}

def notify_admins_about_new_user(user_id, user_name, phone_number):
    """Сповіщає адмінів про нового користувача"""
    global _notified_new_users
    
    # Перевірка на дублікати - якщо уведомлення вже відправлено за останні 10 хвилин, пропускаємо
    import time
    current_time = int(time.time())
    if user_id in _notified_new_users:
        last_notification = _notified_new_users[user_id]
        if (current_time - last_notification) < 600:  # 10 хвилин = 600 секунд
            print(f"[DEBUG] Уведомлення про користувача {user_id} вже відправлено {current_time - last_notification} секунд тому, пропускаємо")
            return
    
    print(f"[DEBUG] notify_admins_about_new_user called for {user_id}")
    try:
        from database import (
            get_total_users_count,
            get_all_admins,
            get_referral_info,
            get_user,
        )
        from telebot.types import InlineKeyboardMarkup, InlineKeyboardButton

        # Загальна кількість користувачів (рахуємо ПЕРЕД додаванням нового користувача, щоб показувати правильне число)
        # Або рахуємо після, якщо користувач вже доданий - тоді показуємо актуальне число
        try:
            total_users = get_total_users_count()
            print(f"[DEBUG] Total users count: {total_users}")
        except Exception as e:
            print(f"[ERROR] Error getting users count: {e}")
            total_users = "?"

        # Дані користувача для посилання
        try:
            user_row = get_user(user_id)
            username = user_row[8] if user_row and len(user_row) > 8 else None
            print(f"[DEBUG] User username: {username}")
        except Exception as e:
            print(f"[ERROR] Error getting user data: {e}")
            username = None

        # Формуємо базовий текст
        msg = (
            "🆕 <b>НОВИЙ КОРИСТУВАЧ!</b>\n\n"
            f"👤 <b>Ім'я:</b> {user_name}\n"
            f"🆔 <b>ID:</b> <code>{user_id}</code>\n"
            + (f"📱 <b>Номер:</b> <code>{phone_number}</code>\n" if phone_number else "")
            + f"📊 <b>Всього користувачів:</b> {total_users}\n"
        )

        # Інформація про реферала (хто запросив)
        ref_info = None
        try:
            ref_info = get_referral_info(user_id)  # (invited_by, name, username, invited_at)
            print(f"[DEBUG] Referral info: {ref_info}")
        except Exception as e:
            print(f"[ERROR] Error getting referral info: {e}")
            ref_info = None
            
        if ref_info:
            inviter_id, inviter_name, inviter_username, invited_at = ref_info
            inviter_link = (
                f"https://t.me/{inviter_username}" if inviter_username else f"tg://user?id={inviter_id}"
            )
            msg += f"👥 <b>Запросив:</b> <a href='{inviter_link}'>{inviter_name}</a> (<code>{inviter_id}</code>)\n"
        else:
            msg += "👥 <b>Запросив:</b> —\n"

        msg += "📅 <b>Дата реєстрації:</b> Зараз\n"

        # Кнопки з відкриттям профілю (надійніше ніж простий текст-лінк)
        open_link = f"https://t.me/{username}" if username else f"tg://user?id={user_id}"
        kb = InlineKeyboardMarkup()
        kb.add(InlineKeyboardButton("🔗 Відкрити профіль", url=open_link))

        # Відправляємо всім адмінам
        try:
            admins = get_all_admins()
            print(f"[DEBUG] Found {len(admins)} administrators: {admins}")
        except Exception as e:
            print(f"[ERROR] Error getting admins list: {e}")
            return

        success_count = 0
        for admin_id in admins:
            try:
                print(f"[DEBUG] Sending notification to admin {admin_id}")
                bot.send_message(admin_id, msg, parse_mode="HTML", disable_web_page_preview=True, reply_markup=kb)
                print(f"[DEBUG] Сповіщення успішно відправлено адміну {admin_id}")
                success_count += 1
            except Exception as e:
                print(f"[ERROR] Помилка відправки сповіщення адміну {admin_id}: {e}")
        
        print(f"[DEBUG] Сповіщення про нового користувача {user_id} завершено. Відправлено {success_count}/{len(admins)} адмінам")
        
        # Зберігаємо час відправки уведомлення для запобігання дублікатам
        _notified_new_users[user_id] = int(time.time())
        
    except Exception as e:
        print(f"[ERROR] Критична помилка сповіщення про нового користувача: {e}")
        import traceback
        traceback.print_exc()

# Глобальний словник для відстеження відправлених уведомлень про рефералів
_notified_referrals = {}

def notify_referrer_about_new_referral(referrer_id, referred_user_id, referred_user_name):
    """Сповіщає реферера про нового реферала"""
    global _notified_referrals
    
    # Перевірка на дублікати - якщо уведомлення вже відправлено за останні 10 хвилин, пропускаємо
    import time
    current_time = int(time.time())
    notification_key = (referrer_id, referred_user_id)
    if notification_key in _notified_referrals:
        last_notification = _notified_referrals[notification_key]
        if (current_time - last_notification) < 600:  # 10 хвилин = 600 секунд
            print(f"[DEBUG] Уведомлення про реферала {referred_user_id} для реферера {referrer_id} вже відправлено {current_time - last_notification} секунд тому, пропускаємо")
            return
    
    print(f"[DEBUG] notify_referrer_about_new_referral викликано: referrer={referrer_id}, referred={referred_user_id}")
    try:
        from database import get_user, get_ref_bonus
        from telebot.types import InlineKeyboardMarkup, InlineKeyboardButton
        
        # Отримуємо дані реферера
        referrer_data = get_user(referrer_id)
        if not referrer_data:
            print(f"[ERROR] Реферер {referrer_id} не знайдений")
            return
            
        referrer_name = referrer_data[1] if referrer_data and len(referrer_data) > 1 else f"Користувач {referrer_id}"
        
        # Отримуємо розмір бонусу
        try:
            ref_bonus = get_ref_bonus()
            print(f"[DEBUG] Розмір реферального бонусу: {ref_bonus}")
        except Exception as e:
            print(f"[ERROR] Помилка отримання розміру бонусу: {e}")
            ref_bonus = 0.0
            
        # Формуємо повідомлення
        msg = (
            "🎉 <b>НОВИЙ РЕФЕРАЛ!</b>\n\n"
            f"👤 <b>Новий користувач:</b> {referred_user_name}\n"
            f"🆔 <b>ID:</b> <code>{referred_user_id}</code>\n"
            f"💰 <b>Ваш бонус:</b> <b>{format_currency(ref_bonus)}₴</b>\n\n"
            f"🎯 <b>Реферал успішно зареєстрований!</b>\n"
            f"💎 <b>Бонус буде нарахований після підтвердження підписки</b>"
        )
        
        # Кнопка для перегляду профілю
        kb = InlineKeyboardMarkup()
        kb.add(InlineKeyboardButton("👤 Переглянути профіль", url=f"tg://user?id={referred_user_id}"))
        
        # Відправляємо повідомлення рефереру
        try:
            bot.send_message(referrer_id, msg, parse_mode="HTML", reply_markup=kb)
            print(f"[DEBUG] Уведомлення про реферала відправлено рефереру {referrer_id}")
            
            # Зберігаємо час відправки уведомлення для запобігання дублікатам
            _notified_referrals[notification_key] = current_time
        except Exception as e:
            print(f"[ERROR] Помилка відправки уведомлення рефереру {referrer_id}: {e}")
            
    except Exception as e:
        print(f"[ERROR] Критична помилка уведомлення про реферала: {e}")
        import traceback
        traceback.print_exc()
def notify_admins_about_returning_user(user_id: int, user_name: str):
    """Сповіщає адмінів, що користувач повернувся після відписки. Додає корисні деталі."""
    print(f"[DEBUG] notify_admins_about_returning_user викликано для {user_id}")
    try:
        from database import (
            get_all_admins,
            get_user,
            get_user_registration_date,
            get_user_last_active,
            get_withdrawn_total,
            get_last_successful_withdrawal,
        )
        from utils import format_currency
        from telebot.types import InlineKeyboardMarkup, InlineKeyboardButton

        user_row = get_user(user_id)
        username = user_row[8] if user_row and len(user_row) > 8 else None
        try:
            total_withdrawn = float(get_withdrawn_total(user_id) or 0)
        except Exception:
            total_withdrawn = 0.0
        try:
            last_withdraw = get_last_successful_withdrawal(user_id)
        except Exception:
            last_withdraw = None

        reg_date_raw = get_user_registration_date(user_id)
        last_active_raw = get_user_last_active(user_id)
        
        # Форматуємо дати
        from datetime import datetime
        reg_date = None
        if reg_date_raw:
            try:
                # Якщо це timestamp (число)
                if isinstance(reg_date_raw, (int, float)):
                    reg_date = format_user_time(datetime.fromtimestamp(reg_date_raw).strftime("%Y-%m-%d %H:%M:%S"), user_id)
                else:
                    reg_date = format_user_time(str(reg_date_raw), user_id)
            except Exception:
                reg_date = str(reg_date_raw)
        
        last_active = None
        if last_active_raw:
            try:
                # Якщо це timestamp (число)
                if isinstance(last_active_raw, (int, float)):
                    last_active = format_user_time(datetime.fromtimestamp(last_active_raw).strftime("%Y-%m-%d %H:%M:%S"), user_id)
                else:
                    last_active = format_user_time(str(last_active_raw), user_id)
            except Exception:
                last_active = str(last_active_raw)

        open_link = f"https://t.me/{username}" if username else f"tg://user?id={user_id}"

        # Отримуємо додаткову інформацію про користувача
        from database import get_deposits_sum, get_user
        try:
            user_data = get_user(user_id)
            balance = float(user_data[2]) if user_data and len(user_data) > 2 and user_data[2] is not None else 0.0
            total_deposited = get_deposits_sum(user_id) or 0.0
        except Exception:
            balance = 0.0
            total_deposited = 0.0

        msg_lines = [
            "🔄 <b>КОРИСТУВАЧ ПОВЕРНУВСЯ!</b>",
            "",
            f"👤 <b>Ім'я:</b> {user_name}",
            f"🆔 <b>ID:</b> <code>{user_id}</code>",
        ]
        if reg_date:
            msg_lines.append(f"📅 <b>Дата реєстрації:</b> {reg_date}")
        if last_active:
            msg_lines.append(f"⏱ <b>Остання активність:</b> {last_active}")
        msg_lines.append(f"💰 <b>Поточний баланс:</b> {format_currency(balance)} ₴")
        msg_lines.append(f"💵 <b>Всього поповнено:</b> {format_currency(total_deposited)} ₴")
        msg_lines.append(f"📤 <b>Всього виведено:</b> {format_currency(total_withdrawn)} ₴")
        if last_withdraw:
            lw_amt = format_currency(last_withdraw.get('amount') or 0)
            lw_req = last_withdraw.get('requisites') or '—'
            lw_when = last_withdraw.get('processed_at') or last_withdraw.get('created_at') or '—'
            msg_lines.append("💳 <b>Останній вивід:</b>")
            msg_lines.append(f"• Сума: {lw_amt} ₴")
            msg_lines.append(f"• Реквізити: {lw_req}")
            msg_lines.append(f"• Дата: {lw_when}")

        kb = InlineKeyboardMarkup()
        kb.add(InlineKeyboardButton("🔗 Відкрити профіль", url=open_link))

        admins = get_all_admins()
        for admin_id in admins:
            try:
                bot.send_message(admin_id, "\n".join(msg_lines), parse_mode="HTML", disable_web_page_preview=True, reply_markup=kb)
            except Exception as e:
                print(f"[ERROR] Помилка відправки returning-user адміну {admin_id}: {e}")

    except Exception as e:
        print(f"[ERROR] notify_admins_about_returning_user: {e}")
    except Exception as e:
        print(f"[ERROR] Помилка сповіщення про нового користувача: {e}")
    else:
        print(f"[DEBUG] Сповіщення про нового користувача {user_id} завершено успішно")

# --- Обробка КОНТАКТУ телефону ---
@bot.message_handler(content_types=['contact'])
def phone_contact_handler(message):
    user_id = message.from_user.id
    contact = message.contact
    
    # Перевіряємо що це контакт самого користувача
    if contact.user_id != user_id:
        bot.send_message(message.chat.id, 
                        "❌ <b>Помилка!</b>\n\n"
                        "📱 Потрібно надіслати <b>СВІЙ КОНТАКТ</b>\n"
                        "🔄 Натисніть кнопку 'Поділитися контактом' знову", 
                        parse_mode="HTML")
        return
    
    phone_number = contact.phone_number
    
    # Додаємо + якщо немає
    if not phone_number.startswith('+'):
        phone_number = '+' + phone_number
    
    # Перевіряємо що це український номер
    if not phone_number.startswith('+380'):
        bot.send_message(message.chat.id, 
                        "❌ <b>Некоректний номер!</b>\n\n"
                        "🇺🇦 Приймаються <b>ТІЛЬКИ УКРАЇНСЬКІ</b> номери!\n"
                        f"📱 Ваш номер: <code>{phone_number}</code>\n"
                        f"✅ Потрібен номер: <code>+380xxxxxxxxx</code>\n\n"
                        f"🔄 Поділіться українським номером", 
                        parse_mode="HTML")
        return
    
    # Перевіряємо довжину номера
    if len(phone_number) != 13:
        bot.send_message(message.chat.id, 
                        "❌ <b>Некоректна довжина номера!</b>\n\n"
                        f"📱 Ваш номер: <code>{phone_number}</code>\n"
                        f"✅ Потрібен формат: <code>+380xxxxxxxxx</code> (13 цифр)\n\n"
                        f"🔄 Поділіться правильним номером", 
                        parse_mode="HTML")
        return
    
    from database import set_user_phone, ensure_user
    
    # Створюємо користувача в базі даних
    user_name = message.from_user.first_name
    if message.from_user.last_name:
        user_name += f" {message.from_user.last_name}"
    ensure_user(user_id, user_name)
    
    # Зберігаємо телефон
    set_user_phone(user_id, phone_number)
    # Скасувати таймер нагадування про номер
    try:
        if hasattr(bot, 'phone_reminders'):
            t = bot.phone_reminders.pop(user_id, None)
            if t:
                t.cancel()
    except Exception:
        pass

    # Видаляємо клавіатуру з кнопкою поділення контактом
    from telebot.types import ReplyKeyboardRemove
    bot.send_message(
        message.chat.id,
        "✅ <b>Номер підтверджено!</b>\n\n"
        "📱 Ваш номер: <code>" + phone_number + "</code>\n\n"
        "🔐 Тепер перевіримо підписку на канали...",
        reply_markup=ReplyKeyboardRemove(),
        parse_mode="HTML"
    )
    
    # ПРОСТА РЕФЕРАЛЬНА СИСТЕМА - після підтвердження номеру
    print(f"[DEBUG] ===== ПЕРЕВІРКА РЕФЕРАЛЬНОЇ СИСТЕМИ =====")
    print(f"[DEBUG] Користувач: {user_id}")
    print(f"[DEBUG] Ім'я: {user_name}")
    
    # Отримуємо реферальне посилання з бази даних
    from database import get_user_state
    import json
    user_state = get_user_state(user_id)
    print(f"[DEBUG] Стан користувача: {user_state}")
    
    referrer_id = None
    if user_state:
        try:
            state_data = json.loads(user_state)
            referrer_id = state_data.get('referrer_id')
            print(f"[DEBUG] Реферальне посилання з бази: {referrer_id}")
        except Exception as e:
            print(f"[DEBUG] Помилка парсингу стану користувача: {e}")
    else:
        print(f"[DEBUG] Стан користувача порожній або None")
    
    if referrer_id and str(referrer_id).isdigit():
        try:
            referrer_id = int(referrer_id)
            print(f"[DEBUG] Знайдено реферальне посилання: {referrer_id}")
            
            # Перевіряємо валідність
            if referrer_id != user_id and referrer_id > 0:
                from database import get_user, save_referral, get_ref_bonus, add_balance, is_user_referred
                
                # Перевіряємо чи користувач вже має реферала
                if not is_user_referred(user_id):
                    # Перевіряємо чи існує реферер
                    referrer = get_user(referrer_id)
                    if referrer:
                        print(f"[DEBUG] Реферер знайдено: {referrer_id}")
                        
                        # Зберігаємо реферальний зв'язок
                        save_referral(user_id, referrer_id)
                        print(f"[DEBUG] Реферальний зв'язок збережено")
                        
                        # Отримуємо бонус і створюємо відкладену винагороду
                        ref_bonus = get_ref_bonus()
                        try:
                            from database import create_referral_reward_pending
                            create_referral_reward_pending(referrer_id, user_id, ref_bonus)
                            print(f"[DEBUG] Pending referral reward created: {ref_bonus}")
                        except Exception as e:
                            print(f"[REFERRAL] pending reward create failed: {e}")
                        
                        # Відправляємо уведомлення рефереру
                        try:
                            notify_referrer_about_new_referral(referrer_id, user_id, user_name)
                        except Exception as e:
                            print(f"[ERROR] Помилка уведомлення реферера: {e}")
                        
                        # Зберігаємо інформацію про реферала для відправки повідомлення після перевірки підписки
                        try:
                            from utils import format_currency
                        except:
                            def format_currency(amount):
                                return f"{amount:.2f}"
                        
                        # Отримуємо ім'я реферера (get_user повертає tuple)
                        if referrer and len(referrer) > 1:
                            referrer_name = referrer[1]  # user_name знаходиться в індексі 1
                        else:
                            referrer_name = f"Користувач {referrer_id}"
                        
                        # Зберігаємо інформацію про реферала в стані користувача
                        referral_info = {
                            "referrer_id": referrer_id,
                            "referrer_name": referrer_name,
                            "ref_bonus": ref_bonus,
                            "user_name": user_name
                        }
                        from database import set_user_state
                        set_user_state(user_id, json.dumps(referral_info))
                        
                        print(f"[DEBUG] ===== ЗБЕРЕЖЕННЯ РЕФЕРАЛЬНОЇ ІНФОРМАЦІЇ =====")
                        print(f"[DEBUG] Користувач: {user_id}")
                        print(f"[DEBUG] Реферальна інформація: {referral_info}")
                        print(f"[DEBUG] JSON: {json.dumps(referral_info)}")
                        print(f"[DEBUG] ✅ Реферальний зв'язок збережено, інформація збережена в стані користувача")
                        
                        # Відправляємо уведомлення рефереру через функцію (з захистом від дублікатів)
                        try:
                            notify_referrer_about_new_referral(referrer_id, user_id, user_name)
                        except Exception as e:
                            print(f"[ERROR] Помилка уведомлення реферера: {e}")
                        
                        print(f"[DEBUG] Реферальна система успішно оброблена!")
                        
                        # Уведомлення адмінам про нового користувача відправляється ТІЛЬКИ після перевірки підписки
                        # Див. subscription_system.verify_subscription_handler()
                        
                        # НЕ очищаємо стан користувача - він потрібен для відправки повідомлення після перевірки підписки
                        # set_user_state(user_id, "{}")
                        
                        # Перевіряємо підписку після успішної реферальної реєстрації
                        try:
                            from subscription_system import send_subscription_required_message
                            print(f"[DEBUG] Викликаю send_subscription_required_message для користувача {user_id}")
                            result = send_subscription_required_message(message, user_id, bot)
                            print(f"[DEBUG] Результат send_subscription_required_message: {result}")
                        except Exception as e:
                            print(f"[ERROR] Помилка перевірки підписки після реферала: {e}")
                            import traceback
                            print(f"[ERROR] Traceback: {traceback.format_exc()}")
                            # Відправляємо повідомлення про помилку користувачу
                            try:
                                bot.send_message(message.chat.id, "❌ Помилка перевірки підписки. Спробуйте пізніше.")
                            except:
                                pass
                    else:
                        print(f"[DEBUG] Реферер {referrer_id} не знайдено в базі")
                else:
                    print(f"[DEBUG] Користувач {user_id} вже має реферала")
            else:
                print(f"[DEBUG] Невалідний реферер: {referrer_id}")
        except Exception as e:
            print(f"[ERROR] Помилка обробки реферала: {e}")
    else:
        print(f"[DEBUG] Немає реферального посилання")
        
        # Уведомлення адмінам про нового користувача відправляється ТІЛЬКИ після перевірки підписки
        # Див. subscription_system.verify_subscription_handler()
        
        # Перевіряємо підписку тільки якщо немає реферального посилання
        try:
            from subscription_system import send_subscription_required_message
            print(f"[DEBUG] Викликаю send_subscription_required_message для користувача {user_id} (без реферала)")
            result = send_subscription_required_message(message, user_id, bot)
            print(f"[DEBUG] Результат send_subscription_required_message: {result}")
        except Exception as e:
            print(f"[ERROR] Помилка перевірки підписки: {e}")
            import traceback
            print(f"[ERROR] Traceback: {traceback.format_exc()}")
            # Відправляємо повідомлення про помилку користувачу
            try:
                bot.send_message(message.chat.id, "❌ Помилка перевірки підписки. Спробуйте пізніше.")
            except:
                pass
    
    # Сповіщення адмінам також відправляється після УСПІШНОЇ перевірки підписки
    # Див. subscription_system.verify_subscription_handler() та send_subscription_required_message()

# --- Обробка неправильного введення тексту замість контакту ---
@bot.message_handler(func=lambda m: m.text and (m.text.startswith('+380') or m.text.startswith('380')))
def phone_text_handler(message):
    """Блокуємо ручний ввід номера: дозволено лише поділитися контактом."""
    bot.send_message(
        message.chat.id,
        "🚫 <b>Ввід номера текстом заборонено.</b>\n\n"
        "📱 Натисніть кнопку <b>\"Поділитися контактом\"</b> нижче.",
        parse_mode="HTML"
    )

# --- декоратор ---
def maintenance_guard(func):
    def wrapper(message_or_call, *args, **kwargs):
        user_id = None
        if hasattr(message_or_call, 'from_user'):
            user_id = message_or_call.from_user.id
        elif hasattr(message_or_call, 'message') and hasattr(message_or_call.message, 'from_user'):
            user_id = message_or_call.message.from_user.id
        if user_id and not is_admin(user_id) and not is_beta(user_id) and get_maintenance_mode():
            chat_id = getattr(message_or_call, 'chat', None)
            if chat_id is None and hasattr(message_or_call, 'message'):
                chat_id = message_or_call.message.chat.id
            elif chat_id is not None:
                chat_id = chat_id.id
            else:
                chat_id = message_or_call.chat.id
            bot.send_message(
                chat_id,
                "<b>🛠 Технічні роботи! 🚫</b>\n\n"
                "Сервіс Investing Palmaron Bot тимчасово недоступний для користувачів.\n"
                "Сервіс Investing Palmaron Bot доступний тільки виключно Бета-Тестерам\n"
                "Ми вдосконалюємо платформу для вашого комфорту та нових можливостей!\n\n"
                "<b>Слідкуйте за оновленнями — повернемось ще кращими! 💹🤖</b>",
                parse_mode="HTML"
            )
            return
        return func(message_or_call, *args, **kwargs)
    return wrapper

# --- Спрощена реферальна логіка (допоміжні функції) ---
def maybe_save_referrer_from_start(message):
    try:
        user_id = message.from_user.id
        args = message.text.split() if getattr(message, 'text', None) else []
        print(f"[DEBUG] maybe_save_referrer_from_start: користувач {user_id}, аргументи = {args}")
        if len(args) > 1 and str(args[1]).isdigit():
            referrer_id = int(args[1])
            print(f"[DEBUG] maybe_save_referrer_from_start: знайдено referrer_id = {referrer_id}")

            # self-referral blocked
            if referrer_id == user_id:
                try:
                    bot.send_message(message.chat.id, "⚠️ Ви не можете використати власне реферальне посилання.")
                except Exception:
                    pass
                return

            from database import set_user_state, is_user_referred, get_referral_info
            import json

            # If user already referred — send creative message and do not overwrite
            try:
                if is_user_referred(user_id):
                    try:
                        info = get_referral_info(user_id)
                        if info:
                            inviter_id = info[0]
                            inviter_name = info[1] if len(info) > 1 and info[1] else f"Користувач {inviter_id}"
                            invited_at = info[3] if len(info) > 3 else None
                            try:
                                import datetime
                                if invited_at:
                                    invited_str = datetime.datetime.fromtimestamp(int(invited_at)).strftime('%Y-%m-%d %H:%M')
                                else:
                                    # fallback to user registration date if referral timestamp missing
                                    try:
                                        from database import get_user_registration_date
                                        reg = get_user_registration_date(user_id)
                                        if reg:
                                            invited_str = datetime.datetime.fromtimestamp(int(reg)).strftime('%Y-%m-%d %H:%M')
                                        else:
                                            invited_str = 'щойно'
                                    except Exception:
                                        invited_str = 'щойно'
                            except Exception:
                                invited_str = 'щойно'
                            creative = (
                                "✨ О, знайоме обличчя! ✨\n\n"
                                f"Ви вже прийшли за реферальним посиланням.\n"
                                f"Вас запросив: <b>{inviter_name}</b> (ID: {inviter_id})\n"
                                f"Коли: {invited_str}\n\n"
                                "Дякуємо, що залишаєтесь з нами! Якщо хочете, поділіться своїм посиланням — воно в Кабінеті → Реферальна програма. 💚"
                            )
                            try:
                                bot.send_message(message.chat.id, creative, parse_mode="HTML")
                            except Exception:
                                pass
                    except Exception:
                        pass
                    return
            except Exception:
                # fallback to saving the referrer
                pass

            # Save referrer for new users
            try:
                set_user_state(user_id, json.dumps({"referrer_id": referrer_id}))
                print(f"[REF] Saved referrer_id={referrer_id} for user={user_id}")
                print(f"[DEBUG] maybe_save_referrer_from_start: спроба відправити повідомлення про збереження реферальної ссылки")
                try:
                    sent_msg = bot.send_message(
                        message.chat.id,
                        "✨ <b>Реферальне посилання збережено!</b>\n\n"
                        "Коли ви підтвердите номер, ваш реферер отримає бонус.\n"
                        "Поділитися своїм посиланням можна в Кабінеті → Реферальна програма.",
                        parse_mode="HTML",
                    )
                    print(f"[DEBUG] ✅ Повідомлення 'Реферальне посилання збережено!' відправлено успішно!")
                except Exception as e:
                    print(f"[ERROR] Помилка відправки повідомлення про збереження реферальної ссылки: {e}")
            except Exception as e:
                print(f"[REF][ERR] maybe_save_referrer_from_start save: {e}")
    except Exception as e:
        print(f"[REF][ERR] maybe_save_referrer_from_start: {e}")

def try_process_referral(user_id: int, chat_id: int, user_name: str) -> bool:
    """Пробує провести реферальну операцію за збереженим referrer_id. Повертає True, якщо нараховано бонус."""
    try:
        from database import get_user_state, is_user_referred, get_user, save_referral, get_ref_bonus, add_balance, set_user_state
        from subscription_system import check_user_subscription
        import json
        state = get_user_state(user_id)
        referrer_id = None
        if state:
            try:
                data = json.loads(state)
                referrer_id = data.get('referrer_id')
            except Exception:
                referrer_id = None
        if referrer_id and str(referrer_id).isdigit():
            referrer_id = int(referrer_id)
            if referrer_id != user_id and referrer_id > 0 and not is_user_referred(user_id):
                referrer = get_user(referrer_id)
                if referrer:
                    # Перевіряємо підписку перед нарахуванням бонусу
                    try:
                        has_subscription = check_user_subscription(user_id, bot, check_only=True)
                    except Exception as e:
                        print(f"[REFERRAL] Помилка перевірки підписки: {e}")
                        has_subscription = False
                    
                    # Зберігаємо реферальний зв'язок
                    save_referral(user_id, referrer_id)
                    ref_bonus = get_ref_bonus()
                    
                    # Якщо підписка є - нараховуємо бонус відразу
                    if has_subscription:
                        try:
                            add_balance(referrer_id, ref_bonus, reason='referral_bonus', 
                                       details=f'Реферальний бонус за користувача {user_id} ({user_name})')
                            print(f"[REFERRAL] Бонус нараховано відразу: {ref_bonus}₴ для {referrer_id}")
                        except Exception as e:
                            print(f"[REFERRAL] Помилка нарахування бонусу: {e}")
                            # Якщо не вдалося нарахувати, створюємо pending
                            try:
                                from database import create_referral_reward_pending
                                create_referral_reward_pending(referrer_id, user_id, ref_bonus)
                            except Exception as e2:
                                print(f"[REFERRAL] Помилка створення pending: {e2}")
                    else:
                        # Якщо підписки немає - не нараховуємо бонус
                        print(f"[REFERRAL] Підписка відсутня, бонус не нараховано для {referrer_id}")
                    
                    # Відправляємо уведомлення рефереру
                    try:
                        from utils import format_currency
                    except Exception:
                        def format_currency(amount):
                            return f"{amount:.2f}"
                    
                    referrer_name = referrer[1] if (referrer and len(referrer) > 1) else f"Користувач {referrer_id}"
                    
                    # Повідомлення рефералу
                    try:
                        if has_subscription:
                            bot.send_message(
                                chat_id,
                                "🎉 <b>РЕФЕРАЛЬНА РЕЄСТРАЦІЯ УСПІШНА!</b>\n\n"
                                f"👤 <b>Ваш реферер:</b> {referrer_name}\n"
                                f"✅ Бонус рефереру зараховано: <b>{format_currency(ref_bonus)} ₴</b>",
                                parse_mode="HTML"
                            )
                        else:
                            bot.send_message(
                                chat_id,
                                "🎉 <b>РЕФЕРАЛЬНА РЕЄСТРАЦІЯ УСПІШНА!</b>\n\n"
                                f"👤 <b>Ваш реферер:</b> {referrer_name}\n"
                                f"⚠️ Бонус рефереру буде зараховано після підписки на канали",
                                parse_mode="HTML"
                            )
                    except Exception:
                        pass
                    
                    # Повідомлення рефереру
                    try:
                        if has_subscription:
                            bot.send_message(
                                referrer_id,
                                "🎉 <b>НОВИЙ РЕФЕРАЛ!</b>\n\n"
                                f"👤 <b>Користувач:</b> {user_name}\n"
                                f"✅ <b>Бонус зараховано:</b> {format_currency(ref_bonus)} ₴",
                                parse_mode="HTML"
                            )
                        else:
                            bot.send_message(
                                referrer_id,
                                "🎉 <b>НОВИЙ РЕФЕРАЛ!</b>\n\n"
                                f"👤 <b>Користувач:</b> {user_name}\n"
                                f"⏳ Бонус буде зараховано після підписки на канали",
                                parse_mode="HTML"
                            )
                    except Exception:
                        pass
                    
                    try:
                        set_user_state(user_id, "{}")
                    except Exception:
                        pass
                    print(f"[REF] Referral processed: user={user_id} referrer={referrer_id} subscription={has_subscription}")
                    return True
        return False
    except Exception as e:
        print(f"[REF][ERR] try_process_referral: {e}")
        import traceback
        traceback.print_exc()
        return False

# --- Спрощена команда: ручна активація реферала /ref <inviter_id> ---
@bot.message_handler(commands=['ref'])
def ref_command(message):
    try:
        user_id = message.from_user.id
        parts = (message.text or '').split()
        if len(parts) < 2:
            return bot.send_message(message.chat.id, "🔗 Введення: /ref <ID інвайтера>\nНапр.: /ref 123456789")
        try:
            referrer_id = int(parts[1])
        except Exception:
            return bot.send_message(message.chat.id, "❌ Некоректний ID інвайтера. Спробуйте ще раз.")
        if referrer_id <= 0 or referrer_id == user_id:
            return bot.send_message(message.chat.id, "❌ Неможливо встановити такого інвайтера.")
        from database import is_user_referred, get_user, save_referral, get_ref_bonus, add_balance, set_user_state
        if is_user_referred(user_id):
            return bot.send_message(message.chat.id, "ℹ️ Реферал уже активований раніше.")
        referrer = get_user(referrer_id)
        if not referrer:
            return bot.send_message(message.chat.id, "❌ Такий інвайтер не знайдений.")
        save_referral(user_id, referrer_id)
        ref_bonus = get_ref_bonus()
        
        # Перевіряємо підписку перед нарахуванням бонусу
        try:
            from subscription_system import check_user_subscription
            has_subscription = check_user_subscription(user_id, bot, check_only=True)
        except Exception as e:
            print(f"[REFERRAL] Помилка перевірки підписки: {e}")
            has_subscription = False
        
        # Якщо підписка є - нараховуємо бонус відразу
        if has_subscription:
            try:
                from database import add_balance
                add_balance(referrer_id, ref_bonus, reason='referral_bonus', 
                           details=f'Реферальний бонус за користувача {user_id} (команда /ref)')
                print(f"[REFERRAL] Бонус нараховано відразу через /ref: {ref_bonus}₴ для {referrer_id}")
            except Exception as e:
                print(f"[REFERRAL] Помилка нарахування бонусу: {e}")
                # Якщо не вдалося нарахувати, створюємо pending
                try:
                    from database import create_referral_reward_pending
                    create_referral_reward_pending(referrer_id, user_id, ref_bonus)
                except Exception as e2:
                    print(f"[REFERRAL] Помилка створення pending: {e2}")
        else:
            # Якщо підписки немає - не нараховуємо бонус
            print(f"[REFERRAL] Підписка відсутня, бонус не нараховано для {referrer_id}")
        
        # Відправляємо уведомлення рефереру
        try:
            user_name = message.from_user.first_name or "Користувач"
            notify_referrer_about_new_referral(referrer_id, user_id, user_name)
        except Exception as e:
            print(f"[ERROR] Помилка уведомлення реферера: {e}")
        try:
            from utils import format_currency
        except Exception:
            def format_currency(amount):
                return f"{amount:.2f}"
        referrer_name = referrer[1] if (referrer and len(referrer) > 1) else f"Користувач {referrer_id}"
        
        if has_subscription:
            bot.send_message(message.chat.id,
                             "🎉 <b>РЕФЕРАЛ АКТИВОВАНО!</b>\n\n"
                             f"👤 <b>Ваш реферер:</b> {referrer_name}\n"
                             f"✅ Бонус рефереру зараховано: <b>{format_currency(ref_bonus)} ₴</b>",
                             parse_mode="HTML")
        else:
            bot.send_message(message.chat.id,
                             "🎉 <b>РЕФЕРАЛ АКТИВОВАНО!</b>\n\n"
                             f"👤 <b>Ваш реферер:</b> {referrer_name}\n"
                             f"⚠️ Бонус рефереру буде зараховано після підписки на канали",
                             parse_mode="HTML")
        try:
            user_name = message.from_user.first_name or "Користувач"
            if message.from_user.last_name:
                user_name += f" {message.from_user.last_name}"
        except Exception:
            user_name = "Користувач"
        try:
            if has_subscription:
                bot.send_message(referrer_id,
                                 "🎉 <b>НОВИЙ РЕФЕРАЛ!</b>\n\n"
                                 f"👤 <b>Користувач:</b> {user_name}\n"
                                 f"✅ <b>Бонус зараховано:</b> {format_currency(ref_bonus)} ₴",
                                 parse_mode="HTML")
            else:
                bot.send_message(referrer_id,
                                 "🎉 <b>НОВИЙ РЕФЕРАЛ!</b>\n\n"
                                 f"👤 <b>Користувач:</b> {user_name}\n"
                                 f"⏳ Бонус буде зараховано після підписки на канали",
                                 parse_mode="HTML")
        except Exception:
            pass
        try:
            set_user_state(user_id, "{}")
        except Exception:
            pass
    except Exception as e:
        try:
            bot.send_message(message.chat.id, f"❌ Помилка: {e}")
        except Exception:
            pass

