# --- Головне меню, якщо треба ---
# @bot.message_handler(commands=['start'])  # disabled duplicate
# @ban_check
def start_handler_disabled_1(message):
    user_id = message.from_user.id
    username = message.from_user.username
    args = message.text.split()
    from database import get_invite_only, is_whitelisted, use_invite, add_to_whitelist, is_valid_invite, add_pending_user, save_user_username, ensure_user, save_referral, add_balance, get_ref_bonus, get_user
    
    # Зберігаємо username користувача
    if username:
        save_user_username(user_id, username)

    # Перевіряємо чи це deep link для ігор
    if len(args) > 1 and args[1].startswith("game_"):
        if not are_games_enabled():
            bot.send_message(message.chat.id, "🚫 Ігри тимчасово вимкнені адміністратором.")
            return
        
        # Витягуємо group_chat_id з deep link
        game_parts = args[1].split("_")
        if len(game_parts) >= 3:  # game_user_id_group_id
            group_chat_id = game_parts[2]
            # Зберігаємо в сесії user state для наступних ігор
            bot.set_state(user_id, "in_game", chat_id=message.chat.id)
            with bot.retrieve_data(user_id, message.chat.id) as data:
                data['group_chat_id'] = group_chat_id
        
        # Створюємо користувача в базі даних якщо його немає
        user_name = message.from_user.first_name
        if message.from_user.last_name:
            user_name += f" {message.from_user.last_name}"
        ensure_user(user_id, user_name)
        
        # Автоматично показуємо меню ігор
        show_private_betting_menu(message)
        return

    # Спрощено: пробуємо зберегти реферера якщо прийшли з deep-link
    maybe_save_referrer_from_start(message)

    # Зберігаємо можливий referrer_id з deep-link, якщо це цифровий аргумент
    if len(args) > 1 and args[1].isdigit():
        try:
            referrer_id = int(args[1])
            if referrer_id != user_id and referrer_id > 0:
                from database import set_user_state
                import json
                state_json = json.dumps({"referrer_id": referrer_id})
                set_user_state(user_id, state_json)
                print(f"[DEBUG] (/start #3) Реферальне посилання збережено: user_id={user_id}, referrer_id={referrer_id}")
        except Exception as e:
            print(f"[ERROR] (/start #3) Не вдалося зберегти referrer_id: {e}")

    # Спрощено: пробуємо зберегти реферера якщо прийшли з deep-link
    maybe_save_referrer_from_start(message)

    invite_only = get_invite_only()

    if is_admin(user_id):
        # Створюємо адміністратора в базі даних
        user_name = message.from_user.first_name
        if message.from_user.last_name:
            user_name += f" {message.from_user.last_name}"
        ensure_user(user_id, user_name)
        show_main_menu(message)
        return

    if invite_only:
        if is_whitelisted(user_id):
            # Створюємо користувача в базі даних
            user_name = message.from_user.first_name
            if message.from_user.last_name:
                user_name += f" {message.from_user.last_name}"
            ensure_user(user_id, user_name)
            # Перевіряємо підписку перед показом меню
            if not check_subscription_before_action(message, bot):
                return  # Якщо підписка не підтверджена, функція вже показала повідомлення
            show_main_menu(message)
            return
        if len(args) > 1 and args[1].startswith("invite_"):
            token = args[1][7:]
            if is_valid_invite(token):
                use_invite(token, user_id)
                add_to_whitelist(user_id)
                # Створюємо користувача в базі даних
                user_name = message.from_user.first_name
                if message.from_user.last_name:
                    user_name += f" {message.from_user.last_name}"
                ensure_user(user_id, user_name)
                # Перевіряємо підписку перед показом меню
                if not check_subscription_before_action(message, bot):
                    return  # Якщо підписка не підтверджена, функція вже показала повідомлення
                show_main_menu(message)
                return
        # Якщо не по інвайту — блокуємо
        add_pending_user(user_id)  # Зберігаємо користувача, який пробував зайти
        from telebot.types import ReplyKeyboardRemove
        bot.send_message(message.chat.id, "🚧 <b>Доступ до бота закритий!</b>\n\n"
                                          "🛡️ <b>Тільки за реферальним посиланням від адміністратора.</b>\n"
                                          "Зверніться до власника бота, щоб отримати доступ.\n"
                                          "🌟 <i>Слідкуйте за оновленнями!</i>", 
                                          parse_mode="HTML",
                                          reply_markup=ReplyKeyboardRemove())
        return

    # Якщо invite_only=0 — усім доступно
    # Створюємо користувача в базі даних
    user_name = message.from_user.first_name
    if message.from_user.last_name:
        user_name += f" {message.from_user.last_name}"
    ensure_user(user_id, user_name)
    
    # Збереження реферального посилання для обробки після підтвердження номеру
    if len(args) > 1 and args[1].isdigit():
        referrer_id = int(args[1])
        
        print(f"[DEBUG] Реферальне посилання знайдено: user_id={user_id}, referrer_id={referrer_id}")
        
        # Перевіряємо що реферер існує і не є самим користувачем
        if referrer_id != user_id and referrer_id > 0:
            # Зберігаємо реферальне посилання в стані користувача
            from database import set_user_state
            import json
            state_data = {"referrer_id": referrer_id}
            state_json = json.dumps(state_data)
            set_user_state(user_id, state_json)
            print(f"[DEBUG] Реферальне посилання збережено в стані: {referrer_id}")
            print(f"[DEBUG] JSON стан: {state_json}")
            try:
                bot.send_message(
                    message.chat.id,
                    "✨ <b>Реферальне посилання збережено!</b>\n\n"
                    "Коли ви підтвердите номер, ваш реферер отримає бонус.\n"
                    "Поділитися своїм посиланням можна в Кабінеті → Реферальна програма.",
                    parse_mode="HTML",
                )
            except Exception:
                pass
        else:
            print(f"[DEBUG] Реферальне посилання відхилено: referrer_id={referrer_id}, user_id={user_id}")
    else:
        print(f"[DEBUG] Звичайний вхід без реферального посилання")
        print(f"[DEBUG] Аргументи: {args}")
    
    # Якщо номеру телефону ще немає — просимо поділитися контактом
    from database import get_user_phone
    user_phone = get_user_phone(user_id)
    if not user_phone:
        from telebot.types import ReplyKeyboardMarkup, KeyboardButton
        keyboard = ReplyKeyboardMarkup(resize_keyboard=True, one_time_keyboard=True)
        keyboard.add(KeyboardButton("📱 Поділитися контактом", request_contact=True))
        bot.send_message(
            message.chat.id,
            "🔐 <b>Вітаємо в Investing Palmaron Bot!</b>\n\n"
            "📱 Для початку роботи потрібно підтвердити ваш номер телефону\n\n"
            "👆 Натисніть кнопку 'Поділитися контактом'",
            reply_markup=keyboard,
            parse_mode="HTML"
        )
        return
    
    # Якщо номер є — спробуємо одразу обробити реферала (якщо збережено)
    try_process_referral(user_id, message.chat.id, user_name)

    # Показуємо головне меню
    show_main_menu(message)


