    fruits_str = "\n".join(fruit_lines) if fruit_lines else "—"
    fruits_value_block = f"💰 Орієнтовна вартість: <b>{format_currency(total_fruits_value)}₴</b>\n\n" if total_fruits_value else "\n"

    # Очікуючі заявки на вивід (прив'язані до користувача)
    try:
        pending_withdraws = len([r for r in get_withdrawals_by_status('pending') if r[1] == user_id])
    except Exception:
        pending_withdraws = 0

    total_fruits_count = int(sum(fruits.values())) if isinstance(fruits, dict) else 0
    status_emoji = "🟢 Онлайн" if (now_ts - (last_active or 0)) <= 120 else "⚪ Офлайн"
    
    # Статус верифікації
    verification_info = get_user_verification_status(user_id)
