        f"━━━━━━━━━━━━━━━━━━━━\n\n"
        f"👤 <b>Ім'я:</b> {user_name}\n"
        f"🆔 <b>ID:</b> <code>{user_id}</code> | {status_emoji}\n"
        f"📅 <b>Реєстрація:</b> {reg_str}\n"
        f"🕒 <b>Остання активність:</b> {last_str} (<i>{last_delta}</i>)\n\n"
        f"🛡️ <b>Верифікація:</b> {verification_display}{suspicious_info}\n\n"
        f"💼 <b>Фінанси</b>\n"
