@bot.message_reaction_handler()
def giveaway_reaction_handler(reaction_update):
    """Обрабатывает реакции на сообщения розыгрышей"""
    try:
        print(f"[DEBUG] message_reaction update received: {reaction_update}")
        if not reaction_update:
            return

        message_id = getattr(reaction_update, 'message_id', None)
        chat = getattr(reaction_update, 'chat', None)
        if not chat or message_id is None:
            return

        chat_id = str(chat.id)

        from database import get_all_giveaways
        # Берём все розыгрыши, чтобы не пропускать статус 'pending'
        active_giveaways = get_all_giveaways(status=None)

        target_giveaway = None
        for giveaway in active_giveaways:
            giveaway_channel_id = str(giveaway.get('channel_id')) if giveaway.get('channel_id') else None
            if giveaway_channel_id and giveaway_channel_id != chat_id:
                continue

            if giveaway.get('post_message_id') == message_id or giveaway.get('started_post_message_id') == message_id:
                target_giveaway = giveaway
                break

        if not target_giveaway:
            return

        # Определяем изменение количества реакций (новые - старые)
        new_reactions = getattr(reaction_update, 'new_reaction', None) or []
        old_reactions = getattr(reaction_update, 'old_reaction', None) or []
        reaction_delta = len(new_reactions) - len(old_reactions)

        if reaction_delta <= 0:
            # Нас интересуют только новые реакции
            print(f"[DEBUG] Reaction delta <= 0 ({reaction_delta}), skipping")
            return

        user_id = None
        if getattr(reaction_update, 'user', None):
            user_id = reaction_update.user.id
        elif getattr(reaction_update, 'actor_chat', None):
            # Если реакцию поставил канал (от имени канала)
            user_id = reaction_update.actor_chat.id

        from giveaway_monitoring import handle_message_reaction
        handle_message_reaction(
            target_giveaway['id'],
            user_id,
            'reaction',
            bot,
            reaction_delta=reaction_delta
        )
        print(f"[INFO] Розыгрыш #{target_giveaway['id']}: обработана реакция, delta={reaction_delta}")
    except Exception as e:
        import traceback
        print(f"[ERROR] Ошибка обработки реакции: {e}")
        traceback.print_exc()

@bot.message_reaction_count_handler()
def giveaway_reaction_count_handler(reaction_count_update):
    """Получает обновления об общем количестве реакций"""
    try:
        print(f"[DEBUG] ===== message_reaction_count_handler ВЫЗВАН =====")
        print(f"[DEBUG] message_reaction_count update received: {reaction_count_update}")
        print(f"[DEBUG] Type: {type(reaction_count_update)}")
        if not reaction_count_update:
            print(f"[DEBUG] reaction_count_update is None/False, exiting")
            return

        message_id = getattr(reaction_count_update, 'message_id', None)
        chat = getattr(reaction_count_update, 'chat', None)
        total_count = getattr(reaction_count_update, 'total_count', None)

        if not chat or message_id is None or total_count is None:
            reactions = getattr(reaction_count_update, 'reactions', None)
            if reactions:
                total_count = 0
                for reaction in reactions:
                    total_count += getattr(reaction, 'total_count', 0) or 0
                print(f"[DEBUG] total_count взят из reactions: {total_count}")
            if not chat or message_id is None or total_count is None:
                return

        try:
            total_count = int(total_count)
        except (TypeError, ValueError):
            print(f"[WARNING] Не удалось преобразовать total_count='{total_count}' в число")
            return

        chat_id = str(chat.id)
        print(f"[DEBUG] Ищем розыгрыш: chat_id={chat_id}, message_id={message_id}, total_count={total_count}")

        from database import get_all_giveaways
        # Берём все розыгрыши, т.к. на этапе сбора реакций статус может быть 'pending'
        active_giveaways = get_all_giveaways(status=None)
        print(f"[DEBUG] Найдено {len(active_giveaways)} розыгрышей для проверки")

        target_giveaway = None
        for giveaway in active_giveaways:
            giveaway_channel_id = str(giveaway.get('channel_id')) if giveaway.get('channel_id') else None
            post_msg_id = giveaway.get('post_message_id')
            started_msg_id = giveaway.get('started_post_message_id')
            
            print(f"[DEBUG] Розыгрыш #{giveaway['id']}: channel_id={giveaway_channel_id}, post_msg_id={post_msg_id}, started_msg_id={started_msg_id}, status={giveaway.get('status')}")
            
            if giveaway_channel_id and giveaway_channel_id != chat_id:
                print(f"[DEBUG] Розыгрыш #{giveaway['id']}: channel_id не совпадает ({giveaway_channel_id} != {chat_id})")
                continue

            if post_msg_id == message_id or started_msg_id == message_id:
                target_giveaway = giveaway
                print(f"[INFO] ✅ Найден розыгрыш #{giveaway['id']} для message_id={message_id}")
                break
        
        if not target_giveaway:
            print(f"[WARNING] Розыгрыш не найден для chat_id={chat_id}, message_id={message_id}")
            return

        from giveaway_monitoring import handle_message_reaction
        print(f"[DEBUG] Вызываем handle_message_reaction для розыгрыша #{target_giveaway['id']} с total_count={total_count}")
        handle_message_reaction(
            target_giveaway['id'],
            user_id=None,
            reaction_type='reaction_count',
            bot=bot,
            absolute_count=total_count
        )
        print(f"[INFO] Розыгрыш #{target_giveaway['id']}: total reaction count обновлён до {total_count}")
    except Exception as e:
        import traceback
        print(f"[ERROR] Ошибка обработки total_count реакций: {e}")
        traceback.print_exc()

# --- Обробка КОНТАКТУ телефону ---
@bot.message_handler(content_types=['contact'])
def phone_contact_handler(message):
    user_id = message.from_user.id
    contact = message.contact
    
    # Перевіряємо що це контакт самого користувача
    if contact.user_id != user_id:
        bot.send_message(message.chat.id, 
                        "❌ <b>Помилка!</b>\n\n"
                        "📱 Потрібно надіслати <b>СВІЙ КОНТАКТ</b>\n"
                        "🔄 Натисніть кнопку 'Поділитися контактом' знову", 
                        parse_mode="HTML")
        return
    
    phone_number = contact.phone_number
    
    # Додаємо + якщо немає
    if not phone_number.startswith('+'):
        phone_number = '+' + phone_number
    
    # Перевіряємо що це український номер
    if not phone_number.startswith('+380'):
        bot.send_message(message.chat.id, 
                        "❌ <b>Некоректний номер!</b>\n\n"
                        "🇺🇦 Приймаються <b>ТІЛЬКИ УКРАЇНСЬКІ</b> номери!\n"
                        f"📱 Ваш номер: <code>{phone_number}</code>\n"
                        f"✅ Потрібен номер: <code>+380xxxxxxxxx</code>\n\n"
                        f"🔄 Поділіться українським номером", 
                        parse_mode="HTML")
        return
    
    # Перевіряємо довжину номера
    if len(phone_number) != 13:
        bot.send_message(message.chat.id, 
                        "❌ <b>Некоректна довжина номера!</b>\n\n"
                        f"📱 Ваш номер: <code>{phone_number}</code>\n"
                        f"✅ Потрібен формат: <code>+380xxxxxxxxx</code> (13 цифр)\n\n"
                        f"🔄 Поділіться правильним номером", 
                        parse_mode="HTML")
        return
    
    from database import set_user_phone, ensure_user
    
    # Створюємо користувача в базі даних
    user_name = message.from_user.first_name
    if message.from_user.last_name:
        user_name += f" {message.from_user.last_name}"
    ensure_user(user_id, user_name)
    
    # Зберігаємо телефон
    set_user_phone(user_id, phone_number)
    
    # ПРОСТА РЕФЕРАЛЬНА СИСТЕМА - після підтвердження номеру
    try:
        from database import get_user_state
        user_state = get_user_state(user_id)
        referrer_id = None
        if user_state:
            import json
            try:
                state_data = json.loads(user_state)
                referrer_id = state_data.get('referrer_id')
            except Exception:
                referrer_id = None
        if referrer_id and str(referrer_id).isdigit():
            referrer_id = int(referrer_id)
            if referrer_id != user_id and referrer_id > 0:
                from database import get_user, save_referral, get_ref_bonus, add_balance, is_user_referred, set_user_state
                if not is_user_referred(user_id):
                    referrer = get_user(referrer_id)
                    if referrer:
                        save_referral(user_id, referrer_id)
                        ref_bonus = get_ref_bonus()
                        try:
                            from database import create_referral_reward_pending
                            create_referral_reward_pending(referrer_id, user_id, ref_bonus)
                        except Exception as e:
                            print(f"[REFERRAL] pending reward create failed: {e}")
                        try:
                            from utils import format_currency
                        except Exception:
                            def format_currency(amount):
                                return f"{amount:.2f}"
                        if referrer and len(referrer) > 1:
                            referrer_name = referrer[1]
                        else:
                            referrer_name = f"Користувач {referrer_id}"
                        success_text = (
                            "🎉 <b>РЕФЕРАЛЬНА РЕЄСТРАЦІЯ УСПІШНА!</b>\n\n"
                            f"👤 <b>Ваш реферер:</b> {referrer_name}\n"
                            f"💰 <b>Бонус рефереру:</b> {format_currency(ref_bonus)} ₴\n\n"
                            "🎁 <b>Що це означає:</b>\n"
                            "• Ви зареєструвалися за реферальним посиланням\n"
                            "• Ваш реферер отримав бонус за вашу реєстрацію\n"
                            "• Тепер ви можете запрошувати своїх друзів\n\n"
                            "🚀 <b>Наступний крок:</b>\n"
                            "Підпишіться на обов'язкові канали та чати для повного доступу!"
                        )
                        try:
                            from subscription_system import send_referral_message_with_subscription_check
                            send_referral_message_with_subscription_check(bot, message.chat.id, user_id, success_text)
                        except Exception:
                            pass
                        # Відправляємо уведомлення рефереру через функцію (з захистом від дублікатів)
                        try:
                            notify_referrer_about_new_referral(referrer_id, user_id, user_name)
                        except Exception as e:
                            print(f"[ERROR] Помилка уведомлення реферера: {e}")
                        try:
                            set_user_state(user_id, "{}")
                        except Exception:
                            pass
    except Exception:
        pass
    
    # Уведомлення адмінам про нового користувача відправляється ТІЛЬКИ після перевірки підписки
    # Див. subscription_system.verify_subscription_handler()

    # Видаляємо клавіатуру з кнопкою поділення контактом
    from telebot.types import ReplyKeyboardRemove
    
    bot.send_message(message.chat.id, 
                    "✅ <b>Номер успешно подтвержден!</b>", 
                    parse_mode="HTML",
                    reply_markup=ReplyKeyboardRemove())
    
    # Показуємо блок підписки одразу (щоб користувач точно бачив UI), тексти не змінюємо
    try:
        from subscription_system import send_subscription_required_message
        ok = send_subscription_required_message(message, user_id, bot)
        if not ok:
            # Якщо не вдалось відправити блок, не залишаємо користувача без дій
            show_main_menu(message)
    except Exception as e:
        print(f"[ERROR] Не вдалося показати блок підписки після підтвердження номера: {e}")
        # fallback, щоб користувач не застряг
        show_main_menu(message)

