# --- Глобальний pre-check для callback'ів ---
@bot.callback_query_handler(func=lambda c: not is_admin(c.from_user.id) and not is_beta(c.from_user.id) and get_maintenance_mode())
def maintenance_callback_block(call):
    global maintenance_messages
    prev_msg_id = maintenance_messages.get(call.from_user.id)
    if prev_msg_id:
        try:
            bot.delete_message(call.message.chat.id, prev_msg_id)
        except Exception:
            pass
    msg = bot.send_message(
        call.message.chat.id,
        "<b>🛠 Технічні роботи! </b>\n\n"
        "Сервіс тимчасово недоступний для користувачів.\n"
        "Ми вдосконалюємо платформу для вашого комфорту та нових можливостей!\n\n"
        "<b>Слідкуйте за оновленнями — повернемось ще кращими! 💹🤖</b>",
        parse_mode="HTML"
    )
    maintenance_messages[call.from_user.id] = msg.message_id
    bot.answer_callback_query(call.id)

