# @bot.message_handler(commands=['start'])  # disabled duplicate
# @ban_check
def start_handler_disabled_2(message):
    user_id = message.from_user.id
    username = message.from_user.username
    args = message.text.split()
    from database import get_invite_only, is_whitelisted, use_invite, add_to_whitelist, is_valid_invite, add_pending_user, save_user_username, ensure_user
    
    # Зберігаємо username користувача
    if username:
        save_user_username(user_id, username)

    # Перевіряємо чи це deep link для ігор
    if len(args) > 1 and args[1].startswith("game_"):
        if not are_games_enabled():
            bot.send_message(message.chat.id, "🚫 Ігри тимчасово вимкнені адміністратором.")
            return
        
        # Витягуємо group_chat_id з deep link
        game_parts = args[1].split("_")
        if len(game_parts) >= 3:  # game_user_id_group_id
            group_chat_id = game_parts[2]
            # Зберігаємо в сесії user state для наступних ігор
            bot.set_state(user_id, "in_game", chat_id=message.chat.id)
            with bot.retrieve_data(user_id, message.chat.id) as data:
                data['group_chat_id'] = group_chat_id
        
        # Створюємо користувача в базі даних якщо його немає
        user_name = message.from_user.first_name
        if message.from_user.last_name:
            user_name += f" {message.from_user.last_name}"
        ensure_user(user_id, user_name)
        
        # Автоматично показуємо меню ігор
        show_private_betting_menu(message)
        return

    # --- Capture referrer from deep link early ---
    try:
        maybe_save_referrer_from_start(message)
    except Exception:
        pass
    if len(args) > 1 and args[1].isdigit():
        try:
            referrer_id = int(args[1])
            if referrer_id != user_id and referrer_id > 0:
                from database import set_user_state, is_user_referred, get_referral_info
                import json
                # Якщо користувач вже має реферала — надішлемо креативне повідомлення з деталями
                try:
                    if is_user_referred(user_id):
                        info = get_referral_info(user_id)
                        if info:
                            inviter_id = info[0]
                            inviter_name = info[1] if len(info) > 1 and info[1] else f"Користувач {inviter_id}"
                            invited_at = info[3] if len(info) > 3 else None
                            try:
                                import datetime
                                invited_str = datetime.datetime.fromtimestamp(invited_at).strftime('%Y-%m-%d %H:%M') if invited_at else 'щойно'
                            except Exception:
                                invited_str = 'щойно'
                            creative = (
                                "✨ О, знайоме обличчя! ✨\n\n"
                                f"Ви вже прийшли за реферальним посиланням.\n"
                                f"Вас запросив: <b>{inviter_name}</b> (ID: {inviter_id})\n"
                                f"Коли: {invited_str}\n\n"
                                "Дякуємо, що залишаєтесь з нами! Якщо хочете, поділіться своїм посиланням — воно в /cabinet → Реферальна програма. 💚"
                            )
                            try:
                                bot.send_message(message.chat.id, creative, parse_mode="HTML")
                            except Exception:
                                pass
                        # Не переписуємо стан — вже є реферальний запис
                        raise SystemExit
                except SystemExit:
                    pass
                except Exception:
                    # у випадку помилки продовжимо і збережемо referrer як зазвичай
                    pass

                # Якщо ще немає реферала — збережемо referrer_id в стані
                try:
                    set_user_state(user_id, json.dumps({"referrer_id": referrer_id}))
                except Exception:
                    pass
        except Exception:
            pass

    invite_only = get_invite_only()

    if is_admin(user_id):
        # Створюємо адміністратора в базі даних
        user_name = message.from_user.first_name
        if message.from_user.last_name:
            user_name += f" {message.from_user.last_name}"
        ensure_user(user_id, user_name)
        show_main_menu(message)
        return

    if invite_only:
        if is_whitelisted(user_id):
            # Створюємо користувача в базі даних
            user_name = message.from_user.first_name
            if message.from_user.last_name:
                user_name += f" {message.from_user.last_name}"
            ensure_user(user_id, user_name)
            # Перевіряємо підписку перед показом меню
            if not check_subscription_before_action(message, bot):
                return  # Якщо підписка не підтверджена, функція вже показала повідомлення
            show_main_menu(message)
            return
        if len(args) > 1 and args[1].startswith("invite_"):
            token = args[1][7:]
            if is_valid_invite(token):
                use_invite(token, user_id)
                add_to_whitelist(user_id)
                # Створюємо користувача в базі даних
                user_name = message.from_user.first_name
                if message.from_user.last_name:
                    user_name += f" {message.from_user.last_name}"
                ensure_user(user_id, user_name)
                # Перевіряємо підписку перед показом меню
                if not check_subscription_before_action(message, bot):
                    return  # Якщо підписка не підтверджена, функція вже показала повідомлення
                show_main_menu(message)
                return
        # Якщо не по інвайту — блокуємо
        add_pending_user(user_id)  # Зберігаємо користувача, який пробував зайти
        from telebot.types import ReplyKeyboardRemove
        bot.send_message(message.chat.id, "🚧 <b>Доступ до бота закритий!</b>\n\n"
                                          "🛡️ <b>Тільки за реферальним посиланням від адміністратора.</b>\n"
                                          "Зверніться до власника бота, щоб отримати доступ.\n"
                                          "🌟 <i>Слідкуйте за оновленнями!</i>", 
                                          parse_mode="HTML",
                                          reply_markup=ReplyKeyboardRemove())
        return

    # Спробуємо одразу обробити реферала (якщо збережено) і показуємо меню
    try_process_referral(user_id, message.chat.id, user_name)
    show_main_menu(message)
    
    # Адміни проходять без перевірки підписки
    if is_admin(user_id):
        from telebot.types import ReplyKeyboardRemove
        bot.send_message(
            message.chat.id,
            get_main_menu_text(),
            reply_markup=main_keyboard(user_id),
            parse_mode="HTML"
        )
        return
    
    # Перевірка підписки
    if not check_subscription_before_action(message, bot):
        return  # Якщо підписка не підтверджена, функція вже показала повідомлення
    
    # Показуємо меню
    from telebot.types import ReplyKeyboardRemove  
    bot.send_message(
        message.chat.id,
        get_main_menu_text(),
        reply_markup=main_keyboard(user_id),
        parse_mode="HTML"
    )

# Duplicate cabinet handler removed - using the first one at line 2215

def _render_cabinet(call):
    from database import (
        get_user, ensure_user, get_user_registration_date, get_user_last_active,
        get_active_boosters_grouped, get_user_achievements, get_ref_count, get_deposits_sum,
        get_user_garden_level, get_garden_level_info, get_user_trees, get_all_fruits,
        get_fruit_price, get_withdrawals_by_status, get_invite_only, update_user_activity
    )
    import time
    try:
        update_user_activity(call.from_user.id)
    except Exception:
        pass
    user_id = call.from_user.id
    user_row = get_user(user_id)
    if not user_row:
        user_name = call.from_user.first_name
        if getattr(call.from_user, 'last_name', None):
            user_name += f" {call.from_user.last_name}"
        ensure_user(user_id, user_name)
        user_row = get_user(user_id)
        if not user_row:
            return ("❌ Помилка профілю", InlineKeyboardMarkup())
    user_id, user_name, balance, withdrawn_user = user_row[:4]
    ref_count = get_ref_count(user_id)
    deposits_sum = get_deposits_sum(user_id)
    reg_date = get_user_registration_date(user_id)
    last_active = get_user_last_active(user_id)
    boosters = get_active_boosters_grouped(user_id)
    achievements = get_user_achievements(user_id)
    reg_str = format_kiev_time(reg_date)
    last_str = format_kiev_time(last_active)
    now_ts = int(time.time())
    def _humanize_delta(seconds:int)->str:
        m = seconds // 60
        h = m // 60
        d = h // 24
        if d>0: return f"{d} д {h%24} год тому"
        if h>0: return f"{h} год {m%60} хв тому"
        if m>0: return f"{m} хв тому"
        return "щойно"
    last_delta = _humanize_delta(max(0, now_ts - (last_active or now_ts)))
    boosters_str = format_boosters_display(boosters)
    ach_str = "<b>😴 Немає досягнень</b>" if not achievements else "\n".join([f"🏆 <b>{a[0]}</b> — <i>{format_kiev_time(a[1])}</i>" for a in achievements])
    # Сад
    try:
        garden_level = get_user_garden_level(user_id)
        level_info = get_garden_level_info(garden_level)
        level_name = level_info['name'] if level_info else '—'
        level_bonus = level_info['bonus_percent'] if level_info else 0
        level_commission = level_info['commission_percent'] if level_info else 15
    except Exception:
        garden_level, level_name, level_bonus, level_commission = 0, '—', 0, 15
    trees = get_user_trees(user_id) or []
    from garden_models import TREE_TYPES, get_tree_name_uk, get_fruit_name_uk
    type_to_emoji = {t['type']: t.get('fruit_emoji','🌳') for t in TREE_TYPES}
    tree_counts = {}
    for t in trees:
        tree_counts[t['type']] = tree_counts.get(t['type'], 0) + 1
    trees_total = sum(tree_counts.values())
    trees_lines = [f"{type_to_emoji.get(tt,'🌳')} {get_tree_name_uk(tt)}: <b>{cnt}</b>" for tt, cnt in tree_counts.items()]
    trees_str = "\n".join(trees_lines) if trees_lines else "—"
    details_block = f"└ Деталі:\n{trees_str}\n" if trees_str != '—' else ""
    # Фрукти
    fruits = get_all_fruits(user_id) or {}
    total_fruits_value = 0.0
    fruit_lines = []
    for ftype, amount in fruits.items():
        price = get_fruit_price(ftype) or 0
        total_fruits_value += (amount or 0) * price
        fruit_lines.append(f"{get_fruit_name_uk(ftype)}: <b>{amount}</b> × {price}₴")
    fruits_str = "\n".join(fruit_lines) if fruit_lines else "—"
    fruits_value_block = f"💰 Орієнтовна вартість: <b>{format_currency(total_fruits_value)}₴</b>\n\n" if total_fruits_value else "\n"
    # Pending withdraws
    try:
        pending_withdraws = len([r for r in get_withdrawals_by_status('pending') if r[1] == user_id])
    except Exception:
        pending_withdraws = 0
    text = (
        f"🏛 <b>ПРОФІЛЬ</b>\n"
        f"━━━━━━━━━━━━━━━━━\n\n"
        f"👤 <b>Ім'я:</b> {user_name}\n"
        f"🗝 <b>ID:</b> <code>{user_id}</code>\n"
        f"📅 <b>Реєстрація:</b> {reg_str}\n"
        f"🕒 <b>Остання активність:</b> {last_str} (<i>{last_delta}</i>)\n\n"
        f"💼 <b>Фінанси</b>\n"
        f"├ Баланс: <b>{format_currency(balance)}₴</b> 🪙\n"
        f"├ Рефералів: <b>{ref_count}</b>\n"
        f"└ Виведено: <b>{format_currency(withdrawn_user)}</b>₴\n\n"
        f"🌳 <b>Мій сад</b>\n"
        f"├ Рівень: <b>{garden_level}</b> — {level_name}\n"
        f"├ Бонус врожаю: <b>+{level_bonus}%</b> | Комісія: <b>{level_commission}%</b>\n"
        f"├ Дерева: {trees_total} шт\n"
        f"{details_block}"
        f"📦 <b>Фрукти</b>\n"
        f"{fruits_str}\n"
        f"{fruits_value_block}"
        f"{boosters_str}\n"
        f"🏆 <b>Досягнення:</b>\n{ach_str}\n"
        f"📨 <b>Очікує на вивід:</b> <b>{pending_withdraws}</b> заявок\n"
    )
    
    # Додаємо статистику завдань
    try:
        from database import get_user_tasks_stats
        tasks_stats = get_user_tasks_stats(user_id)
        text += (
            f"\n📋 <b>Завдання</b>\n"
            f"├ Виконано: <b>{tasks_stats['completed_count']}</b>\n"
            f"└ Отримано нагород: <b>{format_currency(tasks_stats['total_rewards'])}₴</b>\n"
        )
    except Exception:
        pass
    kb = InlineKeyboardMarkup(row_width=2)
    if get_invite_only() == 0:
        kb.add(InlineKeyboardButton("📈 | Реферальна програма", callback_data="ref_program"))
    kb.add(InlineKeyboardButton("💵 | Депозит", callback_data="deposit"), InlineKeyboardButton("💰 | Вивід коштів", callback_data="withdraw"))
    kb.add(InlineKeyboardButton("📋 | Завдання", callback_data="tasks"))
    kb.add(InlineKeyboardButton("⏳ Мої заявки на вивід", callback_data="my_pending_withdrawals"))
    kb.add(InlineKeyboardButton("⬅️ | Повернутися на головну", callback_data="back_home"))
    return (text, kb)

# --- Кнопка з реферальним посиланням у кабінеті ---
# РЕФЕРАЛЬНЫЕ ОБРАБОТЧИКИ ПЕРЕНЕСЕНЫ В handlers/referral_handlers.py
# Старые обработчики ref_program_handler и my_referrals_handler удалены

# --- Головне меню, якщо треба ---
@bot.message_handler(commands=['start'])
@ban_check
def start_handler(message):
    user_id = message.from_user.id
    username = message.from_user.username
    args = message.text.split()
    from database import get_invite_only, is_whitelisted, use_invite, add_to_whitelist, is_valid_invite, add_pending_user, save_user_username, ensure_user
    
    # Зберігаємо username користувача
    if username:
        save_user_username(user_id, username)

    # Перевіряємо чи це deep link для ігор
    if len(args) > 1 and args[1].startswith("game_"):
        if not are_games_enabled():
            bot.send_message(message.chat.id, "🚫 Ігри тимчасово вимкнені адміністратором.")
            return
        
        # Витягуємо group_chat_id з deep link
        game_parts = args[1].split("_")
        if len(game_parts) >= 3:  # game_user_id_group_id
            group_chat_id = game_parts[2]
            # Зберігаємо в сесії user state для наступних ігор
            bot.set_state(user_id, "in_game", chat_id=message.chat.id)
            with bot.retrieve_data(user_id, message.chat.id) as data:
                data['group_chat_id'] = group_chat_id
        
        # Створюємо користувача в базі даних якщо його немає
        user_name = message.from_user.first_name
        if message.from_user.last_name:
            user_name += f" {message.from_user.last_name}"
        ensure_user(user_id, user_name)
        
        # Автоматично показуємо меню ігор
        show_private_betting_menu(message)
        return

    # --- Capture referrer from deep link early (active handler) ---
    print(f"[DEBUG] start_handler: перевіряємо реферальне посилання для користувача {user_id}")
    print(f"[DEBUG] start_handler: аргументи = {args}")
    try:
        maybe_save_referrer_from_start(message)
        print(f"[DEBUG] start_handler: maybe_save_referrer_from_start виконано")
    except Exception as e:
        print(f"[ERROR] start_handler: помилка в maybe_save_referrer_from_start: {e}")
        pass
    if len(args) > 1 and args[1].isdigit():
        try:
            referrer_id = int(args[1])
            if referrer_id != user_id and referrer_id > 0:
                from database import set_user_state
                import json
                set_user_state(user_id, json.dumps({"referrer_id": referrer_id}))
        except Exception:
            pass

    invite_only = get_invite_only()

    if is_admin(user_id):
        # Створюємо адміністратора в базі даних
        user_name = message.from_user.first_name
        if message.from_user.last_name:
            user_name += f" {message.from_user.last_name}"
        ensure_user(user_id, user_name)
        show_main_menu(message)
        return

    if invite_only:
        if is_whitelisted(user_id):
            # Створюємо користувача в базі даних
            user_name = message.from_user.first_name
            if message.from_user.last_name:
                user_name += f" {message.from_user.last_name}"
            ensure_user(user_id, user_name)
            # Перевіряємо підписку перед показом меню
            if not check_subscription_before_action(message, bot):
                return  # Якщо підписка не підтверджена, функція вже показала повідомлення
            show_main_menu(message)
            return
        if len(args) > 1 and args[1].startswith("invite_"):
            token = args[1][7:]
            if is_valid_invite(token):
                use_invite(token, user_id)
                add_to_whitelist(user_id)
                # Створюємо користувача в базі даних
                user_name = message.from_user.first_name
                if message.from_user.last_name:
                    user_name += f" {message.from_user.last_name}"
                ensure_user(user_id, user_name)
                # Перевіряємо підписку перед показом меню
                if not check_subscription_before_action(message, bot):
                    return  # Якщо підписка не підтверджена, функція вже показала повідомлення
                show_main_menu(message)
                return
        # Якщо не по інвайту — блокуємо
        add_pending_user(user_id)  # Зберігаємо користувача, який пробував зайти
        from telebot.types import ReplyKeyboardRemove
        bot.send_message(message.chat.id, "🚧 <b>Доступ до бота закритий!</b>\n\n"
                                          "🛡️ <b>Тільки за реферальним посиланням від адміністратора.</b>\n"
                                          "Зверніться до власника бота, щоб отримати доступ.\n"
                                          "🌟 <i>Слідкуйте за оновленнями!</i>", 
                                          parse_mode="HTML",
                                          reply_markup=ReplyKeyboardRemove())
        return

    # Якщо invite_only=0 — усім доступно
    # Створюємо користувача в базі даних
    user_name = message.from_user.first_name
    if message.from_user.last_name:
        user_name += f" {message.from_user.last_name}"
    ensure_user(user_id, user_name)
    
    # Перевірка номера телефону (якщо увімкнена)
    from database import get_user_phone, is_phone_verification_enabled
    if is_phone_verification_enabled():
        user_phone = get_user_phone(user_id)
        if not user_phone:
            from telebot.types import ReplyKeyboardMarkup, KeyboardButton
            keyboard = ReplyKeyboardMarkup(resize_keyboard=True, one_time_keyboard=True)
            keyboard.add(KeyboardButton("📱 Підтвердити номер", request_contact=True))
            bot.send_message(
                message.chat.id,
                "🎉 <b>РЕФЕРАЛЬНА РЕЄСТРАЦІЯ УСПІШНА!</b>\n\n"
                "📱 Для продовження підтвердьте номер телефону\n\n"
                "👆 Натисніть кнопку 'Поділитися контактом'",
                reply_markup=keyboard,
                parse_mode="HTML"
            )
            return
    
    # Якщо номер є - спробуємо одразу обробити реферала (якщо збережено)
    try:
        from database import get_user_state, is_user_referred, get_user, save_referral, get_ref_bonus, add_balance, set_user_state
        import json
        user_state = get_user_state(user_id)
        referrer_id = None
        if user_state:
            try:
                state_data = json.loads(user_state)
                referrer_id = state_data.get('referrer_id')
            except Exception:
                referrer_id = None
        if referrer_id and str(referrer_id).isdigit():
            referrer_id = int(referrer_id)
            if referrer_id != user_id and referrer_id > 0 and not is_user_referred(user_id):
                referrer = get_user(referrer_id)
                if referrer:
                    save_referral(user_id, referrer_id)
                    ref_bonus = get_ref_bonus()
                    add_balance(referrer_id, ref_bonus, reason="referral_bonus", details=f"За приглашение пользователя {user_id}")
                    try:
                        from utils import format_currency
                    except Exception:
                        def format_currency(amount):
                            return f"{amount:.2f}"
                    if referrer and len(referrer) > 1:
                        referrer_name = referrer[1]
                    else:
                        referrer_name = f"Користувач {referrer_id}"
                    success_text = (
                        "🎉 <b>РЕФЕРАЛЬНА РЕЄСТРАЦІЯ УСПІШНА!</b>\n\n"
                        f"👤 <b>Ваш реферер:</b> {referrer_name}\n"
                        f"💰 <b>Бонус рефереру:</b> {format_currency(ref_bonus)} ₴\n\n"
                        "🚀 Готово!"
                    )
                    try:
                        from subscription_system import send_referral_message_with_subscription_check
                        send_referral_message_with_subscription_check(bot, message.chat.id, user_id, success_text)
                    except Exception:
                        pass
                    notification_text = (
                        "🎉 <b>НОВИЙ РЕФЕРАЛ!</b>\n\n"
                        f"👤 <b>Користувач:</b> {user_name}\n"
                        f"💰 <b>Бонус:</b> {format_currency(ref_bonus)} ₴\n"
                    )
                    try:
                        bot.send_message(referrer_id, notification_text, parse_mode="HTML")
                    except Exception:
                        pass
                    try:
                        set_user_state(user_id, "{}")
                    except Exception:
                        pass
    except Exception:
        pass

    # Після підтвердження номера або якщо перевірка номера вимкнена — перевірка підписки
    try:
        from subscription_system import send_subscription_required_message, check_user_subscription
        if not check_user_subscription(user_id, bot, check_only=True):
            send_subscription_required_message(message, user_id, bot)
            return
    except Exception:
        pass

    # Показуємо головне меню
    show_main_menu(message)

