        f"📅 <b>Створено:</b> <i>{created_time}</i>\n"
        f"❌ <b>Відхилено:</b> <i>{now}</i>\n"
        f"🔢 <b>ID заявки:</b> <code>{tx_id}</code>\n\n"
        f"🚫 <b>Причина:</b>\n<i>{reason}</i>\n\n"
