@bot.callback_query_handler(func=lambda c: c.data == "back_home")
def back_home_handler(call):
    # Перевіряємо чи користувач заблокований
    if check_user_block_before_action(call, bot):
        return
    
    uid = call.from_user.id
    
    # Перевірка спаму
    is_spam, spam_message = check_button_spam(uid, "back_home")
    if is_spam:
        bot.answer_callback_query(call.id, text=spam_message, show_alert=True)
        return
    
    # Очищаємо всі стани користувача
    try:
        bot.delete_state(uid, call.message.chat.id)
    except:
        # Ігноруємо помилки при видаленні стану користувача
        pass
    bot.answer_callback_query(call.id)
    
    # Баннер + текст и клавиатура в одном сообщении, чтобы не было "разрывов"
    try:
        send_banner_with_caption(
            call.message.chat.id,
            "Меню",
            "🏠",
            get_main_menu_text(),
            reply_markup=main_keyboard(uid),
            parse_mode="HTML"
        )
    except Exception:
        bot.send_message(
            call.message.chat.id,
            get_main_menu_text(),
            reply_markup=main_keyboard(uid),
            parse_mode="HTML"
        )

# ==========================
# 🎁 ПОДАРУНОК: ігрова логіка
# ==========================

def _gift_build_keyboard(picked_safe: list[bool], bombs: list[int] | None = None, reveal_all: bool = False) -> InlineKeyboardMarkup:
    """Будує клавіатуру 2x5.
    - Нерозкриті: 🎁
    - Безпечно відкриті: ✅
    - Після завершення (reveal_all): показуємо бомби як 💣
    """
    kb = InlineKeyboardMarkup(row_width=5)
    buttons = []
    bombs_set = set(bombs or [])
    for i in range(10):
        if picked_safe and i < len(picked_safe) and picked_safe[i]:
            label = "✅"
            # Для уже открытых ячеек не добавляем callback_data, чтобы нельзя было кликнуть
            buttons.append(InlineKeyboardButton(label, callback_data="gift_already_opened"))
        elif reveal_all and i in bombs_set:
            label = "💣"
            # Для бомб после завершения игры тоже не добавляем callback_data
            buttons.append(InlineKeyboardButton(label, callback_data="gift_game_finished"))
        else:
            label = "🎁"
            buttons.append(InlineKeyboardButton(label, callback_data=f"gift_pick:{i}"))
    kb.add(*buttons[0:5])
    kb.add(*buttons[5:10])
    # Кнопки керування
    kb.add(
        InlineKeyboardButton("💰 Забрати виграш", callback_data="gift_cashout"),
        InlineKeyboardButton("⬅️ Назад", callback_data="gift_back")
    )
    return kb

def _gift_get_level(user_id: int) -> int:
    try:
        from database import get_user_garden_level_simple
        lvl = int(get_user_garden_level_simple(user_id) or 0)
        return max(1, min(lvl if lvl > 0 else 1, 20))
    except Exception:
        return 1

def _gift_can_play(user_id: int) -> tuple[bool, str | None]:
    import time
    try:
        from database import get_gift_last_play, format_duration, get_gift_cooldown_hours
        last = get_gift_last_play(user_id)
        if last is None:
            return True, None
        cooldown = int(get_gift_cooldown_hours()) * 3600
        left = last + cooldown - int(time.time())
        if left > 0:
            # В alert HTML не рендериться — показуємо простий текст без тегів
            return False, f"⏳ Доступно через: {format_duration(left)}"
        return True, None
    except Exception:
        return True, None

def _gift_pick_fruit_emoji(ftype: str) -> str:
    mapping = {
        'apple': '🍎',
        'pear': '🍐',
        'orange': '🍊',
        'grape': '🍇',
        'cherry': '🍒',
        'peach': '🍑',
    }
    return mapping.get(ftype, '🍎')

def _gift_save_session(user_id: int, sess: dict):
    import json
    from database import set_user_state
    # Зливаємо з наявним станом, щоб не стерти інше
    from database import get_user_state
    raw = get_user_state(user_id)
    try:
        data = json.loads(raw) if raw else {}
    except Exception:
        data = {}
    data['gift_session'] = sess
    set_user_state(user_id, json.dumps(data))

def _gift_load_session(user_id: int) -> dict | None:
    import json
    from database import get_user_state
    raw = get_user_state(user_id)
    if not raw:
        return None
    try:
        data = json.loads(raw)
        return data.get('gift_session')
    except Exception:
        return None

def _gift_clear_session(user_id: int):
    import json
    from database import get_user_state, set_user_state
    raw = get_user_state(user_id)
    try:
        data = json.loads(raw) if raw else {}
        if 'gift_session' in data:
            data.pop('gift_session', None)
            set_user_state(user_id, json.dumps(data))
    except Exception:
        set_user_state(user_id, None)

@bot.callback_query_handler(func=lambda c: c.data == "gift")
@ban_check
@subscription_required
@freeze_check
def gift_menu(call):
    user_id = call.from_user.id
    
    # Проверка доступности кнопки (для не-админов)
    if not is_admin(user_id) and is_button_disabled("gift"):
        message = get_button_message("gift")
        safe_answer_callback_query(call, text=message, show_alert=True)
        return
    
    # Кулдаун
    ok, wait_msg = _gift_can_play(user_id)
    if not ok:
        return bot.answer_callback_query(call.id, wait_msg, show_alert=True)

    # Якщо є активна сесія — покажемо існуючу
    from database import get_gift_session_version
    current_ver = int(get_gift_session_version())
    sess = _gift_load_session(user_id)
    if sess and not sess.get('finished') and int(sess.get('ver', current_ver)) == current_ver:
        picked = sess.get('picked_safe', [False]*10)
        lvl = sess.get('level', 1)
        attempts_left = int(sess.get('attempts_allowed', 0)) - int(sess.get('attempts_used', 0))
        acc_bal = float(sess.get('acc_balance', 0.0))
        acc_fam = float(sess.get('acc_fruits', 0.0))
        kb = _gift_build_keyboard(picked)
        msg = (
            f"🎁 <b>ПОДАРУНОК</b>\n\n"
            f"🌿 Рівень саду: <b>{lvl}</b>\n"
            f"🧪 Спроб залишилося: <b>{attempts_left}</b>\n"
            f"💰 Накопичено: <b>{acc_bal:.2f}</b> UAH + <b>{int(acc_fam)}</b> фрукт(и)\n\n"
            f"Відкривайте безпечні коробочки і заберіть виграш у будь-який момент!"
        )
        try:
            return bot.edit_message_text(msg, call.message.chat.id, call.message.message_id, reply_markup=kb, parse_mode="HTML")
        except Exception:
            return bot.send_message(call.message.chat.id, msg, reply_markup=kb, parse_mode="HTML")

    # Старт нової сесії
    import random
    lvl = _gift_get_level(user_id)
    from database import get_gift_attempts, get_gift_level_attempts, init_default_gift_attempts
    attempts = int(get_gift_attempts(lvl))
    # Инициализируем награды за попытки, если их еще нет
    attempts_data = get_gift_level_attempts(lvl)
    if not attempts_data:
        init_default_gift_attempts(lvl, attempts)
    # Генеруємо бомби (з конфігурації)
    from database import get_gift_bombs_count
    bombs_count = max(0, int(get_gift_bombs_count()))
    bombs = random.sample(range(10), bombs_count)
    sess = {
        'level': lvl,
        'attempts_allowed': attempts,
        'attempts_used': 0,
        'bombs': bombs,
        'picked_safe': [False]*10,
        'finished': False,
        'acc_balance': 0.0,
        'acc_fruits': 0.0,
        'ver': current_ver,
    }
    _gift_save_session(user_id, sess)
    kb = _gift_build_keyboard(sess['picked_safe'])
    msg = (
        f"🎁 <b>ПОДАРУНОК</b>\n\n"
        f"🌿 Рівень саду: <b>{lvl}</b>\n"
        f"🧪 Спроб: <b>{attempts}</b>\n\n"
        f"Відкривайте безпечні коробочки та забирайте виграш коли захочете. Якщо натрапите на 💣 — все згорить!"
    )
    # Перший екран гри краще показувати як нове повідомлення після банера
    try:
        send_banner_with_caption(call.message.chat.id, "Подарунок", "🎁", msg, reply_markup=kb, parse_mode="HTML", subtitle="Відкривай коробочки — уникай бомб")
    except Exception:
        bot.send_message(call.message.chat.id, msg, reply_markup=kb, parse_mode="HTML")

@bot.callback_query_handler(func=lambda c: c.data.startswith("gift_pick:"))
@ban_check
@subscription_required
def gift_pick_handler(call):
    user_id = call.from_user.id
    # Перевірка кулдауну: якщо сесія є — дозволяємо дограти, навіть якщо 24год вийшло в процесі
    from database import get_gift_session_version
    current_ver = int(get_gift_session_version())
    sess = _gift_load_session(user_id)
    if not sess or sess.get('finished'):
        return bot.answer_callback_query(call.id, "🔄 Створіть нову спробу через меню Подарунок", show_alert=True)
    if int(sess.get('ver', current_ver)) != current_ver:
        return bot.answer_callback_query(call.id, "🔄 Сесію оновлено. Відкрийте Подарунок знову.", show_alert=True)
    try:
        idx = int(call.data.split(':')[1])
    except Exception:
        return bot.answer_callback_query(call.id, "❌ Невірна кнопка")
    picked = sess.get('picked_safe', [False]*10)
    if idx < 0 or idx >= 10:
        return bot.answer_callback_query(call.id, "❌ Поза діапазоном")
    if picked[idx]:
        return bot.answer_callback_query(call.id, "⚠️ Цю коробочку вже відкривали")

    lvl = int(sess.get('level', 1))
    from database import get_gift_reward_balance, get_gift_reward_fruit, set_gift_last_play
    bombs = set(sess.get('bombs', []))
    used = int(sess.get('attempts_used', 0)) + 1
    allowed = int(sess.get('attempts_allowed', 0))

    # Відповідаємо на callback для анімації
    bot.answer_callback_query(call.id)
    
    # Якщо це бомба — програш і втрата накопиченого
    if idx in bombs:
        sess['finished'] = True
        sess['attempts_used'] = used
        picked[idx] = False  # бомба не стає безпечною
        _gift_save_session(user_id, sess)
        try:
            import time
            set_gift_last_play(user_id, int(time.time()))
        except Exception:
            pass
        kb = _gift_build_keyboard(picked, list(bombs), reveal_all=True)
        msg = (
            "💥 <b>БОМБА!</b> Нажаль, весь незабраний виграш згорів.\n\n"
            "Спробуйте знову завтра. Удача ще посміхнеться! ✨"
        )
        try:
            return bot.edit_message_text(msg, call.message.chat.id, call.message.message_id, reply_markup=kb, parse_mode="HTML")
        except Exception:
            return bot.send_message(call.message.chat.id, msg, reply_markup=kb, parse_mode="HTML")

    # НОВАЯ СИСТЕМА: Награда по попыткам
    try:
        from database import get_gift_attempt_reward
        attempt_number = sum(1 for v in picked if v) + 1  # Номер текущей попытки (1, 2, 3...)
        
        # Получаем награду для конкретной попытки
        bal_add, ftype, fruit_add = get_gift_attempt_reward(lvl, attempt_number)
        
        # Если нет настроек для этой попытки - используем старую систему как fallback
        if bal_add == 0.0 and fruit_add == 0.0:
            from database import get_gift_reward_balance, get_gift_reward_fruit
            base_bal = float(get_gift_reward_balance(lvl))
            ftype, base_famt = get_gift_reward_fruit(lvl)
            # Старая прогрессивная система как fallback
            bal_add = base_bal * (2 * attempt_number - 1)
            fruit_add = float(base_famt) * attempt_number
        
        # Сохраняем награду за текущую попытку (не накапливаем, а заменяем)
        sess['acc_balance'] = float(bal_add)  # Только награда за текущую попытку
        sess['acc_fruits'] = float(fruit_add)  # Только награда за текущую попытку
        sess['last_attempt_reward'] = attempt_number  # Сохраняем номер последней попытки
        sess['fruit_type'] = ftype  # Сохраняем тип фрукта для cashout
        picked[idx] = True
        sess['picked_safe'] = picked
        sess['attempts_used'] = used
        _gift_save_session(user_id, sess)

        # Якщо досягли ліміту спроб — авто-кашаут
        if used >= allowed:
            return _gift_do_cashout(call, sess, lvl)

        # Інакше — оновлюємо екран
        acc_bal = float(sess['acc_balance'])
        acc_fam = float(sess['acc_fruits'])
        kb = _gift_build_keyboard(picked)
        msg = (
            f"🎁 <b>ПОДАРУНОК</b>\n\n"
            f"✅ Влучно! Виграш за {attempt_number}-й момент: <b>{acc_bal:.2f}</b> UAH та <b>{int(acc_fam)}</b> фрукт(и).\n"
            f"Можете продовжити ризикувати або натиснути \"💰 Забрати виграш\".\n\n"
            f"💡 <i>При виборі \"Забрати виграш\" ви отримаєте нагороду за останній успішний момент.</i>\n\n"
            f"🌿 Рівень: <b>{lvl}</b> | 🧪 Спроб використано: <b>{used}/{allowed}</b>"
        )
        try:
            return bot.edit_message_text(msg, call.message.chat.id, call.message.message_id, reply_markup=kb, parse_mode="HTML")
        except Exception:
            return bot.send_message(call.message.chat.id, msg, reply_markup=kb, parse_mode="HTML")
    except Exception as e:
        import traceback
        traceback.print_exc()
        bot.answer_callback_query(call.id, f"❌ Помилка: {str(e)}", show_alert=True)
        return

def _gift_do_cashout(call, sess, lvl):
    """Нарахувати накопичене та завершити сесію."""
    user_id = call.from_user.id
    from database import add_balance, add_fruit, set_gift_last_play
    acc_bal = float(sess.get('acc_balance', 0.0))
    acc_fam = float(sess.get('acc_fruits', 0.0))
    ftype, _ = (sess.get('fruit_type'), None)
    # Дістанемо fruit_type з рівня налаштувань якщо не збережено
    if not ftype:
        from database import get_gift_reward_fruit
        ftype, _ = get_gift_reward_fruit(lvl)
    # Нарахування
    try:
        if acc_bal > 0:
            add_balance(user_id, acc_bal, reason="account_transfer", details="Поповнення с другого аккаунта")
    except Exception:
        pass
    try:
        if acc_fam > 0:
            add_fruit(user_id, ftype, acc_fam)
    except Exception:
        pass
    # Фініш і кулдаун
    sess['finished'] = True
    _gift_save_session(user_id, sess)
    try:
        import time
        set_gift_last_play(user_id, int(time.time()))
    except Exception:
        pass
    # Показуємо підсумок і відкриваємо всі бомби
    picked = sess.get('picked_safe', [False]*10)
    kb = _gift_build_keyboard(picked, list(sess.get('bombs', [])), reveal_all=True)
    fruit_emoji = _gift_pick_fruit_emoji(ftype)
    last_attempt = sess.get('last_attempt_reward', 'останній')
    msg = (
        f"💰 <b>ВИПЛАТА УСПІШНА</b>\n\n"
        f"На рахунок зараховано: <b>{acc_bal:.2f}</b> UAH і <b>{int(acc_fam)}</b> {fruit_emoji}.\n"
        f"(Виграш за {last_attempt}-й момент)\n\n"
        f"Поверніться завтра за новим шансом!"
    )
    return bot.edit_message_text(msg, call.message.chat.id, call.message.message_id, reply_markup=kb, parse_mode="HTML")

@bot.callback_query_handler(func=lambda c: c.data in ["gift_already_opened", "gift_game_finished"])
def gift_already_opened_handler(call):
    """Обработчик для уже открытых ячеек или завершенной игры"""
    if call.data == "gift_already_opened":
        bot.answer_callback_query(call.id, "⚠️ Цю коробочку вже відкривали", show_alert=False)
    else:
        bot.answer_callback_query(call.id, "⚠️ Гра вже завершена", show_alert=False)

@bot.callback_query_handler(func=lambda c: c.data == "gift_cashout")
@ban_check
@subscription_required
def gift_cashout_handler(call):
    user_id = call.from_user.id
    sess = _gift_load_session(user_id)
    if not sess or sess.get('finished'):
        return bot.answer_callback_query(call.id, "❌ Нема активної сесії")
    lvl = int(sess.get('level', 1))
    return _gift_do_cashout(call, sess, lvl)

@bot.callback_query_handler(func=lambda c: c.data == "gift_back")
def gift_back_handler(call):
    """Розумне повернення з подарунка: якщо виграшу немає — у головне меню, інакше — у сад."""
    try:
        user_id = call.from_user.id
        sess = _gift_load_session(user_id)
        acc_bal = float(sess.get('acc_balance', 0.0)) if sess else 0.0
        acc_fam = float(sess.get('acc_fruits', 0.0)) if sess else 0.0
        # Якщо нічого не зібрано — повертаємо у головне меню
        if (acc_bal <= 0.0) and (acc_fam <= 0.0):
            try:
                bot.answer_callback_query(call.id)
            except Exception:
                pass
            return back_home_handler(call)
        # Інакше повертаємо до саду
        try:
            bot.answer_callback_query(call.id)
        except Exception:
            pass
        return garden_menu_handler(call)
    except Exception:
        # На будь-який випадок — головне меню
        try:
            bot.answer_callback_query(call.id)
        except Exception:
            pass
        return back_home_handler(call)

@bot.callback_query_handler(func=lambda c: c.data == "open_gift_settings")
def open_gift_settings_cb(call):
    if not is_admin(call.from_user.id):
        return bot.answer_callback_query(call.id, "Нема доступу", show_alert=True)
    _gift_open_admin_menu(call.message.chat.id)

