def gift_cfg_attempt_fruit_amount_step(message, lvl, attempt):
    try:
        amount = float(message.text.replace(',', '.').strip())
        from database import get_gift_attempt_reward, set_gift_attempt_reward
        reward_balance, fruit_type, _ = get_gift_attempt_reward(lvl, attempt)
        set_gift_attempt_reward(lvl, attempt, reward_balance, fruit_type, amount)
        bot.reply_to(message, f"✅ Збережено: {amount} {fruit_type} для попытки {attempt}")
    except Exception:
        bot.reply_to(message, "❌ Невірне число")

