@bot.callback_query_handler(func=lambda c: c.data == "garden_history")    
def garden_history_handler(call):
    from database import get_garden_history, get_garden_history_summary, get_user_garden_level, get_garden_level_info
    import datetime
    import time
    user_id = call.from_user.id
    
    # Перевірка спаму
    is_spam, spam_message = check_button_spam(user_id, "garden_history")
    if is_spam:
        bot.answer_callback_query(call.id, text=spam_message, show_alert=True)
        return
    
    # Отримуємо згруповану статистику за останні 7 днів
    summary = get_garden_history_summary(user_id, 7)
    
    if not summary:
        kb = InlineKeyboardMarkup()
        kb.add(InlineKeyboardButton("⬅️ Назад", callback_data="garden_menu"))
        try:
            send_banner_with_caption(call.message.chat.id, "Статистика саду", "📊", "😔 У вас ще немає історії дій у саду.", reply_markup=kb, parse_mode="HTML", subtitle="Останні 7 днів")
        except Exception:
            bot.send_message(call.message.chat.id, "😔 У вас ще немає історії дій у саду.", reply_markup=kb)
        return
    
    # Отримуємо інформацію про рівень саду
    garden_level = get_user_garden_level(user_id)
    level_info = get_garden_level_info(garden_level) if garden_level else None
    level_name = level_info['name'] if level_info else "Стартовий садівник"
    
    # Форматування історії з покращеними емодзі та назвами
    type_emojis = {
        "buy_tree": "🌳",
        "harvest": "🍎",
        "sell_fruit": "💸",
        "level_up": "🚀",
        "booster": "⚡",
        "watering": "💧",
        "garden_commission": "📊",
        "other": "📄"
    }
    
    # Покращений словник для перекладу технічних назв на українські
    type_names = {
        "buy_tree": "Купівля дерева",
        "harvest": "Збір урожаю",
        "sell_fruit": "Продаж фруктів",
        "level_up": "Підвищення рівня",
        "booster": "Активація бустера",
        "watering": "Полив дерев",
        "garden_commission": "Комісія саду",
        "other": "Інша дія"
    }
    
    # Красивий заголовок з інформацією про рівень
    msg = (
        f"🌳✨ <b>СТАТИСТИКА САДУ</b> ✨🌳\n"
        f"━━━━━━━━━━━━━━━━━\n\n"
        f"🏆 <b>Рівень саду:</b> <b>{garden_level}. {level_name}</b>\n"
        f"📅 <b>Період:</b> <b>Останні 7 днів</b>\n"
        f"⏰ <b>Оновлено:</b> <b>{get_kiev_time()}</b>\n\n"
    )

    # Додаємо коротке резюме по типах дій
    if summary:
        grouped_resume = {}
        for row in summary:
            k = row.get('type')
            if not k:
                continue
            grp = grouped_resume.setdefault(k, {'count': 0, 'total': 0.0})
            grp['count'] += int(row.get('count') or 0)
            grp['total'] += float(row.get('total_amount') or 0)
        msg += "📈 <b>Резюме за 7 днів:</b>\n"
        # Форматуємо дружні рядки
        def add_line(label: str, count: float | int | None, total: float | None, total_suffix: str | None = None):
            nonlocal msg
            parts = []
            if count is not None:
                parts.append(f"{int(count)}")
            count_str = f"{parts[0]}" if parts else "0"
            if total is None or total_suffix is None:
                msg += f"├ {label}: {count_str} запис(ів)\n"
            else:
                # Для кількісних метрик (шт) показуємо підпис "кількість"
                total_label = "кількість" if (str(total_suffix).strip().startswith("шт") or str(total_suffix).strip().endswith("шт") or "шт" in str(total_suffix)) else "сума"
                msg += f"├ {label}: {count_str} запис(ів) • {total_label}: <b>{format_currency(total)}{total_suffix}</b>\n"

        # Комісія саду (₴)
        if 'garden_commission' in grouped_resume:
            add_line('Комісія саду', grouped_resume['garden_commission']['count'], grouped_resume['garden_commission']['total'], '₴')
        # Збір урожаю (шт)
        if 'harvest' in grouped_resume:
            add_line('Збір урожаю', grouped_resume['harvest']['count'], grouped_resume['harvest']['total'], ' шт')
        # Автозбір (шт)
        if 'auto_harvest' in grouped_resume:
            add_line('Автозбір', grouped_resume['auto_harvest']['count'], grouped_resume['auto_harvest']['total'], ' шт')
        # Продаж фруктів (шт)
        if 'sell_fruit' in grouped_resume:
            add_line('Продаж фруктів', grouped_resume['sell_fruit']['count'], grouped_resume['sell_fruit']['total'], ' шт')
        # Полив (лише кількість)
        if 'watering' in grouped_resume:
            msg += f"├ Полив дерев: {int(grouped_resume['watering']['count'])} раз(ів)\n"
        # Інші, якщо з'являться: покупки дерев, рівень, бустери як ₴
        if 'buy_tree' in grouped_resume:
            add_line('Покупка дерев', grouped_resume['buy_tree']['count'], grouped_resume['buy_tree']['total'], '₴')
        if 'level_up' in grouped_resume:
            add_line('Підвищення рівня', grouped_resume['level_up']['count'], grouped_resume['level_up']['total'], '₴')
        if 'booster' in grouped_resume:
            add_line('Бустери', grouped_resume['booster']['count'], grouped_resume['booster']['total'], '₴')

        # Підсумок за період (шт)
        total_harvest = float(grouped_resume.get('harvest', {}).get('total', 0.0)) + float(grouped_resume.get('auto_harvest', {}).get('total', 0.0))
        total_sold = float(grouped_resume.get('sell_fruit', {}).get('total', 0.0))
        msg += (
            "└ ────────────────────────\n"
            f"🍎 <b>Зібрано фруктів (шт):</b> <b>{format_currency(total_harvest)}</b>\n"
            f"💸 <b>Продано фруктів (шт):</b> <b>{format_currency(total_sold)}</b>\n\n"
    )
    
    # Групуємо за типами дій
    grouped_actions = {}
    for item in summary:
        action_type = item["type"]
        if action_type not in grouped_actions:
            grouped_actions[action_type] = []
        grouped_actions[action_type].append(item)
    
    # Виводимо покращену згруповану статистику
    type_meta = {
        "garden_commission": {"count_label": "Операцій із комісією", "sum_label": "Сума комісій", "currency_kind": "money"},
        "sell_fruit": {"count_label": "Угод продажу", "sum_label": "Продано фруктів (шт)", "currency_kind": "fruit"},
        "harvest": {"count_label": "Зборів урожаю", "sum_label": "Зібрано фруктів (шт)", "currency_kind": "fruit"},
        "auto_harvest": {"count_label": "Автозборів", "sum_label": "Зібрано фруктів (шт)", "currency_kind": "fruit"},
        "buy_tree": {"count_label": "Покупок дерев", "sum_label": "Витрачено", "currency_kind": "money"},
        "level_up": {"count_label": "Підвищень рівня", "sum_label": "Витрачено", "currency_kind": "money"},
        "booster": {"count_label": "Активацій бустерів", "sum_label": "Витрачено", "currency_kind": "money"},
        "watering": {"count_label": "Поливів"},
    }
    for action_type, items in grouped_actions.items():
        emoji = type_emojis.get(action_type, "📄")
        type_name = type_names.get(action_type, action_type.capitalize())
        
        total_count = sum(int(item.get("count") or 0) for item in items)
        total_amount = sum(float(item.get("total_amount") or 0) for item in items)
        
        meta = type_meta.get(action_type, {"count_label": "Записів", "sum_label": "Сума", "currency_kind": "money"})
        # Для типів без суми показуємо лише кількість
        if "sum_label" not in meta:
            msg += (
                f"┏━━━━━━━━━━━━━━━━━━━━━━━━┓\n"
                f"┃ {emoji} <b>{type_name}</b> {emoji} ┃\n"
                f"┗━━━━━━━━━━━━━━━━━━━━━━━━┛\n"
                f"📊 <b>{meta['count_label']}:</b> <b>{total_count}</b>\n\n"
            )
            continue

        # Формуємо підпис суми залежно від природи валюти
        main_currency = items[0]["currency"] if items else "₴"
        if meta.get("currency_kind") == "fruit":
            from garden_models import get_fruit_name_uk
            translated_currency = get_fruit_name_uk(main_currency) if main_currency in ['apple','pear','cherry','peach'] else main_currency
            amount_display = f"{format_currency(total_amount)} {translated_currency}"
        else:
            # гроші
            currency_sign = "₴" if main_currency in ["UAH", "₴", None, ""] else main_currency
            amount_display = f"{format_currency(total_amount)}{currency_sign}"

            msg += (
                f"┏━━━━━━━━━━━━━━━━━━━━━━━━┓\n"
                f"┃ {emoji} <b>{type_name}</b> {emoji} ┃\n"
                f"┗━━━━━━━━━━━━━━━━━━━━━━━━┛\n"
            f"📊 <b>{meta['count_label']}:</b> <b>{total_count}</b>\n"
            f"💰 <b>{meta['sum_label']}:</b> <b>{amount_display}</b>\n\n"
            )
    
    # Покращені кнопки для детального перегляду
    kb = InlineKeyboardMarkup(row_width=2)
    kb.add(
        InlineKeyboardButton("📅 Сьогодні", callback_data="garden_history_detail_today"),
        InlineKeyboardButton("📅 Тиждень", callback_data="garden_history_detail_week")
    )
    kb.add(
        InlineKeyboardButton("📅 Місяць", callback_data="garden_history_detail_month"),
        InlineKeyboardButton("📋 Всі записи", callback_data="garden_history_detail_all")
    )
    kb.add(InlineKeyboardButton("⬅️ Назад", callback_data="garden_menu"))
    
    bot.edit_message_text(msg, call.message.chat.id, call.message.message_id, reply_markup=kb, parse_mode="HTML")

# Обробники для детального перегляду історії саду
@bot.callback_query_handler(func=lambda c: c.data.startswith("garden_history_detail_"))
def garden_history_detail_handler(call):
    from database import get_garden_history, get_garden_history_by_date, get_user_garden_level, get_garden_level_info
    import datetime
    
    user_id = call.from_user.id
    detail_type = call.data.replace("garden_history_detail_", "")
    
    # Отримуємо інформацію про рівень саду
    garden_level = get_user_garden_level(user_id)
    level_info = get_garden_level_info(garden_level) if garden_level else None
    level_name = level_info['name'] if level_info else "Стартовий садівник"
    
    if detail_type == "all":
        history = get_garden_history(user_id, 50)
        title = "📋 Всі записи історії саду"
        period_text = "Всі часи"
    else:
        history = get_garden_history_by_date(user_id, detail_type)
        titles = {
            "today": "📅 Історія саду за сьогодні",
            "week": "📅 Історія саду за тиждень", 
            "month": "📅 Історія саду за місяць"
        }
        period_texts = {
            "today": "Сьогодні",
            "week": "Останній тиждень",
            "month": "Останній місяць"
        }
        title = titles.get(detail_type, "📋 Історія саду")
        period_text = period_texts.get(detail_type, "Період")
    
    if not history:
        kb = InlineKeyboardMarkup()
        kb.add(InlineKeyboardButton("⬅️ Назад", callback_data="garden_history"))
        bot.edit_message_text("😔 За цей період немає записів у історії саду.", 
                             call.message.chat.id, call.message.message_id, reply_markup=kb)
        return
    
    # Покращене форматування історії
    type_emojis = {
        "buy_tree": "🌳",
        "harvest": "🍎", 
        "sell_fruit": "💸",
        "level_up": "🚀",
        "booster": "⚡",
        "watering": "💧",
        "garden_commission": "📊",
        "other": "📄"
    }
    
    type_names = {
        "buy_tree": "Купівля дерева",
        "harvest": "Збір урожаю",
        "sell_fruit": "Продаж фруктів", 
        "level_up": "Підвищення рівня",
        "booster": "Активація бустера",
        "watering": "Полив дерев",
        "garden_commission": "Комісія саду",
        "other": "Інша дія"
    }
    
    # Показуємо перші 10 записів з пагінацією
    page = 0
    items_per_page = 10
    start_idx = page * items_per_page
    end_idx = start_idx + items_per_page
    page_items = history[start_idx:end_idx]
    
    # Красивий заголовок
    msg = (
        f"🌳✨ <b>ДЕТАЛЬНА ІСТОРІЯ САДУ</b> ✨🌳\n"
        f"━━━━━━━━━━━━━━━━━\n\n"
        f"🏆 <b>Рівень саду:</b> <b>{garden_level}. {level_name}</b>\n"
        f"📅 <b>Період:</b> <b>{period_text}</b>\n"
        f"📊 <b>Записів:</b> <b>{len(history)}</b>\n"
        f"⏰ <b>Оновлено:</b> <b>{get_kiev_time()}</b>\n\n"
    )
    
    for i, item in enumerate(page_items, 1):
        emoji = type_emojis.get(item["type"], "📄")
        type_name = type_names.get(item["type"], item["type"].capitalize())
        dt = datetime.datetime.fromtimestamp(item["timestamp"]).strftime("%d.%m.%Y %H:%M")
        comment = f" — {item['comment']}" if item['comment'] else ""
        
        if item['currency']:
            # Перекладаємо назви фруктів як валюту
            from garden_models import get_fruit_name_uk
            if item['currency'] in ['apple', 'pear', 'cherry', 'peach']:
                translated_currency = get_fruit_name_uk(item['currency'])
                amount_str = f"{format_currency(item['amount'])} {translated_currency}"
            else:
                amount_str = f"{format_currency(item['amount'])} {item['currency']}"
        else:
            amount_str = f"{item['amount']}"
        
        # Перекладаємо назви фруктів в коментарях
        from garden_models import get_fruit_name_uk, get_tree_name_uk
        translated_comment = comment
        if comment and any(fruit_type in comment for fruit_type in ['apple', 'pear', 'cherry', 'peach']):
            for fruit_type in ['apple', 'pear', 'cherry', 'peach']:
                if fruit_type in comment:
                    fruit_name = get_fruit_name_uk(fruit_type)
                    translated_comment = comment.replace(fruit_type, fruit_name)
                    break
        
        # Покращений формат запису
        msg += (
            f"┏━━━━━━━━━━━━━━━━━━━━━━━━┓\n"
            f"┃ {emoji} <b>{type_name}</b> {emoji} ┃\n"
            f"┗━━━━━━━━━━━━━━━━━━━━━━━━┛\n"
            f"💰 <b>Сума:</b> <b>{amount_str}</b>\n"
            f"📝 <b>Деталі:</b> <i>{translated_comment}</i>\n"
            f"⏰ <b>Час:</b> <code>{dt}</code>\n\n"
        )
    
    # Додаємо інформацію про пагінацію
    total_pages = (len(history) + items_per_page - 1) // items_per_page
    if total_pages > 1:
        msg += f"📄 Сторінка {page + 1} з {total_pages} (всього {len(history)} записів)\n\n"
    
    # Кнопки навігації
    kb = InlineKeyboardMarkup(row_width=3)
    
    # Кнопки пагінації
    nav_buttons = []
    if page > 0:
        nav_buttons.append(InlineKeyboardButton("◀️", callback_data=f"garden_history_page_{detail_type}_{page-1}"))
    nav_buttons.append(InlineKeyboardButton(f"{page+1}/{total_pages}", callback_data="no_action"))
    if page < total_pages - 1:
        nav_buttons.append(InlineKeyboardButton("▶️", callback_data=f"garden_history_page_{detail_type}_{page+1}"))
    
    if nav_buttons:
        kb.add(*nav_buttons)
    
    # Кнопки періодів
    kb.add(
        InlineKeyboardButton("📅 Сьогодні", callback_data="garden_history_detail_today"),
        InlineKeyboardButton("📅 Тиждень", callback_data="garden_history_detail_week"),
        InlineKeyboardButton("📅 Місяць", callback_data="garden_history_detail_month")
    )
    kb.add(InlineKeyboardButton("📋 Всі записи", callback_data="garden_history_detail_all"))
    kb.add(InlineKeyboardButton("⬅️ Назад", callback_data="garden_history"))
    
    bot.edit_message_text(msg, call.message.chat.id, call.message.message_id, reply_markup=kb, parse_mode="HTML")

# Обробник пагінації
@bot.callback_query_handler(func=lambda c: c.data.startswith("garden_history_page_"))
def garden_history_page_handler(call):
    from database import get_garden_history, get_garden_history_by_date, get_user_garden_level, get_garden_level_info
    import datetime
    
    user_id = call.from_user.id
    parts = call.data.split("_")
    detail_type = parts[3]
    page = int(parts[4])
    
    # Отримуємо інформацію про рівень саду
    garden_level = get_user_garden_level(user_id)
    level_info = get_garden_level_info(garden_level) if garden_level else None
    level_name = level_info['name'] if level_info else "Стартовий садівник"
    
    if detail_type == "all":
        history = get_garden_history(user_id, 50)
        title = "📋 Всі записи історії саду"
        period_text = "Всі часи"
    else:
        history = get_garden_history_by_date(user_id, detail_type)
        titles = {
            "today": "📅 Історія саду за сьогодні",
            "week": "📅 Історія саду за тиждень",
            "month": "📅 Історія саду за місяць"
        }
        period_texts = {
            "today": "Сьогодні",
            "week": "Останній тиждень",
            "month": "Останній місяць"
        }
        title = titles.get(detail_type, "📋 Історія саду")
        period_text = period_texts.get(detail_type, "Період")
    
    if not history:
        kb = InlineKeyboardMarkup()
        kb.add(InlineKeyboardButton("⬅️ Назад", callback_data="garden_history"))
        bot.edit_message_text("😔 За цей період немає записів у історії саду.",
                             call.message.chat.id, call.message.message_id, reply_markup=kb)
        return
    
    # Покращене форматування історії
    type_emojis = {
        "buy_tree": "🌳",
        "harvest": "🍎",
        "sell_fruit": "💸",
        "level_up": "🚀",
        "booster": "⚡",
        "watering": "💧",
        "garden_commission": "📊",
        "other": "📄"
    }
    
    type_names = {
        "buy_tree": "Купівля дерева",
        "harvest": "Збір урожаю",
        "sell_fruit": "Продаж фруктів",
        "level_up": "Підвищення рівня",
        "booster": "Активація бустера",
        "watering": "Полив дерев",
        "garden_commission": "Комісія саду",
        "other": "Інша дія"
    }
    
    # Показуємо записи з пагінацією
    items_per_page = 10
    start_idx = page * items_per_page
    end_idx = start_idx + items_per_page
    page_items = history[start_idx:end_idx]
    
    # Красивий заголовок
    msg = (
        f"🌳✨ <b>ДЕТАЛЬНА ІСТОРІЯ САДУ</b> ✨🌳\n"
        f"━━━━━━━━━━━━━━━━━\n\n"
        f"🏆 <b>Рівень саду:</b> <b>{garden_level}. {level_name}</b>\n"
        f"📅 <b>Період:</b> <b>{period_text}</b>\n"
        f"📊 <b>Записів:</b> <b>{len(history)}</b>\n"
        f"⏰ <b>Оновлено:</b> <b>{get_kiev_time()}</b>\n\n"
    )
    
    for i, item in enumerate(page_items, 1):
        emoji = type_emojis.get(item["type"], "📄")
        type_name = type_names.get(item["type"], item["type"].capitalize())
        dt = datetime.datetime.fromtimestamp(item["timestamp"]).strftime("%d.%m.%Y %H:%M")
        comment = f" — {item['comment']}" if item['comment'] else ""
        
        if item['currency']:
            amount_str = f"{format_currency(item['amount'])} {item['currency']}"
        else:
            amount_str = f"{item['amount']}"
        
        # Перекладаємо назви фруктів в коментарях
        from garden_models import get_fruit_name_uk, get_tree_name_uk
        translated_comment = comment
        if comment and any(fruit_type in comment for fruit_type in ['apple', 'pear', 'cherry', 'peach']):
            for fruit_type in ['apple', 'pear', 'cherry', 'peach']:
                if fruit_type in comment:
                    fruit_name = get_fruit_name_uk(fruit_type)
                    translated_comment = comment.replace(fruit_type, fruit_name)
                    break
        
        # Покращений формат запису
        msg += (
            f"┏━━━━━━━━━━━━━━━━━━━━━━━━┓\n"
            f"┃ {emoji} <b>{type_name}</b> {emoji} ┃\n"
            f"┗━━━━━━━━━━━━━━━━━━━━━━━━┛\n"
            f"💰 <b>Сума:</b> <b>{amount_str}</b>\n"
            f"📝 <b>Деталі:</b> <i>{translated_comment}</i>\n"
            f"⏰ <b>Час:</b> <code>{dt}</code>\n\n"
        )
    
    # Додаємо інформацію про пагінацію
    total_pages = (len(history) + items_per_page - 1) // items_per_page
    if total_pages > 1:
        msg += f"📄 Сторінка {page + 1} з {total_pages} (всього {len(history)} записів)\n\n"
    
    # Кнопки навігації
    kb = InlineKeyboardMarkup(row_width=3)
    
    # Кнопки пагінації
    nav_buttons = []
    if page > 0:
        nav_buttons.append(InlineKeyboardButton("◀️", callback_data=f"garden_history_page_{detail_type}_{page-1}"))
    nav_buttons.append(InlineKeyboardButton(f"{page+1}/{total_pages}", callback_data="no_action"))
    if page < total_pages - 1:
        nav_buttons.append(InlineKeyboardButton("▶️", callback_data=f"garden_history_page_{detail_type}_{page+1}"))
    
    if nav_buttons:
        kb.add(*nav_buttons)
    
    # Кнопки періодів
    kb.add(
        InlineKeyboardButton("📅 Сьогодні", callback_data="garden_history_detail_today"),
        InlineKeyboardButton("📅 Тиждень", callback_data="garden_history_detail_week"),
        InlineKeyboardButton("📅 Місяць", callback_data="garden_history_detail_month")
    )
    kb.add(InlineKeyboardButton("📋 Всі записи", callback_data="garden_history_detail_all"))
    kb.add(InlineKeyboardButton("⬅️ Назад", callback_data="garden_history"))
    
    bot.edit_message_text(msg, call.message.chat.id, call.message.message_id, reply_markup=kb, parse_mode="HTML")

# Обробник для кнопки "no_action"
@bot.callback_query_handler(func=lambda c: c.data == "no_action")
def no_action_handler(call):
    bot.answer_callback_query(call.id)

@bot.callback_query_handler(func=lambda c: c.data == "garden_overview")
@ban_check
@subscription_required
@phone_required
def garden_overview_handler(call):
    if check_maintenance(call): return
    
    from database import get_user, get_user_trees, get_all_fruits, get_all_fruit_prices, get_garden_commission, get_user_garden_commission, get_user_garden_level, get_garden_level_info, can_upgrade_garden_level, get_user_trees_with_watering, water_tree, check_and_remove_withered_trees, ensure_watering_system
    from garden_models import TREE_TYPES, FRUITS, get_dynamic_income
    import time, datetime

    user_id = call.from_user.id
    
    # Перевірка спаму
    is_spam, spam_message = check_button_spam(user_id, "garden_overview")
    if is_spam:
        bot.answer_callback_query(call.id, text=spam_message, show_alert=True)
        return
    
    # Переконаємося, що таблиці системи поливу створені
    ensure_watering_system()
    
    user_row = get_user(user_id)
    if not user_row:
        bot.send_message(call.message.chat.id, "Користувача не знайдено.")
        return
    
    balance = user_row[2]
    trees = get_user_trees(user_id)
    fruits = get_all_fruits(user_id)
    prices = get_all_fruit_prices()
    commission = get_user_garden_commission(user_id)
    
    # Інформація про рівень саду
    garden_level = get_user_garden_level(user_id)
    level_info = get_garden_level_info(garden_level)
    can_upgrade = can_upgrade_garden_level(user_id)
    
    # Перевіряємо і видаляємо завялі дерева
    removed_withered = check_and_remove_withered_trees(user_id)
    
    # Повідомлення про завялі дерева
    if removed_withered > 0:
        bot.send_message(call.message.chat.id, f"⚠️ <b>Увага!</b> {removed_withered} дерево було видалено через відсутність поливу протягом довгого часу.", parse_mode="HTML")
    
    # Отримуємо дерева з інформацією про полив
    trees_with_watering = get_user_trees_with_watering(user_id)
    
    # Підрахунок дерев
    tree_counts = {}
    total_hourly_income = 0
    next_harvest_minutes = None
    
    from database import get_economy_harvest_multiplier
    from garden_models import get_effective_tree_income
    econ_mult = get_economy_harvest_multiplier()
    for tree_data in trees_with_watering:
        tree_type = tree_data['tree_type']
        count = tree_data['count']
        watering_status = tree_data['watering_status']
        
        tree_counts[tree_type] = count
        
        # Підрахунок доходності з бонусом від рівня саду
        # Пер-деревна дохідність: якщо адмін задав значення — не зменшуємо економікою
        income_per_hour = get_effective_tree_income(tree_type, econ_mult)
        bonus = level_info['bonus_percent'] if level_info else 0
        income_with_bonus = income_per_hour * (1 + bonus / 100)
        total_hourly_income += income_with_bonus * count
        
        # Розрахунок часу до збору (використовуємо старі дані)
        for tree in trees:
            if tree['type'] == tree_type:
                last_harvest = tree['last_harvest'] or tree['planted_at'] or int(time.time())
                hours_since = (int(time.time()) - last_harvest) // 3600
                
                if hours_since >= 1:
                    # Можна збирати
                    minutes_until_next = 0
                else:
                    # Розраховуємо хвилини до збору
                    minutes_since = (int(time.time()) - last_harvest) // 60
                    minutes_until_next = max(0, 60 - minutes_since)
                
                if next_harvest_minutes is None or minutes_until_next < next_harvest_minutes:
                    next_harvest_minutes = minutes_until_next
                break
    
    # Формуємо список дерев
    tree_display = []
    bonus = level_info['bonus_percent'] if level_info else 0
    
    # Створюємо словник для швидкого пошуку статусу поливу
    watering_statuses = {tree_data['tree_type']: tree_data['watering_status'] for tree_data in trees_with_watering}
    
    for ttype in TREE_TYPES:
        count = tree_counts.get(ttype['type'], 0)
        watering_status = watering_statuses.get(ttype['type'])
        
        if count > 0:
            from garden_models import get_effective_tree_income
            per_tree_income = get_effective_tree_income(ttype['type'], econ_mult)
            income = per_tree_income * count
            income_with_bonus = income * (1 + bonus / 100)
            bonus_text = f" (+{bonus}%)" if bonus > 0 else ""
            
            # Знаходимо найстаріше дерево цього типу для розрахунку прогресу
            oldest_tree = None
            for tree in trees:
                if tree['type'] == ttype['type']:
                    if oldest_tree is None or (tree['last_harvest'] or tree['planted_at']) < (oldest_tree['last_harvest'] or oldest_tree['planted_at']):
                        oldest_tree = tree
            
            if oldest_tree:
                last_harvest = oldest_tree['last_harvest'] or oldest_tree['planted_at']
                progress_percent, time_until, time_text, status_emoji = calculate_harvest_progress(last_harvest, ttype['type'], user_id)
                progress_bar = create_progress_bar(progress_percent)

                # Наглядний лічильник накопичення від останнього збору (КЕПИМО до 1 години і враховуємо полив)
                seconds_since = max(0, int(time.time()) - (oldest_tree['last_harvest'] or oldest_tree['planted_at']))
                hours_since = seconds_since / 3600.0
                # Блокування росту при відсутності поливу або якщо дерево засохло
                watering_blocked_local = False
                if watering_status:
                    wl = watering_status.get('water_level', 100)
                    iw = watering_status.get('is_withered', False)
                    # Ріст повністю зупинено, якщо води недостатньо (<20%) або дерево зав'яло
                    watering_blocked_local = iw or wl < 20
                # Якщо ріст заблоковано — накопичення 0 за час простою
                # Якщо росте — накопичуємо не більше ніж за 1 годину від моменту останнього перезапуску (last_harvest)
                # Якщо немає води — ріст призупиняється, але прогрес НЕ обнуляється
                effective_hours = 0.0 if watering_blocked_local else min(1.0, hours_since)
                accumulated_raw = per_tree_income * effective_hours * count * (1 + bonus / 100)
                accumulated = f"{accumulated_raw:.6f}"  # показуємо до 6 знаків після коми
                
                # Додаємо інформацію про полив
                watering_info = ""
                if watering_status:
                    water_level = watering_status.get('water_level', 100)
                    is_withered = watering_status.get('is_withered', False)
                    
                    # Створюємо прогрес-бар для води
                    water_progress = create_water_progress_bar(water_level)
                    
                    if is_withered:
                        watering_info = f"\n│   💧 <b>ПОТРЕБУЄ ПОЛИВУ!</b> 🌱"
                    elif water_level < 50:
                        watering_info = f"\n│   💧 [{water_progress}] {water_level}% ⚠️"
                    elif water_level < 80:
                        watering_info = f"\n│   💧 [{water_progress}] {water_level}% 💧"
                    else:
                        watering_info = f"\n│   💧 [{water_progress}] {water_level}% ✅"
                else:
                    # Якщо дерево ще не поливалися, показуємо 100%
                    water_progress = create_water_progress_bar(100)
                    watering_info = f"\n│   💧 [{water_progress}] 100% ✅"
                
                tree_display.append(
                    f"├ {ttype['fruit_emoji']} <b>{ttype['name']}</b> × {count}\n"
                    f"│   🔹 За дерево: <b>{per_tree_income:.1f}/год</b>  →  Разом: <b>{income_with_bonus:.1f}/год{bonus_text}</b>\n"
                    f"│   🧮 Накопичено з останнього збору: <b>{accumulated}</b> шт\n"
                    f"│   ⏳ [{progress_bar}] {progress_percent:.0f}%{watering_info}\n"
                    f"└   {status_emoji} {time_text}"
                )
        else:
            # Для дерев які не мають активних екземплярів
            income = get_dynamic_income(ttype['type']) * count
            income_with_bonus = income * (1 + bonus / 100)
            bonus_text = f" (+{bonus}%)" if bonus > 0 else ""
            tree_display.append(f"├ {ttype['fruit_emoji']} <b>{ttype['name']}</b> × {count} → <b>{income_with_bonus:.1f}/год{bonus_text}</b>")
    
    # Формуємо список фруктів із цінами
    fruit_display = []
    total_fruit_value = 0
    has_fruits = False
    
    for fruit in FRUITS:
        amount = fruits.get(fruit['type'], 0)
        price = prices.get(fruit['type'], 0)
        if amount > 0:
            has_fruits = True
            value = amount * price
            user_profit = value * (1 - commission / 100)
            total_fruit_value += user_profit
            fruit_display.append(f"├ {fruit['emoji']} <b>{format_currency(amount)}</b> шт × <b>{format_currency(price)}₴</b> = <b>{format_currency(user_profit)}₴</b>")
    
    # Статус наступного збору
    if next_harvest_minutes is not None:
        if next_harvest_minutes == 0:
            harvest_status = "🟢 <b>ГОТОВО ДО ЗБОРУ!</b>"
        elif next_harvest_minutes <= 5:
            harvest_status = f"🟡 <b>Збір через {next_harvest_minutes} хв.</b>"
        else:
            harvest_status = f"🔴 <b>Збір через {next_harvest_minutes} хв.</b>"
    else:
        harvest_status = "❌ <b>Немає дерев</b>"
    
    # Головне повідомлення
    level_name = level_info['name'] if level_info else "Стартовий садівник"
    upgrade_hint = " 🔓" if can_upgrade else ""
    
    # Яскраве повідомлення, якщо час збирати
    urgent_block = ""
    if next_harvest_minutes == 0:
        urgent_block = (
            "🍎✨ <b>Потрібно зібрати фрукти!</b>\n"
            "<i>Натисніть кнопку “Зібрати фрукти” нижче, щоб не втрачати час.</i>\n\n"
        )
    
    msg = (
        f"🌳✨ <b>ВАШ ОСОБИСТИЙ САД</b> ✨🌳\n"
        f"━━━━━━━━━━━━━━━━━\n\n"
        f"💰 <b>Баланс:</b> <b>{format_currency(balance)}₴</b>\n"
        f"🏆 <b>Рівень саду:</b> <b>{garden_level}. {level_name}{upgrade_hint}</b>\n"
        f"🕐 <b>Статус збору:</b> {harvest_status}\n"
        f"📊 <b>Комісія саду:</b> <b>{commission}%</b>\n\n"
        f"{urgent_block}"
    )
    
    if tree_display:
        tree_text = ''.join([line + '\n' for line in tree_display])
        msg += (
            f"🌱 <b>ВАШІ ДЕРЕВА:</b>\n"
            f"{tree_text}"
            f"└ 💎 <b>Загальний дохід:</b> <b>{format_currency(total_hourly_income)}/год</b>\n"
            f"ℹ️ <i>Загальний дохід = (дохідність 1 дерева × к-сть дерев) × бонус рівня.</i>\n\n"
        )
    else:
        msg += f"🌱 <b>ДЕРЕВА:</b> <i>Ще не посаджено</i>\n\n"
    
    if fruit_display:
        # Обмежуємо кількість фруктів для відображення
        max_fruits_to_show = 5
        if len(fruit_display) > max_fruits_to_show:
            fruit_text = ''.join([line + '\n' for line in fruit_display[:max_fruits_to_show]])
            fruit_text += f"├ ... та ще {len(fruit_display) - max_fruits_to_show} типів фруктів\n"
        else:
            fruit_text = ''.join([line + '\n' for line in fruit_display])
        
        msg += (
            f"🍎 <b>ГОТОВІ ФРУКТИ:</b>\n"
            f"{fruit_text}"
            f"└ 💸 <b>Загальна вартість:</b> <b>{format_currency(total_fruit_value)}₴</b>\n\n"
        )
    else:
        # Перевіряємо чи є дерева і чи готові вони до збору
        if trees:
            # Перевіряємо чи є дерева які потребують поливу
            trees_need_watering = []
            
            # Групуємо дерева за типом для ефективності
            tree_types = {}
            for tree in trees:
                tree_type = tree['type']
                if tree_type not in tree_types:
                    tree_types[tree_type] = 0
                tree_types[tree_type] += 1
            
            # Перевіряємо кожен тип дерева один раз
            for tree_type, count in tree_types.items():
                watering_status = get_tree_watering_status(user_id, tree_type)
                water_level = watering_status.get('water_level', 100)
                is_withered = watering_status.get('is_withered', False)
                
                if is_withered or water_level < 20:
                    ttype = next((t for t in TREE_TYPES if t['type'] == tree_type), None)
                    if ttype:
                        if count > 1:
                            trees_need_watering.append(f"{ttype['name']} x{count}")
                        else:
                            trees_need_watering.append(ttype['name'])
            
            if trees_need_watering:
                tree_names = ", ".join(trees_need_watering)
                msg += f"🍎 <b>ФРУКТИ:</b> <i>🌱 Дерева потребують поливу: {tree_names}</i>\n\n"
            elif next_harvest_minutes == 0:
                msg += f"🍎 <b>ФРУКТИ:</b> <i>Готові до збору! Натисніть кнопку знизу</i>\n\n"
            else:
                msg += f"🍎 <b>ФРУКТИ:</b> <i>Фрукти ще ростуть... Зачекайте поки дерева дозріють</i>\n\n"
        else:
            msg += (
                "🍎 <b>ФРУКТИ:</b> "
                "<i>У вас ще немає дерев. Спершу придбайте дерево, і воно почне приносити плоди!</i>\n\n"
            )
    
    msg += (
        f"💡 <b>ПОРАДИ:</b>\n"
        f"• Збирайте фрукти кожну годину\n"
        f"• Купуйте різні дерева для більшого доходу\n"
        f"• Стежте за цінами на біржі\n\n"
        f"🚀 <i>Розвивайте свій сад і збагачуйтеся!</i>"
    )
    
    # Кнопки з динамічними емодзі
    kb = InlineKeyboardMarkup(row_width=2)
    
    # Кнопка збору (заблокована якщо рівень 0)
    locked_by_level = (garden_level == 0)
    harvest_emoji = "🔒🍎" if locked_by_level else ("🍎✨" if next_harvest_minutes == 0 else "🍎")
    harvest_text = f"{harvest_emoji} Зібрати фрукти" if not locked_by_level else "🔒 Відкрийте рівень 1, щоб збирати"
    
    # Кнопка продажу (з сумою якщо є фрукти)
    sell_emoji = "📈💰" if has_fruits else "📈"
    sell_text = f"{sell_emoji} Біржа фруктів"
    if has_fruits and total_fruit_value > 0:
        sell_text += f" ({format_currency(total_fruit_value)}₴)"
    
    # Компактне розташування кнопок по 2-3 в рядку
    if locked_by_level:
        kb.add(
            InlineKeyboardButton("🚀 Відкрити рівень 1", callback_data="upgrade_garden_level"),
            InlineKeyboardButton(sell_text, callback_data="sell_fruits")
        )
    else:
        kb.add(
            InlineKeyboardButton(harvest_text, callback_data="harvest_fruits"),
            InlineKeyboardButton(sell_text, callback_data="sell_fruits")
        )
    kb.add(
        InlineKeyboardButton("💧 Полити дерева", callback_data="water_trees"),
        InlineKeyboardButton("🛒 Купити дерево", callback_data="buy_tree")
    )
    kb.add(
        InlineKeyboardButton("📊 Статистика", callback_data="garden_history"),
        InlineKeyboardButton("🚀 Апгрейд" if can_upgrade else "ℹ️ Рівні", 
                           callback_data="upgrade_garden_level" if can_upgrade else "garden_levels_info")
    )
    kb.add(InlineKeyboardButton("⬅️ Назад", callback_data="garden_menu"))
    
    # Банер саду з динамічним підзаголовком
    try:
        total_trees = sum(tree_counts.values()) if isinstance(tree_counts, dict) else 0
        subtitle = f"Рівень: {garden_level} | Дерев: {total_trees} | Дохід: {format_currency(total_hourly_income)}/год"
    except Exception:
        subtitle = None
    # Рендеримо простим повідомленням без банера
    try:
        bot.edit_message_text(msg, call.message.chat.id, call.message.message_id, reply_markup=kb, parse_mode="HTML")
        # Відстежуємо це повідомлення
        track_bot_message(call.message.chat.id, call.message.message_id)
    except Exception:
        sent_msg = bot.send_message(call.message.chat.id, msg, reply_markup=kb, parse_mode="HTML")
        if sent_msg:
            track_bot_message(call.message.chat.id, sent_msg.message_id)

# --- Полив дерев ---
@bot.callback_query_handler(func=lambda c: c.data == "water_trees")
@phone_required
def water_trees_handler(call):
    from database import get_user_trees_with_watering, water_tree, get_watering_settings
    import time
    
    user_id = call.from_user.id
    
    # Перевірка спаму
    is_spam, spam_message = check_button_spam(user_id, "water_trees")
    if is_spam:
        bot.answer_callback_query(call.id, text=spam_message, show_alert=True)
        return
    
    # Отримуємо дерева з інформацією про полив
    try:
        trees_with_watering = get_user_trees_with_watering(user_id)
    except Exception as e:
        print(f"Помилка отримання дерев: {e}")
        bot.answer_callback_query(call.id, "❌ Помилка отримання дерев!", show_alert=True)
        return
    
    if not trees_with_watering:
        bot.answer_callback_query(call.id, "❌ У вас немає дерев для поливу!", show_alert=True)
        return
    
    # Перевіряємо чи є дерева, які можна полити
    can_water_trees = []
    already_watered_trees = []
    needs_watering_trees = []
    settings = get_watering_settings()
    watering_interval = settings.get('watering_interval', 900)  # 15 хвилин
    current_time = int(time.time())
    
    for tree_data in trees_with_watering:
        tree_type = tree_data['tree_type']
        tree_count = tree_data['count']
        watering_status = tree_data['watering_status']
        
        # Перевіряємо чи дерева вже политі
        if watering_status and watering_status.get('last_watered'):
            time_since_watering = current_time - watering_status['last_watered']
            current_level = watering_status.get('water_level', 100)
            is_withered = watering_status.get('is_withered', False)
            
            # Вважаємо "вже политі" тільки якщо і таймер не минув, і рівень води повний, і не засохлі
            if time_since_watering < watering_interval and current_level >= 100 and not is_withered:
                already_watered_trees.append(tree_type)
                continue
        
        # Перевіряємо чи потрібен полив (низький рівень води або засохлі)
        if watering_status:
            current_level = watering_status.get('water_level', 100)
            is_withered = watering_status.get('is_withered', False)
            if current_level < 100 or is_withered:
                needs_watering_trees.append((tree_type, tree_count))
        
        can_water_trees.append(tree_type)
    
    # Якщо всі дерева вже политі
    if not can_water_trees:
        msg = f"🌱 <b>ВСІ ДЕРЕВА ВЖЕ ПОЛИТІ!</b> 🌱\n\n"
        msg += f"💧 <b>Ваші дерева не потребують поливу</b>\n"
        # Розраховуємо час наступного поливу
        import time
        next_watering_time = int(time.time()) + watering_interval
        next_watering_str = format_kiev_time(next_watering_time)
        msg += f"⏰ <b>Наступний полив через:</b> {watering_interval // 60} хв. /{next_watering_str.split()[-1]}\n\n"
        msg += f"🌱 <b>Дерева продовжують ріст!</b>\n"
        msg += f"📈 <b>Перевірте рівень води в саду</b>"
        
        # Кнопки
        kb = InlineKeyboardMarkup(row_width=2)
        kb.add(
            InlineKeyboardButton("🌱 Мій сад", callback_data="garden_overview"),
            InlineKeyboardButton("⬅️ Назад", callback_data="garden_menu")
        )
        
        try:
            bot.edit_message_text(
                msg,
                call.message.chat.id,
                call.message.message_id,
                reply_markup=kb,
                parse_mode="HTML"
            )
            # Відстежуємо це повідомлення
            track_bot_message(call.message.chat.id, call.message.message_id)
            # Очищаємо старі повідомлення
            cleanup_old_bot_messages(call.message.chat.id, keep_last_n=1)
        except Exception as e:
            print(f"Error in water_trees_handler: {e}")
            bot.answer_callback_query(call.id, "🌱 Всі дерева вже политі!", show_alert=True)
        return
    
    # Поливаємо дерева, які можна полити
    watered_count = 0
    watered_tree_count = 0  # Загальна кількість политого дерев
    messages = []
    
    for tree_type in can_water_trees:
        try:
            # Знаходимо кількість дерев цього типу
            tree_count = next((count for ttype, count in [(td['tree_type'], td['count']) for td in trees_with_watering] if ttype == tree_type), 1)
            
            # Поливаємо всі дерева цього типу (water_tree працює на рівні типу)
            success, message = water_tree(user_id, tree_type)
            if success:
                watered_count += 1  # Кількість типів дерев
                watered_tree_count += tree_count  # Загальна кількість дерев
                messages.append(f"✅ {message}")
                print(f"[WATERING] Успішно полито {tree_count} дерев типу {tree_type} для користувача {user_id}")
            else:
                messages.append(f"⚠️ {message}")
                print(f"[WATERING] Не вдалося полити дерева типу {tree_type}: {message}")
        except Exception as e:
            print(f"[WATERING ERROR] Помилка поливу дерева {tree_type}: {e}")
            import traceback
            traceback.print_exc()
            messages.append(f"❌ Помилка поливу дерева {tree_type}")
    
    # Формуємо повідомлення
    msg = f"💧 <b>ПОЛИВ ДЕРЕВ ЗАВЕРШЕНО!</b> 💧\n\n"
    if watered_tree_count > 0:
        msg += f"✅ <b>Полито дерев:</b> {watered_tree_count} шт ({watered_count} типів)\n"
    else:
        msg += f"⚠️ <b>Полито типів дерев:</b> {watered_count}\n"
    if already_watered_trees:
        msg += f"🌱 <b>Вже политі:</b> {len(already_watered_trees)} типів дерев\n"
    msg += f"⏰ <b>Час поливу:</b> {get_kiev_time_short()}\n"
    msg += f"💧 <b>Рівень води:</b> 100%\n\n"
    msg += f"🌱 <b>Ваші дерева продовжують ріст!</b>\n"
    # Розраховуємо час наступного поливу
    next_watering_time = current_time + watering_interval
    next_watering_str = format_kiev_time(next_watering_time)
    msg += f"📈 <b>Наступний полив через:</b> {watering_interval // 60} хв. /{next_watering_str.split()[-1]}"
    
    # Кнопки
    kb = InlineKeyboardMarkup(row_width=2)
    kb.add(
        InlineKeyboardButton("🌱 Мій сад", callback_data="garden_overview"),
        InlineKeyboardButton("⬅️ Назад", callback_data="garden_menu")
    )
    
    try:
        bot.edit_message_text(
            msg,
            call.message.chat.id,
            call.message.message_id,
            reply_markup=kb,
            parse_mode="HTML"
        )
        # Відстежуємо це повідомлення для майбутнього очищення
        track_bot_message(call.message.chat.id, call.message.message_id)
        # Очищаємо старі повідомлення, залишаючи тільки останнє
        cleanup_old_bot_messages(call.message.chat.id, keep_last_n=1)
    except Exception as e:
        print(f"Error in water_trees_handler: {e}")
        try:
            # Якщо не вдалося відредагувати, надсилаємо нове повідомлення
            sent_msg = bot.send_message(call.message.chat.id, msg, reply_markup=kb, parse_mode="HTML")
            if sent_msg:
                track_bot_message(call.message.chat.id, sent_msg.message_id)
            cleanup_old_bot_messages(call.message.chat.id, keep_last_n=1)
        except Exception as e2:
            print(f"Error sending message in water_trees_handler: {e2}")
        bot.answer_callback_query(call.id, "✅ Дерева полито!", show_alert=True)

# --- Апгрейд рівня саду ---
@bot.callback_query_handler(func=lambda c: c.data == "upgrade_garden_level")
def upgrade_garden_level_handler(call):
    from database import get_user, get_user_garden_level, get_next_garden_level_price, get_garden_level_info
    
    user_id = call.from_user.id
    user = get_user(user_id)
    balance = user[2] if user else 0
    
    current_level = get_user_garden_level(user_id)
    next_level_price = get_next_garden_level_price(user_id)
    next_level_info = get_garden_level_info(current_level + 1)
    
    if not next_level_info:
        bot.answer_callback_query(call.id, "❌ Досягнуто максимальний рівень!", show_alert=True)
        return
    
    # Порівняння переваг
    current_level_info = get_garden_level_info(current_level)
    current_bonus = current_level_info['bonus_percent'] if current_level_info else 0
    current_commission = current_level_info['commission_percent'] if current_level_info else 15
    
    new_bonus = next_level_info['bonus_percent']
    new_commission = next_level_info['commission_percent']
    
    can_afford = balance >= next_level_price
    status_emoji = "✅" if can_afford else "❌"
    
    # Динамічний текст переваг для різних рівнів
    if current_level == 0:
        perks_block = (
            f"💡 <b>МОЖЛИВОСТІ ПІСЛЯ ВІДКРИТТЯ РІВНЯ 1:</b>\n"
            f"• Почати заробляти в саду\n"
            f"• Відкрити доступ до яблунь\n"
            f"• Стартові бонуси та статистика\n"
            f"• Перший крок до статусу садівника\n\n"
        )
    elif current_level == 1:
        perks_block = (
            f"💡 <b>ПЕРЕВАГИ АПГРЕЙДУ:</b>\n"
            f"• Більший дохід від усіх дерев\n"
            f"• Менша комісія при продажу\n"
            f"• Доступ до нових видів дерев\n"
            f"• Престиж вище — крок до Срібного рівня\n\n"
        )
    else:
        perks_block = (
            f"💡 <b>ПЕРЕВАГИ АПГРЕЙДУ:</b>\n"
            f"• Ще краща врожайність (більший бонус)\n"
            f"• Ще нижча комісія при продажу\n"
            f"• Розширений доступ до дерев та функцій\n"
            f"• Вищий статус і додаткові можливості\n\n"
        )
    
    msg = (
        f"🚀✨ <b>АПГРЕЙД РІВНЯ САДУ</b> ✨🚀\n"
        f"━━━━━━━━━━━━━━━━━\n\n"
        f"💰 <b>Ваш баланс:</b> <b>{format_currency(balance)}₴</b>\n"
        f"💸 <b>Вартість апгрейду:</b> <b>{format_currency(next_level_price)}₴</b> {status_emoji}\n\n"
        f"📊 <b>ПОТОЧНИЙ РІВЕНЬ {current_level}:</b>\n"
        f"├ 📈 Бонус до врожаю: <b>{current_bonus}%</b>\n"
        f"├ 💰 Комісія: <b>{current_commission}%</b>\n"
        f"└ 🌱 Доступні дерева: <b>{len(current_level_info['available_trees']) if current_level_info else 1}</b>\n\n"
        f"🆙 <b>НОВИЙ РІВЕНЬ {current_level + 1}: {next_level_info['name']}</b>\n"
        f"├ 📈 Бонус до врожаю: <b>{new_bonus}%</b> (+{new_bonus - current_bonus}%)\n"
        f"├ 💰 Комісія: <b>{new_commission}%</b> (-{current_commission - new_commission}%)\n"
        f"├ 🌱 Доступні дерева: <b>{len(next_level_info['available_trees'])}</b>\n"
        f"└ 📝 {next_level_info['description']}\n\n"
        f"{perks_block}"
        f"🚀 <i>Інвестуйте у своє майбутнє!</i>"
    )
    
    kb = InlineKeyboardMarkup()
    
    if can_afford:
        kb.add(InlineKeyboardButton("✅ Підтвердити апгрейд", callback_data="confirm_garden_upgrade"))
    else:
        kb.add(InlineKeyboardButton("❌ Недостатньо коштів", callback_data="garden_overview"))
    
    kb.add(InlineKeyboardButton("⬅️ Назад до саду", callback_data="garden_overview"))
    
    bot.edit_message_text(msg, call.message.chat.id, call.message.message_id, reply_markup=kb, parse_mode="HTML")

@bot.callback_query_handler(func=lambda c: c.data == "confirm_garden_upgrade")
def confirm_garden_upgrade_handler(call):
    from database import get_user, get_user_garden_level, get_next_garden_level_price, set_user_garden_level, add_balance, get_garden_level_info
    
    user_id = call.from_user.id
    user = get_user(user_id)
    balance = user[2] if user else 0
    
    current_level = get_user_garden_level(user_id)
    upgrade_price = get_next_garden_level_price(user_id)
    new_level = current_level + 1
    new_level_info = get_garden_level_info(new_level)
    
    if balance < upgrade_price:
        try:
            bot.answer_callback_query(call.id, "❌ Недостатньо коштів!", show_alert=True)
        except Exception:
            pass
        return
    
    # Виконуємо апгрейд
    add_balance(user_id, -upgrade_price, reason="garden_level_up", details=f"to level {new_level}")
    set_user_garden_level(user_id, new_level)
    
    # Логируем активность в саду (если функция существует)
    try:
        from database import log_garden_activity
        log_garden_activity(
            user_id,
            "upgrade",
            f"Рівень {new_level}",
            quantity=1,
            cost=upgrade_price,
            metadata={
                'old_level': current_level,
                'new_level': new_level,
                'level_name': new_level_info['name'],
                'bonus_percent': new_level_info['bonus_percent'],
                'commission_percent': new_level_info['commission_percent']
            }
        )
    except ImportError:
        pass  # Функция может отсутствовать
    except Exception as e:
        print(f"[confirm_garden_upgrade] error logging activity: {e}")
    
    # Повідомлення про успішний апгрейд
    msg = (
        f"🎉🚀 <b>ВІТАЄМО З АПГРЕЙДОМ!</b> 🚀🎉\n"
        f"━━━━━━━━━━━━━━━━━\n\n"
        f"🏆 <b>Новий рівень саду:</b> <b>{new_level}. {new_level_info['name']}</b>\n"
        f"💰 <b>Витрачено:</b> <b>{format_currency(upgrade_price)}₴</b>\n"
        f"💸 <b>Новий баланс:</b> <b>{format_currency(balance - upgrade_price)}₴</b>\n\n"
        f"✨ <b>НОВІ МОЖЛИВОСТІ:</b>\n"
        f"├ 📈 Бонус до врожаю: <b>+{new_level_info['bonus_percent']}%</b>\n"
        f"├ 💰 Комісія знижена до: <b>{new_level_info['commission_percent']}%</b>\n"
        f"├ 🌱 Доступні нові дерева\n"
        f"└ 🎯 Підвищений статус у системі\n\n"
        f"🌟 <b>{new_level_info['description']}</b>\n\n"
        f"🚀 <i>Ваш сад тепер приносить ще більше прибутку!</i>"
    )
    
    kb = InlineKeyboardMarkup()
    kb.add(InlineKeyboardButton("🌳 Повернутися до саду", callback_data="garden_overview"))
    kb.add(InlineKeyboardButton("🛒 Купити нові дерева", callback_data="buy_tree"))
    
    try:
        bot.edit_message_text(msg, call.message.chat.id, call.message.message_id, reply_markup=kb, parse_mode="HTML")
        bot.answer_callback_query(call.id, "✅ Рівень підвищено!")
    except Exception as e:
        # Если не удалось редактировать (например, было фото), отправляем новое сообщение
        print(f"[confirm_garden_upgrade] error editing message: {e}")
        try:
            bot.send_message(call.message.chat.id, msg, reply_markup=kb, parse_mode="HTML")
            bot.answer_callback_query(call.id, "✅ Рівень підвищено!")
        except Exception as e2:
            print(f"[confirm_garden_upgrade] error sending message: {e2}")
            bot.answer_callback_query(call.id, "✅ Рівень підвищено!", show_alert=True)

@bot.callback_query_handler(func=lambda c: c.data == "income_stats")
@ban_check
@subscription_required
@phone_required
def income_stats_handler(call):
    if check_maintenance(call): return
    
    from database import get_user_garden_level, get_level_income_stats, get_garden_level_info, get_level_price
    from garden_models import GARDEN_LEVELS
    
    user_id = call.from_user.id
    current_level = get_user_garden_level(user_id)
    income_stats = get_level_income_stats(user_id, current_level)
    level_info = get_garden_level_info(current_level)
    
    # Формуємо повідомлення про статистику
    msg = (
        f"📊 <b>СТАТИСТИКА ДОХОДУ НА РІВНІ {current_level}</b>\n"
        f"━━━━━━━━━━━━━━━━━\n\n"
        f"🏆 <b>Рівень:</b> {level_info['name'] if level_info else 'Невідомий'}\n"
        f"💰 <b>Загальний дохід:</b> <b>{income_stats['total_income']:.0f}₴</b>\n"
        f"🎯 <b>Ліміт доходу:</b> <b>{income_stats['income_limit']:.0f}₴</b>\n"
        f"📈 <b>Використано:</b> <b>{income_stats['percentage']:.1f}%</b>\n"
        f"💎 <b>Залишилось:</b> <b>{income_stats['remaining']:.0f}₴</b>\n\n"
    )
    
    # Додаємо інформацію про статус
    if income_stats['is_limited']:
        msg += (
            f"⚠️ <b>СТАТУС: ЛІМІТ ДОСЯГНУТО</b>\n"
            f"• Ваш дохід зменшено до 10%\n"
            f"• Рекомендуємо підвищити рівень саду\n"
            f"• Наступний рівень дасть новий ліміт\n\n"
        )
    elif income_stats['should_warn']:
        msg += (
            f"⚠️ <b>СТАТУС: НАБЛИЖЕННЯ ДО ЛІМІТУ</b>\n"
            f"• При 100% дохід зменшиться до 10%\n"
            f"• Підвищіть рівень для продовження\n\n"
        )
    else:
        msg += (
            f"✅ <b>СТАТУС: НОРМАЛЬНИЙ</b>\n"
            f"• Ваш дохід не обмежений\n"
            f"• Можете продовжувати заробляти\n\n"
        )
    
    # Додаємо інформацію про наступні рівні
    msg += f"🚀 <b>НАСТУПНІ РІВНІ:</b>\n"
    for level in GARDEN_LEVELS:
        if level['level'] > current_level:
            dynamic_price = get_level_price(level['level'])
            next_income_limit = dynamic_price * 10  # Приблизний ліміт
            msg += f"├ Рівень {level['level']}: {level['name']}\n"
            msg += f"├ Ліміт: ~{next_income_limit:.0f}₴\n"
            msg += f"└ Ціна: {dynamic_price:.0f}₴\n\n"
            break
    
    msg += (
        f"💡 <b>ПОРАДИ:</b>\n"
        f"• Кожен рівень має свій ліміт доходу\n"
        f"• Після досягнення ліміту дохід зменшується\n"
        f"• Підвищуйте рівень для більших можливостей\n"
        f"• Інвестуйте в довгострокову перспективу\n\n"
        f"🎯 <i>Розвивайтеся стратегічно!</i>"
    )
    
    kb = InlineKeyboardMarkup()
    if current_level < len(GARDEN_LEVELS):
        kb.add(InlineKeyboardButton("🚀 Підвищити рівень", callback_data="upgrade_garden_level"))
    kb.add(InlineKeyboardButton("⬅️ Назад", callback_data="garden_overview"))
    
    bot.edit_message_text(msg, call.message.chat.id, call.message.message_id, reply_markup=kb, parse_mode="HTML")

