@bot.callback_query_handler(func=lambda c: c.data.startswith("buy_tree_confirm_"))
def buy_tree_confirm_handler(call):
    from garden_models import TREE_TYPES, get_effective_tree_income
    from database import get_tree_price, get_user, get_garden_commission
    # Перевірка вимкнених бустерів не потрібна тут
    
    user_id = call.from_user.id
    
    # Перевірка спаму
    is_spam, spam_message = check_button_spam(user_id, "buy_tree_confirm")
    if is_spam:
        bot.answer_callback_query(call.id, text=spam_message, show_alert=True)
        return
    tree_type = call.data.replace("buy_tree_confirm_", "")
    ttype = next((t for t in TREE_TYPES if t['type'] == tree_type), None)
    
    if not ttype:
        bot.answer_callback_query(call.id, text="Невідомий тип дерева.", show_alert=True)
        return
    
    user = get_user(user_id)
    if not user:
        bot.answer_callback_query(call.id, text="Користувача не знайдено.", show_alert=True)
        return
    
    balance = user[2]
    base_price = get_tree_price(tree_type) or ttype['price_uah']
    final_price = base_price
    
    # Застосовуємо знижки від бустерів
    # За потреби: тут може застосовуватися знижка від бустера
    
    commission = get_user_garden_commission(user_id)
    from database import get_economy_harvest_multiplier, get_fruit_price
    econ_mult = get_economy_harvest_multiplier()
    fruit_price = get_fruit_price(ttype['fruit']) or 0
    # Годинна дохідність у фруктах з урахуванням економіки лише якщо адмін НЕ задав власне значення
    fruits_per_hour = get_effective_tree_income(tree_type, econ_mult)
    
    # Розрахунки доходності з урахуванням реальної ціни фрукту
    hourly_profit = (fruits_per_hour * fruit_price) * (1 - commission / 100)
    daily_profit = hourly_profit * 24
    payback_days = round(final_price / daily_profit, 1) if daily_profit > 0 else "∞"
    monthly_profit = daily_profit * 30
    
    # Перевірка коштів
    if balance < final_price:
        bot.answer_callback_query(call.id, text=f"❌ Недостатньо коштів! Потрібно {format_currency(final_price)}₴, у вас {format_currency(balance)}₴", show_alert=True)
        return
    
    # Детальна інформація про покупку
    discount_text = ""
    if final_price < base_price:
        discount_text = f"\n💸 <b>Знижка:</b> <b>-{format_currency(base_price - final_price)}₴</b>"
    
    msg = (
        f"🌱 <b>ПІДТВЕРДЖЕННЯ ПОКУПКИ</b>\n"
        f"━━━━━━━━━━━━━━━━━━\n\n"
        f"{ttype['fruit_emoji']} <b>Дерево:</b> {ttype['name']}\n"
        f"💰 <b>Ціна:</b> <b>{format_currency(final_price)}₴</b>{discount_text}\n"
        f"💳 <b>Ваш баланс:</b> <b>{format_currency(balance)}₴</b>\n"
        f"💸 <b>Залишиться:</b> <b>{format_currency(balance - final_price)}₴</b>\n\n"
        f"📊 <b>ПРИБУТКОВІСТЬ:</b>\n"
        f"├ ⚡ <b>Дохід за годину:</b> {fruits_per_hour:.2f} {ttype['fruit_emoji']} = <b>{format_currency(hourly_profit)}₴</b>\n"
        f"├ 🌅 <b>Дохід за день:</b> <b>{format_currency(daily_profit)}₴</b>\n"
        f"├ 📅 <b>Окупність:</b> <b>{payback_days} днів</b>\n"
        f"└ 📈 <b>Дохід за місяць:</b> <b>{format_currency(monthly_profit)}₴</b>\n\n"
        f"💡 <b>Умови:</b>\n"
        f"• Комісія саду: <b>{commission}%</b>\n"
        f"• Збір фруктів: <b>кожну годину</b> (тільки якщо дерево полито)\n"
        f"• Після покупки: <b>спочатку полийте</b>, перший збір — не раніше ніж через 1 годину\n\n"
        f"🤔 <i>Підтверджуєте покупку?</i>"
    )
    
    kb = InlineKeyboardMarkup(row_width=2)
    kb.add(
        InlineKeyboardButton("✅ Купити", callback_data=f"buy_tree_execute_{tree_type}"),
        InlineKeyboardButton("❌ Відмінити", callback_data="buy_tree")
    )
    
    bot.edit_message_text(msg, call.message.chat.id, call.message.message_id, reply_markup=kb, parse_mode="HTML")

@bot.callback_query_handler(func=lambda c: c.data.startswith("buy_tree_execute_"))
def buy_tree_execute_handler(call):
    print(f"[buy_tree_execute] called with data: {call.data}")
    from garden_models import TREE_TYPES
    from database import add_balance, get_user_trees, _db, get_tree_price, get_user, add_garden_transaction
    # Перевірка вимкнених бустерів не потрібна тут
    import time
    
    user_id = call.from_user.id
    print(f"[buy_tree_execute] user_id: {user_id}")
    
    # Перевірка спаму
    is_spam, spam_message = check_button_spam(user_id, "buy_tree_execute")
    if is_spam:
        print(f"[buy_tree_execute] spam detected: {spam_message}")
        bot.answer_callback_query(call.id, text=spam_message, show_alert=True)
        return
    tree_type = call.data.replace("buy_tree_execute_", "")
    print(f"[buy_tree_execute] tree_type: {tree_type}")
    ttype = next((t for t in TREE_TYPES if t['type'] == tree_type), None)
    
    if not ttype:
        bot.answer_callback_query(call.id, text="Помилка: невідомий тип дерева.", show_alert=True)
        return
    
    user = get_user(user_id)
    if not user:
        bot.answer_callback_query(call.id, text="Помилка: користувача не знайдено.", show_alert=True)
        return
    
    balance = user[2]
    base_price = get_tree_price(tree_type) or ttype['price_uah']
    final_price = base_price
    
    # Застосовуємо знижки від бустерів
    # За потреби: тут може застосовуватися знижка від бустера
    
    # Повторна перевірка коштів
    if balance < final_price:
        bot.answer_callback_query(call.id, text="❌ Недостатньо коштів!", show_alert=True)
        return
    
    # Виконання покупки
    add_balance(user_id, -final_price, reason="buy_tree", details=f"{ttype['name']} ({tree_type})")
    current_time = int(time.time())
    
    with _db() as con:
        # Створюємо дерево так, щоб перший збір був не раніше ніж через 1 годину
        con.execute(
            "INSERT INTO trees (user_id, type, level, planted_at, last_harvest) VALUES (?, ?, ?, ?, ?)",
            (user_id, tree_type, 1, current_time, current_time)
        )
        # Початковий рівень води 80%, щоб вимагати полив та ріст
        try:
            con.execute(
                "INSERT OR REPLACE INTO tree_watering (user_id, tree_type, water_level, last_watered) VALUES (?, ?, ?, ?)",
                (user_id, tree_type, 80, current_time)
            )
        except Exception:
            pass
        con.commit()
    
    # Запис транзакції: в грошах
    add_garden_transaction(
        user_id,
        "buy_tree",
        float(final_price),
        "UAH",
        current_time,
        comment=f"Куплено {ttype['name']} за {format_currency(final_price)}₴"
    )
    
    # Перевіряємо завдання типу buy_tree
    from database import check_buy_tree_tasks
    check_buy_tree_tasks(user_id, tree_type)
    
    # Логируем активность в саду (если функция существует)
    try:
        from database import log_garden_activity
        log_garden_activity(
            user_id,
            "tree_buy",
            ttype['name'],
            quantity=1,
            cost=final_price,
            metadata={
                'tree_type': tree_type,
                'level': 1,
                'base_price': base_price
            }
        )
    except ImportError:
        pass  # Функция может отсутствовать
    except Exception as e:
        print(f"[buy_tree_execute] error logging activity: {e}")
    
    # Успішне повідомлення
    print(f"[buy_tree_execute] покупка выполнена, формируем сообщение...")
    new_balance = balance - final_price
    msg = (
        f"🎉 <b>ПОКУПКА УСПІШНА!</b>\n"
        f"━━━━━━━━━━━━━━━━━━\n\n"
        f"{ttype['fruit_emoji']} <b>Куплено:</b> {ttype['name']}\n"
        f"💰 <b>Витрачено:</b> <b>{format_currency(final_price)}₴</b>\n"
        f"💳 <b>Новий баланс:</b> <b>{format_currency(new_balance)}₴</b>\n\n"
        f"🌱 <b>Що далі:</b> полийте дерево, щоб воно <u>почало рости</u>.\n"
        f"⏰ <b>Перший збір</b> буде доступний не раніше ніж через 1 годину.\n"
        f"💧 Без поливу ріст зупиняється.\n\n"
        f"🚀 <i>Вітаємо з розширенням саду!</i>"
    )
    
    kb = InlineKeyboardMarkup()
    kb.add(InlineKeyboardButton("🌳 Переглянути сад", callback_data="garden_overview"))
    kb.add(InlineKeyboardButton("🛒 Купити ще", callback_data="buy_tree"))
    
    print(f"[buy_tree_execute] отправляем сообщение... chat_id={call.message.chat.id}, message_id={call.message.message_id}")
    
    # Пытаемся отредактировать сообщение или отправить новое
    try:
        # Пробуем отредактировать
        bot.edit_message_text(msg, call.message.chat.id, call.message.message_id, reply_markup=kb, parse_mode="HTML")
        print(f"[buy_tree_execute] сообщение успешно отредактировано")
        bot.answer_callback_query(call.id, "✅ Дерево куплено!")
    except Exception as e:
        # Если не удалось отредактировать (например, было фото/баннер), отправляем новое сообщение
        print(f"[buy_tree_execute] error editing message: {e}")
        import traceback
        traceback.print_exc()
        try:
            # Отправляем новое сообщение
            sent_msg = bot.send_message(call.message.chat.id, msg, reply_markup=kb, parse_mode="HTML")
            print(f"[buy_tree_execute] success: sent new message {sent_msg.message_id}")
            bot.answer_callback_query(call.id, "✅ Дерево куплено!")
        except Exception as e2:
            print(f"[buy_tree_execute] error sending message: {e2}")
            traceback.print_exc()
            # Последняя попытка - хотя бы показать alert
            try:
                bot.answer_callback_query(call.id, "✅ Дерево куплено! Перевірте сад.", show_alert=True)
            except Exception as e3:
                print(f"[buy_tree_execute] error showing alert: {e3}")
    
    # Перевірка досягнень
    total_trees = len(get_user_trees(user_id))
    from database import add_achievement_if_needed
    new_ach = add_achievement_if_needed(user_id, "trees_total", total_trees)
    if new_ach:
        try:
            bot.send_message(user_id, f"🏆 <b>Нове досягнення!</b> <code>{new_ach}</code>\n\n<em>Заберіть нагороду у профілі!</em>", parse_mode="HTML")
        except Exception:
            pass

# --- Сад ---   
@bot.callback_query_handler(func=lambda c: c.data == "harvest_fruits")
def harvest_fruits_handler(call):
    import time
    from database import get_user_trees, add_fruit, add_garden_transaction, get_user_garden_level, get_garden_level_info
    from garden_models import TREE_TYPES, FRUITS, get_dynamic_income
    # Сумісність: локальна логіка бустерів без зовнішнього модуля
    
    user_id = call.from_user.id
    # Буфер результатів збору для інтеграції з подіями
    if not hasattr(bot, 'harvest_results'):
        bot.harvest_results = {}
    
    # Перевірка спаму
    is_spam, spam_message = check_button_spam(user_id, "harvest_fruits")
    if is_spam:
        bot.answer_callback_query(call.id, text=spam_message, show_alert=True)
        return
    # Антидубль на 60 секунд
    try:
        import time
        if not hasattr(bot, '_harvest_lock_until'):
            bot._harvest_lock_until = {}
        lock_until = bot._harvest_lock_until.get(user_id, 0)
        now_ts = int(time.time())
        if now_ts < lock_until:
            bot.answer_callback_query(call.id, text="⏳ Зачекайте трохи перед наступним збором.", show_alert=True)
            return
        bot._harvest_lock_until[user_id] = now_ts + 60
    except Exception:
        pass
    # Перевірка рівня саду: з рівнем 0 збір недоступний
    garden_level = get_user_garden_level(user_id)
    if garden_level == 0:
        bot.answer_callback_query(
            call.id,
            text="🔒 Щоб збирати фрукти, спочатку відкрийте Рівень 1 у саду.",
            show_alert=True
        )
        return

    trees = get_user_trees(user_id)
    if not trees:
        bot.answer_callback_query(
            call.id,
            text="У вас немає дерев. 🌱 Придбайте дерево, щоб вирощувати фрукти!",
            show_alert=True
        )
        return
        
    # Отримуємо бонуси від рівня саду
    level_info = get_garden_level_info(garden_level)
    bonus = level_info['bonus_percent'] if level_info else 0
    
    # Перевіряємо обмеження доходу на рівні
    from database import get_income_multiplier_for_level, should_show_level_upgrade_warning, get_level_income_stats
    income_multiplier = get_income_multiplier_for_level(user_id, garden_level)
    should_warn = should_show_level_upgrade_warning(user_id, garden_level)
    income_stats = get_level_income_stats(user_id, garden_level)
    
    # Отримуємо активні бустери
    active_boosters_info = []
    
    now = int(time.time())
    total_harvest = {f['type']: 0 for f in FRUITS}
    updated = False
    total_bonus_fruits = 0
    all_applied_boosters = []
    
    event_notes = []
    
    # Групуємо дерева за типом для коректної обробки кількох дерев одного типу
    trees_by_type = {}
    for tree in trees:
        tree_type = tree['type']
        if tree_type not in trees_by_type:
            trees_by_type[tree_type] = []
        trees_by_type[tree_type].append(tree)
    
    # Обробляємо кожен тип дерев окремо
    for tree_type, type_trees in trees_by_type.items():
        ttype = next((t for t in TREE_TYPES if t['type'] == tree_type), None)
        if not ttype:
            continue
        
        # Знаходимо найстаріше дерево цього типу (найменший last_harvest)
        oldest_tree = None
        oldest_last_harvest = None
        for tree in type_trees:
            tree_last_harvest = tree['last_harvest'] or tree['planted_at'] or now
            if oldest_last_harvest is None or tree_last_harvest < oldest_last_harvest:
                oldest_last_harvest = tree_last_harvest
                oldest_tree = tree
        
        if not oldest_tree:
            continue
        
        # Перевіряємо чи найстаріше дерево готове до збору
        last_harvest = oldest_last_harvest
        hours = (now - last_harvest) // 3600
        
        # Застосовуємо бустери прискореного росту
        hours = apply_speed_growth_boosters(user_id, hours)
        
        # Перевіряємо рівень води (для типу дерев)
        from database import get_tree_watering_status
        watering_status = get_tree_watering_status(user_id, tree_type)
        water_level = watering_status.get('water_level', 100)
        is_withered = watering_status.get('is_withered', False)
        
        # Якщо дерева засохли або рівень води дуже низький, вони не ростуть
        watering_blocked = is_withered or water_level < 20
        
        # Перевіримо, чи є пошкодження від подій (storm) - перевіряємо для найстарішого дерева
        damage_pct = 0.0
        try:
            from database import get_tree_damage
            dmg = get_tree_damage(user_id, oldest_tree['id'])
            if dmg and dmg.get('damaged_until', 0) > now:
                damage_pct = float(dmg.get('damage_pct', 0.0) or 0.0)
        except Exception:
            pass

        if hours >= 1 and not watering_blocked:  # Можна збирати тільки якщо пройшло 1+ годин і дерева политі
            # АТОМАРНА ПЕРЕВІРКА: перевіряємо і оновлюємо last_harvest в одній транзакції
            # щоб уникнути багів з множинним збором
            try:
                from database import _db
                with _db() as con:
                    # Отримуємо актуальний last_harvest найстарішого дерева з бази даних
                    db_row = con.execute("SELECT last_harvest, planted_at FROM trees WHERE id=?", (oldest_tree['id'],)).fetchone()
                    if not db_row:
                        continue
                    
                    db_last_harvest = db_row[0] or db_row[1] or now
                    db_hours = (now - db_last_harvest) // 3600
                    
                    # Застосовуємо бустери прискореного росту
                    db_hours = apply_speed_growth_boosters(user_id, db_hours)
                    
                    # Перевіряємо актуальний статус поливу з бази
                    water_row = con.execute("SELECT water_level, is_withered FROM tree_watering WHERE user_id=? AND tree_type=?", (user_id, tree_type)).fetchone()
                    db_water_level = int(water_row[0]) if water_row and water_row[0] is not None else 100
                    db_is_withered = bool(water_row[1]) if water_row and water_row[1] is not None else False
                    db_watering_blocked = db_is_withered or db_water_level < 20
                    
                    # Фінальна перевірка: чи дійсно можна збирати?
                    if db_hours < 1 or db_watering_blocked:
                        # Не можна збирати - пропускаємо цей тип дерев
                        continue
                    
                    # ВСЕ ОК - виконуємо збір з ВСІХ дерев цього типу одночасно
                    # Базовий дохід з бонусом від рівня саду з урахуванням глобальної економіки
                    from database import get_economy_harvest_multiplier
                    from garden_models import get_effective_tree_income
                    econ_mult = get_economy_harvest_multiplier()
                    income_per_hour = get_effective_tree_income(ttype['type'], econ_mult)
                    effective_hours = 1  # КЕП: збираємо максимум за 1 годину
                    
                    # Розраховуємо фрукти для ОДНОГО дерева
                    base_fruits_per_tree = effective_hours * income_per_hour
                    bonus_fruits_per_tree = base_fruits_per_tree * (bonus / 100) if bonus > 0 else 0
                    fruits_per_tree = base_fruits_per_tree + bonus_fruits_per_tree
                    
                    # Застосовуємо бустери врожаю (для одного дерева)
                    final_fruits_per_tree = fruits_per_tree
                    
                    # Застосовуємо обмеження доходу на рівні
                    final_fruits_per_tree = final_fruits_per_tree * income_multiplier
                    
                    # Якщо дерева пошкоджені — зменшуємо final_fruits
                    if damage_pct > 0:
                        final_fruits_per_tree = final_fruits_per_tree * max(0.0, 1.0 - damage_pct)
                        event_notes.append("🌪️ 🌳 Дерев: <b>100 шт</b>")
                    
                    # Події: модифікації збору (буря/дощ/посуха/шкідники/турбо/золоті)
                    try:
                        final_fruits_per_tree = apply_event_harvest_modifiers(user_id, final_fruits_per_tree, ttype['type'], event_notes)
                    except Exception:
                        pass
                    
                    # Множимо на кількість дерев цього типу
                    tree_count = len(type_trees)
                    total_fruits_for_type = final_fruits_per_tree * tree_count
                    total_bonus_for_type = bonus_fruits_per_tree * tree_count
                    
                    # Атомарно: зменшуємо воду і фіксуємо last_harvest для ВСІХ дерев типу
                    current = db_water_level
                    new_level = max(0, current - 50)
                    con.execute("UPDATE tree_watering SET water_level=? WHERE user_id=? AND tree_type=?", (new_level, user_id, tree_type))
                    
                    # Оновлюємо last_harvest для ВСІХ дерев цього типу
                    tree_ids = [tree['id'] for tree in type_trees]
                    placeholders = ','.join(['?'] * len(tree_ids))
                    con.execute(f"UPDATE trees SET last_harvest=? WHERE id IN ({placeholders})", (now, *tree_ids))
                    con.commit()
                    
                    # Тільки після успішного коміту додаємо фрукти
                    total_bonus_fruits += total_bonus_for_type
                    add_fruit(user_id, ttype['fruit'], total_fruits_for_type)
                    total_harvest[ttype['fruit']] += total_fruits_for_type
                    add_garden_transaction(user_id, "harvest", total_fruits_for_type, ttype['fruit'], now, comment=f"Зібрано з {ttype['name']} (×{tree_count})")
                    
                    # Перевіряємо завдання типу harvest
                    from database import check_harvest_tasks
                    check_harvest_tasks(user_id)
                    
                    updated = True
            except Exception as e:
                print(f"[ERROR] Помилка атомарного збору для типу дерев {tree_type}: {e}")
                import traceback
                traceback.print_exc()
                continue
    if not updated:
        # Перевіряємо чи є дерева які потребують поливу (групуємо за типом)
        trees_need_watering = []
        checked_types = set()
        for tree in trees:
            tree_type = tree['type']
            if tree_type in checked_types:
                continue
            checked_types.add(tree_type)
            
            watering_status = get_tree_watering_status(user_id, tree_type)
            water_level = watering_status.get('water_level', 100)
            is_withered = watering_status.get('is_withered', False)
            
            if is_withered or water_level < 20:
                ttype = next((t for t in TREE_TYPES if t['type'] == tree_type), None)
                if ttype:
                    trees_need_watering.append(ttype['name'])
        
        if trees_need_watering:
            tree_names = ", ".join(trees_need_watering)
            bot.answer_callback_query(call.id, text=f"🌱 Дерева потребують поливу: {tree_names}\n\n💧 Політь дерева щоб вони могли рости!", show_alert=True)
            try:
                bot.harvest_results[user_id] = {'ok': False, 'reason': 'need_water'}
            except Exception:
                pass
        else:
            bot.answer_callback_query(call.id, text="Фрукти ще не виросли. Зачекайте поки пройде 1 година з останнього збору!", show_alert=True)
            try:
                bot.harvest_results[user_id] = {'ok': False, 'reason': 'not_ready'}
            except Exception:
                pass
        return
    else:
        # Якщо зібрали — пуш-повідомлення власнику при активному нагадувачі
        try:
            from database import get_active_boosters
            boosts = get_active_boosters(user_id)
            has_reminder = any(bt == 'remind_harvest' for bt, _ in boosts)
            if has_reminder:
                bot.send_message(user_id, "🔔 Збір виконано! Наступне нагадування прийде, коли знову дозріє урожай і дерева будуть политі.")
            # Автополив: якщо активний — повідомляємо залишок і автополив за потреби буде виконуватись у фоні
            has_autowater = any(bt == 'autowater' for bt, _ in boosts)
            if has_autowater:
                try:
                    # Показ залишку часу
                    import time
                    exp = next((exp for bt, exp in boosts if bt=='autowater'), None)
                    if exp:
                        remaining = max(0, int(exp - time.time()))
                        hh = remaining // 3600; mm = (remaining // 60) % 60
                        bot.send_message(user_id, f"💧 Автополив активний — залишилось {hh}г {mm}хв")
                except Exception:
                    pass
        except Exception:
            pass
        
    # Формуємо красиве повідомлення про збір (повний варіант)
    fruit_lines = []
    total_collected = 0
    for f in FRUITS:
        amount = total_harvest[f['type']]
        if amount > 0:
            total_collected += amount
            fruit_lines.append(f"├ {f['emoji']} <b>{f['name']}</b> × <b>{format_currency(amount)}</b> шт")

    if not fruit_lines:
        msg = "❌ Немає фруктів для збору."
    else:
        level_name = level_info['name'] if level_info else "Стартовий садівник"
        bonus_text = f" (+{bonus}%)" if bonus > 0 else ""

        # Формуємо інформацію про активні бустери
        active_boosters_text = ""
        if active_boosters_info:
            active_boosters_text = "\n🚀 <b>АКТИВНІ БУСТЕРИ:</b>\n"
            for booster in active_boosters_info:
                active_boosters_text += f"├ {booster['emoji']} <b>{booster['name']}</b> — {booster['hours_left']:.1f}г\n"
            active_boosters_text += "└ ────────────────────────\n"

        # Формуємо інформацію про застосовані бустери
        applied_boosters_text = ""
        if all_applied_boosters:
            applied_boosters_text = "\n⚡ <b>ЗАСТОСОВАНІ БУСТЕРИ:</b>\n"
            for booster in all_applied_boosters:
                applied_boosters_text += f"├ {booster}\n"
            applied_boosters_text += "└ ────────────────────────\n"

        # Інформація про активні події, що вплинули на збір
        events_text = ""
        if event_notes:
            events_text = "\n🎯 <b>ВПЛИВ ПОДІЙ:</b>\n" + "\n".join([f"├ {n}" for n in event_notes]) + "\n└ ────────────────────────\n"

        msg = (
            f"🎉✨ <b>ЗБІР УРОЖАЮ ЗАВЕРШЕНО!</b> ✨🎉\n"
            f"━━━━━━━━━━━━━━━━━\n\n"
            f"🏆 <b>Рівень саду:</b> <b>{garden_level}. {level_name}</b>\n"
            f"📈 <b>Бонус врожаю:</b> <b>{bonus}%{bonus_text}</b>"
            + active_boosters_text +
            f"🍎 <b>ЗІБРАНІ ФРУКТИ:</b>\n"
            + "\n".join(fruit_lines) + 
            f"\n└ 📊 <b>Загалом зібрано:</b> <b>{format_currency(total_collected)}</b> шт"
            + applied_boosters_text + events_text + "\n"
        )

        # Логируем активность в саду (если функция существует)
        try:
            from database import log_garden_activity
            for f in FRUITS:
                amount = total_harvest[f['type']]
                if amount > 0:
                    log_garden_activity(
                        user_id,
                        "harvest",
                        f['name'],
                        quantity=amount,
                        cost=0.0,
                        metadata={
                            'fruit_type': f['type'],
                            'garden_level': garden_level,
                            'bonus_percent': bonus,
                            'event_notes': event_notes
                        }
                    )
        except ImportError:
            pass  # Функция может отсутствовать
        except Exception as e:
            print(f"[harvest_fruits] error logging activity: {e}")
        
        # Фіксуємо результат для інших хендлерів (події) з деталями
        try:
            bot.harvest_results[user_id] = {
                'ok': True,
                'total': float(total_collected),
                'details': {
                    'fruits': total_harvest,
                    'event_notes': event_notes,
                }
            }
            # Оновимо просту статистику для активної простої події (якщо триває)
            try:
                now2 = _simple_now()
                active_keys = [k for k,v in (_simple_events or {}).items() if v and v.get('end',0)>now2]
                if active_keys:
                    ev = _simple_events.get(active_keys[0])
                    if ev is not None:
                        stats = ev.setdefault('harvest_stats', {})
                        stats[user_id] = float(stats.get(user_id, 0.0)) + float(total_collected)
            except Exception:
                pass
        except Exception:
            pass

        if total_bonus_fruits > 0:
            msg += f"🎁 <b>Бонусні фрукти:</b> <b>+{total_bonus_fruits:.1f}</b> шт від рівня саду!\n\n"

        # Додаємо інформацію про обмеження доходу
        income_limit_text = ""
        if income_multiplier < 1.0:
            if income_stats['is_limited']:
                income_limit_text = f"\n⚠️ <b>УВАГА!</b> Ви досягли ліміту доходу на рівні {garden_level}!\n"
                income_limit_text += f"📊 Доходність зменшена до <b>{income_multiplier*100:.0f}%</b>\n"
                income_limit_text += f"🚀 <b>Рекомендуємо підвищити рівень саду!</b>\n"
            elif should_warn:
                income_limit_text = f"\n⚠️ <b>ПОПЕРЕДЖЕННЯ!</b> Ви наближаєтесь до ліміту доходу!\n"
                income_limit_text += f"📊 Використано: <b>{income_stats['percentage']:.1f}%</b> від ліміту\n"
                income_limit_text += f"💰 Залишилось: <b>{income_stats['remaining']:.0f}₴</b>\n"
                income_limit_text += f"🚀 <b>Підвищіть рівень саду для продовження заробітку!</b>\n"

        msg += (
            f"💡 <b>ПОРАДИ:</b>\n"
            f"• Збирайте урожай кожну годину\n"
            f"• Підвищуйте рівень саду для більших бонусів\n"
            f"• Продавайте фрукти для отримання прибутку\n\n"
            f"🚀 <i>Ваш сад приносить стабільний дохід!</i>"
            + income_limit_text
        )

    kb = InlineKeyboardMarkup()
    kb.add(InlineKeyboardButton("📈 Біржа фруктів", callback_data="sell_fruits"))
    # Кнопка окремої статистики події
    kb.add(InlineKeyboardButton("📊 Статистика події", callback_data="harvest_event_stats"))

    # Додаємо кнопку статистики доходу якщо є обмеження
    if income_multiplier < 1.0 or should_warn:
        kb.add(InlineKeyboardButton("📊 Статистика доходу", callback_data="income_stats"))

    kb.add(InlineKeyboardButton("⬅️ Повернутися до саду", callback_data="garden_overview"))

    # Не змінюємо повідомлення події у чаті, якщо виклик прийшов через simple_ev_harvest
    try:
        edit_current_message = (getattr(call, 'data', '') == 'harvest_fruits')
    except Exception:
        edit_current_message = True
    if edit_current_message:
        try:
            bot.edit_message_text(msg, call.message.chat.id, call.message.message_id, reply_markup=kb, parse_mode="HTML")
            bot.answer_callback_query(call.id, "✅ Урожай зібрано!")
            # Відстежуємо це повідомлення для майбутнього очищення
            track_bot_message(call.message.chat.id, call.message.message_id)
            # Очищаємо старі повідомлення, залишаючи тільки останнє
            cleanup_old_bot_messages(call.message.chat.id, keep_last_n=1)
        except Exception as e:
            # Если не удалось отредактировать (например, было фото), отправляем новое сообщение
            print(f"[harvest_fruits] error editing message: {e}")
            try:
                sent_msg = bot.send_message(call.message.chat.id, msg, reply_markup=kb, parse_mode="HTML")
                bot.answer_callback_query(call.id, "✅ Урожай зібрано!")
                # Відстежуємо нове повідомлення
                if sent_msg:
                    track_bot_message(call.message.chat.id, sent_msg.message_id)
                # Очищаємо старі повідомлення
                cleanup_old_bot_messages(call.message.chat.id, keep_last_n=1)
            except Exception as e2:
                print(f"[harvest_fruits] error sending message: {e2}")
                bot.answer_callback_query(call.id, "✅ Урожай зібрано!", show_alert=True)
    else:
        # Надішлемо повний звіт у приват, щоб не чіпати картку події в чаті
        try:
            sent_msg = bot.send_message(user_id, msg, reply_markup=kb, parse_mode="HTML")
            bot.answer_callback_query(call.id, "✅ Урожай зібрано!")
            # Відстежуємо повідомлення в приватному чаті
            if sent_msg:
                track_bot_message(user_id, sent_msg.message_id)
            # Очищаємо старі повідомлення
            cleanup_old_bot_messages(user_id, keep_last_n=1)
        except Exception as e:
            print(f"[harvest_fruits] error sending private message: {e}")
            bot.answer_callback_query(call.id, "✅ Урожай зібрано!", show_alert=True)
    # Після збору фруктів — перевірка досягнення
    from database import get_all_fruits
    total_fruits = sum(get_all_fruits(user_id).values())
    new_ach = add_achievement_if_needed(user_id, "fruits_total", total_fruits)
    if new_ach:
        try:
            bot.send_message(user_id, f"🏆 <b>Вітаємо! Ви отримали нове досягнення:</b> <code>{new_ach}</code>\n\n<em>Заберіть свою нагороду у профілі!</em>", parse_mode="HTML")
        except Exception:
            pass

@bot.callback_query_handler(func=lambda c: c.data == "sell_fruits")
@freeze_check
def sell_fruits_menu_handler(call):
    """Обычная биржа фруктов - отдельное меню"""
    from database import get_all_fruits, get_effective_fruit_price
    from garden_models import FRUITS
    user_id = call.from_user.id
    
    # Перевірка спаму
    is_spam, spam_message = check_button_spam(user_id, "sell_fruits")
    if is_spam:
        bot.answer_callback_query(call.id, text=spam_message, show_alert=True)
        return
    
    fruits = get_all_fruits(user_id)
    kb = InlineKeyboardMarkup(row_width=2)  # 2 кнопки в рядку для лучшего отображения
    fruit_buttons = []
    has_fruits = False
    
    for f in FRUITS:
        amount = fruits.get(f['type'], 0)
        try:
            price = get_effective_fruit_price(f['type'])
        except Exception:
            price = 0
        if amount > 0:
            has_fruits = True
            fruit_buttons.append(
                InlineKeyboardButton(
                    f"{f['emoji']} {format_currency(amount)}шт | {format_currency(price)}₴",
                    callback_data=f"exchange_sell_{f['type']}"
                )
            )
    
    # Добавляем кнопки фруктов
    if fruit_buttons:
        kb.add(*fruit_buttons)
    
    # Кнопки навигации
    kb.add(InlineKeyboardButton("🔄 Оновити ціни", callback_data="sell_fruits"))
    kb.add(InlineKeyboardButton("⬅️ Назад", callback_data="garden_overview"))
    # Отображение меню биржи
    if has_fruits:
        caption = (
            "📈 <b>БІРЖА ФРУКТІВ</b> 📈\n"
            "━━━━━━━━━━━━━━━━━\n\n"
            "💰 <b>Ваші активи на біржі:</b>\n"
            "💡 <i>Натисніть на фрукт для продажу на біржі!</i>\n"
            "📊 <i>Курс валют оновлюється в реальному часі</i>"
        )
        try:
            send_banner_with_caption(call.message.chat.id, "Біржа фруктів", "📈", caption, reply_markup=kb, parse_mode="HTML", subtitle="Торгівля в реальному часі")
        except Exception:
            bot.send_message(call.message.chat.id, caption, reply_markup=kb, parse_mode="HTML")
    else:
        caption = (
                "📈 <b>БІРЖА ФРУКТІВ</b> 📈\n"
                "━━━━━━━━━━━━━━━━━\n\n"
            "😔 <b>У вас немає активів для торгівлі</b>\n"
            "🌱 <i>Зберіть урожай і повертайтеся на біржу!</i>\n"
            "💡 <i>Біржа чекає на ваші фруктові активи</i>"
        )
        try:
            send_banner_with_caption(call.message.chat.id, "Біржа фруктів", "📈", caption, reply_markup=kb, parse_mode="HTML", subtitle="Додайте фрукти, щоб торгувати")
        except Exception:
            bot.send_message(call.message.chat.id, caption, reply_markup=kb, parse_mode="HTML")

@bot.callback_query_handler(func=lambda c: c.data == "buyer_market")
@freeze_check
def buyer_market_handler(call):
    """Специальное меню скупщика с повышенными ценами"""
    user_id = call.from_user.id
    
    # Проверка активного события скупщика
    try:
        buyer_event = _get_active_event('buyer')
    except Exception:
        buyer_event = None
    
    if not buyer_event:
        return bot.answer_callback_query(call.id, "❌ Скупщик зараз недоступний", show_alert=True)
    
    # Получаем параметры события
    try:
        params = _json_loads_safe(buyer_event.get('params', '{}'))
        bonus_pct = float(params.get('bonus_price_pct', 0.15))  # +15% по умолчанию
        limit_total = float(params.get('limit', 100.0))  # Лимит на всю продажу
    except Exception:
        bonus_pct = 0.15
        limit_total = 100.0
    
    fruits = get_all_fruits(user_id)
    kb = InlineKeyboardMarkup(row_width=2)
    fruit_buttons = []
    has_fruits = False
    
    for f in FRUITS:
        amount = fruits.get(f['type'], 0)
        if amount > 0:
            has_fruits = True
            try:
                base_price = get_effective_fruit_price(f['type'])
                buyer_price = base_price * (1 + bonus_pct)  # Повышенная цена
            except Exception:
                base_price = 0
                buyer_price = 0
            
            fruit_buttons.append(
                InlineKeyboardButton(
                    f"{f['emoji']} {format_currency(amount)}шт | {format_currency(buyer_price)}₴ (+{int(bonus_pct*100)}%)",
                    callback_data=f"buyer_sell_{f['type']}"
                )
            )
    
    if fruit_buttons:
        kb.add(*fruit_buttons)
    kb.add(InlineKeyboardButton("⬅️ Назад", callback_data="sell_fruits"))
    
