@bot.callback_query_handler(func=lambda c: c.data.startswith("buyer_sell_"))
def buyer_sell_fruit_handler(call):
    """Обработка продажи фруктов скупщику"""
    from database import get_fruit_amount, get_effective_fruit_price, get_user_garden_commission, set_user_state
    import time
    
    user_id = call.from_user.id
    fruit_type = call.data.replace("buyer_sell_", "")
    
    # Проверка активного события скупщика
    try:
        buyer_event = _get_active_event('buyer')
    except Exception:
        buyer_event = None
    
    if not buyer_event:
        return bot.answer_callback_query(call.id, "❌ Скупщик вже пішов", show_alert=True)
    
    # Получаем параметры
    try:
        params = _json_loads_safe(buyer_event.get('params', '{}'))
        bonus_pct = float(params.get('bonus_price_pct', 0.15))
        limit_total = float(params.get('limit', 100.0))
    except Exception:
        bonus_pct = 0.15
        limit_total = 100.0
    
    amount_owned = get_fruit_amount(user_id, fruit_type)
    base_price = get_effective_fruit_price(fruit_type)
    buyer_price = base_price * (1 + bonus_pct)
    
    fruit = next((f for f in FRUITS if f['type'] == fruit_type), None)
    if not fruit:
        fruit = {"type": fruit_type, "name": fruit_type, "emoji": ""}
    
    if amount_owned <= 0:
        return bot.answer_callback_query(call.id, "❌ У вас немає цього фрукта", show_alert=True)
    
    # Максимум можно продать - меньшее из owned и limit
    max_sell = min(amount_owned, limit_total)
    
    # Сохраняем состояние для следующего шага
    import json
    state_data = {
        'state': 'buyer_selling',
        'data': {
            'fruit_type': fruit_type,
            'max_amount': max_sell,
            'buyer_price': buyer_price,
            'bonus_pct': bonus_pct,
            'timestamp': int(time.time())
        }
    }
    set_user_state(user_id, json.dumps(state_data))
    
    commission_pct = get_user_garden_commission(user_id)
    
    msg = (
        f"🧑‍🌾 <b>ПРОДАЖ СКУПЩИКУ</b>\n"
        f"━━━━━━━━━━━━━━━━━━━━\n\n"
        f"{fruit['emoji']} <b>{fruit['name']}</b>\n\n"
        f"📦 <b>На руках:</b> <b>{format_currency(amount_owned)}</b> шт\n"
        f"💰 <b>Ціна скупщика:</b> <b>{format_currency(buyer_price)}₴</b> за шт (+{int(bonus_pct*100)}%)\n"
        f"📊 <b>Комісія саду:</b> <b>{commission_pct}%</b>\n"
        f"📦 <b>Максимум для продажу:</b> <b>{format_currency(max_sell)}</b> шт\n\n"
        f"💡 <i>Введіть кількість для продажу (до {format_currency(max_sell)} шт):</i>"
    )
    
    kb = InlineKeyboardMarkup()
    kb.add(InlineKeyboardButton("❌ Скасувати", callback_data="buyer_market"))
    
    try:
        bot.edit_message_text(msg, call.message.chat.id, call.message.message_id, reply_markup=kb, parse_mode="HTML")
    except Exception:
        bot.send_message(call.message.chat.id, msg, reply_markup=kb, parse_mode="HTML")
    
    # Регистрируем обработчик следующего сообщения
    bot.register_next_step_handler(call.message, process_buyer_sell_amount)

def process_buyer_sell_amount(message):
    """Обработка введенного количества для продажи скупщику"""
    from database import get_user_state, clear_user_state, get_fruit_amount, get_user_garden_commission, add_balance, add_fruit
    import time
    import json
    
    user_id = message.from_user.id
    state_raw = get_user_state(user_id)
    
    # Парсим состояние из JSON
    try:
        state = json.loads(state_raw) if state_raw else {}
    except Exception:
        state = {}
    
    if not state or state.get('state') != 'buyer_selling':
        return bot.send_message(message.chat.id, "❌ Сесія продажу закінчилась")
    
    data = state.get('data', {})
    fruit_type = data.get('fruit_type')
    max_amount = float(data.get('max_amount', 0))
    buyer_price = float(data.get('buyer_price', 0))
    bonus_pct = float(data.get('bonus_pct', 0.15))
    
    # Проверка таймаута (5 минут)
    if int(time.time()) - int(data.get('timestamp', 0)) > 300:
        clear_user_state(user_id)
        return bot.send_message(message.chat.id, "❌ Час на продаж вичерпано")
    
    try:
        amount = float(str(message.text).strip().replace(',', '.'))
        if amount <= 0:
            raise ValueError("Negative")
    except Exception:
        return bot.send_message(message.chat.id, "❌ Введіть коректне число")
    
    current_amount = get_fruit_amount(user_id, fruit_type)
    if amount > current_amount:
        return bot.send_message(message.chat.id, f"❌ У вас тільки {format_currency(current_amount)} шт")
    
    if amount > max_amount:
        return bot.send_message(message.chat.id, f"❌ Скупщик купує максимум {format_currency(max_amount)} шт")
    
    # Расчет
    commission_pct = get_user_garden_commission(user_id)
    total_value = amount * buyer_price
    commission = total_value * (commission_pct / 100.0)
    net_amount = total_value - commission
    
    # Получаем информацию о фрукте
    fruit = next((f for f in FRUITS if f['type'] == fruit_type), None)
    if not fruit:
        fruit = {"type": fruit_type, "name": fruit_type, "emoji": ""}
    
    # Подтверждение
    msg = (
        f"🧑‍🌾 <b>ПІДТВЕРДЖЕННЯ ПРОДАЖУ СКУПЩИКУ</b>\n"
        f"━━━━━━━━━━━━━━━━━━━━\n\n"
        f"{fruit['emoji']} <b>[{fruit['name']}]</b>\n"
        f"📦 <b>Кількість:</b> <b>{format_currency(amount)}</b> шт\n"
        f"💰 <b>Ціна за шт:</b> <b>{format_currency(buyer_price)}₴</b> (+{int(bonus_pct*100)}%)\n"
        f"💵 <b>Сума:</b> <b>{format_currency(total_value)}₴</b>\n"
        f"📊 <b>Комісія:</b> <b>{commission_pct}%</b> → <b>{format_currency(commission)}₴</b>\n"
        f"💎 <b>До зарахування:</b> <b>{format_currency(net_amount)}₴</b>\n\n"
        f"⚡ <i>Скупщик чекає на підтвердження!</i>"
    )
    
    kb = InlineKeyboardMarkup()
    kb.add(
        InlineKeyboardButton("✅ Підтвердити", callback_data=f"buyer_confirm_{fruit_type}_{amount}"),
        InlineKeyboardButton("❌ Скасувати", callback_data="buyer_market")
    )
    
    bot.send_message(message.chat.id, msg, reply_markup=kb, parse_mode="HTML")

@bot.callback_query_handler(func=lambda c: c.data.startswith("buyer_confirm_"))
def buyer_confirm_sell_handler(call):
    """Подтверждение продажи скупщику"""
    from database import get_fruit_amount, get_user_garden_commission, add_balance, add_fruit, clear_user_state
    
    user_id = call.from_user.id
    parts = call.data.replace("buyer_confirm_", "").split("_")
    fruit_type = "_".join(parts[:-1])
    amount = float(parts[-1])
    
    # Проверка события
    try:
        buyer_event = _get_active_event('buyer')
    except Exception:
        buyer_event = None
    
    if not buyer_event:
        clear_user_state(user_id)
        return bot.answer_callback_query(call.id, "❌ Скупщик вже пішов", show_alert=True)
    
    # Параметры
    try:
        params = _json_loads_safe(buyer_event.get('params', '{}'))
        bonus_pct = float(params.get('bonus_price_pct', 0.15))
    except Exception:
        bonus_pct = 0.15
    
    current_amount = get_fruit_amount(user_id, fruit_type)
    if amount > current_amount:
        clear_user_state(user_id)
        return bot.answer_callback_query(call.id, "❌ Недостатньо фруктів", show_alert=True)
    
    base_price = get_effective_fruit_price(fruit_type)
    buyer_price = base_price * (1 + bonus_pct)
    commission_pct = get_user_garden_commission(user_id)
    total_value = amount * buyer_price
    commission = total_value * (commission_pct / 100.0)
    net_amount = total_value - commission
    
    # Выполняем продажу
    add_fruit(user_id, fruit_type, -amount)
    add_balance(user_id, net_amount)
    
    # Записуємо транзакцію продажу
    import time
    add_garden_transaction(user_id, "sale", net_amount, "UAH", int(time.time()), 
                          comment=f"Продано {amount} {fruit_type} скупщику")
    
    # Перевіряємо завдання типу sell_fruits
    from database import check_sell_fruits_tasks
    check_sell_fruits_tasks(user_id, net_amount)
    
    clear_user_state(user_id)
    
    fruit = next((f for f in FRUITS if f['type'] == fruit_type), None)
    if not fruit:
        fruit = {"type": fruit_type, "name": fruit_type, "emoji": ""}
    
    success_msg = (
        f"✅ <b>ПРОДАЖ УСПІШНИЙ!</b>\n"
        f"━━━━━━━━━━━━━━━━━━━━\n\n"
        f"{fruit['emoji']} <b>Продано скупщику:</b> <b>{format_currency(amount)}</b> шт <b>{fruit['name']}</b>\n"
        f"💰 <b>Отримано:</b> <b>{format_currency(net_amount)}₴</b>\n\n"
        f"🎉 <i>Дякуємо за співпрацю!</i>"
    )
    
    try:
        bot.edit_message_text(success_msg, call.message.chat.id, call.message.message_id, parse_mode="HTML")
    except Exception:
        bot.send_message(call.message.chat.id, success_msg, parse_mode="HTML")
    
    bot.answer_callback_query(call.id, f"✅ Продано {format_currency(amount)} шт за {format_currency(net_amount)}₴")

@bot.callback_query_handler(func=lambda c: c.data == "harvest_event_stats")
def harvest_event_stats_handler(call):
    user_id = call.from_user.id
    try:
        res = getattr(bot, 'harvest_results', {}).get(user_id)
    except Exception:
        res = None
    if not res or not res.get('ok'):
        return bot.answer_callback_query(call.id, "Нема детальної статистики для останнього збору.", show_alert=True)
    details = res.get('details', {})
    fruits = details.get('fruits', {})
    notes = details.get('event_notes', [])
    lines = ["📊 Детальна статистика збору:"]
    total = 0
    for ft, amt in fruits.items():
        lines.append(f"• {ft}: {format_currency(amt)} шт")
        total += float(amt or 0)
    lines.append(f"\n🔢 Загалом: {format_currency(total)} шт")
    if notes:
        lines.append("\n🎯 Вплив подій:")
        for n in notes:
            lines.append(f"• {n}")
    bot.answer_callback_query(call.id, "\n".join(lines), show_alert=True)

