        f"━━━━━━━━━━━━━━━━━━━━\n\n"
        f"{fruit['emoji']} <b>Продано на біржі:</b> <b>{format_currency(amount)}</b> шт <b>{fruit['name']}</b>\n"
        f"💰 <b>Отримано:</b> <b>{format_currency(net_amount)}₴</b>\n\n"
