@bot.callback_query_handler(func=lambda c: c.data == "admin_user_tx_prompt")
def admin_user_tx_prompt(call):
    if not is_admin(call.from_user.id):
        return bot.answer_callback_query(call.id, "Нема доступу", show_alert=True)
    try:
        from telebot.types import InlineKeyboardMarkup, InlineKeyboardButton
        kb = InlineKeyboardMarkup().add(InlineKeyboardButton("⬅️ Назад", callback_data="panel"))
    except Exception:
        kb = None
    edit_or_send(call,
        "🔎 Введіть <b>ID</b> або <b>@username</b> користувача для перегляду транзакцій:",
        reply_markup=kb,
        parse_mode="HTML"
    )
    bot.register_next_step_handler(call.message, admin_user_tx_prompt_fetch)

def admin_user_tx_prompt_fetch(message):
    try:
        raw = (message.text or "").strip()
        user_id = None
        if raw.startswith("@"):
            try:
                from database import get_user_id_by_username
                uid = get_user_id_by_username(raw)
                if uid:
                    user_id = int(uid)
            except Exception:
                user_id = None
        if user_id is None:
            try:
                user_id = int(raw)
            except Exception:
                user_id = None
        if not user_id:
            from telebot.types import InlineKeyboardMarkup, InlineKeyboardButton
            kb = InlineKeyboardMarkup().add(InlineKeyboardButton("⬅️ Назад", callback_data="panel"))
            return bot.send_message(message.chat.id, "❌ Невірний ввід. Вкажіть ID або @username.", reply_markup=kb)

        from telebot.types import InlineKeyboardMarkup, InlineKeyboardButton
        kb = InlineKeyboardMarkup()
        kb.add(InlineKeyboardButton("📒 Відкрити транзакції", callback_data=f"admin_user_tx:{user_id}"))
        kb.add(InlineKeyboardButton("⬅️ Назад", callback_data="panel"))
        bot.send_message(
            message.chat.id,
            f"Обраний користувач: <code>{user_id}</code>. Натисніть, щоб відкрити транзакції.",
            reply_markup=kb,
            parse_mode="HTML"
        )
    except Exception as e:
        try:
            bot.send_message(message.chat.id, f"❌ Помилка: {e}")
        except Exception:
            pass

