@bot.callback_query_handler(func=lambda c: c.data == "admin_buttons_management")
def admin_buttons_management_handler(call):
    """Главное меню управления кнопками"""
    if not is_admin(call.from_user.id):
        return bot.answer_callback_query(call.id, "Нема доступу", show_alert=True)
    
    safe_answer_callback_query(call)
    
    buttons = get_all_disabled_buttons()
    button_status = {b['button_id']: b['is_disabled'] for b in buttons}
    
    kb = InlineKeyboardMarkup(row_width=1)
    
    # Показываем список всех доступных кнопок
    for button_id, button_name in AVAILABLE_BUTTONS.items():
        is_disabled = button_status.get(button_id, False)
        status_icon = "🔴" if is_disabled else "🟢"
        kb.add(InlineKeyboardButton(
            f"{status_icon} {button_name}",
            callback_data=f"admin_button_toggle:{button_id}"
        ))
    
    kb.add(InlineKeyboardButton("➕ Додати нову кнопку", callback_data="admin_button_add"))
    kb.add(InlineKeyboardButton("⬅️ Назад", callback_data="panel"))
    
    msg = (
        "🔒 <b>Управління доступністю кнопок</b>\n\n"
        "🟢 - Кнопка активна\n"
        "🔴 - Кнопка відключена\n\n"
        "Натисніть на кнопку, щоб змінити її статус."
    )
    
    try:
        bot.edit_message_text(msg, call.message.chat.id, call.message.message_id, reply_markup=kb, parse_mode="HTML")
    except Exception:
        bot.send_message(call.message.chat.id, msg, reply_markup=kb, parse_mode="HTML")

@bot.callback_query_handler(func=lambda c: c.data.startswith("admin_button_toggle:"))
def admin_button_toggle_handler(call):
    """Переключение статуса кнопки"""
    if not is_admin(call.from_user.id):
        return bot.answer_callback_query(call.id, "Нема доступу", show_alert=True)
    
    try:
        button_id = call.data.split(":")[1]
    except (ValueError, IndexError):
        return bot.answer_callback_query(call.id, "❌ Помилка", show_alert=True)
    
    safe_answer_callback_query(call)
    
    button_name = AVAILABLE_BUTTONS.get(button_id, button_id)
    button_info = get_button_info(button_id)
    is_currently_disabled = button_info['is_disabled'] if button_info else False
    
    # Переключаем статус
    new_status = not is_currently_disabled
    set_button_disabled(button_id, button_name, is_disabled=new_status)
    
    status_text = "відключено" if new_status else "увімкнено"
    bot.answer_callback_query(call.id, f"✅ Кнопка {status_text}", show_alert=True)
    
    # Возвращаемся в меню управления
    call.data = "admin_buttons_management"
    admin_buttons_management_handler(call)

@bot.callback_query_handler(func=lambda c: c.data == "admin_button_add")
def admin_button_add_handler(call):
    """Добавление новой кнопки для управления"""
    if not is_admin(call.from_user.id):
        return bot.answer_callback_query(call.id, "Нема доступу", show_alert=True)
    
    safe_answer_callback_query(call)
    
    kb = InlineKeyboardMarkup(row_width=1)
    kb.add(InlineKeyboardButton("⬅️ Назад", callback_data="admin_buttons_management"))
    
    msg = (
        "➕ <b>Додати нову кнопку</b>\n\n"
        "Введіть ID кнопки (callback_data) та її назву через двокрапку:\n\n"
        "Приклад:\n"
        "<code>my_button:Назва кнопки</code>\n\n"
        "Або введіть тільки ID кнопки, якщо вона вже існує в системі."
    )
    
    try:
        bot.edit_message_text(msg, call.message.chat.id, call.message.message_id, reply_markup=kb, parse_mode="HTML")
    except Exception:
        bot.send_message(call.message.chat.id, msg, reply_markup=kb, parse_mode="HTML")
    
    bot.register_next_step_handler(call.message, admin_button_add_process)

def admin_button_add_process(message):
    """Обработка добавления новой кнопки"""
    if not is_admin(message.from_user.id):
        return
    
    try:
        text = message.text.strip()
        
        if ":" in text:
            button_id, button_name = text.split(":", 1)
            button_id = button_id.strip()
            button_name = button_name.strip()
        else:
            button_id = text.strip()
            button_name = button_id
        
        # Добавляем кнопку как отключенную по умолчанию
        set_button_disabled(button_id, button_name, is_disabled=True)
        
        kb = InlineKeyboardMarkup(row_width=1)
        kb.add(InlineKeyboardButton("⬅️ Назад", callback_data="admin_buttons_management"))
        
        bot.send_message(
            message.chat.id,
            f"✅ Кнопка <b>{button_name}</b> (ID: <code>{button_id}</code>) додана та відключена.\n\n"
            "Тепер ви можете керувати її статусом з меню управління кнопками.",
            reply_markup=kb,
            parse_mode="HTML"
        )
    except Exception as e:
        kb = InlineKeyboardMarkup(row_width=1)
        kb.add(InlineKeyboardButton("⬅️ Назад", callback_data="admin_buttons_management"))
        bot.send_message(
            message.chat.id,
            f"❌ Помилка при додаванні кнопки: {e}",
            reply_markup=kb
        )

@bot.callback_query_handler(func=lambda c: c.data.startswith("admin_button_edit:"))
def admin_button_edit_handler(call):
    """Редактирование сообщения для отключенной кнопки"""
    if not is_admin(call.from_user.id):
        return bot.answer_callback_query(call.id, "Нема доступу", show_alert=True)
    
    try:
        button_id = call.data.split(":")[1]
    except (ValueError, IndexError):
        return bot.answer_callback_query(call.id, "❌ Помилка", show_alert=True)
    
    safe_answer_callback_query(call)
    
    button_info = get_button_info(button_id)
    if not button_info:
        return bot.answer_callback_query(call.id, "❌ Кнопка не знайдена", show_alert=True)
    
    kb = InlineKeyboardMarkup(row_width=1)
    kb.add(InlineKeyboardButton("⬅️ Назад", callback_data="admin_buttons_management"))
    
    msg = (
        f"✏️ <b>Редагування повідомлення</b>\n\n"
        f"Кнопка: <b>{button_info['button_name']}</b>\n"
        f"ID: <code>{button_id}</code>\n\n"
        f"Поточне повідомлення:\n"
        f"<i>{button_info['message']}</i>\n\n"
        f"Введіть нове повідомлення для цієї кнопки:"
    )
    
    try:
        bot.edit_message_text(msg, call.message.chat.id, call.message.message_id, reply_markup=kb, parse_mode="HTML")
    except Exception:
        bot.send_message(call.message.chat.id, msg, reply_markup=kb, parse_mode="HTML")
    
    # Сохраняем button_id в состоянии пользователя для следующего шага
    set_user_state(call.from_user.id, f"admin_button_edit_msg:{button_id}")
    bot.register_next_step_handler(call.message, admin_button_edit_message_process)

def admin_button_edit_message_process(message):
    """Обработка редактирования сообщения"""
    if not is_admin(message.from_user.id):
        return
    
    try:
        user_state = get_user_state(message.from_user.id)
        if not user_state or not user_state.startswith("admin_button_edit_msg:"):
            return
        
        button_id = user_state.split(":")[1]
        new_message = message.text.strip()
        
        button_info = get_button_info(button_id)
        if button_info:
            button_name = button_info['button_name']
            set_button_disabled(button_id, button_name, message=new_message, is_disabled=True)
            
            kb = InlineKeyboardMarkup(row_width=1)
            kb.add(InlineKeyboardButton("⬅️ Назад", callback_data="admin_buttons_management"))
            
            bot.send_message(
                message.chat.id,
                f"✅ Повідомлення для кнопки <b>{button_name}</b> оновлено!",
                reply_markup=kb,
                parse_mode="HTML"
            )
        
        clear_user_state(message.from_user.id)
    except Exception as e:
        kb = InlineKeyboardMarkup(row_width=1)
        kb.add(InlineKeyboardButton("⬅️ Назад", callback_data="admin_buttons_management"))
        bot.send_message(
            message.chat.id,
            f"❌ Помилка: {e}",
            reply_markup=kb
        )

@bot.callback_query_handler(func=lambda c: c.data == "events_menu")
def events_menu_handler(call):
    if not is_admin(call.from_user.id):
        return bot.answer_callback_query(call.id, "Нема доступу", show_alert=True)
    from telebot.types import InlineKeyboardMarkup, InlineKeyboardButton
    # Коротка статистика
    try:
        from database import get_active_events
        rows = get_active_events() or []
        import time
        now = int(time.time())
        active = [r for r in rows if (r[5] or '') == 'active' and (r[4] or 0) > now]
        scheduled = [r for r in rows if (r[5] or '') == 'scheduled' and (r[4] or 0) > now]
        next_end_secs = min([(r[4] or 0) - now for r in active], default=None)
        next_end_mins = (next_end_secs // 60) if (isinstance(next_end_secs, int) and next_end_secs >= 0) else None
        stats_line = f"👁️ Активних: <b>{len(active)}</b> • 🗓 Заплановано: <b>{len(scheduled)}</b>" + (f" • ⏳ Найближче: <b>{next_end_mins} хв</b>" if next_end_mins is not None else "")
    except Exception:
        stats_line = "👁️ Активних: <b>—</b> • 🗓 Заплановано: <b>—</b>"
    kb = InlineKeyboardMarkup(row_width=3)
    kb.add(
        InlineKeyboardButton("🟢 Запустити подію", callback_data="event_start_menu"),
        InlineKeyboardButton("📜 Активні", callback_data="event_list"),
        InlineKeyboardButton("⚙️ Авто-події", callback_data="event_auto"),
    )
    # Спрощені події (надійні, без БД)
    kb.add(InlineKeyboardButton("🟢 Простий: Буря (15 хв)", callback_data="simple_event_start:storm"))
    kb.add(InlineKeyboardButton("🟢 Простий: Посуха (15 хв)", callback_data="simple_event_start:drought"))
    kb.add(InlineKeyboardButton("🟢 Простий: Шкідники (15 хв)", callback_data="simple_event_start:pests"))
    kb.add(InlineKeyboardButton("🟢 Простий: Турбо (15 хв)", callback_data="simple_event_start:rush"))
    kb.add(InlineKeyboardButton("🟢 Простий: Золоте (15 хв)", callback_data="simple_event_start:golden"))
    kb.add(InlineKeyboardButton("🟢 Простий: Скупщик (15 хв)", callback_data="simple_event_start:buyer"))
    kb.add(InlineKeyboardButton("🟢 Простий: Ринок (15 хв)", callback_data="simple_event_start:market"))
    kb.add(InlineKeyboardButton("⬅️ Назад", callback_data="panel"))
    edit_or_send(call, f"🎉 <b>УПРАВЛІННЯ ПОДІЯМИ</b>\n{stats_line}\n\nОберіть дію:", reply_markup=kb, parse_mode="HTML")

