@bot.callback_query_handler(func=lambda c: c.data and c.data.startswith("giveaway_game_type:"))
def create_giveaway_game_type_handler(call):
    from database import is_admin, is_giveaway_manager
    if not is_admin(call.from_user.id) and not is_giveaway_manager(call.from_user.id):
        return bot.answer_callback_query(call.id, "Нема доступу", show_alert=True)
    
    import json
    game_type = call.data.split(":")[1]
    game_name = "🎰 Слот-машина 777" if game_type == "777" else "🃏 Блекджек 21"
    
    # Зберігаємо вибір типу гри
    from database import set_user_state, get_user_state
    state = get_user_state(call.from_user.id) or "{}"
    if isinstance(state, str):
        try:
            state = json.loads(state) if state and state != "{}" else {}
        except:
            state = {}
    if not isinstance(state, dict):
        state = {}
    state['giveaway_game_type'] = game_type
    set_user_state(call.from_user.id, json.dumps(state))
    
    from telebot.types import InlineKeyboardMarkup, InlineKeyboardButton
    kb = InlineKeyboardMarkup()
    kb.add(InlineKeyboardButton("❌ Скасувати", callback_data="giveaway_cancel"))
    
    bot.answer_callback_query(call.id, f"✅ Обрано: {game_name}")
    
    msg = bot.send_message(
        call.message.chat.id,
        f"🎁 <b>СТВОРЕННЯ РОЗІГРАШУ</b>\n\n"
        f"🎮 <b>Тип гри:</b> {game_name}\n\n"
        f"📝 <b>Крок 1/5:</b> Введіть назву розіграшу\n\n"
        "Приклад: <i>Новорічний розіграш 1000₴</i>",
        reply_markup=kb,
        parse_mode="HTML"
    )
    bot.register_next_step_handler(msg, create_giveaway_step1_title)

