def create_giveaway_step1_title(message):
    """Крок 1: Назва розіграшу"""
    from telebot.types import InlineKeyboardMarkup, InlineKeyboardButton
    from database import is_admin, is_giveaway_manager
    
    if not is_admin(message.from_user.id) and not is_giveaway_manager(message.from_user.id):
        return
    
    # Проверяем, не является ли это отменой
    if message.text and message.text.strip().lower() in ['скасувати', 'cancel', '❌']:
        from database import set_user_state
        set_user_state(message.from_user.id, "{}")
        bot.send_message(message.chat.id, "❌ Створення розіграшу скасовано")
        return
    
    title = message.text.strip()
    if not title or len(title) < 3:
        kb = InlineKeyboardMarkup()
        kb.add(InlineKeyboardButton("❌ Скасувати", callback_data="giveaway_cancel"))
        bot.send_message(message.chat.id, "❌ Назва занадто коротка. Мінімум 3 символи.", reply_markup=kb)
        bot.register_next_step_handler(message, create_giveaway_step1_title)
        return
    
    # Сохраняем в состоянии (зберігаємо попередній стан, включаючи game_type)
    from database import get_user_state, set_user_state
    import json
    state = get_user_state(message.from_user.id) or "{}"
    try:
        state_data = json.loads(state) if state and state != "{}" else {}
    except:
        state_data = {}
    if not isinstance(state_data, dict):
        state_data = {}
    # Зберігаємо game_type якщо він є в стані, інакше за замовчуванням
    if 'giveaway_game_type' not in state_data:
        state_data['giveaway_game_type'] = '777'  # За замовчуванням
    state_data['giveaway_title'] = title
    state_data['step'] = 2
    set_user_state(message.from_user.id, json.dumps(state_data))
    print(f"[DEBUG] create_giveaway_step1_title: збережено game_type={state_data.get('giveaway_game_type')}")
    
    kb = InlineKeyboardMarkup()
    kb.add(InlineKeyboardButton("❌ Скасувати", callback_data="giveaway_cancel"))
    
    bot.send_message(
        message.chat.id,
        "🎁 <b>СТВОРЕННЯ РОЗІГРАШУ</b>\n\n"
        f"✅ Назва: <b>{title}</b>\n\n"
        "📝 <b>Крок 2/5:</b> Оберіть тип призу\n\n"
        "1️⃣ 💰 Гроші\n"
        "2️⃣ 🌳 Дерево\n"
        "3️⃣ ⚡ Бустер\n"
        "4️⃣ 🏆 Досягнення\n"
        "5️⃣ 🍎 Фрукти\n\n"
        "Введіть номер (1-5):",
        reply_markup=kb,
        parse_mode="HTML"
    )
    bot.register_next_step_handler(message, create_giveaway_step2_prize_type)

