def giveaway_delete_handler(call):
    """Видаляє/скасовує розіграш"""
    from database import is_giveaway_manager
    if not is_giveaway_manager(call.from_user.id):
        return bot.answer_callback_query(call.id, "Нема доступу", show_alert=True)
    
    try:
        giveaway_id = int(call.data.split(":")[1])
    except (ValueError, IndexError):
        return bot.answer_callback_query(call.id, "❌ Помилка", show_alert=True)
    
    from database import get_giveaway, cancel_giveaway
    from giveaway_monitoring import stop_giveaway_monitoring
    
    try:
        giveaway = get_giveaway(giveaway_id)
        if not giveaway:
            return bot.answer_callback_query(call.id, "❌ Розіграш не знайдено", show_alert=True)
        
        if giveaway['status'] == 'completed':
            return bot.answer_callback_query(call.id, "❌ Не можна видалити завершений розіграш", show_alert=True)
        
        # Скасовуємо розіграш
        cancel_giveaway(giveaway_id)
        
        # Зупиняємо моніторинг
        try:
            stop_giveaway_monitoring(giveaway_id)
        except Exception as e:
            print(f"[WARNING] Не вдалося зупинити моніторинг: {e}")
        
        # Якщо розіграш був активним і мав пост в каналі, можна спробувати видалити пост
        if giveaway.get('channel_id') and giveaway.get('post_message_id'):
            try:
                bot.delete_message(
                    chat_id=giveaway['channel_id'],
                    message_id=giveaway['post_message_id']
                )
            except Exception as e:
                print(f"[WARNING] Не вдалося видалити пост з каналу: {e}")
        
        bot.answer_callback_query(call.id, "✅ Розіграш скасовано та видалено")
        
        # Оновлюємо список
        giveaways_active_handler(call)
        
    except Exception as e:
        import traceback
        traceback.print_exc()
        bot.answer_callback_query(call.id, f"❌ Помилка: {str(e)}", show_alert=True)

