def giveaway_winner_manual_input_handler(message):
    """Обработка ввода победителя вручную"""
    from database import is_giveaway_manager
    if not is_giveaway_manager(message.from_user.id):
        return
    
    from database import get_user_state, set_user_state, get_giveaway
    from giveaway_monitoring import _complete_giveaway
    import json
    
    try:
        state = get_user_state(message.from_user.id)
        if not state or state == "{}":
            return
        
        state_data = json.loads(state)
        if state_data.get('action') != 'giveaway_winner_manual':
            return
        
        giveaway_id = state_data.get('giveaway_id')
        giveaway = get_giveaway(giveaway_id)
        if not giveaway:
            bot.reply_to(message, "❌ Розіграш не знайдено")
            set_user_state(message.from_user.id, "{}")
            return
        
        if giveaway['status'] != 'active':
            bot.reply_to(message, "❌ Розіграш вже завершено")
            set_user_state(message.from_user.id, "{}")
            return
        
        # Парсим ввод пользователя
        text = message.text.strip()
        winners_count = giveaway.get('winners_count', 1)
        
        # Разделяем по запятой
        winner_strings = [w.strip() for w in text.split(',') if w.strip()]
        
        if len(winner_strings) == 0:
            bot.reply_to(message, "❌ Не вказано жодного переможця")
            return
        
        if winners_count > 1 and len(winner_strings) != winners_count:
            bot.reply_to(message, f"❌ Потрібно вказати рівно {winners_count} переможців, а вказано {len(winner_strings)}")
            return
        
        # Парсим каждого победителя
        winner_ids = []
        errors = []
        
        for i, winner_str in enumerate(winner_strings, 1):
            winner_id = None
            
            if winner_str.startswith('@'):
                # Это username
                username = winner_str[1:].strip()
                if not username:
                    errors.append(f"Переможець {i}: невірний формат username")
                    continue
                
                # Сначала пробуем найти в базе данных
                from database import get_user_id_by_username
                winner_id = get_user_id_by_username(username)
                
                # Если не нашли в базе, пробуем через Telegram API
                if not winner_id:
                    try:
                        chat = bot.get_chat(f"@{username}")
                        if chat and chat.id:
                            winner_id = chat.id
                    except Exception as e:
                        print(f"[DEBUG] Не удалось найти пользователя @{username} через Telegram API: {e}")
                
                if not winner_id:
                    errors.append(f"Переможець {i}: не вдалося знайти користувача @{username}")
                    continue
            else:
                # Пробуем извлечь число (user_id)
                try:
                    winner_id = int(winner_str)
                except ValueError:
                    errors.append(f"Переможець {i}: невірний формат ({winner_str})")
                    continue
            
            if winner_id:
                winner_ids.append(winner_id)
        
        if errors:
            error_msg = "❌ Помилки:\n" + "\n".join(errors)
            bot.reply_to(message, error_msg)
            return
        
        if not winner_ids:
            bot.reply_to(message, "❌ Не вдалося визначити жодного переможця")
            return
        
        # Завершаем розыгрыш с победителями
        _complete_giveaway(giveaway_id, winner_ids, bot)
        
        # Отримуємо інформацію про переможців та розіграш
        from utils import get_user_name
        from database import get_giveaway
        giveaway_info = get_giveaway(giveaway_id)
        giveaway_title = giveaway_info.get('title', 'Розіграш') if giveaway_info else 'Розіграш'
        
        # Формуємо красиве повідомлення
        winners_list = []
        for i, winner_id in enumerate(winner_ids, 1):
            winner_name = get_user_name(winner_id)
            winners_list.append(f"{i}. {winner_name} (<code>{winner_id}</code>)")
        
        if len(winner_ids) == 1:
            success_msg = (
                f"✅ <b>РОЗІГРАШ ЗАВЕРШЕНО!</b>\n\n"
                f"📌 <b>Розіграш:</b> {giveaway_title}\n"
                f"🏆 <b>Переможець:</b> {winners_list[0]}"
            )
        else:
            success_msg = (
                f"✅ <b>РОЗІГРАШ ЗАВЕРШЕНО!</b>\n\n"
                f"📌 <b>Розіграш:</b> {giveaway_title}\n"
                f"🏆 <b>Переможці ({len(winner_ids)}):</b>\n" + "\n".join(winners_list)
            )
        bot.reply_to(message, success_msg, parse_mode="HTML")
        
        # Очищаем состояние
        set_user_state(message.from_user.id, "{}")
        
    except Exception as e:
        import traceback
        traceback.print_exc()
        bot.reply_to(message, f"❌ Помилка: {str(e)}")
        try:
            set_user_state(message.from_user.id, "{}")
        except:
            pass

