def _is_json_state_message(message):
    """Перевіряє чи повідомлення має JSON стан"""
    try:
        state = get_user_state(message.from_user.id)
        return state and state.strip().startswith(('{', '['))
    except:
        return False

@bot.message_handler(func=_is_json_state_message)
def update_reactions_manual_handler(message):
    """Обработчик ручного ввода количества реакций"""
    from database import get_user_state, set_user_state, get_giveaway, update_giveaway_status, get_active_giveaways
    import json
    
    try:
        state = get_user_state(message.from_user.id)
        if not state:
            return  # Не наш обработчик
        
        # Перевірка чи state є JSON (може бути простою строкою типу 'waiting_grant_role:...')
        try:
            state_data = json.loads(state)
        except (json.JSONDecodeError, ValueError):
            # Якщо state не JSON, то це не наш обработчик
            return
        
        action = state_data.get('action')
        
        # Обработка пакетного обновления
        if action == 'update_reactions_batch':
            giveaway_ids = state_data.get('giveaway_ids', [])
            current_index = state_data.get('current_index', 0)
            updated = state_data.get('updated', 0)
            failed = state_data.get('failed', 0)
            
            if current_index >= len(giveaway_ids):
                # Все розыгрыши обновлены
                set_user_state(message.from_user.id, "{}")
                bot.send_message(
                    message.chat.id,
                    f"✅ <b>ОБНОВЛЕНИЕ ЗАВЕРШЕНО</b>\n\n"
                    f"✅ Обновлено: {updated}\n"
                    f"⚠️ Не удалось: {failed}",
                    parse_mode="HTML"
                )
                return
            
            # Проверяем отмену
            if message.text and message.text.strip().lower() in ['скасувати', 'cancel', '❌', 'отмена']:
                set_user_state(message.from_user.id, "{}")
                bot.send_message(message.chat.id, "❌ Пакетное обновление отменено")
                return
            
            try:
                reactions_count = int(message.text.strip())
                if reactions_count < 0:
                    raise ValueError
            except ValueError:
                bot.send_message(message.chat.id, "❌ Введіть коректне число (0 або більше) або 'скасувати' для отмены")
                return
            
            giveaway_id = giveaway_ids[current_index]
            giveaway = get_giveaway(giveaway_id)
            
            if not giveaway:
                failed += 1
                current_index += 1
                state_data['current_index'] = current_index
                state_data['failed'] = failed
                set_user_state(message.from_user.id, json.dumps(state_data))
                
                if current_index < len(giveaway_ids):
                    next_giveaway = get_giveaway(giveaway_ids[current_index])
                    bot.send_message(
                        message.chat.id,
                        f"❌ Розыгрыш #{giveaway_id} не найден\n\n"
                        f"📌 <b>Розыгрыш {current_index + 1}/{len(giveaway_ids)}:</b> #{next_giveaway['id']}\n"
                        f"🎁 {next_giveaway['title']}\n\n"
                        f"Введите количество реакций:",
                        parse_mode="HTML"
                    )
                return
            
            # Обновляем счетчик
            try:
                _update_single_giveaway_reactions(giveaway_id, reactions_count, bot)
                updated += 1
            except Exception as e:
                print(f"[ERROR] Ошибка обновления розыгрыша #{giveaway_id}: {e}")
                failed += 1
            
            current_index += 1
            state_data['current_index'] = current_index
            state_data['updated'] = updated
            state_data['failed'] = failed
            set_user_state(message.from_user.id, json.dumps(state_data))
            
            # Переходим к следующему розыгрышу
            if current_index < len(giveaway_ids):
                next_giveaway = get_giveaway(giveaway_ids[current_index])
                bot.send_message(
                    message.chat.id,
                    f"✅ Розыгрыш #{giveaway_id} обновлен ({reactions_count} реакций)\n\n"
                    f"📌 <b>Розыгрыш {current_index + 1}/{len(giveaway_ids)}:</b> #{next_giveaway['id']}\n"
                    f"🎁 {next_giveaway['title']}\n\n"
                    f"Введите количество реакций:",
                    parse_mode="HTML"
                )
            else:
                # Все обновлено
                set_user_state(message.from_user.id, "{}")
                bot.send_message(
                    message.chat.id,
                    f"✅ <b>ОБНОВЛЕНИЕ ЗАВЕРШЕНО</b>\n\n"
                    f"✅ Обновлено: {updated}\n"
                    f"⚠️ Не удалось: {failed}",
                    parse_mode="HTML"
                )
            return
        
        # Обработка одиночного обновления
        if action != 'update_reactions':
            return  # Не наш обработчик
        
        giveaway_id = state_data.get('giveaway_id')
        if not giveaway_id:
            set_user_state(message.from_user.id, "{}")
            return
        
        try:
            reactions_count = int(message.text.strip())
            if reactions_count < 0:
                raise ValueError
        except ValueError:
            bot.send_message(message.chat.id, "❌ Введіть коректне число (0 або більше)")
            return
        
        giveaway = get_giveaway(giveaway_id)
        if not giveaway:
            bot.send_message(message.chat.id, "❌ Розыгрыш не знайдено")
            set_user_state(message.from_user.id, "{}")
            return
        
        # Обновляем счетчик
        try:
            _update_single_giveaway_reactions(giveaway_id, reactions_count, bot)
            bot.send_message(message.chat.id, f"✅ Розыгрыш #{giveaway_id} обновлен! Реакций: {reactions_count}")
        except Exception as e:
            bot.send_message(message.chat.id, f"❌ Ошибка: {str(e)}")
        
        # Очищаем состояние
        set_user_state(message.from_user.id, "{}")
            
    except Exception as e:
        import traceback
        traceback.print_exc()
        bot.send_message(message.chat.id, f"❌ Помилка: {str(e)}")
        set_user_state(message.from_user.id, "{}")

def _update_single_giveaway_reactions(giveaway_id, reactions_count, bot):
    """Обновляет реакции для одного розыгрыша"""
    from database import get_giveaway, update_giveaway_status
    from giveaway_monitoring import _process_giveaway_activation
    from giveaway_system import format_prize_text
    
    giveaway = get_giveaway(giveaway_id)
    if not giveaway:
        raise ValueError(f"Розыгрыш #{giveaway_id} не найден")
    
    # Обновляем счетчик
    update_giveaway_status(
        giveaway_id,
        'active',
        reactions_count=reactions_count
    )
    
    # Получаем обновленные данные розыгрыша
    updated_giveaway = get_giveaway(giveaway_id)
    required_reactions = updated_giveaway.get('required_reactions', 0)
    
    # Проверяем, нужно ли создать пост о начале розыгрыша
    if reactions_count >= required_reactions and required_reactions > 0:
        # Проверяем, не создан ли уже пост о начале
        if not updated_giveaway.get('started_post_message_id'):
            print(f"[INFO] При ручном обновлении: достигнуто {reactions_count}/{required_reactions} реакций, создаем пост о начале")
            _process_giveaway_activation(giveaway_id, bot)
    
    # Обновляем пост в канале (если пост о начале еще не создан)
    updated_giveaway = get_giveaway(giveaway_id)
    channel_id = updated_giveaway.get('channel_id')
    post_message_id = updated_giveaway.get('post_message_id')
    
    # Обновляем только оригинальный пост, если пост о начале еще не создан
    if channel_id and post_message_id and not updated_giveaway.get('started_post_message_id'):
        prize_data = {
            'prize_type': updated_giveaway['prize_type'],
            'prize_value': updated_giveaway['prize_value'],
            'prize_extra': updated_giveaway.get('prize_extra')
        }
        prize_text = format_prize_text(prize_data)
        
        updated_text = (
            f"🎁 <b>РОЗЫГРЫШ!</b> 🎁\n\n"
            f"📌 <b>{updated_giveaway['title']}</b>\n\n"
            f"🎁 <b>Приз:</b> {prize_text}\n\n"
            f"📊 <b>Для запуска нужно:</b> {required_reactions} реакций\n\n"
            f"💬 <b>Как участвовать:</b>\n"
            f"1. Поставьте реакцию на этот пост\n"
            f"2. Когда соберется {required_reactions} реакций, розыгрыш запустится\n"
            f"3. Отправьте эмодзи в комментариях\n"
            f"4. Кто первый выбьет 777 - побеждает!"
        )
        
        bot.edit_message_text(
            updated_text,
            chat_id=channel_id,
            message_id=post_message_id,
            parse_mode="HTML"
        )

@bot.callback_query_handler(func=lambda c: c.data == "giveaways_stats")
def giveaways_stats_handler(call):
    """Статистика розыгрышей"""
    if not is_admin(call.from_user.id):
        return bot.answer_callback_query(call.id, "Нема доступу", show_alert=True)
    
    from database import get_all_giveaways, get_giveaway_stats
    from telebot.types import InlineKeyboardMarkup, InlineKeyboardButton
    
    try:
        all_giveaways = get_all_giveaways(limit=100)
        
        if not all_giveaways:
            kb = InlineKeyboardMarkup()
            kb.add(InlineKeyboardButton("⬅️ Назад", callback_data="giveaways_menu"))
            return edit_or_send(call, "📊 <b>СТАТИСТИКА РОЗЫГРЫШЕЙ</b>\n\n❌ Данных пока нет.", reply_markup=kb, parse_mode="HTML")
        
        # Общая статистика
        total = len(all_giveaways)
        active = len([g for g in all_giveaways if g['status'] == 'active'])
        pending = len([g for g in all_giveaways if g['status'] == 'pending'])
        completed = len([g for g in all_giveaways if g['status'] == 'completed'])
        cancelled = len([g for g in all_giveaways if g['status'] == 'cancelled'])
        
        # Статистика по участникам и призам
        total_participants = 0
        total_reactions = 0
        total_prize_value = 0
        game_types = {'777': 0, 'blackjack': 0}
        
        for g in all_giveaways:
            stats = get_giveaway_stats(g['id'])
            if stats:
                total_participants += stats.get('participants_count', 0)
                total_reactions += stats.get('reactions_collected', 0)
            
            # Подсчет призов
            try:
                if g['prize_type'] == 'balance':
                    total_prize_value += float(g['prize_value'])
            except:
                pass
            
            # Подсчет типов игр
            game_type = g.get('game_type') or '777'
            if game_type in game_types:
                game_types[game_type] += 1
        
        text = "📊 <b>СТАТИСТИКА РОЗЫГРЫШЕЙ</b>\n\n"
        text += f"📈 <b>Загальна статистика:</b>\n"
        text += f"• Всього розыгрышей: <b>{total}</b>\n"
        text += f"• 🟢 Активних: <b>{active}</b>\n"
        text += f"• ⏳ Очікують: <b>{pending}</b>\n"
        text += f"• ✅ Завершено: <b>{completed}</b>\n"
        text += f"• ❌ Скасовано: <b>{cancelled}</b>\n\n"
        
        text += f"🎮 <b>Типи ігор:</b>\n"
        text += f"• 🎰 Слот-машина 777: <b>{game_types['777']}</b>\n"
        text += f"• 🃏 Блекджек 21: <b>{game_types['blackjack']}</b>\n\n"
        
        text += f"👥 <b>Участники:</b>\n"
        text += f"• Всього участників: <b>{total_participants}</b>\n"
        text += f"• Всього реакцій: <b>{total_reactions}</b>\n"
        
        if completed > 0:
            avg_participants = total_participants / completed if completed > 0 else 0
            text += f"• Середня кількість участників: <b>{avg_participants:.1f}</b>\n"
        
        if total_prize_value > 0:
            text += f"\n💰 <b>Призи:</b>\n"
            text += f"• Всього виплачено балансу: <b>{total_prize_value:.2f}₴</b>\n"
        
        kb = InlineKeyboardMarkup()
        kb.add(InlineKeyboardButton("⬅️ Назад", callback_data="giveaways_menu"))
        
        edit_or_send(call, text, reply_markup=kb, parse_mode="HTML")
        
    except Exception as e:
        import traceback
        traceback.print_exc()
        bot.answer_callback_query(call.id, f"❌ Помилка: {str(e)}", show_alert=True)

