@bot.callback_query_handler(func=lambda c: c.data.startswith("event_start:"))
def event_start_quick(call):
    if not is_admin(call.from_user.id):
        return bot.answer_callback_query(call.id, "Нема доступу", show_alert=True)
    try:
        _, etype, dur_s = call.data.split(":", 2)
        dur = int(dur_s)
    except Exception:
        return bot.answer_callback_query(call.id)
    try:
        from database import create_event
        params = { 'dur': dur }
        eid = create_event(etype, params, dur, call.from_user.id, call.message.chat.id, 0)
        try:
            bot.answer_callback_query(call.id, f"Стартовано {etype} #{eid}")
        except Exception:
            pass
        # Оповістити чати
        try:
            # Стартуємо розсилку анонсу, якщо можливо
            evt = _get_active_event(etype)
            if evt and evt['id'] == eid:
                _broadcast_event_announcement(evt)
        except Exception:
            pass
        # Повернутися до меню
        return events_menu_handler(call)
    except Exception as e:
        try:
            bot.answer_callback_query(call.id, f"❌ Помилка старту: {e}", show_alert=True)
        except Exception:
            pass

@bot.callback_query_handler(func=lambda c: c.data == "event_stop_menu")
def event_stop_menu(call):
    if not is_admin(call.from_user.id):
        return bot.answer_callback_query(call.id, "Нема доступу", show_alert=True)
    from telebot.types import InlineKeyboardMarkup, InlineKeyboardButton
    from database import get_active_events
    import time
    now = int(time.time())
    rows = get_active_events() or []
    active = [r for r in rows if (r[5] or '') in ('active','scheduled') and (r[4] or 0) > now]
    kb = InlineKeyboardMarkup(row_width=2)
    for (eid, etype, p, st, en, status, *_ ) in active[:30]:
        mins = max(0, int((en or 0) - now) // 60)
        kb.add(InlineKeyboardButton(f"⏹ #{eid} {etype} • {mins}хв", callback_data=f"event_stop:{eid}"))
    kb.add(InlineKeyboardButton("⬅️ Назад", callback_data="events_menu"))
    text = "⏹ <b>ЗУПИНИТИ ПОДІЮ</b>\nОберіть з активних:" if active else "⏹ Активних подій немає."
    bot.edit_message_text(text, call.message.chat.id, call.message.message_id, reply_markup=kb, parse_mode="HTML")

@bot.callback_query_handler(func=lambda c: c.data.startswith("event_stop:"))
def event_stop_action(call):
    if not is_admin(call.from_user.id):
        return bot.answer_callback_query(call.id, "Нема доступу", show_alert=True)
    try:
        eid = int(call.data.split(":",1)[1])
    except Exception:
        return bot.answer_callback_query(call.id)
    try:
        from database import end_event
        end_event(eid)
        try:
            bot.answer_callback_query(call.id, f"Зупинено #{eid}")
        except Exception:
            pass
    except Exception as e:
        try:
            bot.answer_callback_query(call.id, f"❌ Помилка: {e}", show_alert=True)
        except Exception:
            pass
    try:
        # Спробуємо надіслати підсумок у той чат, де була створена подія
        from database import get_event_by_id, get_event_participants
        row = get_event_by_id(eid)
        if row:
            _, etype, params_s, st, en, status, created_by, chat_id = row
            params = _json_loads_safe(params_s)
            title = {
                'storm': '🌪️ Буря', 'rain': '🌧️ Дощ', 'drought': '🔥 Посуха',
                'pests': '🐛 Шкідники', 'rush': '⚡ Турбо', 'golden': '🥇 Золоте',
                'buyer': '🧑‍🌾 Скупщик', 'market': '🕸️ Чорний ринок'
            }.get((etype or '').lower(), '🎉 Подія')
            # Учасники
            parts = get_event_participants(eid) or []
            users = list({p[0] for p in parts})
            # Збираємо короткий підсумок
            import time as _t
            dur = max(0, int(en or _t.time()) - int(st or _t.time())) // 60
            lines = [
                f"✅ <b>Подію завершено:</b> {title}",
                f"⏳ Тривалість: <b>{dur} хв</b>",
                f"👥 Учасників: <b>{len(users)}</b>",
            ]
            if etype == 'golden':
                try:
                    gcount = int(params.get('golden_count', 0))
                    greward = float(params.get('reward', 0))
                    if gcount or greward:
                        lines.append(f"🥇 Золоті: <b>{gcount}</b> • Нагорода: <b>{format_currency(greward)}₴</b>")
                except Exception:
                    pass
            # Відзначимо топ-5 активних (за кількістю дій)
            try:
                from collections import Counter
                c = Counter([p[0] for p in parts])
                top = c.most_common(5)
                if top:
                    lines.append("\n🏆 ТОП-учасники:")
                    for i, (uid, cnt) in enumerate(top, start=1):
                        medal = '🥇' if i == 1 else ('🥈' if i == 2 else ('🥉' if i == 3 else '🏅'))
                        lines.append(f"{medal} <a href='tg://user?id={uid}'>учасник</a> — <b>{cnt}</b> дій")
            except Exception:
                pass
            # Кнопки деталей
            from telebot.types import InlineKeyboardMarkup, InlineKeyboardButton
            kb = InlineKeyboardMarkup(row_width=2)
            kb.add(
                InlineKeyboardButton("📜 Список", callback_data="event_list"),
                InlineKeyboardButton("🎉 Події", callback_data="events_menu")
            )
            try:
                target_chat = chat_id or call.message.chat.id
                bot.send_message(target_chat, "\n".join(lines), parse_mode="HTML", reply_markup=kb)
            except Exception:
                pass
    except Exception:
        pass
    return event_stop_menu(call)

