def withdraw_change_user_id_step(message):
    if not is_admin(message.from_user.id):
        return bot.reply_to(message, "❌ Немає прав")
    try:
        uid = int((message.text or '').strip())
    except Exception:
        msg = bot.reply_to(message, "❌ Введіть числовий ID користувача:")
        return bot.register_next_step_handler(msg, withdraw_change_user_id_step)
    # Показуємо поточну суму і просимо нове значення
    from database import get_withdrawn_total
    current = get_withdrawn_total(uid)
    msg = bot.reply_to(message, f"Поточна сума виводу користувача <code>{uid}</code>: <b>{current:.2f}₴</b>\n\nВведіть нове значення (₴):", parse_mode="HTML")
    bot.register_next_step_handler(msg, withdraw_change_user_value_step, uid)

def withdraw_change_user_value_step(message, target_uid):
    if not is_admin(message.from_user.id):
        return bot.reply_to(message, "❌ Немає прав")
    try:
        new_total = float((message.text or '0').replace(',', '.'))
        if new_total < 0:
            raise ValueError
    except Exception:
        msg = bot.reply_to(message, "❌ Введіть коректне додатнє число (₴):")
        return bot.register_next_step_handler(msg, withdraw_change_user_value_step, target_uid)
    from database import set_withdrawn_total, get_withdrawn_total
    ok = set_withdrawn_total(int(target_uid), new_total)
    updated = get_withdrawn_total(int(target_uid))
    if ok:
        bot.reply_to(message, f"✅ Оновлено. Нова сума виводу для <code>{target_uid}</code>: <b>{updated:.2f}₴</b>", parse_mode="HTML")
    else:
        bot.reply_to(message, "❌ Не вдалося оновити суму. Спробуйте ще раз.")

