@bot.callback_query_handler(func=lambda c: c.data in ["ar_toggle_enabled", "ar_set_interval", "ar_set_segment", "ar_set_low_level", "ar_send_now"]) 
def admin_auto_reminders_actions(call):
    if not is_admin(call.from_user.id):
        return bot.answer_callback_query(call.id, "Немає доступу", show_alert=True)
    from database import set_game_setting, get_game_setting
    if call.data == "ar_toggle_enabled":
        cur = get_game_setting('auto_reminders_enabled', '1') == '1'
        set_game_setting('auto_reminders_enabled', '0' if cur else '1')
        return admin_auto_reminders(call)
    elif call.data == "ar_set_interval":
        msg = bot.send_message(call.message.chat.id, "⏱ Введіть інтервал у годинах (6–168):")
        return bot.register_next_step_handler(msg, _ar_apply_interval)
    elif call.data == "ar_set_segment":
        from telebot.types import InlineKeyboardMarkup, InlineKeyboardButton
        kb = InlineKeyboardMarkup(row_width=1)
        for seg in ("all", "non_ambassador", "low_level"):
            kb.add(InlineKeyboardButton(seg, callback_data=f"ar_seg:{seg}"))
        kb.add(InlineKeyboardButton("⬅️ Назад", callback_data="admin_auto_reminders"))
        try:
            bot.answer_callback_query(call.id)
        except Exception:
            pass
        return safe_edit_reply_markup(call, reply_markup=kb)
    elif call.data == "ar_set_low_level":
        msg = bot.send_message(call.message.chat.id, "🎚 Введіть максимальний рівень саду для сегмента low_level (напр. 1 або 2):")
        return bot.register_next_step_handler(msg, _ar_apply_level_max)
    elif call.data == "ar_send_now":
        # Запускаємо одноразову розсилку у потоці
        try:
            import threading
            th = threading.Thread(target=_run_soft_reminders_once_safe, name="soft-reminders-once", daemon=True)
            th.start()
            bot.answer_callback_query(call.id, "🚀 Розсилка запущена")
        except Exception:
            bot.answer_callback_query(call.id)
        return

def _ar_apply_interval(message):
    try:
        val = int((message.text or '').strip())
        if val < 6 or val > 168:
            raise ValueError
    except Exception:
        msg = bot.send_message(message.chat.id, "❗ Введіть ціле число від 6 до 168")
        return bot.register_next_step_handler(msg, _ar_apply_interval)
    from database import set_game_setting
    set_game_setting('auto_reminders_interval_hours', str(val))
    try:
        bot.send_message(message.chat.id, f"✅ Інтервал встановлено: {val} год")
    except Exception:
        pass
    # Повертаємося в меню
    class _Dummy:
        def __init__(self, chat_id, msg_id, uid):
            self.message = type('obj', (), {'chat': type('obj', (), {'id': chat_id}), 'message_id': msg_id})
            self.from_user = type('obj', (), {'id': uid})
            self.id = 0
    return admin_auto_reminders(_Dummy(message.chat.id, getattr(message, 'message_id', 0), message.from_user.id))

def _ar_apply_level_max(message):
    try:
        val = int((message.text or '').strip())
        if val < 0 or val > 10:
            raise ValueError
    except Exception:
        msg = bot.send_message(message.chat.id, "❗ Введіть рівень від 0 до 10")
        return bot.register_next_step_handler(msg, _ar_apply_level_max)
    from database import set_game_setting
