@bot.callback_query_handler(func=lambda c: c.data.startswith("broadcast_export:"))
def admin_broadcast_export(call):
    if not is_admin(call.from_user.id):
        return bot.answer_callback_query(call.id, "⛔️ Немає доступу", show_alert=True)
    try:
        run_id = int(call.data.split(":",1)[1])
    except Exception:
        return bot.answer_callback_query(call.id, "Невірний ID", show_alert=True)
    from database import fetch_broadcast_results
    rows = fetch_broadcast_results(run_id)
    import io, csv
    buf = io.StringIO()
    writer = csv.writer(buf)
    writer.writerow(["user_id","status","error_code","error_type","error_desc","sent_at"]) 
    for user_id, status, error_code, error_type, error_desc, sent_at in rows:
        writer.writerow([user_id, status, error_code or '', error_type or '', (error_desc or '').replace('\n',' '), sent_at])
    data = buf.getvalue().encode('utf-8')
    from telebot.types import InputFile
    bot.send_document(call.message.chat.id, InputFile(io.BytesIO(data), filename=f"broadcast_{run_id}.csv"), caption=f"Експорт розсилки #{run_id}")

