def build_profile_card_text_kb(user_id: int):
    from database import get_user, get_active_boosters, get_user_garden_level, get_user_verification_status
    u = get_user(user_id)
    if not u:
        return "❌ Користувача не знайдено у базі", InlineKeyboardMarkup().add(InlineKeyboardButton("⬅️ Назад", callback_data="panel"))
    name = u[1] or f"ID{user_id}"
    balance = float(u[2] or 0)
    try:
        level = get_user_garden_level(user_id)
    except Exception:
        level = 0
    boosters = []
    try:
        boosters = get_active_boosters(user_id)
    except Exception:
        boosters = []
    import html, time
    booster_lines = []
    for btype, exp in boosters:
        if exp is None:
            booster_lines.append(f"• <b>{btype}</b> — ♾️")
        else:
            remaining = max(0, int(exp - time.time()))
            mm = (remaining // 60) % 60
            hh = remaining // 3600
            booster_lines.append(f"• <b>{btype}</b> — {hh}г {mm}хв")
    boosters_text = "\n".join(booster_lines) if booster_lines else "<i>Немає</i>"
    
    # Перевіряємо, чи заморожений користувач
    is_frozen, freeze_info = get_user_freeze_info(user_id)
    freeze_status = ""
    if is_frozen and freeze_info:
        frozen_timestamp = convert_frozen_timestamp_to_int(freeze_info['frozen_at'])
        frozen_date = time.strftime('%d.%m.%Y %H:%M', time.localtime(frozen_timestamp))
        freeze_status = f"\n\n🧊 <b>АККАУНТ ЗАМОРОЖЕНО</b> 🧊\n❄️ <b>Дата:</b> {frozen_date}\n📝 <b>Причина:</b> {freeze_info.get('reason', 'Не вказано')}"
    
    # Статус верифікації
    verification_info = get_user_verification_status(user_id)
    verification_status = verification_info['status']
    suspicious_score = verification_info.get('suspicious_activity_score', 0)
    
    if verification_status == 'verified':
        verification_display = "✅ Верифіковано"
    elif verification_status == 'pending':
        verification_display = "⏳ Очікує верифікації"
    elif verification_status == 'rejected':
        verification_display = "❌ Відхилено"
    else:
        verification_display = "❌ Не верифіковано"
    
    verification_block = f"\n🛡️ <b>Верифікація:</b> {verification_display}"
    if suspicious_score >= 70:
        verification_block += f"\n⚠️ <b>Підозріла активність:</b> {suspicious_score}/100"
    
    card = (
        f"👤 <b>ПРОФІЛЬ КОРИСТУВАЧА</b>\n"
        f"━━━━━━━━━━━━━━━━━━━━\n\n"
        f"🆔 ID: <code>{user_id}</code>\n"
        f"👤 Ім'я: <a href='tg://user?id={user_id}'>{html.escape(name)}</a>\n"
        f"💰 Баланс: <b>{format_currency(balance)}₴</b>\n"
        f"🏆 Рівень саду: <b>{level}</b>\n"
        f"⚡ Активні бустери:\n{boosters_text}{verification_block}{freeze_status}"
    )
    kb = InlineKeyboardMarkup(row_width=2)
    kb.add(
        InlineKeyboardButton("💌 Надіслати повідомлення", callback_data=f"admin_msg_user:{user_id}"),
        InlineKeyboardButton("🪵 Редагувати сад", callback_data=f"admin_edit_garden_{user_id}")
    )
    kb.add(
        InlineKeyboardButton("🏆 Змінити рівень", callback_data=f"admin_edit_level:{user_id}"),
        InlineKeyboardButton("💰 Змінити баланс", callback_data=f"admin_edit_balance:{user_id}")
    )
    kb.add(
        InlineKeyboardButton("🚫 Бан у боті", callback_data=f"admin_ban_user:{user_id}"),
        InlineKeyboardButton("🔓 Розбан", callback_data=f"admin_unban_user:{user_id}")
    )
    # Кнопки заморозки
    if is_frozen:
        kb.add(InlineKeyboardButton("🧊 Розморозити", callback_data=f"admin_unfreeze_user:{user_id}"))
    else:
        kb.add(InlineKeyboardButton("❄️ Заморозити", callback_data=f"admin_freeze_user:{user_id}"))
    
    # Кнопки верифікації
    if verification_status == 'pending':
        kb.add(
            InlineKeyboardButton("✅ Верифікувати", callback_data=f"admin_verify_user:{user_id}"),
            InlineKeyboardButton("❌ Відхилити", callback_data=f"admin_reject_verification:{user_id}")
        )
        kb.add(InlineKeyboardButton("📋 Переглянути дані", callback_data=f"admin_view_verification:{user_id}"))
    elif verification_status == 'verified':
        kb.add(InlineKeyboardButton("🛡️ Верифіковано", callback_data=f"admin_view_verification:{user_id}"))
    elif verification_status == 'rejected':
        kb.add(InlineKeyboardButton("🔄 Повторна верифікація", callback_data=f"admin_view_verification:{user_id}"))
    else:
        kb.add(InlineKeyboardButton("🛡️ Переглянути верифікацію", callback_data=f"admin_view_verification:{user_id}"))
    
    kb.add(
        InlineKeyboardButton("📊 Профіль", callback_data=f"admin_profile_stats:{user_id}:profile"),
        InlineKeyboardButton("🌱 Сад", callback_data=f"admin_profile_stats:{user_id}:garden")
    )
    kb.add(
        InlineKeyboardButton("💰 Фінанси", callback_data=f"admin_profile_stats:{user_id}:finance"),
        InlineKeyboardButton("🧿 Аукціони", callback_data=f"admin_profile_stats:{user_id}:auctions")
    )
    kb.add(InlineKeyboardButton("👥 Реферали", callback_data=f"admin_profile_stats:{user_id}:referrals"))
    kb.add(
        InlineKeyboardButton("📒 Транзакції", callback_data=f"admin_user_tx:{user_id}"),
        InlineKeyboardButton("🔍 Діагностика", callback_data=f"admin_balance_diagnosis:{user_id}")
    )
    kb.add(InlineKeyboardButton("⬅️ Назад", callback_data="panel"))
    return card, kb

