@bot.callback_query_handler(func=lambda c: c.data.startswith("admin_freeze_user:"))
def admin_freeze_user(call):
    """Заморожує акаунт користувача"""
    if not is_admin(call.from_user.id):
        return bot.answer_callback_query(call.id, "⛔️ Немає доступу", show_alert=True)
    
    try:
        user_id = int(call.data.split(":", 1)[1])
    except Exception:
        return bot.answer_callback_query(call.id, "❌ Помилка ID користувача")
    
    # Перевіряємо, чи не заморожений вже
    is_frozen, _ = get_user_freeze_info(user_id)
    if is_frozen:
        return bot.answer_callback_query(call.id, "❌ Акаунт вже заморожено", show_alert=True)
    
    # Запитуємо причину заморозки
    msg = bot.send_message(
        call.message.chat.id,
        f"❄️ <b>ЗАМОРОЗКА АКАУНТА</b>\n\n"
        f"👤 <b>Користувач:</b> <code>{user_id}</code>\n\n"
        f"📝 <b>Введіть причину заморозки:</b>\n"
        f"<i>Наприклад: Порушення правил, підозріла активність, тощо.</i>",
        parse_mode="HTML"
    )
    bot.register_next_step_handler(msg, admin_freeze_user_reason, user_id)

def admin_freeze_user_reason(message, user_id):
    """Обробляє причину заморозки"""
    if not is_admin(message.from_user.id):
        return
    
    reason = message.text.strip()
    if not reason:
        bot.reply_to(message, "❌ Причина не може бути порожньою")
        return
    
    # Заморожуємо акаунт
    freeze_user_account(user_id, reason)
    success = True
    
    if success:
        # Повідомляємо користувача про заморозку
        try:
            bot.send_message(
                user_id,
                f"🧊 <b>АКАУНТ ЗАМОРОЖЕНО</b> 🧊\n\n"
                f"❄️ <b>Ваш акаунт тимчасово заблоковано</b>\n\n"
                f"📝 <b>Причина:</b> {reason}\n\n"
                f"⚠️ <b>Доступні дії обмежено:</b>\n"
                f"• ❌ Не можна виводити кошти\n"
                f"• ❌ Не можна продавати фрукти\n"
                f"• ❌ Не можна брати участь в іграх\n"
                f"• ❌ Не можна отримувати подарунки\n\n"
                f"💬 <b>Для розблокування зверніться до адміністратора</b>",
                parse_mode="HTML"
            )
        except Exception:
            pass
        
        bot.reply_to(
            message,
            f"✅ <b>Акаунт успішно заморожено</b>\n\n"
            f"👤 <b>Користувач:</b> <code>{user_id}</code>\n"
            f"📝 <b>Причина:</b> {reason}\n"
            f"👨‍💼 <b>Адмін:</b> {message.from_user.first_name}",
            parse_mode="HTML"
        )
    else:
        bot.reply_to(message, "❌ Помилка при заморозці акаунта")

