@bot.callback_query_handler(func=lambda c: c.data.startswith("admin_verify_user:"))
def admin_verify_user_handler(call):
    """Верифікує користувача"""
    if not is_admin(call.from_user.id):
        return bot.answer_callback_query(call.id, "⛔️ Немає доступу", show_alert=True)
    
