@bot.callback_query_handler(func=lambda c: c.data.startswith("admin_view_verification:"))
def admin_view_verification_handler(call):
    """Переглядає дані верифікації користувача"""
    if not is_admin(call.from_user.id):
        return bot.answer_callback_query(call.id, "⛔️ Немає доступу", show_alert=True)
    
    try:
        user_id = int(call.data.split(":", 1)[1])
    except Exception:
        return bot.answer_callback_query(call.id, "❌ Помилка ID користувача")
    
    from database import get_user_verification_status, get_user
    import time
    
    verification_info = get_user_verification_status(user_id)
    user_row = get_user(user_id)
    user_name = user_row[1] if user_row else f"ID{user_id}"
    
    status = verification_info['status']
    verification_data = verification_info.get('verification_data', {})
    suspicious_score = verification_info.get('suspicious_activity_score', 0)
    reasons = verification_info.get('suspicious_activity_reasons', [])
    
    msg = (
        f"🛡️ <b>ДАНІ ВЕРИФІКАЦІЇ</b>\n"
        f"━━━━━━━━━━━━━━━━━━━━\n\n"
        f"👤 <b>Користувач:</b> <a href='tg://user?id={user_id}'>{user_name}</a>\n"
        f"🆔 <b>ID:</b> <code>{user_id}</code>\n\n"
    )
    
    if status == 'verified':
        msg += "✅ <b>Статус:</b> Верифіковано\n"
        if verification_info.get('verification_verified_at'):
            verified_date = time.strftime('%d.%m.%Y %H:%M', time.localtime(verification_info['verification_verified_at']))
            msg += f"📅 <b>Дата верифікації:</b> {verified_date}\n"
    elif status == 'pending':
        msg += "⏳ <b>Статус:</b> Очікує верифікації\n"
        if verification_info.get('verification_requested_at'):
            requested_date = time.strftime('%d.%m.%Y %H:%M', time.localtime(verification_info['verification_requested_at']))
            msg += f"📅 <b>Дата запиту:</b> {requested_date}\n"
    elif status == 'rejected':
        msg += "❌ <b>Статус:</b> Відхилено\n"
    else:
        msg += "❌ <b>Статус:</b> Не верифіковано\n"
    
    msg += "\n📋 <b>Дані верифікації:</b>\n"
    if verification_data:
        if verification_data.get('phone'):
            msg += f"📱 <b>Телефон:</b> <code>{verification_data['phone']}</code>\n"
        if verification_data.get('email'):
            msg += f"📧 <b>Email:</b> <code>{verification_data['email']}</code>\n"
        if verification_data.get('additional_info'):
            msg += f"📝 <b>Додаткова інформація:</b>\n{verification_data['additional_info']}\n"
    else:
        msg += "<i>Дані відсутні</i>\n"
    
    if suspicious_score > 0:
        msg += f"\n⚠️ <b>Підозріла активність:</b> {suspicious_score}/100\n"
        if reasons:
            msg += "<b>Причини:</b>\n"
            for reason in reasons[:5]:  # Показуємо максимум 5 причин
                msg += f"• {reason}\n"
    
    kb = InlineKeyboardMarkup()
    if status == 'pending':
        kb.add(
            InlineKeyboardButton("✅ Верифікувати", callback_data=f"admin_verify_user:{user_id}"),
            InlineKeyboardButton("❌ Відхилити", callback_data=f"admin_reject_verification:{user_id}")
        )
    kb.add(InlineKeyboardButton("⬅️ Назад", callback_data=f"admin_view_profile"))
    
    try:
        bot.edit_message_text(msg, call.message.chat.id, call.message.message_id, reply_markup=kb, parse_mode="HTML")
    except Exception:
        bot.send_message(call.message.chat.id, msg, reply_markup=kb, parse_mode="HTML")

@bot.callback_query_handler(func=lambda c: c.data.startswith("admin_balance_diagnosis:"))
def admin_balance_diagnosis(call):
    """Диагностика баланса пользователя - показывает полную картину финансов"""
    if not is_admin(call.from_user.id):
        return bot.answer_callback_query(call.id, "⛔️ Немає доступу", show_alert=True)
    
    try:
        user_id = int(call.data.split(":",1)[1])
    except Exception:
        return bot.answer_callback_query(call.id, "❌ Помилка ID користувача")
    
    from database import get_user_balance_summary, get_user_balance_ledger
    
    try:
        summary = get_user_balance_summary(user_id)
        ledger = get_user_balance_ledger(user_id, 10)  # Последние 10 записей
        
        msg = (
            f"🔍 <b>ДІАГНОСТИКА БАЛАНСУ</b>\n"
            f"👤 <b>Користувач:</b> <code>{user_id}</code>\n"
            f"━━━━━━━━━━━━━━━━━━━━\n\n"
            f"💰 <b>Поточний баланс:</b> <b>{summary['current_balance']:.2f}₴</b>\n"
            f"📈 <b>Всього депозитів:</b> <b>{summary['total_deposits']:.2f}₴</b>\n"
            f"📉 <b>Всього виводів:</b> <b>{summary['total_withdrawals']:.2f}₴</b>\n"
            f"📊 <b>Зміни в ledger:</b> <b>{summary['total_ledger_delta']:.2f}₴</b>\n"
            f"📝 <b>Записів в ledger:</b> <b>{summary['ledger_count']}</b>\n\n"
            f"🧮 <b>Очікуваний баланс:</b> <b>{summary['expected_balance']:.2f}₴</b>\n"
            f"⚠️ <b>Розбіжність:</b> <b>{summary['discrepancy']:.2f}₴</b>\n\n"
        )
        
        if abs(summary['discrepancy']) > 0.01:
            msg += f"🚨 <b>УВАГА!</b> Є розбіжність у балансі!\n\n"
        
        if ledger:
            msg += f"📋 <b>Останні зміни балансу:</b>\n"
            import time
            for r in ledger[:5]:  # Показываем только последние 5
                delta, balance_before, balance_after, reason, details, created_at = r
                dt = time.strftime('%d.%m %H:%M', time.localtime(int(created_at)))
                sign = '+' if float(delta) > 0 else '-' if float(delta) < 0 else '='
                msg += f"• <b>{dt}</b> {sign}{abs(float(delta)):.2f}₴ ({reason or 'unknown'})\n"
                if details:
                    msg += f"  <i>{details[:50]}{'...' if len(details) > 50 else ''}</i>\n"
        
        kb = InlineKeyboardMarkup()
        kb.add(InlineKeyboardButton("📒 Повні транзакції", callback_data=f"admin_user_tx:{user_id}"))
        kb.add(InlineKeyboardButton("⬅️ Назад", callback_data=f"admin_profile_stats:{user_id}:profile"))
        
        try:
            bot.edit_message_text(msg, call.message.chat.id, call.message.message_id, reply_markup=kb, parse_mode="HTML")
        except Exception:
            bot.send_message(call.message.chat.id, msg, reply_markup=kb, parse_mode="HTML")
            
    except Exception as e:
        error_msg = f"❌ Помилка діагностики: {str(e)}"
        try:
            bot.edit_message_text(error_msg, call.message.chat.id, call.message.message_id, parse_mode="HTML")
        except Exception:
            bot.send_message(call.message.chat.id, error_msg, parse_mode="HTML")

