def _admin_edit_balance_apply(message, target_id):
    try:
        delta = float(str(message.text).replace(',', '.'))
        from database import add_balance, get_user
        add_balance(target_id, delta)
        new_balance = (get_user(target_id) or [None,None,0])[2]
        bot.send_message(message.chat.id, f"✅ Баланс змінено на {delta:+.2f}₴. Новий баланс: {new_balance:.2f}₴")
        try:
            bot.send_message(target_id, f"💼 Ваш баланс змінено на {delta:+.2f}₴. Новий баланс: {new_balance:.2f}₴")
        except Exception:
            pass
    except Exception as e:
        bot.send_message(message.chat.id, f"❌ Помилка: {e}")

