@bot.callback_query_handler(func=lambda c: c.data.startswith("admin_profile_stats:"))
def admin_profile_stats(call):
    if not is_admin(call.from_user.id):
        return bot.answer_callback_query(call.id, "⛔️ Немає доступу", show_alert=True)
    try:
        from database import update_last_active
        update_last_active(call.from_user.id)
    except Exception:
        pass
    parts = call.data.split(":")
    uid = int(parts[1]); section = parts[2]
    import html, time
    from database import get_user, get_user_registration_date, get_user_last_active, get_ref_count
    from database import get_user_trees, get_garden_history_summary, get_garden_history
    from database import _db, get_withdrawn_total
    u = get_user(uid)
    name = html.escape(u[1] if u and u[1] else f"ID{uid}")
    kb = InlineKeyboardMarkup()
    # Показ онлайн-статусу (≤2 хв) від last_active
    try:
        from database import get_user_last_active
        import time
        last = int(get_user_last_active(uid) or 0)
        online = (int(time.time()) - last) <= 120
        status_line = "🟢 Зараз онлайн (≤ 2 хв)" if online else "⚫ Офлайн"
    except Exception:
        status_line = ""
    if section == 'profile':
        reg = get_user_registration_date(uid)
        last = get_user_last_active(uid)
        reg_fmt = format_user_time(reg, uid)
        last_fmt = format_user_time(last, uid)
        refs = get_ref_count(uid)
        text = (
            f"📊 <b>СТАТИСТИКА ПРОФІЛЮ</b>\n"
            f"━━━━━━━━━━━━━━━━━━━━\n\n"
            f"👤 Користувач: <a href='tg://user?id={uid}'>{name}</a>\n"
            f"{status_line}\n"
            f"📅 Реєстрація: <b>{reg_fmt}</b>\n"
            f"⏰ Остання активність: <b>{last_fmt}</b>\n"
            f"👥 Рефералів: <b>{refs}</b>\n"
        )
        kb.add(InlineKeyboardButton("⬅️ До профілю", callback_data=f"admin_profile_open:{uid}"))
        return bot.edit_message_text(text, call.message.chat.id, call.message.message_id, reply_markup=kb, parse_mode="HTML")
    kb.add(InlineKeyboardButton("⬅️ До профілю", callback_data=f"admin_profile_open:{uid}"))
    # Повернення до профілю відкриває старт; використаємо швидкий виклик
    if section == 'profile':
        reg = get_user_registration_date(uid)
        last = get_user_last_active(uid)
        reg_fmt = format_user_time(reg, uid)
        last_fmt = format_user_time(last, uid)
        refs = get_ref_count(uid)
        text = (
            f"📊 <b>СТАТИСТИКА ПРОФІЛЮ</b>\n"
            f"━━━━━━━━━━━━━━━━━━━━\n\n"
            f"👤 Користувач: <a href='tg://user?id={uid}'>{name}</a>\n"
            f"📅 Реєстрація: <b>{reg_fmt}</b>\n"
            f"⏰ Остання активність: <b>{last_fmt}</b>\n"
            f"👥 Рефералів: <b>{refs}</b>\n"
        )
        return bot.edit_message_text(text, call.message.chat.id, call.message.message_id, reply_markup=kb, parse_mode="HTML")
    if section == 'garden':
        trees = get_user_trees(uid)
        from collections import Counter
        from garden_models import TREE_TYPES, get_tree_name_uk
        type_to_emoji = {t['type']: t.get('fruit_emoji','🌳') for t in TREE_TYPES}
        
        # Заголовок
        lines = ["🌱 <b>СТАТИСТИКА САДУ</b>", "━━━━━━━━━━━━━━━━━━━━", ""]
        
        # Дерева: підрахунок і деталі
        lines.append(f"🌳 Всього дерев: <b>{len(trees)}</b>")
        type_counts = Counter([t['type'] for t in trees])
        if type_counts:
            for t, cnt in type_counts.most_common():
                name = get_tree_name_uk(t)
                emoji = type_to_emoji.get(t, '🌳')
                lines.append(f"{emoji} {name}: <b>{cnt}</b>")

        # Новая детальная активность из garden_activity_log
        try:
            from database import get_garden_activity_log
            activity_log = get_garden_activity_log(uid, 50)
            
            if activity_log:
                lines.append("")
                lines.append("📋 <b>Остання активність:</b>")
                
                # Группируем по типам
                tree_purchases = []
                booster_purchases = []
                harvests = []
                sales = []
                upgrades = []
                
                for activity in activity_log:
                    if activity['activity_type'] == 'tree_buy':
                        tree_purchases.append(activity)
                    elif activity['activity_type'] == 'booster_buy':
                        booster_purchases.append(activity)
                    elif activity['activity_type'] == 'harvest':
                        harvests.append(activity)
                    elif activity['activity_type'] == 'sale':
                        sales.append(activity)
                    elif activity['activity_type'] == 'upgrade':
                        upgrades.append(activity)
                
                # Показываем последние покупки деревьев
                if tree_purchases:
                    lines.append("\n🌳 <b>Останні покупки дерев:</b>")
                    for activity in tree_purchases[:5]:
                        time_str = format_kiev_time(activity['timestamp'])
                        lines.append(f"• {activity['item_name']} x{activity['quantity']} - {activity['cost']:.2f}₴ ({time_str})")
                
                # Показываем последние покупки бустеров
                if booster_purchases:
                    lines.append("\n⚡ <b>Останні бустери:</b>")
                    for activity in booster_purchases[:5]:
                        time_str = format_kiev_time(activity['timestamp'])
                        duration = activity['metadata'].get('duration_text', 'N/A')
                        lines.append(f"• {activity['item_name']} - {activity['cost']:.2f}₴ ({duration}) ({time_str})")
                
                # Показываем последние сборы
                if harvests:
                    lines.append("\n🍎 <b>Останні збори:</b>")
                    for activity in harvests[:5]:
                        time_str = format_kiev_time(activity['timestamp'])
                        lines.append(f"• {activity['item_name']} x{activity['quantity']} ({time_str})")
                
                # Показываем последние продажи
                if sales:
                    lines.append("\n💰 <b>Останні продажі:</b>")
                    for activity in sales[:5]:
                        time_str = format_kiev_time(activity['timestamp'])
                        lines.append(f"• {activity['item_name']} x{activity['quantity']} - {activity['cost']:.2f}₴ ({time_str})")
                
                # Показываем последние апгрейды
                if upgrades:
                    lines.append("\n⬆️ <b>Останні апгрейди:</b>")
                    for activity in upgrades[:3]:
                        time_str = format_kiev_time(activity['timestamp'])
                        lines.append(f"• {activity['item_name']} - {activity['cost']:.2f}₴ ({time_str})")
            else:
                lines.append("\n📋 <b>Активність:</b>")
                lines.append("Поки що немає записів активності в саду")
                
        except Exception as e:
            lines.append(f"\n❌ Помилка завантаження активності: {e}")
        
        # Додаємо фільтри історії саду
        lines.append("")
        lines.append("🧾 <i>Історія: оберіть період нижче</i>")
        fk = InlineKeyboardMarkup()
        fk.add(
            InlineKeyboardButton("📅 Сьогодні", callback_data=f"admin_garden_history:{uid}:today"),
            InlineKeyboardButton("📅 7 днів", callback_data=f"admin_garden_history:{uid}:week")
        )
        fk.add(InlineKeyboardButton("📅 30 днів", callback_data=f"admin_garden_history:{uid}:month"))
        fk.add(InlineKeyboardButton("⬅️ До профілю", callback_data=f"admin_profile_open:{uid}"))
        bot.edit_message_text("\n".join(lines), call.message.chat.id, call.message.message_id, reply_markup=fk, parse_mode="HTML")
        return
    if section == 'finance':
        balance = float(u[2] if u and u[2] else 0)
        withdrawn = get_withdrawn_total(uid)
        # Суми депозитів зарахованих
        dep_total = 0.0
        try:
            with _db() as con:
                row = con.execute("SELECT COALESCE(SUM(amount),0) FROM deposit_tx WHERE user_id=? AND status='approved'", (uid,)).fetchone()
                dep_total = float(row[0] if row and row[0] is not None else 0.0)
        except Exception:
            dep_total = 0.0
        text = (
            f"💰 <b>ФІНАНСИ КОРИСТУВАЧА</b>\n"
            f"━━━━━━━━━━━━━━━━━━━━\n\n"
            f"💼 Баланс: <b>{format_currency(balance)}₴</b>\n"
            f"🏦 Депозити (зарах.): <b>{format_currency(dep_total)}₴</b>\n"
            f"💸 Виведено: <b>{format_currency(withdrawn)}₴</b>\n"
        )
        # Останні 10 операцій: депозити та виводи
        try:
            with _db() as con:
                tx_rows = con.execute("SELECT 'withdraw' as t, tx_id, amount, status, created_at FROM tx WHERE user_id=? ORDER BY tx_id DESC LIMIT 10", (uid,)).fetchall()
                dep_rows = con.execute("SELECT 'deposit' as t, id, amount, status, created_at FROM deposit_tx WHERE user_id=? ORDER BY id DESC LIMIT 10", (uid,)).fetchall()
            lines = [text, "", "🧾 <b>Останні транзакції</b>:"]
            def fmt(row):
                t, _id, amt, st, dt = row
                icon = '⬆️' if t=='withdraw' else '⬇️'
                return f"{icon} {t}: <b>{format_currency(float(amt))}₴</b> — <i>{st}</i> ({dt})"
            for r in (tx_rows + dep_rows)[:10]:
                try:
                    lines.append(fmt(r))
                except Exception:
                    pass
            text = "\n".join(lines)
        except Exception:
            pass
        return bot.edit_message_text(text, call.message.chat.id, call.message.message_id, reply_markup=kb, parse_mode="HTML")
    if section == 'auctions':
        part_cnt = 0; win_cnt = 0; sum_max = 0.0; removed_cnt = 0
        try:
            with _db() as con:
                row = con.execute("SELECT COUNT(DISTINCT auction_id) FROM auction_bids WHERE user_id=?", (uid,)).fetchone(); part_cnt = int(row[0] or 0)
                row = con.execute("SELECT COUNT(*) FROM auctions WHERE winner_user_id=?", (uid,)).fetchone(); win_cnt = int(row[0] or 0)
                row = con.execute("SELECT COALESCE(SUM(max_amt),0) FROM (SELECT MAX(amount) AS max_amt FROM auction_bids WHERE user_id=? GROUP BY auction_id)", (uid,)).fetchone(); sum_max = float(row[0] or 0)
                row = con.execute("SELECT COUNT(*) FROM auction_removed WHERE user_id=?", (uid,)).fetchone(); removed_cnt = int(row[0] or 0)
        except Exception:
            pass
        text = (
            f"🧿 <b>АУКЦІОНИ</b>\n"
            f"━━━━━━━━━━━━━━━━━━━━\n\n"
            f"🎯 Участей: <b>{part_cnt}</b>\n"
            f"👑 Перемог: <b>{win_cnt}</b>\n"
            f"💵 Сума макс.ставок: <b>{format_currency(sum_max)}₴</b>\n"
            f"🚫 Видалень з лотів: <b>{removed_cnt}</b>\n"
        )
        # Останні 10 ставок та виграші
        try:
            with _db() as con:
                bids = con.execute("SELECT auction_id, amount, created_at FROM auction_bids WHERE user_id=? ORDER BY created_at DESC LIMIT 10", (uid,)).fetchall()
                wins = con.execute("SELECT id, winner_price FROM auctions WHERE winner_user_id=? ORDER BY ends_at DESC LIMIT 10", (uid,)).fetchall()
            lines = [text, "", "📈 <b>Останні ставки</b>:"]
            for a_id, amt, ts in bids:
                lines.append(f"• Лот #{a_id}: {format_currency(float(amt))}₴")
            lines.append("")
            lines.append("🏁 <b>Виграші</b>:")
            for a_id, price in wins:
                lines.append(f"• Лот #{a_id}: {format_currency(float(price))}₴")
            text = "\n".join(lines)
        except Exception:
            pass
        return bot.edit_message_text(text, call.message.chat.id, call.message.message_id, reply_markup=kb, parse_mode="HTML")
    if section == 'referrals':
        from database import get_referrals
        refs = get_referrals(uid) or []
        lines = ["👥 <b>РЕФЕРАЛИ</b>", "━━━━━━━━━━━━━━━━━━━━", ""]
        lines.append(f"Всього: <b>{len(refs)}</b>")
        for rid, rname in refs[:20]:
            lines.append(f"• <a href='tg://user?id={rid}'>{html.escape(rname or str(rid))}</a>")
        kb = InlineKeyboardMarkup().add(InlineKeyboardButton("⬅️ До профілю", callback_data=f"admin_profile_open:{uid}"))
        return bot.edit_message_text("\n".join(lines), call.message.chat.id, call.message.message_id, reply_markup=kb, parse_mode="HTML")


