@bot.callback_query_handler(func=lambda c: c.data == "set_withdraw_channel_prompt")
def set_withdraw_channel_prompt(call):
    if not is_admin(call.from_user.id):
        return bot.answer_callback_query(call.id, "⛔️ Немає доступу", show_alert=True)
    msg = bot.send_message(
        call.message.chat.id,
        "📝 <b>Надішліть @username каналу, його ID (-100...), або просто перешліть повідомлення з каналу сюди.</b>",
        parse_mode="HTML"
    )
    bot.register_next_step_handler(msg, process_withdraw_channel_input)
    bot.answer_callback_query(call.id)

def process_withdraw_channel_input(message):
    if not is_admin(message.from_user.id):
        return bot.send_message(message.chat.id, "⛔️ Немає доступу")
    from database import set_withdraw_channel
    channel_id = None
    # 1) Переслане повідомлення з каналу
    try:
        forward_chat = getattr(message, 'forward_from_chat', None)
        if forward_chat and forward_chat.id:
            channel_id = forward_chat.id
    except Exception:
        pass
    # 2) Текст (@username або -100...)
    if channel_id is None and message.text:
        text = message.text.strip()
        if text.startswith('@'):
            try:
                chat = bot.get_chat(text)
                channel_id = chat.id
            except Exception as e:
                return bot.send_message(message.chat.id, f"❌ Не вдалося отримати ID каналу по username. Помилка: {e}")
        else:
            try:
                channel_id = int(text)
            except Exception:
                return bot.send_message(message.chat.id, "❌ Надішліть коректний @username, -100 ID, або переслане повідомлення з каналу.")
    try:
        set_withdraw_channel(channel_id)
        bot.send_message(message.chat.id, f"✅ Канал виводів встановлено: <code>{channel_id}</code>", parse_mode="HTML")
    except Exception as e:
        bot.send_message(message.chat.id, f"❌ Помилка збереження каналу: {e}")
    # Повертаємо меню
    try:
        class DummyFrom:
            id = message.from_user.id
        class DummyCall:
            def __init__(self, chat_id, message_id):
                self.message = type('obj', (), {'chat': type('obj', (), {'id': chat_id}), 'message_id': message_id})
                self.from_user = DummyFrom()
                self.id = 0
        set_withdraw_channel_menu(DummyCall(message.chat.id, message.message_id))
    except Exception:
        pass

