@bot.callback_query_handler(func=lambda c: c.data.startswith("admin_set_level_price_"))
def admin_set_level_price_start(call):
    level = int(call.data.replace("admin_set_level_price_", ""))
    from database import get_level_price
    current = get_level_price(level)
    msg = bot.send_message(call.message.chat.id, f"Введіть нову ціну для рівня <b>{level}</b> (поточна: <b>{format_currency(current)}₴</b>):", parse_mode="HTML")
    bot.register_next_step_handler(msg, admin_set_level_price_apply, level)

def admin_set_level_price_apply(message, level):
    from database import set_level_price
    try:
        new_price = float(message.text.replace(",", "."))
        if new_price < 0:
            raise ValueError
    except Exception:
        msg = bot.send_message(message.chat.id, "❗ Введіть коректну ціну (невід'ємне число)!")
        return bot.register_next_step_handler(msg, admin_set_level_price_apply, level)
    set_level_price(level, new_price)
    bot.send_message(message.chat.id, f"✅ Ціну рівня <b>{level}</b> змінено на <b>{format_currency(new_price)}₴</b>.", parse_mode="HTML")
    # Повернення в меню рівнів
    # Викликаємо відображення меню знову
    try:
        class DummyFrom:
            id = 0
        class DummyCall:
            def __init__(self, chat_id, message_id):
                self.message = type('obj', (), {'chat': type('obj', (), {'id': chat_id}), 'message_id': message_id})
                self.from_user = DummyFrom()
                self.id = 0
        last_msg_id = message.message_id
        admin_garden_levels_handler(DummyCall(message.chat.id, last_msg_id))
    except Exception:
        pass
    # Кінець операції — повернемо користувача в меню рівнів (зроблено вище)

