@bot.callback_query_handler(func=lambda c: c.data == "admin_remove_admin")
def admin_remove_admin_handler(call):
    if check_maintenance(call): return
    from database import is_bot_creator
    if not is_bot_creator(call.from_user.id):
        return bot.answer_callback_query(call.id, "⛔️ Немає доступу", show_alert=True)
    
    # Отримуємо список адміністраторів
    from database import _db
    with _db() as con:
        admins = con.execute("SELECT user_id FROM admins").fetchall()
    
    if not admins:
        bot.answer_callback_query(call.id, "📝 Список адміністраторів порожній", show_alert=True)
        return
    
    safe_answer_callback_query(call, "👤 Введіть ID адміністратора для сняття прав")
    admin_list = "👑 <b>Поточні адміністратори:</b>\n\n"
    for admin in admins:
        admin_list += f"• <code>{admin[0]}</code>\n"
    
    admin_list += "\nВведіть ID адміністратора, якого потрібно сняти з прав:"
    
    bot.send_message(
        call.message.chat.id,
        admin_list,
        parse_mode="HTML"
    )
    
