@bot.callback_query_handler(func=lambda c: c.data == "admin_list_roles")
def admin_list_roles_handler(call):
    """Показує список користувачів з ролями"""
    if check_maintenance(call): return
    from database import is_bot_creator, get_all_users_with_roles
    if not is_bot_creator(call.from_user.id):
        return bot.answer_callback_query(call.id, "⛔️ Немає доступу", show_alert=True)
    
    users = get_all_users_with_roles()
    
    if not users:
        bot.answer_callback_query(call.id, "📝 Немає користувачів з ролями", show_alert=True)
        return
    
    from telebot.types import InlineKeyboardMarkup, InlineKeyboardButton
    kb = InlineKeyboardMarkup(row_width=1)
    
    role_display_names = {
        'giveaway_manager': 'Менеджер розіграшів',
        'payout_manager': 'Менеджер виплат'
    }
    
    from database import get_user_giveaway_limits, get_giveaway_limits
    global_limits = get_giveaway_limits()
    
    text = "📋 <b>Користувачі з ролями:</b>\n\n"
    for user in users:
        roles_display = []
        has_giveaway_role = False
        for r in user['roles']:
            role_display = role_display_names.get(r['role'], r['role'])
            roles_display.append(role_display)
            if r['role'] == 'giveaway_manager':
                has_giveaway_role = True
        roles_text = ", ".join(roles_display)
        text += f"👤 <b>{user['user_name']}</b> (<code>{user['user_id']}</code>)\n"
        text += f"   🎭 Ролі: <b>{roles_text}</b>\n"
        
        # Показуємо персональні ліміти якщо є
        if has_giveaway_role:
            user_limits = get_user_giveaway_limits(user['user_id'])
            if user_limits['max_prize_amount'] is not None or user_limits['max_per_day'] is not None:
                text += f"   📊 <i>Ліміти:</i> "
                limits_parts = []
                if user_limits['max_prize_amount'] is not None:
                    limits_parts.append(f"Макс. сума: {user_limits['max_prize_amount']}₴")
                else:
                    limits_parts.append(f"Макс. сума: {global_limits['max_prize_amount']}₴ (глобальний)")
                if user_limits['max_per_day'] is not None:
                    limits_parts.append(f"Макс./день: {user_limits['max_per_day']}")
                else:
                    limits_parts.append(f"Макс./день: {global_limits['max_per_day']} (глобальний)")
                text += ", ".join(limits_parts) + "\n"
            else:
                text += f"   📊 <i>Ліміти:</i> Глобальні (сума: {global_limits['max_prize_amount']}₴, день: {global_limits['max_per_day']})\n"
        
        # Додаємо кнопку для налаштування лімітів якщо це менеджер розіграшів
        if has_giveaway_role:
            kb.add(InlineKeyboardButton(
                f"⚙️ Ліміти {user['user_name']}",
                callback_data=f"admin_set_user_limits:{user['user_id']}"
            ))
        text += "\n"
    
    kb.add(InlineKeyboardButton("⬅️ Назад", callback_data="admin_roles_menu"))
    
    edit_or_send(call, text, reply_markup=kb, parse_mode="HTML")
    bot.answer_callback_query(call.id)

