@bot.message_handler(func=lambda m: get_user_state(m.from_user.id) and str(get_user_state(m.from_user.id)).startswith("waiting_grant_role:"))
def admin_grant_role_step_handler(message):
    """Обробник введення user_id для видачі ролі"""
    from database import is_bot_creator, get_user_state, set_user_state, grant_role, get_user, get_user_id_by_username
    
    print(f"[DEBUG] admin_grant_role_step_handler TRIGGERED for user {message.from_user.id}")
    print(f"[DEBUG] Message text: '{message.text}'")
    
    if not is_bot_creator(message.from_user.id):
        print(f"[DEBUG] User {message.from_user.id} is not bot creator, returning")
        return
    
    state = get_user_state(message.from_user.id)
    print(f"[DEBUG] User state: '{state}'")
    if not state or not state.startswith("waiting_grant_role:"):
        print(f"[DEBUG] State doesn't match waiting_grant_role pattern, returning")
        return
    
    role = state.split(":")[1]
    role_names = {
        'giveaway_manager': 'менеджер розіграшів',
        'payout_manager': 'менеджер виплат'
    }
    role_name = role_names.get(role, role)
    
    try:
        user_input = message.text.strip()
        if not user_input:
            bot.reply_to(message, "❌ Помилка: Введіть ID або @username користувача!")
            return
        
        target_user_id = None
        
        # Перевірка чи це @username
        if user_input.startswith("@"):
            username = user_input.replace("@", "").strip()
            if not username:
                bot.reply_to(message, "❌ Помилка: Введіть коректний @username (наприклад: @username)")
                return
            try:
                target_user_id = get_user_id_by_username(user_input)
                if not target_user_id:
                    bot.reply_to(message, f"❌ Користувача {user_input} не знайдено в базі даних")
                    set_user_state(message.from_user.id, None)
                    return
            except Exception as e:
                print(f"[ERROR] Error getting user by username {user_input}: {e}")
                bot.reply_to(message, f"❌ Помилка при пошуку користувача {user_input}: {e}")
                set_user_state(message.from_user.id, None)
                return
        else:
            # Спробуємо перетворити в число
            try:
                target_user_id = int(user_input)
            except ValueError:
                bot.reply_to(message, "❌ Помилка: ID має бути числом або @username!\n\n💡 Приклад: 123456789 або @username")
                return
        
        # Перевірка чи користувач існує
        try:
            user = get_user(target_user_id)
            if not user:
                bot.reply_to(message, f"❌ Користувача з ID {target_user_id} не знайдено в базі даних")
                set_user_state(message.from_user.id, None)
                return
        except Exception as e:
            print(f"[ERROR] Error getting user {target_user_id}: {e}")
            bot.reply_to(message, f"❌ Помилка при отриманні даних користувача: {e}")
            set_user_state(message.from_user.id, None)
            return
        
        # Видаємо роль
        try:
            grant_role(target_user_id, role, granted_by=message.from_user.id)
        except Exception as e:
            print(f"[ERROR] Error granting role {role} to user {target_user_id}: {e}")
            bot.reply_to(message, f"❌ Помилка при видачі ролі: {e}")
            set_user_state(message.from_user.id, None)
            return
        
        user_name = user[1] if user and len(user) > 1 else f"Користувач {target_user_id}"
        
        bot.reply_to(message,
            f"✅ <b>Успішно!</b>\n\n"
            f"👤 Користувач <b>{user_name}</b> (<code>{target_user_id}</code>) отримав роль <b>{role_name}</b>!\n\n"
            f"📱 Користувач побачить кнопку в головному меню після перезапуску бота (/start).",
            parse_mode="HTML"
        )
        
        # Повідомлення користувачу
        try:
            bot.send_message(target_user_id,
                f"🎉 <b>Вітаємо!</b>\n\n"
                f"🎭 <b>Ви отримали роль: {role_name}</b>\n\n"
                f"👑 <b>Видано:</b> Створювач бота\n"
                f"⏰ <b>Час:</b> Зараз\n\n"
                f"📱 Натисніть /start щоб побачити нове меню",
                parse_mode="HTML"
            )
        except Exception as e:
            print(f"[ERROR] Failed to send message to user {target_user_id}: {e}")
            # Не вважаємо це критичною помилкою - роль вже видана
        
        set_user_state(message.from_user.id, None)
        
    except Exception as e:
        print(f"[ERROR] Unexpected error in admin_grant_role_step_handler: {e}")
        import traceback
        traceback.print_exc()
        bot.reply_to(message, f"❌ Помилка: {str(e)}\n\n💡 Перевірте правильність введених даних")
        set_user_state(message.from_user.id, None)

@bot.callback_query_handler(func=lambda c: c.data == "giveaway_manager_menu")
def giveaway_manager_menu_handler(call):
    """Меню менеджера розіграшів"""
    if check_maintenance(call): return
    from database import is_giveaway_manager
    if not is_giveaway_manager(call.from_user.id):
        return bot.answer_callback_query(call.id, "⛔️ Немає доступу", show_alert=True)
    
    from telebot.types import InlineKeyboardMarkup, InlineKeyboardButton
    from database import get_giveaway_limits, get_giveaway_daily_stats, get_user_giveaway_limits
    
    global_limits = get_giveaway_limits()
    user_limits = get_user_giveaway_limits(call.from_user.id)
    stats = get_giveaway_daily_stats(call.from_user.id)
    
