# --- Глобальний pre-check для звичайних повідомлень ---
@bot.message_handler(func=lambda m: (
    not is_admin(m.from_user.id)
    and not is_beta(m.from_user.id)
    and get_maintenance_mode()
    and m.chat.type == 'private'
    and not (
        (getattr(m, 'text', None) and str(m.text).startswith('/'))  # дозволяємо ВСІ команди під час технічних робіт
        or (getattr(m, 'content_type', None) == 'contact')
    )
))
def maintenance_message_block(message):
    global maintenance_messages
    # Видалити попереднє повідомлення, якщо є
    prev_msg_id = maintenance_messages.get(message.from_user.id)
    if prev_msg_id:
        try:
            bot.delete_message(message.chat.id, prev_msg_id)
        except Exception:
            pass  # Якщо вже видалено або не знайдено — ігноруємо
    # Надіслати нове повідомлення
    msg = bot.send_message(
        message.chat.id,
        "<b>🛠 Технічні роботи! 🚫</b>\n\n"
        "Сервіс тимчасово недоступний для користувачів.\n"
        "Ми вдосконалюємо платформу для вашого комфорту та нових можливостей!\n\n"
        "<b>Слідкуйте за оновленнями — повернемось ще кращими! 💹🤖</b>",
        parse_mode="HTML"
    )
    # Запам'ятати message_id
    maintenance_messages[message.from_user.id] = msg.message_id

@bot.callback_query_handler(func=lambda c: c.data == "change_daily_bonus")
def change_daily_bonus_handler(call):
    from database import get_daily_bonus, set_ref_bonus
    current_bonus = get_daily_bonus()
    msg = bot.send_message(call.message.chat.id, f"Введіть нову суму щоденного бонусу (поточна: {current_bonus}):")
    bot.register_next_step_handler(msg, save_new_daily_bonus_step)

def save_new_daily_bonus_step(message):
    from database import set_daily_bonus
    try:
        new_bonus = float(message.text.replace(",", "."))
        if new_bonus < 0:
            raise ValueError
    except ValueError:
        msg = bot.send_message(message.chat.id, "❗ Введіть коректну суму!")
        return bot.register_next_step_handler(msg, save_new_daily_bonus_step)
    set_daily_bonus(new_bonus)
    bot.send_message(message.chat.id, f"✅ Щоденний бонус успішно змінено на {new_bonus}₴.")

@bot.callback_query_handler(func=lambda c: c.data == "change_min_deposit")
def change_min_deposit_handler(call):
    from database import get_min_deposit
    current_min = get_min_deposit()
    msg = bot.send_message(call.message.chat.id, f"Введіть нову мінімальну суму депозиту (поточна: {current_min}):")
    bot.register_next_step_handler(msg, save_new_min_deposit_step)

def save_new_min_deposit_step(message):
    from database import set_min_deposit
    try:
        new_min = float(message.text.replace(",", "."))
        if new_min < 0:
            raise ValueError
    except ValueError:
        msg = bot.send_message(message.chat.id, "❗ Введіть коректну суму!")
        return bot.register_next_step_handler(msg, save_new_min_deposit_step)
    set_min_deposit(new_min)
    bot.send_message(message.chat.id, f"✅ Мінімальний депозит успішно змінено на {new_min}₴.")

# --- Всі створені заявки на вивід ---
@bot.callback_query_handler(func=lambda c: c.data == "withdraw_requests")
def withdraw_requests_handler(call):
    from database import is_admin, is_payout_manager
    if not is_admin(call.from_user.id) and not is_payout_manager(call.from_user.id):
        return bot.answer_callback_query(call.id, "⛔️ Немає доступу", show_alert=True)
    try:
        from database import get_withdrawals_by_status, get_user
    except Exception as e:
        return bot.answer_callback_query(call.id, f"❌ Помилка імпорту: {e}", show_alert=True)
    requests = get_withdrawals_by_status("pending")
    # Пріоритезуємо амбасадорів (@palmaron_bot) зверху списку
    try:
        from database import is_ambassador
        def _is_amb_req(req):
            try:
                return 1 if is_ambassador(req[1]) else 0
            except Exception:
                return 0
        # Сортуємо: спочатку амбасадори (1 -> True), далі інші, зберігаючи початковий порядок між групами
        requests = sorted(requests, key=lambda r: (0 - _is_amb_req(r)))
    except Exception:
        pass
    kb = InlineKeyboardMarkup()
    kb.add(InlineKeyboardButton("🗂 Історія заявок", callback_data="withdraw_history"))
    if not requests:
        try:
            bot.edit_message_text("😴 Немає активних заявок на вивід!", call.message.chat.id, call.message.message_id, reply_markup=kb)
        except Exception:
            bot.send_message(call.message.chat.id, "😴 Немає активних заявок на вивід!", reply_markup=kb)
        return
    for req in requests:
        # tx_id, user_id, amount, comment, status, created_at, processed_at, requisites
        tx_id, user_id, amount, comment, status, created_at, processed_at, requisites = req
        user = get_user(user_id)
        user_name = user[1] if user else "—"
        
        # Форматування дати створення у часовий пояс користувача
        created_time = format_user_time(created_at, user_id)
        
        req_kb = InlineKeyboardMarkup()
        req_kb.add(
            InlineKeyboardButton("✅ Підтвердити", callback_data=f"withdraw_approve_{tx_id}"),
            InlineKeyboardButton("❌ Відхилити", callback_data=f"withdraw_reject_{tx_id}"),
        )
        req_kb.add(InlineKeyboardButton("👤 Переглянути профіль", callback_data=f"admin_view_profile_{user_id}"))
        
        # Отримуємо інформацію про комісію
        try:
            from database import get_effective_withdraw_commission_percent, is_ambassador
            fee_percent = get_effective_withdraw_commission_percent(user_id)
            fee = amount * (fee_percent / 100.0)
            net = amount - fee
            is_amb = is_ambassador(user_id)
            commission_text = f"📊 <b>Комісія:</b> <b>{fee_percent}%</b> → <b>{format_currency(fee)}₴</b>\n💎 <b>До зарахування:</b> <b>{format_currency(net)}₴</b>"
            if is_amb:
                commission_text += "\n💎 <b>Амбасадор: без комісії</b>"
        except Exception as e:
            print(f"[ERROR] Помилка отримання комісії: {e}")
            commission_text = ""
        
        bot.send_message(
            call.message.chat.id,
            f"💸 <b>Заявка на вивід</b> №{tx_id}\n"
            f"👤 <b>Користувач:</b> <code>{user_id}</code> ({user_name})\n"
            f"💰 <b>Сума:</b> <b>{format_currency(amount)}₴</b>\n"
            f"{commission_text}\n"
            f"💳 <b>Реквізити:</b> <code>{requisites or '—'}</code>\n"
            f"📅 <b>Створено:</b> <b>{created_time}</b>\n"
            f"🔄 <b>Статус:</b> <b>⏳ Очікує підтвердження</b>\n\n"
            f"💎 <i>Investing Palmaron Bot — надійний партнер у світі інвестицій</i>",
            reply_markup=req_kb,
            parse_mode="HTML"
        )
    bot.send_message(call.message.chat.id, "Переглянути історію заявок:", reply_markup=kb)

# --- Історія заявок на вивід ---
@bot.callback_query_handler(func=lambda c: c.data == "withdraw_history")
def withdraw_history_handler(call):
    from database import get_withdrawals_by_status, get_user
    admin_id = call.from_user.id
    # --- Видалення попередніх повідомлень з історією ---
    if not hasattr(bot, 'user_data'):
        bot.user_data = {}
    if 'withdraw_history_msgs' in bot.user_data.get(admin_id, {}):
        for msg_id in bot.user_data[admin_id]['withdraw_history_msgs']:
            try:
                bot.delete_message(call.message.chat.id, msg_id)
            except Exception:
                pass
    bot.user_data.setdefault(admin_id, {})['withdraw_history_msgs'] = []
    # --- Формування нової історії ---
    requests = get_withdrawals_by_status("done") + get_withdrawals_by_status("rejected")
    if not requests:
        msg = bot.send_message(call.message.chat.id, "🗂 Історія порожня!")
        bot.user_data[admin_id]['withdraw_history_msgs'].append(msg.message_id)
        return
    for req in requests:
        tx_id, user_id, amount, comment, status, created_at, processed_at, requisites = req
        user = get_user(user_id)
        user_name = user[1] if user else "—"
        status_text = "<b>✅ Успішно</b> 🎉" if status == "done" else "<b>❌ Відхилено</b> 🚫"
        
        # Форматування дати створення у часовий пояс користувача
        created_time = format_user_time(created_at, user_id)
        
        # Форматування дати обробки у часовий пояс користувача
        processed_time = format_user_time(processed_at, user_id)
        
        msg = bot.send_message(
            call.message.chat.id,
            f"<b>🗂 Заявка №{tx_id}</b>\n"
            f"👤 <b>Користувач:</b> <code>{user_id}</code> ({user_name})\n"
            f"💸 <b>Сума:</b> <b>{format_currency(amount)}₴</b>\n"
            f"🏦 <b>Сервіс:</b> <i>{comment or '—'}</i>\n"
            f"💳 <b>Реквізити:</b> <code>{requisites or '—'}</code>\n"
            f"📅 <b>Створено:</b> <b>{created_time}</b>\n"
            f"⚡ <b>Оброблено:</b> <b>{processed_time}</b>\n"
            f"🔄 <b>Статус:</b> {status_text}\n\n"
            f"💎 <i>Investing Palmaron Bot — надійний партнер у світі інвестицій</i>",
            parse_mode="HTML"
        )
        bot.user_data[admin_id]['withdraw_history_msgs'].append(msg.message_id)
    # --- Кнопки повернення та чистки ---
    kb = InlineKeyboardMarkup()
    kb.add(
        InlineKeyboardButton("⬅️ Повернутись в адмінку", callback_data="panel"),
        InlineKeyboardButton("🏠 Головне меню", callback_data="back_home"),
        InlineKeyboardButton("🧹 Очистити історію", callback_data="clear_withdraw_history")
    )
    msg = bot.send_message(call.message.chat.id, "⬅️ Повернутись в адмін‑панель або головне меню:", reply_markup=kb)
    bot.user_data[admin_id]['withdraw_history_msgs'].append(msg.message_id)

