@bot.callback_query_handler(func=lambda c: c.data == "admin_balance_stats")
def admin_balance_stats_handler(call):
    """Показує топ користувачів за балансом"""
    try:
        if check_maintenance(call): return
        if not is_admin(call.from_user.id):
            return bot.answer_callback_query(call.id, "Нема доступу", show_alert=True)
        
        from database import _db
        from utils import get_user_name
        
        # Отримуємо топ користувачів за балансом
        with _db() as con:
            rows = con.execute("""
                SELECT user_id, user_name, balance, username 
                FROM users 
                WHERE balance > 0 
                ORDER BY balance DESC 
                LIMIT 50
            """).fetchall()
        
        if not rows:
            bot.answer_callback_query(call.id)
            edit_or_send(call, "📊 <b>Статистика балансів</b>\n\n❌ Користувачів з балансом не знайдено.", parse_mode="HTML")
            return
        
        # Формуємо повідомлення з топом
        text = "📊 <b>ТОП БАЛАНСІВ</b>\n\n"
        text += "🏆 <b>Топ-50 користувачів за балансом:</b>\n\n"
        
        for idx, (user_id, user_name, balance, username) in enumerate(rows, 1):
            # Форматуємо ім'я користувача
            display_name = user_name if user_name else f"User{user_id}"
            if username:
                display_name = f"@{username}"
            elif user_name:
                # Обрізаємо довгі імена
                display_name = user_name[:20] if len(user_name) > 20 else user_name
            
            # Емодзі для топ-3
            medal = ""
            if idx == 1:
                medal = "🥇"
            elif idx == 2:
                medal = "🥈"
            elif idx == 3:
                medal = "🥉"
            else:
                medal = f"{idx}."
            
            # Форматуємо баланс
            balance_str = f"{balance:.2f}₴"
            if balance >= 1000:
                balance_str = f"{balance/1000:.1f}K₴"
            if balance >= 1000000:
                balance_str = f"{balance/1000000:.1f}M₴"
            
            # Компактний формат
            text += f"{medal} <b>{display_name}</b> — <code>{balance_str}</code> (ID: {user_id})\n"
            
            # Перевіряємо довжину повідомлення (Telegram ліміт ~4096 символів)
            if len(text) > 3500:
                text += f"\n... та ще {len(rows) - idx} користувачів"
                break
        
        # Додаємо загальну статистику
        with _db() as con:
            total_users = con.execute("SELECT COUNT(*) FROM users WHERE balance > 0").fetchone()[0]
            total_balance = con.execute("SELECT SUM(balance) FROM users WHERE balance > 0").fetchone()[0] or 0.0
        
        text += f"\n📈 <b>Загальна статистика:</b>\n"
        text += f"👥 Користувачів з балансом: <b>{total_users}</b>\n"
        text += f"💰 Загальний баланс: <b>{total_balance:.2f}₴</b>"
        
        # Кнопка назад
        kb = InlineKeyboardMarkup()
        kb.add(InlineKeyboardButton("⬅️ Назад", callback_data="panel"))
        
        bot.answer_callback_query(call.id)
        edit_or_send(call, text, reply_markup=kb, parse_mode="HTML")
        
    except Exception as e:
        import traceback
        traceback.print_exc()
        send_admin_error(call, e, where="статистика балансів")

