def process_take_balance_user_step(message):
    if is_cancel_step(message):
        bot.send_message(message.chat.id, "Операцію скасовано.")
        return
    try:
        user_id = int(message.text.strip())
    except ValueError:
        msg = bot.send_message(message.chat.id, "❗ Введіть коректний ID!")
        return bot.register_next_step_handler(msg, process_take_balance_user_step)
    user_row = get_user(user_id)
    if not user_row:
        msg = bot.send_message(message.chat.id, "❌ Користувача не знайдено! Введіть інший ID:")
        return bot.register_next_step_handler(msg, process_take_balance_user_step)
    user_name = user_row[1]
    balance = user_row[2]
    msg = bot.send_message(message.chat.id, f"Введіть <b>суму</b> для зняття у <b>{user_name}</b> (<code>{user_id}</code>):\nБаланс: <b>{format_currency(balance)}₴</b>", parse_mode="HTML")
    bot.register_next_step_handler(msg, process_take_balance_amount_step, user_id, user_name, balance)

def process_take_balance_amount_step(message, user_id, user_name, balance):
    if is_cancel_step(message):
        bot.send_message(message.chat.id, "Операцію скасовано.")
        return
    try:
        amount = float(message.text.replace(",", ".").strip())
        if amount <= 0:
            raise ValueError
    except ValueError:
        msg = bot.send_message(message.chat.id, "❗ Введіть коректну суму!")
        return bot.register_next_step_handler(msg, process_take_balance_amount_step, user_id, user_name, balance)
    if amount > balance:
        msg = bot.send_message(message.chat.id, f"❌ Недостатньо коштів! Баланс користувача: <b>{format_currency(balance)}₴</b>", parse_mode="HTML")
        return bot.register_next_step_handler(msg, process_take_balance_amount_step, user_id, user_name, balance)
    add_balance(user_id, -amount, reason="withdraw", details=f"Вивід коштів")
    bot.send_message(message.chat.id, f"✅ У <b>{user_name}</b> (<code>{user_id}</code>) знято <b>{format_currency(amount)}₴</b>!", parse_mode="HTML")
    try:
        bot.send_message(user_id, f"💸 <b>У вас забрали {format_currency(amount)}₴!</b>", parse_mode="HTML")
    except Exception:
        pass

