def save_new_ref_bonus_step(message):
    try:
        new_bonus = float(message.text.replace(",", "."))
        if new_bonus < 0:
            bot.send_message(message.chat.id, "❌ Бонус не може бути від'ємним. Спробуйте ще раз.")
            return
    except ValueError:
        bot.send_message(message.chat.id, "❌ Будь ласка, введіть коректне число.")
        return
    set_ref_bonus(new_bonus)
    bot.send_message(message.chat.id, f"✅ Реферальний бонус успішно змінено на {new_bonus}₴.")

