def process_add_deposit_user_step(message):
    if is_cancel_step(message):
        bot.send_message(message.chat.id, "Операцію скасовано.")
        return
    try:
        user_id = int(message.text.strip())
    except ValueError:
        msg = bot.send_message(message.chat.id, "❗ Введіть коректний ID!")
        return bot.register_next_step_handler(msg, process_add_deposit_user_step)
    user_row = get_user(user_id)
    if not user_row:
        msg = bot.send_message(message.chat.id, "❌ Користувача не знайдено! Введіть інший ID:")
        return bot.register_next_step_handler(msg, process_add_deposit_user_step)
    user_name = user_row[1]
    msg = bot.send_message(message.chat.id, f"Введіть <b>суму</b> депозиту для <b>{user_name}</b> (<code>{user_id}</code>):", parse_mode="HTML")
    bot.register_next_step_handler(msg, process_add_deposit_amount_step, user_id, user_name)

def process_add_deposit_amount_step(message, user_id, user_name):
    if is_cancel_step(message):
        bot.send_message(message.chat.id, "Операцію скасовано.")
        return
    try:
        amount = float(message.text.replace(",", ".").strip())
        if amount <= 0:
            raise ValueError
    except ValueError:
        msg = bot.send_message(message.chat.id, "❗ Введіть коректну суму!")
        return bot.register_next_step_handler(msg, process_add_deposit_amount_step, user_id, user_name)
    add_deposit(user_id, amount)
    try:
        from database import log_admin_action
        log_admin_action(user_id, message.from_user.id, 'deposit_add', f'+{amount}')
    except Exception:
        pass
    new_deposit = get_deposits_sum(user_id)
    # Повідомлення адміну
    bot.send_message(
                message.chat.id,
        f"✅ Користувачу <b>{user_name}</b> (<code>{user_id}</code>) <b>додано депозит {format_currency(amount)}₴</b>!\n"
        f"Новий депозит: <b>{format_currency(new_deposit)}₴</b>",
                parse_mode="HTML"
            )
    # Повідомлення користувачу
    try:
            bot.send_message(
            user_id,
            f"🏦 <b>Ваш депозит поповнено на {format_currency(amount)}₴!</b>\n"
            f"Новий депозит: <b>{format_currency(new_deposit)}₴</b>",
                parse_mode="HTML"
            )
    except Exception:
        pass
    # Після додавання депозиту — перевірка досягнення
    new_ach = add_achievement_if_needed(user_id, "deposits_total", new_deposit)
    if new_ach:
        try:
            bot.send_message(user_id, f"🏆 <b>Вітаємо! Ви отримали нове досягнення:</b> <code>{new_ach}</code>\n\n<em>Заберіть свою нагороду у профілі!</em>", parse_mode="HTML")
        except Exception:
            pass

