@bot.callback_query_handler(func=lambda c: c.data == "my_pending_withdrawals")
def my_pending_withdrawals_handler(call):
    from database import get_withdrawals_by_status
    user_id = call.from_user.id
    # --- Видалення попередніх повідомлень з заявками ---
    if not hasattr(bot, 'user_data'):
        bot.user_data = {}
    if 'my_pending_withdraw_msgs' in bot.user_data.get(user_id, {}):
        for msg_id in bot.user_data[user_id]['my_pending_withdraw_msgs']:
            try:
                bot.delete_message(call.message.chat.id, msg_id)
            except Exception:
                pass
    bot.user_data.setdefault(user_id, {})['my_pending_withdraw_msgs'] = []
    # --- Показати лише заявки зі статусом pending ---
    requests = [r for r in get_withdrawals_by_status("pending") if r[1] == user_id]
    kb = InlineKeyboardMarkup()
    kb.add(InlineKeyboardButton("🗂 Історія заявок", callback_data="my_withdraw_history"))
    if not requests:
        msg = bot.send_message(call.message.chat.id, "😴 У вас немає активних заявок на вивід!", reply_markup=kb)
        bot.user_data[user_id]['my_pending_withdraw_msgs'].append(msg.message_id)
        return
    for req in requests:
        # Підтримка як старого (7 полів), так і нового (8 полів з requisites) формату
        if len(req) >= 8:
            tx_id, user_id, amount, comment, status, created_at, processed_at, requisites = req
        else:
            tx_id, user_id, amount, comment, status, created_at, processed_at = req
        # Замість статусу 'pending' показуємо 'Очікує підтвердження'
        status_text = "⏳ Очікує підтвердження" if status == "pending" else status
        
        # Форматування дати створення у часовий пояс користувача
        created_time = format_user_time(created_at, user_id)
        
        msg = bot.send_message(
            call.message.chat.id,
            f"⏳ <b>Ваша заявка на вивід</b> №{tx_id}\n"
            f"💰 <b>Сума:</b> <b>{format_currency(amount)}₴</b>\n"
            f"📅 <b>Створено:</b> <b>{created_time}</b>\n"
            f"🔄 <b>Статус:</b> <b>{status_text}</b>\n\n"
            f"💡 Залишайтесь з нами — удача вже поруч! 🍀\n"
            f"💎 <i>Investing Palmaron Bot — надійний партнер у світі інвестицій</i>",
            parse_mode="HTML"
        )
        bot.user_data[user_id]['my_pending_withdraw_msgs'].append(msg.message_id)
    # Кнопка для перегляду історії
    msg = bot.send_message(call.message.chat.id, "Переглянути історію виводів:", reply_markup=kb)
    bot.user_data[user_id]['my_pending_withdraw_msgs'].append(msg.message_id)

@bot.callback_query_handler(func=lambda c: c.data == "my_withdraw_history")
def my_withdraw_history_handler(call):
    from database import get_withdrawals_by_status
    user_id = call.from_user.id
    # --- Видалення попередніх повідомлень з історією ---
    if not hasattr(bot, 'user_data'):
        bot.user_data = {}
    if 'my_withdraw_history_msgs' in bot.user_data.get(user_id, {}):
        for msg_id in bot.user_data[user_id]['my_withdraw_history_msgs']:
            try:
                bot.delete_message(call.message.chat.id, msg_id)
            except Exception:
                pass
    bot.user_data.setdefault(user_id, {})['my_withdraw_history_msgs'] = []
    # --- Формування нової історії ---
    requests = [r for r in get_withdrawals_by_status("done") + get_withdrawals_by_status("rejected") if r[1] == user_id]
    if not requests:
        msg = bot.send_message(call.message.chat.id, "📜 У вас ще немає історії виводів!")
        bot.user_data[user_id]['my_withdraw_history_msgs'].append(msg.message_id)
        return
    for req in requests:
        tx_id, user_id, amount, comment, status, created_at, processed_at, requisites = req
        status_text = "✅ Успішно" if status == "done" else "❌ Відхилено"
        
        # Форматування дати створення у часовий пояс користувача
        created_time = format_user_time(created_at, user_id)
        
        # Форматування дати обробки у часовий пояс користувача
        processed_time = format_user_time(processed_at, user_id)
        
        msg = bot.send_message(
            call.message.chat.id,
            f"📜 <b>Заявка №{tx_id}</b>\n"
            f"💰 <b>Сума:</b> <b>{format_currency(amount)}₴</b>\n"
            f"🏦 <b>Сервіс:</b> <i>{comment or '—'}</i>\n"
            f"💳 <b>Реквізити:</b> <code>{requisites or '—'}</code>\n"
            f"📅 <b>Створено:</b> <b>{created_time}</b>\n"
            f"⚡ <b>Оброблено:</b> <b>{processed_time}</b>\n"
            f"🔄 <b>Статус:</b> {status_text}\n\n"
            f"💎 <i>Investing Palmaron Bot — надійний партнер у світі інвестицій</i>",
            parse_mode="HTML"
        )
        bot.user_data[user_id]['my_withdraw_history_msgs'].append(msg.message_id)

@bot.callback_query_handler(func=lambda c: c.data == "settings")
def settings_handler(call):
    user_id = call.from_user.id
    
    # Перевірка спаму
    is_spam, spam_message = check_button_spam(user_id, "settings")
    if is_spam:
        bot.answer_callback_query(call.id, text=spam_message, show_alert=True)
        return
    
    # Отримуємо поточний часовий пояс користувача
    current_timezone = get_user_timezone(user_id)
    current_time = get_user_current_time(user_id)
    
    # Получаем настройки пользователя
    from database import get_user_setting, set_user_setting
    
    # Получаем текущие настройки
    language = get_user_setting(user_id, 'language', 'uk')
    payout_notifications = get_user_setting(user_id, 'payout_notifications', '1') == '1'
    success_gif = get_user_setting(user_id, 'success_gif', '1') == '1'
    
