@bot.callback_query_handler(func=lambda c: c.data == "toggle_language")
def toggle_language_handler(call):
    user_id = call.from_user.id
    from database import get_user_setting, set_user_setting
    
    current_lang = get_user_setting(user_id, 'language', 'uk')
    new_lang = 'ru' if current_lang == 'uk' else 'uk'
    set_user_setting(user_id, 'language', new_lang)
    
    bot.answer_callback_query(call.id, f"🌍 Мова змінена на {'🇺🇦 Українська' if new_lang == 'uk' else '🇷🇺 Русский'}")
    return settings_handler(call)

@bot.callback_query_handler(func=lambda c: c.data == "toggle_payout_notifications")
def toggle_payout_notifications_handler(call):
    user_id = call.from_user.id
    from database import get_user_setting, set_user_setting, get_garden_level
    
    current = get_user_setting(user_id, 'payout_notifications', '1') == '1'
    
    # Проверяем уровень сада для отключения уведомлений
    if not current:  # Если пытаемся включить - всегда можно
        new_value = '1'
        set_user_setting(user_id, 'payout_notifications', new_value)
        bot.answer_callback_query(call.id, "🔔 Сповіщення про виплати увімкнено")
    else:  # Если пытаемся отключить - проверяем уровень сада
        garden_level = get_garden_level(user_id)
        if garden_level >= 4:
            new_value = '0'
            set_user_setting(user_id, 'payout_notifications', new_value)
            bot.answer_callback_query(call.id, "🔔 Сповіщення про виплати вимкнено")
        else:
            bot.answer_callback_query(call.id, "❌ Вимкнути сповіщення можна тільки з 4+ рівня сада", show_alert=True)
            return settings_handler(call)
    
    return settings_handler(call)

