def get_chat_name(chat_id):
    """Получает название канала/чата по ID"""
    try:
        chat_info = bot.get_chat(chat_id)
        if chat_info.username:
            return f"@{chat_info.username}"
        return chat_info.title or f"Канал {chat_id}"
    except Exception as e:
        print(f"[WARNING] Не удалось получить название канала/чата {chat_id}: {e}")
        return f"Канал {chat_id}"

def get_chat_link(chat_id):
    """Формирует ссылку для перехода к каналу/чату"""
    try:
        chat_info = bot.get_chat(chat_id)
        if chat_info.username:
            return f"https://t.me/{chat_info.username}"
        # Для каналов/чатов без username используем формат c/channel_id
        # Убираем минус и первые 4 цифры (1000) для супергрупп
        channel_id_str = str(chat_id)
        if channel_id_str.startswith('-100'):
            # Формат для супергрупп: -1001234567890 -> c/1234567890
            pure_id = channel_id_str[4:]
            return f"https://t.me/c/{pure_id}"
        elif channel_id_str.startswith('-'):
            # Для обычных групп: -123456789 -> c/123456789
            pure_id = channel_id_str[1:]
            return f"https://t.me/c/{pure_id}"
        else:
            # Для публичных каналов с ID
            return f"https://t.me/c/{channel_id_str}"
    except Exception as e:
        print(f"[WARNING] Не удалось сформировать ссылку для {chat_id}: {e}")
        # Fallback - используем формат c/ для супергрупп
        channel_id_str = str(chat_id)
        if channel_id_str.startswith('-100'):
            pure_id = channel_id_str[4:]
            return f"https://t.me/c/{pure_id}"
        return f"https://t.me/c/{channel_id_str}"

@bot.callback_query_handler(func=lambda c: c.data == "tasks")
@ban_check
@subscription_required
@phone_required
def tasks_handler(call):
    """Обработчик кнопки Завдання"""
    user_id = call.from_user.id
    
    # Перевірка спаму
    is_spam, spam_message = check_button_spam(user_id, "tasks")
    if is_spam:
        bot.answer_callback_query(call.id, text=spam_message, show_alert=True)
        return
    
    from database import get_active_tasks, get_user_tasks_stats, get_user_task_completions
    
    # Получаем статистику пользователя
    stats = get_user_tasks_stats(user_id)
    
    # Получаем доступные задания
    available_tasks = get_active_tasks(user_id)
    
    # Получаем последние выполнения
    recent_completions = get_user_task_completions(user_id, limit=5)
    
    text = (
        f"📋 <b>ЗАВДАННЯ</b>\n"
        f"━━━━━━━━━━━━━━━━━━\n\n"
        f"📊 <b>Ваша статистика:</b>\n"
        f"├ ✅ Виконано завдань: <b>{stats['completed_count']}</b>\n"
        f"└ 💰 Отримано нагород: <b>{stats['total_rewards']:.2f} ₴</b>\n\n"
    )
    
    if available_tasks:
        text += f"🎯 <b>Доступні завдання ({len(available_tasks)}):</b>\n\n"
        
        # Показываем первые 5 заданий
        for i, task in enumerate(available_tasks[:5], 1):
            task_type_emoji = {
                'subscribe_channel': '📢',
                'subscribe_chat': '💬',
                'invite_users': '👥',
                'deposit': '💵',
                'buy_tree': '🌳',
                'harvest': '🍎',
                'sell_fruits': '💰'
            }.get(task['task_type'], '📋')
            
            task_type_name = get_task_type_name_uk(task['task_type'])
            
            # Формируем детали задания в зависимости от типа
            task_details = ""
            task_data = task.get('task_data', {})
            if task['task_type'] == 'subscribe_channel':
                channel_id = task_data.get('channel_id', '')
                channel_name = get_chat_name(channel_id)
                task_details = f"Підписатися на канал: <b>{channel_name}</b>"
            elif task['task_type'] == 'subscribe_chat':
                chat_id = task_data.get('chat_id', '')
                chat_name = get_chat_name(chat_id)
                task_details = f"Приєднатися до чату: <b>{chat_name}</b>"
            elif task['task_type'] == 'invite_users':
                count = task_data.get('count', 0)
                task_details = f"Запросити <b>{count}</b> друзів"
            elif task['task_type'] == 'deposit':
                amount = task_data.get('amount', 0)
                task_details = f"Поповнити баланс на суму від <b>{amount:.2f} ₴</b>"
            elif task['task_type'] == 'buy_tree':
                tree_type = task_data.get('tree_type', '')
                tree_names = {'apple': 'Яблуня', 'pear': 'Груша', 'cherry': 'Вишня', 'peach': 'Персик'}
                tree_name = tree_names.get(tree_type, tree_type)
                task_details = f"Купити дерево: <b>{tree_name}</b>"
            elif task['task_type'] == 'harvest':
                count = task_data.get('count', 0)
                task_details = f"Зібрати урожай <b>{count}</b> разів"
            elif task['task_type'] == 'sell_fruits':
                amount = task_data.get('amount', 0)
                task_details = f"Продати фрукты на суму від <b>{amount:.2f} ₴</b>"
            
            max_completions_text = ""
            if task['max_completions']:
                max_completions_text = f" (Виконань: <b>{task['current_completions']}/{task['max_completions']}</b>)"
            
            description = task.get('description')
            description_text = f"\n   📝 <i>{description}</i>" if description else ""
            
            text += (
                f"{i}. {task_type_emoji} <b>{task['title']}</b>\n"
                f"   🏷 Тип: <b>{task_type_name}</b>\n"
                f"   💰 Нагорода: <b>{task['reward_amount']:.2f} ₴</b>{max_completions_text}\n"
                f"   📋 Умова: {task_details}{description_text}\n\n"
            )
        
        if len(available_tasks) > 5:
            text += f"<i>... та ще {len(available_tasks) - 5} завдань</i>\n\n"
    else:
        text += "😴 <i>Наразі немає доступних завдань</i>\n\n"
    
    if recent_completions:
        text += f"📜 <b>Останні виконання:</b>\n"
        import time
        for completion in recent_completions[:3]:
            date_str = time.strftime('%d.%m %H:%M', time.localtime(completion['completed_at']))
            text += f"• {completion['task_title']} — <b>{completion['reward_received']:.2f} ₴</b> ({date_str})\n"
        text += "\n"
    
    kb = InlineKeyboardMarkup(row_width=1)
    if available_tasks:
        kb.add(InlineKeyboardButton("📋 Доступні завдання", callback_data="tasks_available"))
    kb.add(InlineKeyboardButton("📜 Мої виконання", callback_data="tasks_my_completions"))
    kb.add(InlineKeyboardButton("⬅️ Назад", callback_data="cabinet"))
    
    try:
        send_banner_with_caption(call.message.chat.id, "Завдання", "📋", text, reply_markup=kb, parse_mode="HTML", subtitle="Система нагород")
    except Exception:
        bot.send_message(call.message.chat.id, text, reply_markup=kb, parse_mode="HTML")
    
    bot.answer_callback_query(call.id)

