@bot.callback_query_handler(func=lambda c: c.data.startswith("task_check:"))
@ban_check
@subscription_required
@phone_required
def task_check_handler(call):
    """Обработчик проверки выполнения задания (для всех типов заданий)"""
    user_id = call.from_user.id
    
    try:
        task_id = int(call.data.split(":")[1])
    except ValueError:
        bot.answer_callback_query(call.id, "❌ Помилка", show_alert=True)
        return
    
    from database import get_task_by_id, complete_task, add_balance, get_user_task_completions
    from telebot.types import InlineKeyboardMarkup, InlineKeyboardButton
    from database import get_ref_count, _db
    
    task = get_task_by_id(task_id)
    
    if not task:
        bot.answer_callback_query(call.id, "❌ Завдання не знайдено", show_alert=True)
        return
    
    # Проверяем, не выполнял ли пользователь уже это задание
    completions = get_user_task_completions(user_id, limit=1000)
    if any(c['task_id'] == task_id for c in completions):
        bot.answer_callback_query(call.id, "✅ Ви вже виконали це завдання", show_alert=True)
        return
    
    bot.answer_callback_query(call.id, "⏳ Перевіряємо виконання...")
    
    task_data = task.get('task_data', {})
    task_type = task['task_type']
    is_completed = False
    check_message = ""
    
    # Проверяем выполнение в зависимости от типа задания
    if task_type == 'subscribe_channel':
        channel_id = task_data.get('channel_id')
        if channel_id:
            try:
                member = bot.get_chat_member(chat_id=channel_id, user_id=user_id)
                if member.status not in ['left', 'kicked']:
                    is_completed = True
                else:
                    channel_name = get_chat_name(channel_id)
                    channel_link = get_chat_link(channel_id)
                    check_message = f"❌ Підпишіться на канал <b>{channel_name}</b>"
            except Exception as e:
                check_message = "❌ Помилка перевірки підписки"
    
    elif task_type == 'subscribe_chat':
        chat_id = task_data.get('chat_id')
        if chat_id:
            try:
                member = bot.get_chat_member(chat_id=chat_id, user_id=user_id)
                if member.status not in ['left', 'kicked']:
                    is_completed = True
                else:
                    chat_name = get_chat_name(chat_id)
                    chat_link = get_chat_link(chat_id)
                    check_message = f"❌ Приєднайтесь до чату <b>{chat_name}</b>"
            except Exception as e:
                check_message = "❌ Помилка перевірки участі в чаті"
    
    elif task_type == 'invite_users':
        required_count = task_data.get('count', 0)
        ref_count = get_ref_count(user_id)
        if ref_count >= required_count:
            is_completed = True
        else:
            check_message = f"❌ Потрібно запросити {required_count} друзів. У вас: {ref_count}"
    
    elif task_type == 'deposit':
        required_amount = task_data.get('amount', 0)
        # Проверяем общую сумму депозитов пользователя
        from database import get_deposits_sum
        total_deposits = get_deposits_sum(user_id)
        if total_deposits >= required_amount:
            is_completed = True
        else:
            check_message = f"❌ Потрібно поповнити баланс на {required_amount:.2f} ₴. Поповнено: {total_deposits:.2f} ₴"
    
    elif task_type == 'buy_tree':
        required_tree_type = task_data.get('tree_type', '')
        # Проверяем наличие дерева нужного типа
        from database import get_user_trees
        trees = get_user_trees(user_id)
        user_has_tree = any(t['type'] == required_tree_type for t in trees)
        if user_has_tree:
            is_completed = True
        else:
            tree_names = {'apple': 'Яблуня', 'pear': 'Груша', 'cherry': 'Вишня', 'peach': 'Персик'}
            tree_name = tree_names.get(required_tree_type, required_tree_type)
            check_message = f"❌ Потрібно купити дерево: {tree_name}"
    
    elif task_type == 'harvest':
        required_count = task_data.get('count', 0)
        # Подсчитываем количество сборов урожая
        harvest_count = 0
        with _db() as con:
            result = con.execute("""
                SELECT COUNT(*) FROM garden_transactions 
                WHERE user_id = ? AND type = 'harvest'
            """, (user_id,)).fetchone()
            harvest_count = result[0] if result else 0
        
        if harvest_count >= required_count:
            is_completed = True
        else:
            check_message = f"❌ Потрібно зібрати урожай {required_count} разів. Зібрано: {harvest_count}"
    
    elif task_type == 'sell_fruits':
        required_amount = task_data.get('amount', 0)
        # Получаем общую сумму продаж
        total_sold = 0.0
        with _db() as con:
            result = con.execute("""
                SELECT COALESCE(SUM(amount), 0) FROM garden_transactions 
                WHERE user_id = ? AND type = 'sale'
            """, (user_id,)).fetchone()
            total_sold = float(result[0]) if result else 0.0
        
        if total_sold >= required_amount:
            is_completed = True
        else:
            check_message = f"❌ Потрібно продати фрукты на {required_amount:.2f} ₴. Продано: {total_sold:.2f} ₴"
    
    # Если задание выполнено - выдаем награду
    if is_completed:
        if complete_task(task_id, user_id, task['reward_amount'], 
                        proof_data={'checked_via': 'manual_check', 'task_type': task_type}):
            # Добавляем награду
            if task['reward_type'] == 'balance':
                add_balance(user_id, task['reward_amount'], reason='task_completion',
                           details=f'Завдання: {task["title"]}')
            
            task_type_name = get_task_type_name_uk(task_type)
            
            bot.edit_message_text(
                f"✅ <b>ЗАВДАННЯ ВИКОНАНО!</b>\n\n"
                f"📋 <b>{task['title']}</b>\n"
                f"🏷 <b>Тип:</b> {task_type_name}\n"
                f"💰 <b>Нагорода:</b> <b>{task['reward_amount']:.2f} ₴</b>\n\n"
                f"🎉 <b>Вітаємо! Кошти зараховано на баланс.</b>",
                call.message.chat.id,
                call.message.message_id,
                parse_mode="HTML"
            )
            
            bot.answer_callback_query(
                call.id,
                f"✅ Завдання виконано! Отримано {task['reward_amount']:.2f} ₴",
                show_alert=True
            )
        else:
            bot.answer_callback_query(call.id, "❌ Помилка виконання завдання", show_alert=True)
    else:
        # Задание не выполнено - показываем сообщение с кнопками
        kb = InlineKeyboardMarkup(row_width=1)
        
        # Добавляем кнопки перехода для заданий подписки
        if task_type == 'subscribe_channel':
            channel_id = task_data.get('channel_id')
            if channel_id:
                channel_link = get_chat_link(channel_id)
                channel_name = get_chat_name(channel_id)
                kb.add(InlineKeyboardButton(
                    f"📢 Перейти до каналу: {channel_name[:25]}",
                    url=channel_link
                ))
        elif task_type == 'subscribe_chat':
            chat_id = task_data.get('chat_id')
            if chat_id:
                chat_link = get_chat_link(chat_id)
                chat_name = get_chat_name(chat_id)
                kb.add(InlineKeyboardButton(
                    f"💬 Перейти до чату: {chat_name[:25]}",
                    url=chat_link
                ))
        
        # Добавляем кнопку проверки повторно
        kb.add(InlineKeyboardButton(
            "🔄 Перевірити ще раз",
            callback_data=f"task_check:{task_id}"
        ))
        kb.add(InlineKeyboardButton("⬅️ Назад", callback_data="tasks_available"))
        
        # Формируем сообщение об ошибке
        error_text = check_message if check_message else "❌ Завдання ще не виконано"
        
        bot.edit_message_text(
            f"❌ <b>ЗАВДАННЯ НЕ ВИКОНАНО</b>\n\n"
            f"📋 <b>{task['title']}</b>\n\n"
            f"{error_text}\n\n"
            f"<i>Виконайте умову завдання та натисніть 'Перевірити ще раз'</i>",
            call.message.chat.id,
            call.message.message_id,
            reply_markup=kb,
            parse_mode="HTML"
        )
        bot.answer_callback_query(call.id, error_text, show_alert=True)

