# Захист від дублювання кроку виводу
withdraw_in_progress = set()

@bot.callback_query_handler(func=lambda c: c.data.startswith("withdraw_service_"))
def withdraw_service_handler(call):
    user_id = call.from_user.id
    # Захист від дублювання
    if user_id in withdraw_in_progress:
        bot.answer_callback_query(call.id, "Ви вже обрали спосіб виводу. Дочекайтесь завершення!", show_alert=True)
        return
    withdraw_in_progress.add(user_id)
    # Перевірка спаму
    is_spam, spam_message = check_button_spam(user_id, "withdraw_service")
    if is_spam:
        withdraw_in_progress.discard(user_id)
        bot.answer_callback_query(call.id, text=spam_message, show_alert=True)
        return
    service = call.data.replace("withdraw_service_", "")
    if service == "Back":
        withdraw_in_progress.discard(user_id)
        return back_home_handler(call)
    services = {"PrivatBank": "ПриватБанк", "Monobank": "МоноБанк", "Other": "Інше"}
    service_name = services.get(service, "Інше")
    min_withdraw = get_min_withdraw()
    
    # Показываем информацию о доступном лимите вывода
    from database import get_deposits_sum, get_withdrawn_total
    user_row = get_user(user_id)
    current_balance = user_row[2] if user_row else 0
    total_deposited = get_deposits_sum(user_id)
    total_withdrawn = get_withdrawn_total(user_id)
    
    limit_info = ""
    if total_deposited > 0:
        profit = max(0, current_balance + total_withdrawn - total_deposited)
        PROFIT_WITHDRAW_PERCENT = 0.6
        remaining_deposit = max(0, total_deposited - total_withdrawn)
        available_profit = profit * PROFIT_WITHDRAW_PERCENT
        max_available = remaining_deposit + available_profit
        
        limit_info = (
            f"\n"
            f"📊 <b>Доступно до виводу:</b> <b>{format_currency(max_available)}₴</b>\n"
            f"   └ Депозит: {format_currency(remaining_deposit)}₴\n"
            f"   └ Прибуток (60%): {format_currency(available_profit)}₴\n"
        )
    
    msg = bot.send_message(
        call.message.chat.id,
        "💳 <b>Ви обрали спосіб виводу:</b> <b>{}</b>\n\n"
        "💸 <b>Введіть суму для виводу (грн):</b>\n"
        "💰 Приклад: <code>200</code>\n\n"
        "🔒 <i>Швидка обробка заявок 24/7!</i>\n"
        "📊 <b>Мінімальна сума виводу:</b> <code>{}₴</code>{}\n\n"
        "🌟 <b>Введіть суму у відповідь на це повідомлення:</b>".format(service_name, min_withdraw, limit_info),
        parse_mode="HTML",
    )
    bot.register_next_step_handler(msg, process_withdraw_amount_step, service_name)

def process_withdraw_amount_step(message, service_name):
    user_id = message.from_user.id
    if is_cancel_step(message):
        bot.send_message(message.chat.id, "Операцію скасовано.")
        withdraw_in_progress.discard(user_id)
        return
    try:
        amount = float(message.text.replace(",", ".").strip())
        if amount <= 0:
            raise ValueError
        min_withdraw = get_min_withdraw()
        if amount < min_withdraw:
            msg = bot.send_message(message.chat.id, f"❗ Мінімальна сума для виводу: <b>{format_currency(min_withdraw)}₴</b>! Введіть більшу суму.", parse_mode="HTML")
            return bot.register_next_step_handler(msg, process_withdraw_amount_step, service_name)
    except ValueError:
        msg = bot.send_message(message.chat.id, "❗ Введіть коректну суму!")
        return bot.register_next_step_handler(msg, process_withdraw_amount_step, service_name)
    
    # Перевірка верифікації та лімітів
    from database import get_user_verification_status, analyze_suspicious_activity, is_user_verified
    verification_info = get_user_verification_status(user_id)
    is_verified = is_user_verified(user_id)
    
    # Ліміти для неверифікованих користувачів
    MAX_WITHDRAW_UNVERIFIED = 500.0  # Максимум 500₴ для неверифікованих
    MAX_DAILY_WITHDRAW_UNVERIFIED = 1000.0  # Максимум 1000₴ на добу для неверифікованих
    
    if not is_verified:
        # Перевірка ліміту на одну транзакцію
        if amount > MAX_WITHDRAW_UNVERIFIED:
            bot.send_message(
                message.chat.id,
                f"⚠️ <b>ОБМЕЖЕННЯ ВИВОДУ</b>\n\n"
                f"Для неверифікованих користувачів максимальна сума виводу: <b>{format_currency(MAX_WITHDRAW_UNVERIFIED)}₴</b>\n\n"
                f"💡 <b>Для збільшення ліміту:</b>\n"
                f"1. Перейдіть у кабінет\n"
                f"2. Натисніть \"🛡️ Пройти верифікацію\"\n"
                f"3. Заповніть форму\n\n"
                f"Після верифікації ви зможете виводити більші суми!",
                parse_mode="HTML"
            )
            withdraw_in_progress.discard(user_id)
            return
        
        # Перевірка добового ліміту
        from database import get_withdrawals_by_status
        import time
        today_start = int(time.time()) - (time.time() % 86400)
        today_withdrawals = [
            w for w in get_withdrawals_by_status('approved') 
            if w[1] == user_id and w[4] >= today_start
        ]
        today_total = sum(float(w[2]) for w in today_withdrawals)
        
        if today_total + amount > MAX_DAILY_WITHDRAW_UNVERIFIED:
            remaining = MAX_DAILY_WITHDRAW_UNVERIFIED - today_total
            bot.send_message(
                message.chat.id,
                f"⚠️ <b>ДОБОВИЙ ЛІМІТ ВИЧЕРПАНО</b>\n\n"
                f"Для неверифікованих користувачів добовий ліміт: <b>{format_currency(MAX_DAILY_WITHDRAW_UNVERIFIED)}₴</b>\n"
                f"Ви вже вивели сьогодні: <b>{format_currency(today_total)}₴</b>\n"
                f"Залишилось: <b>{format_currency(max(0, remaining))}₴</b>\n\n"
                f"💡 Пройдіть верифікацію для збільшення лімітів!",
                parse_mode="HTML"
            )
            withdraw_in_progress.discard(user_id)
            return
    
    # Аналіз підозрілої активності перед виводом
    suspicious_score, suspicious_reasons = analyze_suspicious_activity(user_id)
    
    # Якщо підозріла активність висока - блокуємо вивід
    if suspicious_score >= 70:
        bot.send_message(
            message.chat.id,
            f"🚫 <b>ВИВІД ЗАБЛОКОВАНО</b>\n\n"
            f"Виявлено підозрілу активність вашого акаунту.\n\n"
            f"⚠️ <b>Оцінка ризику:</b> {suspicious_score}/100\n\n"
            f"💡 <b>Що робити:</b>\n"
            f"1. Пройдіть верифікацію з кабінету\n"
            f"2. Зверніться до підтримки для уточнення\n\n"
            f"Після перевірки вивід буде відновлено.",
            parse_mode="HTML"
        )
        withdraw_in_progress.discard(user_id)
        return
    
    user_row = get_user(user_id)
    if not user_row or user_row[2] < amount:
        bot.send_message(message.chat.id, f"❌ Недостатньо коштів! Ваш баланс: <b>{format_currency(user_row[2] if user_row else 0)}₴</b>", parse_mode="HTML")
        withdraw_in_progress.discard(user_id)
        return
    
    # Проверка: можно вывести депозит + процент від прибутку
    from database import get_deposits_sum, get_withdrawn_total
    total_deposited = get_deposits_sum(user_id)
    total_withdrawn = get_withdrawn_total(user_id)
    current_balance = user_row[2] if user_row else 0
    
    # Рассчитываем прибыль: баланс + виведено - депозити (не може бути від'ємною)
    profit = max(0, current_balance + total_withdrawn - total_deposited)
    
    # Базовий відсоток прибутку, який можна вивести
    PROFIT_WITHDRAW_PERCENT = 0.6
    # Якщо депозитів ще не було — дозволяємо виводити 100% бонусів (розіграші, рефералка тощо)
    if total_deposited <= 0:
        PROFIT_WITHDRAW_PERCENT = 1.0
    
    # Остаток депозита, который можно вывести
    remaining_deposit = max(0, total_deposited - total_withdrawn)
    
    # Доступная прибыль к выводу (60% от прибыли)
    available_profit = profit * PROFIT_WITHDRAW_PERCENT
    
    # Максимально доступно к выводу = остаток депозита + доступная прибыль
    max_available = remaining_deposit + available_profit
    
    # Проверяем, что запрошенная сумма не превышает доступный лимит
    if amount > max_available:
        bot.send_message(
            message.chat.id,
            f"❌ <b>Перевищення ліміту виводу!</b>\n\n"
            f"💰 <b>Поповнено:</b> {format_currency(total_deposited)}₴\n"
            f"📤 <b>Вже виведено:</b> {format_currency(total_withdrawn)}₴\n"
            f"💵 <b>Зароблено прибутку:</b> {format_currency(profit)}₴\n"
            f"💎 <b>Доступно до виводу:</b> {format_currency(max_available)}₴\n"
            f"   └ Депозит: {format_currency(remaining_deposit)}₴\n"
            f"   └ Прибуток (60%): {format_currency(available_profit)}₴\n\n"
            f"⚠️ Ви можете вивести депозит + 60% від заробленої прибутку.\n"
            f"💡 Поповніть баланс або заробіть більше для збільшення ліміту!",
            parse_mode="HTML"
        )
        withdraw_in_progress.discard(user_id)
        return
    
    from database import get_effective_withdraw_commission_percent
    fee_percent = get_effective_withdraw_commission_percent(user_id)
    fee = amount * (fee_percent / 100.0)
    net = amount - fee
    
    # Показываем информацию о доступном лимите вывода
    remaining_after_withdraw = max_available - amount
    limit_info = f"\n📊 <b>Залишиться доступно до виводу:</b> {format_currency(max(0, remaining_after_withdraw))}₴\n"
    
    msg = bot.send_message(
        message.chat.id,
        f"<b>💳 Введіть реквізити для виводу</b>\n\n"
        f"💸 <b>Сума виводу:</b> <b>{format_currency(amount)}₴</b>\n"
        f"📊 <b>Комісія:</b> {fee_percent}% → <b>{format_currency(fee)}₴</b>\n"
        f"💎 <b>До зарахування:</b> <b>{format_currency(net)}₴</b>{limit_info}\n"
        f"<b>Вкажіть номер картки українського банку!</b> 🇺🇦\n"
        f"<b>• Мінімум 16 цифр</b> (наприклад, <code>5375 4141 1234 5678</code>)\n"
        f"<b>• Тільки картки українських банків</b> (ПриватБанк, МоноБанк тощо)\n\n"
        f"Введіть номер картки у відповідь на це повідомлення.",
        parse_mode="HTML",
    )
    bot.register_next_step_handler(msg, process_withdraw_requisites_step, service_name, amount)
    withdraw_in_progress.discard(user_id)

