def process_withdraw_requisites_step(message, service_name, amount):
    requisites = message.text.strip()
    digits = ''.join(filter(str.isdigit, requisites))
    if len(digits) < 16:
        msg = bot.send_message(
            message.chat.id,
            "❗ <b>Введіть коректні реквізити!</b>\n\n"
            "💳 Вкажіть номер картки українського банку (мінімум 16 цифр).\n"
            "🇺🇦 <b>Тільки картки українських банків!</b>\n\n"
            "Наприклад: <code>5375 4141 1234 5678</code>\n\n"
            "Будь ласка, перевірте уважно та спробуйте ще раз.",
            parse_mode="HTML",
        )
        return bot.register_next_step_handler(msg, process_withdraw_requisites_step, service_name, amount)
    user_id = message.from_user.id
    user_row = get_user(user_id)
    balance_before = user_row[2] if user_row else 0
    balance_after = max(0, balance_before - amount)
    pretty_card = ' '.join([digits[max(i-4,0):i] for i in range(4, len(digits)+4, 4)]) if len(digits) >= 16 else requisites
    kb = InlineKeyboardMarkup(row_width=1)
    kb.add(
        InlineKeyboardButton("✅ Підтвердити вивід", callback_data=f"confirm_withdraw_{service_name}_{amount}_{digits}"),
        InlineKeyboardButton("❌ Скасувати", callback_data="cancel_withdraw"),
    )
    # Вираховуємо комісію для прозорості перед підтвердженням
    from database import get_effective_withdraw_commission_percent, is_ambassador
    fee_percent = get_effective_withdraw_commission_percent(user_id)
    fee = amount * (fee_percent / 100.0)
    net = amount - fee
    amb_line = "\n💎 Амбасадор: без комісії" if is_ambassador(user_id) else ""
    bot.send_message(
        message.chat.id,
        f"🔎 <b>ПЕРЕВІРТЕ ДАНІ ПЕРЕД ПІДТВЕРДЖЕННЯМ</b>\n"
        f"💰 <b>Сума:</b> <b>{format_currency(amount)}₴</b>\n"
        f"📊 <b>Комісія:</b> <b>{fee_percent}%</b> → <b>{format_currency(fee)}₴</b>{amb_line}\n"
        f"💎 <b>До зарахування:</b> <b>{format_currency(net)}₴</b>\n"
        f"🏦 <b>Сервіс:</b> <b>{service_name}</b>\n"
        f"💳 <b>Реквізити:</b> <code>{pretty_card}</code>\n"
        f"🧾 <b>Баланс:</b> {format_currency(balance_before)}₴ → <b>{format_currency(balance_after)}₴</b>\n\n"
        f"✅ Якщо все вірно — натисніть <b>Підтвердити вивід</b>.",
        reply_markup=kb,
        parse_mode="HTML",
    )

@bot.callback_query_handler(func=lambda c: c.data.startswith("withdraw_approve_"))
def withdraw_approve_handler(call):
    """Підтвердження виводу адміністратором з постом у канал як раніше (без повторного списання)."""
    from database import is_admin, is_payout_manager
    if not is_admin(call.from_user.id) and not is_payout_manager(call.from_user.id):
        return bot.answer_callback_query(call.id, "⛔️ Немає доступу", show_alert=True)
    try:
        tx_id = int(call.data.split("_", 2)[2])
    except Exception:
        return bot.answer_callback_query(call.id, "❌ Невірний ID заявки", show_alert=True)

    from database import get_withdrawal_by_id, _db, get_withdraw_channel, get_user, check_payout_limits, increment_payout_daily_stats, is_bot_creator
    import datetime, html

    req = get_withdrawal_by_id(tx_id)
    if not req:
        return bot.answer_callback_query(call.id, "❌ Заявку не знайдено!", show_alert=True)

    # Підтримка нового формату (з requisites)
    if len(req) >= 8:
        tx_id, user_id, amount, comment, status, created_at, processed_at, requisites = req
    else:
        tx_id, user_id, amount, comment, status, created_at, processed_at = req
        requisites = None

    if status != 'pending':
        return bot.answer_callback_query(call.id, "⚠️ Заявка вже оброблена!", show_alert=True)

    # Перевірка лімітів для менеджерів виплат (не для повних адмінів)
    if is_payout_manager(call.from_user.id) and not is_admin(call.from_user.id):
        is_valid, error_msg, needs_approval = check_payout_limits(call.from_user.id, amount)
        
        if not is_valid:
            from telebot.types import InlineKeyboardMarkup, InlineKeyboardButton
            kb = InlineKeyboardMarkup()
            kb.add(InlineKeyboardButton("⬅️ Назад", callback_data="withdraw_requests"))
            bot.send_message(call.message.chat.id, f"❌ <b>Помилка:</b> {error_msg}", reply_markup=kb, parse_mode="HTML")
            return bot.answer_callback_query(call.id, error_msg, show_alert=True)
        
        # Якщо потрібне підтвердження, запитуємо у створювача бота
        if needs_approval:
            from telebot.types import InlineKeyboardMarkup, InlineKeyboardButton
            kb = InlineKeyboardMarkup()
            kb.add(InlineKeyboardButton("✅ Підтвердити", callback_data=f"payout_approve_confirm:{tx_id}"))
            kb.add(InlineKeyboardButton("❌ Скасувати", callback_data="withdraw_requests"))
            bot.send_message(call.message.chat.id,
                f"⚠️ <b>Потрібне підтвердження!</b>\n\n"
                f"Сума виплати <b>{amount}₴</b> перевищує поріг підтвердження.\n"
                f"Виплата буде одобрена після підтвердження створювачем бота.",
                reply_markup=kb,
                parse_mode="HTML"
            )
            return bot.answer_callback_query(call.id, "Потрібне підтвердження створювача бота", show_alert=True)

    # Позначаємо як виконано (баланс списано при створенні заявки)
    try:
        now_db = datetime.datetime.now().strftime("%Y-%m-%d %H:%M:%S")
        with _db() as con:
            con.execute("UPDATE tx SET status='done', processed_at=? WHERE tx_id=? AND status='pending'", (now_db, tx_id))
            con.commit()
    except Exception as e:
        return bot.answer_callback_query(call.id, f"❌ Помилка підтвердження: {e}", show_alert=True)

    # Дані користувача для повідомлень
    user_info = get_user(user_id)
    user_name = (user_info[1] if user_info else None) or "Користувач"
    user_balance = user_info[2] if user_info else 0
    total_withdrawn = user_info[3] if user_info and len(user_info) > 3 else 0

    # Використовуємо час обробки з бази даних (now_db) замість поточного часу
    try:
        # Конвертуємо формат часу з БД в читабельний формат
        processed_datetime = datetime.datetime.strptime(now_db, "%Y-%m-%d %H:%M:%S")
        now_human = processed_datetime.strftime("%d.%m.%Y %H:%M")
    except Exception:
        # Якщо помилка - використовуємо поточний час як запасний варіант
        now_human = datetime.datetime.now().strftime("%d.%m.%Y %H:%M")
    
    try:
        created_time = parse_created_at(created_at)
    except Exception:
        created_time = "—"

    # Отримуємо інформацію про комісію та статус амбассадора
    from database import get_effective_withdraw_commission_percent, is_ambassador
    fee_percent = get_effective_withdraw_commission_percent(user_id)
    fee = amount * (fee_percent / 100.0)
    net = amount - fee
    is_amb = is_ambassador(user_id)

    # Оновлюємо поле "всього виведено" і публікація у канал
    try:
        channel_id = get_withdraw_channel()
    except Exception:
        channel_id = None
    # Оновлюємо статистику користувача (total withdrawn) — додаємо суму виводу
    try:
        from database import set_withdrawn_total
        set_withdrawn_total(user_id, float(total_withdrawn) + float(amount))
    except Exception:
        pass
    
    # Оновлюємо статистику для менеджерів виплат
    if is_payout_manager(call.from_user.id) and not is_admin(call.from_user.id):
        increment_payout_daily_stats(call.from_user.id, amount)
    if channel_id:
        try:
            emoji_money = "💸" if amount >= 500 else ("💰" if amount >= 100 else "🪙")
            emoji_celebration = "🎉🎊" if amount >= 1000 else ("🎉" if amount >= 500 else "✨")
            safe_user_name = html.escape(user_name) if user_name else str(user_id)
            safe_comment = html.escape(comment) if comment else '—'
            
            # Формуємо інформацію про комісію та амбассадора
            if is_amb:
                commission_details = f"├ 💎 <b>Комісія:</b> <i>0% (Амбасадор - без комісії)</i>\n"
                net_info = f"💎 <b>Виплачено:</b> <b>{format_currency(amount)}₴</b>\n"
            else:
                commission_details = f"├ 📊 <b>Комісія:</b> <b>{fee_percent}%</b> → <b>{format_currency(fee)}₴</b>\n"
                net_info = f"💎 <b>Виплачено:</b> <b>{format_currency(net)}₴</b>\n"
            
            channel_msg = (
                f"🚀 <b>УСПІШНИЙ ВИВІД КОШТІВ!</b> {emoji_celebration}\n\n"
                f"{emoji_money} <b>СУМА ЗАПИТУ:</b> <b><u>{format_currency(amount)}₴</u></b>\n"
                f"{net_info}"
                f"👤 <b>Користувач:</b> <a href='tg://user?id={user_id}'>{safe_user_name}</a>\n"
                f"💼 <b>Статистика користувача:</b>\n"
                f"└ 📈 <b>Загально виведено:</b> <b>{format_currency(total_withdrawn + float(amount))}₴</b>\n\n"
                f"📝 <b>Деталі операції:</b>\n"
                f"├ ⚡ <b>Оброблено:</b> <i>{now_human}</i>\n"
                f"{commission_details}"
                f"├ 🔢 <b>ID заявки:</b> <code>#{tx_id}</code>\n"
                f"└ 💼 <b>Сервіс:</b> <i>{safe_comment}</i>\n\n"
                f"🌟 <b>Вітаємо з успішним виводом!</b> 🌟\n"
            )
            # Надсилаємо GIF якщо налаштований
            try:
                from database import get_withdraw_success_gif_file_id
                gif_id = get_withdraw_success_gif_file_id()
            except Exception:
                gif_id = None
            if gif_id:
                try:
                    bot.send_animation(channel_id, gif_id, caption=channel_msg, parse_mode="HTML")
                except Exception:
                    bot.send_message(channel_id, channel_msg, parse_mode="HTML")
            else:
                bot.send_message(channel_id, channel_msg, parse_mode="HTML")
        except Exception:
            pass

    # Повідомлення адміну (редагуємо існуюче з відключеними кнопками)
    admin_msg = (
        f"✅ <b>ВИВІД ПІДТВЕРДЖЕНО!</b>\n"
        "━━━━━━━━━━━━━━━━━━━━\n\n"
        f"💰 <b>Сума:</b> <b>{format_currency(amount)}₴</b>\n"
        f"👤 <b>Користувач:</b> <a href='tg://user?id={user_id}'>{user_name}</a>\n"
        f"🆔 <b>ID:</b> <code>{user_id}</code>\n"
        f"💳 <b>Поточний баланс:</b> <b>{format_currency(user_balance)}₴</b>\n"
        f"📋 <b>Коментар:</b> {comment or '—'}\n"
        f"📅 <b>Створено:</b> <i>{created_time}</i>\n"
        f"✅ <b>Підтверджено:</b> <i>{now_human}</i>\n"
        f"🔢 <b>ID заявки:</b> <code>{tx_id}</code>\n\n"
        f"🎯 <i>Кошти переведено користувачу!</i> 💎"
    )
    
    # Кнопки відключені після обробки
    from telebot.types import InlineKeyboardMarkup, InlineKeyboardButton
    disabled_kb = InlineKeyboardMarkup()
    disabled_kb.add(InlineKeyboardButton("✅ Оброблено", callback_data="noop"))
    
    try:
        bot.edit_message_text(admin_msg, call.message.chat.id, call.message.message_id, parse_mode="HTML", reply_markup=disabled_kb)
    except Exception:
        try:
            bot.send_message(call.message.chat.id, admin_msg, parse_mode="HTML", reply_markup=disabled_kb)
        except Exception:
            pass

    # Повідомлення користувачу з кнопкою повернення
    user_msg = (
        "🎉 <b>ВИВІД ПІДТВЕРДЖЕНО!</b>\n"
        "━━━━━━━━━━━━━━━━━━━━\n\n"
        f"💰 <b>Сума виводу:</b> <b>{format_currency(amount)}₴</b>\n"
        + (f"💳 <b>Реквізити:</b> <code>{requisites}</code>\n" if requisites else "") +
        f"📅 <b>Час підтвердження:</b> <i>{now_human}</i>\n"
        f"🔢 <b>ID заявки:</b> <code>{tx_id}</code>\n\n"
        "💸 <b>Кошти вже в дорозі!</b>\n"
        "⏰ Очікуйте надходження протягом 1-24 годин"
    )
    try:
        from telebot.types import InlineKeyboardMarkup, InlineKeyboardButton
        kb = InlineKeyboardMarkup()
        kb.add(InlineKeyboardButton("✨ Чудово", callback_data="cabinet"))
        bot.send_message(user_id, user_msg, parse_mode="HTML", reply_markup=kb)
    except Exception:
        pass

    bot.answer_callback_query(call.id, f"✅ Вивід {format_currency(amount)}₴ підтверджено!", show_alert=False)

@bot.callback_query_handler(func=lambda c: c.data and c.data.startswith("payout_approve_confirm:"))
def payout_approve_confirm_handler(call):
    """Підтвердження виплати з великою сумою створювачем бота"""
    from database import is_bot_creator, get_withdrawal_by_id, _db, get_withdraw_channel, get_user, increment_payout_daily_stats, is_payout_manager, is_admin
    if not is_bot_creator(call.from_user.id):
        return bot.answer_callback_query(call.id, "⛔️ Тільки створювач бота може підтверджувати", show_alert=True)
    
    try:
        tx_id = int(call.data.split(":")[1])
    except Exception:
        return bot.answer_callback_query(call.id, "❌ Невірний ID заявки", show_alert=True)
    
    # Викликаємо оригінальний обробник одобрення
    # Створюємо фейковий callback з правильним форматом
    class FakeCall:
        def __init__(self, original_call, tx_id):
            self.from_user = original_call.from_user
            self.message = original_call.message
            self.data = f"withdraw_approve_{tx_id}"
            self.id = original_call.id
    
    fake_call = FakeCall(call, tx_id)
    
    # Отримуємо інформацію про заявку для оновлення статистики менеджера
    req = get_withdrawal_by_id(tx_id)
    if req:
        if len(req) >= 8:
            _, user_id, amount, _, _, _, _, _ = req
        else:
            _, user_id, amount, _, _, _, _ = req
        
        # Знаходимо менеджера, який спробував одобрити (з повідомлення)
        # Для простоти, оновлюємо статистику для створювача бота, якщо він підтвердив
        # В реальності потрібно зберігати інформацію про менеджера, який запросив підтвердження
        pass
    
    # Викликаємо оригінальний обробник
    withdraw_approve_handler(fake_call)
    
    bot.answer_callback_query(call.id, f"✅ Виплата підтверджена!", show_alert=True)

