def process_set_fruit_price_step(message, fruit_type):
    try:
        # Перевіряємо чи це не команда або скасування
        if message.text.startswith('/') or message.text.lower() in ['скасувати', 'cancel', 'отмена', 'стоп']:
            cancel_msg = (
                "❌ <b>Зміну ціни скасовано</b>\n"
                "━━━━━━━━━━━━━━━━━━━━\n\n"
                "🔄 Повертаємося до меню зміни цін..."
            )
            bot.send_message(message.chat.id, cancel_msg, parse_mode="HTML")
            return
            
        # Очищаємо текст від пробілів та замінюємо кому на крапку
        clean_text = message.text.strip().replace(",", ".")
        
        # Перевіряємо чи це число
        if not clean_text.replace(".", "").isdigit():
            error_msg = (
                "❌ <b>Помилка введення!</b>\n"
                "━━━━━━━━━━━━━━━━━━━━\n\n"
                "💡 <b>Введіть коректну ціну:</b>\n"
                "• Тільки число (25, 50.5, 100.00)\n"
                "• Можна використовувати кому або крапку\n"
                "• Мінімальна ціна: 0.01₴\n\n"
                "🔄 <i>Спробуйте ще раз</i>"
            )
            bot.send_message(message.chat.id, error_msg, parse_mode="HTML")
            return
            
        price = float(clean_text)
        
        # Перевіряємо чи ціна позитивна та мінімальна
        if price <= 0:
            error_msg = (
                "❌ <b>Недопустима ціна!</b>\n"
                "━━━━━━━━━━━━━━━━━━━━\n\n"
                "💡 <b>Ціна повинна бути:</b>\n"
                "• Більше 0\n"
                "• Мінімальна: 0.01₴\n\n"
                "🔄 <i>Спробуйте ще раз</i>"
            )
            bot.send_message(message.chat.id, error_msg, parse_mode="HTML")
            return
            
        from database import set_fruit_price
        from garden_models import FRUITS
        
        fruit = next((f for f in FRUITS if f['type'] == fruit_type), None)
        fruit_name = fruit['name'] if fruit else fruit_type
        
        # Перевіряємо чи фрукт існує
        if not fruit:
            error_msg = (
                "❌ <b>Фрукт не знайдено!</b>\n"
                "━━━━━━━━━━━━━━━━━━━━\n\n"
                f"🔍 <b>Тип фрукта:</b> {fruit_type}\n"
                "💡 <i>Перевірте правильність типу фрукта</i>"
            )
            bot.send_message(message.chat.id, error_msg, parse_mode="HTML")
            return
        
        # Отримуємо стару ціну з бази даних або базову ціну
        old_price = get_fruit_price(fruit_type) or (fruit['price_uah'] if fruit and 'price_uah' in fruit else 0)
        
        # Зберігаємо нову ціну
        try:
            set_fruit_price(fruit_type, price)
        except Exception as save_error:
            error_msg = (
                "❌ <b>Помилка збереження!</b>\n"
                "━━━━━━━━━━━━━━━━━━━━\n\n"
                "🔧 <b>Не вдалося зберегти ціну в базі даних</b>\n"
                f"📝 Деталі: {str(save_error)}\n\n"
                "🔄 <i>Спробуйте ще раз або зверніться до адміністратора</i>"
            )
            bot.send_message(message.chat.id, error_msg, parse_mode="HTML")
            return
        
        # Визначаємо зміну ціни
        price_change = price - old_price
        change_emoji = "📈" if price_change > 0 else "📉" if price_change < 0 else "➡️"
        change_text = "збільшена" if price_change > 0 else "зменшена" if price_change < 0 else "не змінилася"
        
        # Креативне повідомлення про успіх
        fruit_emoji = fruit['emoji'] if fruit and 'emoji' in fruit else "🍎"
        success_msg = (
            f"🎉 <b>ЦІНУ УСПІШНО ЗМІНЕНО!</b>\n"
            f"━━━━━━━━━━━━━━━━━━━━\n\n"
            f"🍎 <b>Фрукт:</b> {fruit_emoji} {fruit_name}\n"
            f"💰 <b>Стара ціна:</b> <s>{old_price}₴</s>\n"
            f"💎 <b>Нова ціна:</b> <u>{format_currency(price)}₴</u>\n"
            f"{change_emoji} <b>Зміна:</b> {change_text}\n\n"
            f"✨ <i>Тепер {fruit_name} коштує {format_currency(price)}₴!</i>\n"
            f"🌱 <b>Користувачі зможуть продавати за новою ціною!</b>"
        )
        
        # Кнопки для подальших дій
        kb = InlineKeyboardMarkup(row_width=2)
        kb.add(
            InlineKeyboardButton("🔄 Змінити ще", callback_data="admin_change_fruit_price"),
            InlineKeyboardButton("📊 Всі ціни", callback_data="admin_view_all_fruit_prices")
        )
        kb.add(InlineKeyboardButton("⬅️ Назад", callback_data="panel"))
        
        bot.send_message(message.chat.id, success_msg, reply_markup=kb, parse_mode="HTML")
        
    except ValueError:
        error_msg = (
            "❌ <b>Помилка введення!</b>\n"
            "━━━━━━━━━━━━━━━━━━━━\n\n"
            "💡 <b>Введіть коректну ціну:</b>\n"
            "• Тільки число (25, 50.5, 100.00)\n"
            "• Можна використовувати кому або крапку\n"
            "• Мінімальна ціна: 0.01₴\n\n"
            "🔄 <i>Спробуйте ще раз</i>"
        )
        bot.send_message(message.chat.id, error_msg, parse_mode="HTML")
    except Exception as e:
        error_msg = (
            "❌ <b>Системна помилка!</b>\n"
            "━━━━━━━━━━━━━━━━━━━━\n\n"
            "🔧 <b>Не вдалося змінити ціну</b>\n"
            f"📝 Деталі: {str(e)}\n\n"
            "🔄 <i>Спробуйте ще раз або зверніться до адміністратора</i>"
        )
        bot.send_message(message.chat.id, error_msg, parse_mode="HTML")

