# Адмінська функція очищення історії саду
@bot.callback_query_handler(func=lambda c: c.data == "admin_cleanup_garden_history")
def admin_cleanup_garden_history_handler(call):
    from database import cleanup_old_garden_history, get_garden_history_stats
    import datetime
    
    # Очищаємо записи старіше 90 днів
    deleted_count = cleanup_old_garden_history(90)
    
    # Отримуємо статистику
    stats = get_garden_history_stats()
    
    msg = f"<b>🧹 Очищення історії саду завершено</b>\n\n"
    msg += f"✅ Видалено записів: <b>{deleted_count}</b>\n"
    msg += f"📊 Загальна кількість записів: <b>{stats['total_records']}</b>\n\n"
    
    if stats['oldest_timestamp']:
        oldest_date = datetime.datetime.fromtimestamp(stats['oldest_timestamp']).strftime("%d.%m.%Y")
        msg += f"📅 Найстаріший запис: <b>{oldest_date}</b>\n"
    
    if stats['newest_timestamp']:
        newest_date = datetime.datetime.fromtimestamp(stats['newest_timestamp']).strftime("%d.%m.%Y")
        msg += f"📅 Найновіший запис: <b>{newest_date}</b>\n"
    
    kb = InlineKeyboardMarkup()
    kb.add(InlineKeyboardButton("⬅️ Назад", callback_data="panel"))
    
    bot.edit_message_text(msg, call.message.chat.id, call.message.message_id, reply_markup=kb, parse_mode="HTML")

@bot.callback_query_handler(func=lambda c: c.data == "boosters_menu")
def boosters_menu_handler(call):
    from garden_models import BOOSTERS
    from database import get_booster_price, get_user, is_booster_enabled
    from telebot.types import InlineKeyboardMarkup, InlineKeyboardButton
    # Сумісність: локальна логіка без зовнішнього модуля
    
    user_id = call.from_user.id
    
    # Перевірка спаму
    is_spam, spam_message = check_button_spam(user_id, "boosters_menu")
    if is_spam:
        bot.answer_callback_query(call.id, text=spam_message, show_alert=True)
        return
    user = get_user(user_id)
    balance = user[2] if user else 0
    
    # Отримуємо активні бустери
    active_boosters = []
    
    msg = (
        f"🚀✨ <b>МАГАЗИН БУСТЕРІВ</b> ✨🚀\n"
        f"━━━━━━━━━━━━━━━━━\n\n"
        f"💰 <b>Ваш баланс:</b> <b>{format_currency(balance)}₴</b>\n\n"
    )
    
    # Показуємо активні бустери
    if active_boosters:
        msg += f"⚡ <b>АКТИВНІ БУСТЕРИ:</b>\n"
        for booster in active_boosters:
            hours = booster['hours_left']
            if hours >= 1:
                time_text = f"{hours:.1f}г"
            else:
                minutes = hours * 60
                time_text = f"{minutes:.0f}хв"
            msg += f"├ {booster['emoji']} <b>{booster['name']}</b> — {time_text}\n"
        msg += "└ ────────────────────────\n\n"
    
    msg += f"💫 <b>ДОСТУПНІ БУСТЕРИ:</b>\n\n"
    
    kb = InlineKeyboardMarkup(row_width=1)
    
    for b in BOOSTERS:
        price = get_booster_price(b['type']) or 50  # За замовчуванням 50₴
        duration_text = f"{b['duration_hours']}г" if b['duration_hours'] >= 1 else f"{int(b['duration_hours'] * 60)}хв"
        can_afford = balance >= price
        enabled = True if b['type'] == 'autowater' else is_booster_enabled(b['type'])
        status_emoji = "✅" if (can_afford and enabled) else ("🚫" if not enabled else "❌")
        
        # Детальна кнопка
        button_text = (
            f"{status_emoji} {b['emoji']} {b['name']} — {price:.0f}₴\n"
            f"💫 {b['effect']} • ⏰ {duration_text}"
        )
        
        cb = f"buy_booster_{b['type']}" if enabled else f"buy_booster_disabled_{b['type']}"
        kb.add(InlineKeyboardButton(button_text, callback_data=cb))
    
    kb.add(InlineKeyboardButton("⬅️ Назад до саду", callback_data="garden_overview"))
    
    msg += (
        f"💡 <b>ПОРАДИ:</b>\n"
        f"• Комбінуйте різні бустери для максимального ефекту\n"
        f"• Використовуйте перед збором великого урожаю\n"
        f"• VIP статус дає доступ до ексклюзивних функцій\n"
        f"• Прискорений ріст допомагає швидше заробляти\n\n"
        f"🚀 <i>Прискорьте свій розвиток з нашими бустерами!</i>"
    )
    
    # Після переходу з екранів із банером попереднє повідомлення часто фото —
    # редагування тексту дає 400. Відправимо нове повідомлення-банер.
    try:
        short_caption = build_caption_from_text(msg, 1024)
        send_banner_with_caption(call.message.chat.id, "Бусти", "⚡", short_caption, reply_markup=kb, parse_mode="HTML", subtitle="Магазин прискорювачів")
        if len(msg) > 1024:
            bot.send_message(call.message.chat.id, msg, parse_mode="HTML")
    except Exception:
        try:
            bot.edit_message_text(msg, call.message.chat.id, call.message.message_id, reply_markup=kb, parse_mode="HTML")
        except Exception:
            bot.send_message(call.message.chat.id, msg, reply_markup=kb, parse_mode="HTML")

@bot.callback_query_handler(func=lambda c: c.data.startswith("buy_booster_disabled_"))
def buy_booster_disabled_handler(call):
    from garden_models import BOOSTERS
    booster_type = call.data.replace("buy_booster_disabled_", "")
    booster = next((b for b in BOOSTERS if b['type'] == booster_type), None)
    name = booster['name'] if booster else booster_type
    emoji = booster['emoji'] if booster and 'emoji' in booster else '⚡'
    bot.answer_callback_query(
        call.id,
        f"{emoji} {name} тимчасово недоступний до придбання.\nНаші механіки підкручують гіперпривід — повернеться зовсім скоро!",
        show_alert=True
    )

@bot.callback_query_handler(func=lambda c: c.data.startswith("buy_booster_") and not c.data.startswith("buy_booster_confirm_"))
def buy_booster_handler(call):
    from garden_models import BOOSTERS
    from database import get_booster_price, add_balance, _db, get_user, is_booster_enabled
    import time
    
    user_id = call.from_user.id
    
    # Перевірка спаму
    is_spam, spam_message = check_button_spam(user_id, "buy_booster")
    if is_spam:
        bot.answer_callback_query(call.id, text=spam_message, show_alert=True)
        return
    booster_type = call.data.replace("buy_booster_", "")
    booster = next((b for b in BOOSTERS if b['type'] == booster_type), None)
    
    if not booster:
        bot.answer_callback_query(call.id, text="❌ Невідомий буст!", show_alert=True)
        return
    
    # Перевірка увімкнення (autowater дозволяємо завжди, remind_harvest перевіряємо)
    if booster_type != 'autowater' and not is_booster_enabled(booster_type):
        from garden_models import BOOSTERS as BS
        booster = next((b for b in BS if b['type'] == booster_type), {"name": booster_type, "emoji": "⚡"})
        bot.answer_callback_query(call.id, f"{booster.get('emoji','⚡')} {booster.get('name', booster_type)} тимчасово відпочиває 😴\nЗагляньте пізніше — повернеться з новою силою!", show_alert=True)
        return
    price = get_booster_price(booster_type) or 50
    # Для бустерів з керованою тривалістю дати можливість вказати тривалість перед підтвердженням
    if booster_type in ('remind_harvest','autowater'):
        kb = InlineKeyboardMarkup(row_width=2)
        # Опції: 1д, 7д, 30д, 365д з відображенням ціни
        base_price = price
        # Мінімальний строк (днів) для покупки і коефіцієнти з налаштувань
        def _get_min_days() -> int:
            try:
                from database import get_game_setting
                md = int(float(get_game_setting('booster_min_days', '4')))
                return max(1, md)
            except Exception:
                return 4
        min_days = _get_min_days()
        def _read_mult_key(key: str, default_val: float) -> float:
            try:
                from database import get_game_setting
                v = float(get_game_setting(key, str(default_val)))
                return max(0.1, v)
            except Exception:
                return default_val
        # Дефолтні коефіцієнти: мін.дні ~ лінійно, 7д ~4, 30д ~15, 365д ~150
        mult_min = _read_mult_key(f'booster_mult_{min_days}d', float(min_days))
        mult_7d = _read_mult_key('booster_mult_7d', 4.0)
        mult_30d = _read_mult_key('booster_mult_30d', 15.0)
        mult_365d = _read_mult_key('booster_mult_365d', 150.0)
        def _mult(hours: int) -> float:
            if hours == 24*min_days: return mult_min
            if hours == 24*7: return mult_7d
            if hours == 24*30: return mult_30d
            if hours == 24*365: return mult_365d
            return max(1.0, hours/24.0)
        # Пакети: мін.дні, 7, 30, 365
        days_options = []
        for d in (min_days, 7, 30, 365):
            if d not in days_options and d >= min_days:
                days_options.append(d)
        options = [(d*24, f"{d}д") for d in days_options]
        row = []
        for h,label in options:
            cost = int(round(base_price * _mult(h)))
            btn = InlineKeyboardButton(f"{label} — {cost}₴", callback_data=f"buy_booster_confirm_{booster_type}_{h}")
            row.append(btn)
            if len(row) == 2:
                kb.add(*row); row = []
        if row:
            kb.add(*row)
        kb.add(InlineKeyboardButton("❌ Відмінити", callback_data="boosters_menu"))
        extra = ("\n\nℹ️ <b>Опис:</b> " + ("Надсилає пуш-нагадування, коли хоч одне дерево готове до збору та полите. Перевіряє стан щопівгодини."
                 if booster_type=='remind_harvest' else "Автоматично поливає дерева за потреби протягом обраного періоду."))
        try:
            bot.edit_message_text(
                f"{booster.get('emoji','⚡')} <b>{booster['name']}</b> — оберіть тривалість дії" + extra + f"\n\n💵 <i>Базова ціна за 1 день:</i> <b>{int(base_price)}₴</b>\n" +
                (f"🔒 Мінімальна покупка: <b>{min_days}д</b>" if min_days>1 else ""),
                call.message.chat.id,
                call.message.message_id,
                reply_markup=kb,
                parse_mode="HTML"
            )
        except Exception:
            # Якщо попереднє повідомлення було банером/фото — просто надішлемо новий екран
            _try_delete_call_message(call)
            bot.send_message(
                call.message.chat.id,
                f"{booster.get('emoji','⚡')} <b>{booster['name']}</b> — оберіть тривалість дії" + extra + f"\n\n💵 <i>Базова ціна за 1 день:</i> <b>{int(base_price)}₴</b>\n" +
                (f"🔒 Мінімальна покупка: <b>{min_days}д</b>" if min_days>1 else ""),
                reply_markup=kb,
                parse_mode="HTML"
            )
        finally:
            try:
                bot.answer_callback_query(call.id)
            except Exception:
                pass
        return
    user = get_user(user_id)
    balance = user[2] if user else 0
    
    if balance < price:
        bot.answer_callback_query(call.id, text=f"❌ Недостатньо коштів! Потрібно {price:.0f}₴, у вас {format_currency(balance)}₴", show_alert=True)
        return
    
    # Розраховуємо час дії бустера
    duration_seconds = int(booster['duration_hours'] * 3600)
    end_time = int(time.time()) + duration_seconds
    duration_text = f"{booster['duration_hours']}г" if booster['duration_hours'] >= 1 else f"{int(booster['duration_hours'] * 60)}хв"
    
    # Підтвердження покупки
    kb = InlineKeyboardMarkup(row_width=2)
    kb.add(
        InlineKeyboardButton("✅ Підтверджую", callback_data=f"buy_booster_confirm_{booster_type}_{price}"),
        InlineKeyboardButton("❌ Відмінити", callback_data="boosters_menu")
    )
    # Додаємо детальний опис бустера
    booster_desc = booster.get('description', '')
    confirm_msg = (
        f"⚡ <b>ПІДТВЕРДЖЕННЯ ПОКУПКИ</b>\n"
        f"━━━━━━━━━━━━━━━━━\n\n"
        f"{booster['emoji']} <b>{booster['name']}</b> — <b>{price:.0f}₴</b>\n"
        f"⏰ Тривалість: <b>{duration_text}</b>\n"
        f"ℹ️ <i>{booster_desc}</i>\n\n"
        f"💬 Підтвердіть придбання бустера."
    )
    return bot.edit_message_text(confirm_msg, call.message.chat.id, call.message.message_id, reply_markup=kb, parse_mode="HTML")
    
    # Красиве повідомлення про покупку
    msg = (
        f"🎉✨ <b>БУСТЕР АКТИВОВАНО!</b> ✨🎉\n"
        f"━━━━━━━━━━━━━━━━━\n\n"
        f"{booster['emoji']} <b>{booster['name']}</b>\n\n"
        f"💫 <b>Ефект:</b> <i>{booster['effect']}</i>\n"
        f"⏰ <b>Тривалість:</b> <b>{duration_text}</b>\n"
        f"💰 <b>Витрачено:</b> <b>{price:.0f}₴</b>\n"
        f"💳 <b>Новий баланс:</b> <b>{format_currency(balance - price)}₴</b>\n\n"
        f"📝 <b>Опис:</b>\n<i>{booster['description']}</i>\n\n"
        f"🚀 <b>Використовуйте бустер максимально ефективно!</b>\n"
        f"💡 <i>Комбінуйте з іншими бустерами для кращого результату</i>"
    )
    
    kb = InlineKeyboardMarkup()
    kb.add(InlineKeyboardButton("🍎 Зібрати урожай", callback_data="harvest_fruits"))
    kb.add(InlineKeyboardButton("🛒 Купити ще бустери", callback_data="boosters_menu"))
    kb.add(InlineKeyboardButton("🌳 Повернутися до саду", callback_data="garden_overview"))
    
    bot.edit_message_text(msg, call.message.chat.id, call.message.message_id, reply_markup=kb, parse_mode="HTML")
    bot.answer_callback_query(call.id, text="🚀 Бустер активовано!", show_alert=False)

@bot.callback_query_handler(func=lambda c: c.data.startswith("buy_booster_confirm_"))
def buy_booster_confirm_handler(call):
    from database import add_balance, _db, get_user, get_booster_price, grant_booster
    from garden_models import BOOSTERS
    import time
    parts = call.data.split("_")
    # Новий формат: buy_booster_confirm_{type}_{hours}; Старий: buy_booster_confirm_{type}_{price}_{hours}
    booster_type = parts[3]
    duration_hours_override = None
    total_price = None
    base_price = get_booster_price(booster_type) or 50
    try:
        if len(parts) == 5 and parts[4].isdigit():
            duration_hours_override = float(parts[4])
        elif len(parts) >= 6 and parts[4].replace('.', '').isdigit() and parts[5].replace('.', '').isdigit():
            total_price = float(parts[4])
            duration_hours_override = float(parts[5])
    except Exception:
        pass
    booster = next((b for b in BOOSTERS if b['type'] == booster_type), None)
    if not booster:
        # Фолбек для нових бустерів, якщо модель ще не оновилась у процесі
        fallback_emoji = '💧' if booster_type == 'autowater' else '⚡'
        booster = {"type": booster_type, "name": booster_type, "emoji": fallback_emoji, "duration_hours": 24, "description": ""}
    user_id = call.from_user.id
    user = get_user(user_id)
    balance = user[2] if user else 0
    # Коефіцієнти з адмін-налаштувань
    def _read_mult(days_key: str, default_val: float) -> float:
        try:
            from database import get_game_setting
            v = float(get_game_setting(days_key, str(default_val)))
            return max(0.1, v)
        except Exception:
            return default_val
    # Мінімальні дні та коефіцієнти
    def _get_min_days() -> int:
        try:
            from database import get_game_setting
            md = int(float(get_game_setting('booster_min_days', '4')))
            return max(1, md)
        except Exception:
            return 4
    min_days = _get_min_days()
    def _read_mult_key(key: str, default_val: float) -> float:
        try:
            from database import get_game_setting
            v = float(get_game_setting(key, str(default_val)))
            return max(0.1, v)
        except Exception:
            return default_val
    mult_min = _read_mult_key(f'booster_mult_{min_days}d', float(min_days))
    mult_7d = _read_mult_key('booster_mult_7d', 4.0)
    mult_30d = _read_mult_key('booster_mult_30d', 15.0)
    mult_365d = _read_mult_key('booster_mult_365d', 150.0)
    def _mult(hours: float) -> float:
        hours = float(hours)
        if abs(hours-(24.0*min_days)) < 0.01: return mult_min
        if abs(hours-168.0) < 0.01: return mult_7d
        if abs(hours-720.0) < 0.01: return mult_30d
        if abs(hours-8760.0) < 0.01: return mult_365d
        return max(1.0, hours/24.0)
    if duration_hours_override is not None:
        total_price = int(round(base_price * _mult(duration_hours_override))) if total_price is None else int(round(total_price))
        duration_seconds = int(float(duration_hours_override) * 3600)
        duration_text = f"{int(duration_hours_override/24)}д" if duration_hours_override >= 24 else f"{int(duration_hours_override)}г"
    else:
        total_price = int(round(base_price))
        duration_seconds = int(booster['duration_hours'] * 3600)
        duration_text = f"{booster['duration_hours']}г" if booster['duration_hours'] >= 1 else f"{int(booster['duration_hours'] * 60)}хв"
    if balance < total_price:
        return bot.answer_callback_query(call.id, f"❌ Недостатньо коштів! Потрібно {total_price:.0f}₴", show_alert=True)
    end_time = int(time.time()) + duration_seconds
    # Списуємо кошти
    add_balance(user_id, -total_price, reason="booster_purchase", details=f"{booster_type}:{duration_text}")
    # Додаємо буст
    with _db() as con:
        con.execute("INSERT INTO boosters (user_id, type, expires_at) VALUES (?, ?, ?)", (user_id, booster_type, end_time))
        con.commit()
    
    # Логируем активность в саду
    from database import log_garden_activity
    log_garden_activity(
        user_id,
        "booster_buy",
        booster['name'],
        quantity=1,
        cost=total_price,
        metadata={
            'booster_type': booster_type,
            'duration_hours': duration_hours_override or booster.get('duration_hours', 24),
            'duration_text': duration_text,
            'expires_at': end_time
        }
    )
    # Повідомлення
    msg = (
        f"🎉✨ <b>БУСТЕР АКТИВОВАНО!</b> ✨🎉\n"
        f"━━━━━━━━━━━━━━━━━\n\n"
        f"{booster['emoji']} <b>{booster['name']}</b>\n\n"
        f"⏰ <b>Тривалість:</b> <b>{duration_text}</b>\n"
        f"💰 <b>Витрачено:</b> <b>{total_price:.0f}₴</b>\n"
        f"💳 <b>Новий баланс:</b> <b>{format_currency(balance - total_price)}₴</b>\n"
    )
    kb = InlineKeyboardMarkup()
    kb.add(InlineKeyboardButton("🍎 Зібрати урожай", callback_data="harvest_fruits"))
    kb.add(InlineKeyboardButton("🛒 Купити ще бустери", callback_data="boosters_menu"))
    kb.add(InlineKeyboardButton("🌳 Повернутися до саду", callback_data="garden_overview"))
    bot.edit_message_text(msg, call.message.chat.id, call.message.message_id, reply_markup=kb, parse_mode="HTML")
    # Справка по автополиву
    if booster_type == 'autowater':
        try:
            bot.send_message(call.message.chat.id,
                "ℹ️ <b>Як працює Автополив</b>\n"
                "• Поливає дерева автоматично, коли рівень води падає нижче порогу\n"
                "• Перевірка кожні 2 хв у фоновому режимі\n"
                "• Прогрес росту не скидається; ріст продовжується з поточного відсотка\n"
                "• Натисніть ‘Кабінет’ — розділ ‘Активні бустери’ покаже час, що залишився",
                parse_mode="HTML")
        except Exception:
            pass
    bot.answer_callback_query(call.id, text="🚀 Бустер активовано!", show_alert=False)

    # Активуємо керовані бустери з заданою тривалістю
    try:
        if booster_type in ('remind_harvest','autowater'):
            hours = duration_hours_override if duration_hours_override is not None else booster.get('duration_hours', 24)
            duration_seconds = int(float(hours) * 3600)
            grant_booster(call.from_user.id, booster_type, duration_seconds)
    except Exception as e:
        print(f"[{booster_type}] activation error: {e}")

