def process_admin_add_tree(message, user_id, tree_type):
    try:
        count = int(message.text.strip())
        from database import _db
        import time
        for _ in range(count):
            with _db() as con:
                con.execute(
                    "INSERT INTO trees (user_id, type, level, planted_at, last_harvest) VALUES (?, ?, ?, ?, ?)",
                    (user_id, tree_type, 1, int(time.time()), int(time.time()))
                )
                con.commit()
        from garden_models import get_tree_name_uk
        tree_name = get_tree_name_uk(tree_type)
        bot.send_message(message.chat.id, f"Видано {count} дерев типу {tree_name} користувачу {user_id}.")
    except Exception:
        bot.send_message(message.chat.id, "Помилка! Введіть коректну кількість.")

