@bot.callback_query_handler(func=lambda c: c.data.startswith("admin_remove_tree_confirm:"))
def admin_remove_tree_confirm(call):
    try:
        try:
            bot.answer_callback_query(call.id)
        except Exception:
            pass
        _, user_id, tree_type, qty = call.data.split(":", 3)
        user_id = int(user_id); qty = int(qty)
        from database import _db
        from garden_models import get_tree_name_uk
        deleted = 0
        if qty > 0:
            with _db() as con:
                ids = [row[0] for row in con.execute("SELECT id FROM trees WHERE user_id=? AND type=? ORDER BY planted_at ASC LIMIT ?", (user_id, tree_type, qty))]
                for tree_id in ids:
                    con.execute("DELETE FROM trees WHERE id=?", (tree_id,))
                con.commit()
                deleted = len(ids)
        name = get_tree_name_uk(tree_type)
        kb = InlineKeyboardMarkup()
        kb.add(InlineKeyboardButton("⬅️ Назад", callback_data=f"admin_edit_garden_{user_id}"))
        bot.edit_message_text(f"✅ Видалено {deleted} дерев типу <b>{name}</b> у користувача <code>{user_id}</code>.", call.message.chat.id, call.message.message_id, reply_markup=kb, parse_mode="HTML")
    except Exception as e:
        bot.answer_callback_query(call.id, f"❌ Помилка: {e}", show_alert=True)

def process_admin_remove_tree(message, user_id, tree_type):
    try:
        count = int(message.text.strip())
        from database import _db
        with _db() as con:
            # Видаляємо N дерев цього типу (по id)
            ids = [row[0] for row in con.execute("SELECT id FROM trees WHERE user_id=? AND type=? LIMIT ?", (user_id, tree_type, count))]
            for tree_id in ids:
                con.execute("DELETE FROM trees WHERE id=?", (tree_id,))
            con.commit()
        from garden_models import get_tree_name_uk
        tree_name = get_tree_name_uk(tree_type)
        bot.send_message(message.chat.id, f"Видалено {len(ids)} дерев типу {tree_name} у користувача {user_id}.")
    except Exception:
        bot.send_message(message.chat.id, "Помилка! Введіть коректну кількість.")

