def process_admin_give_booster(message, user_id, booster_type):
    try:
        hours = int(message.text.strip())
        from database import _db
        import time
        expires_at = int(time.time()) + hours * 3600
        with _db() as con:
            con.execute(
                "INSERT INTO boosters (user_id, type, expires_at) VALUES (?, ?, ?)",
                (user_id, booster_type, expires_at)
            )
            con.commit()
        from garden_models import BOOSTERS
        booster_name = next((b['name'] for b in BOOSTERS if b['type'] == booster_type), booster_type)
        bot.send_message(message.chat.id, f"Видано бустер {booster_name} на {hours} годин користувачу {user_id}.")
    except Exception:
        bot.send_message(message.chat.id, "Помилка! Введіть коректну кількість годин.")

