def promo_code_check(message):
    # Если админ ввёл слэш‑команду, маршрутизируем её и выходим
    if _route_slash_command(message):
        return
    code = message.text.strip()
    user_id = message.from_user.id
    from database import use_promo_code, add_balance, add_fruit
    
    # Очищаємо всі стани користувача
    try:
        bot.delete_state(user_id, message.chat.id)
    except:
        pass
    
    # Видаляємо повідомлення з промокодом
    try:
        bot.delete_message(message.chat.id, message.message_id)
    except:
        pass
    
    # Створюємо клавіатуру з кнопкою "Назад"
    kb = InlineKeyboardMarkup()
    kb.add(InlineKeyboardButton("⬅️ Назад", callback_data="back_home"))
    
    ok, result = use_promo_code(code, user_id)
    if not ok:
        bot.send_message(message.chat.id, f"❌ {result}", reply_markup=kb)
        return
    reward, info = result
    # Новий формат: info — dict з ключами type/item
    if isinstance(info, dict):
        rtype = info.get('type')
        ritem = info.get('item')
        if rtype == 'fruit':
            add_fruit(user_id, ritem, int(reward))
            from garden_models import get_fruit_name_uk
            item_name = get_fruit_name_uk(ritem)
            bot.send_message(
                message.chat.id,
                f"🎉 <b>Промокод активовано</b>\n💎 Нараховано: <b>{int(reward)} {item_name}</b>",
                reply_markup=kb,
                parse_mode="HTML"
            )
        elif rtype == 'booster':
            from database import grant_booster
            from garden_models import BOOSTERS
            grant_booster(user_id, ritem, int(reward))
            booster_name = next((b['name'] for b in BOOSTERS if b['type'] == ritem), ritem)
            booster_emoji = next((b.get('emoji', '⚡') for b in BOOSTERS if b['type'] == ritem), '⚡')
            bot.send_message(
                message.chat.id,
                f"{booster_emoji} Активовано бустер <b>{booster_name}</b> на {int(reward)//60} хв!",
                reply_markup=kb,
                parse_mode="HTML"
            )
        elif rtype == 'tree':
            from database import grant_tree
            grant_tree(user_id, ritem, int(reward))
            bot.send_message(message.chat.id, f"🌳 Видано {int(reward)} дерево(а) типу <b>{ritem}</b>!", reply_markup=kb, parse_mode="HTML")
        elif rtype == 'achievement':
            from database import grant_achievement
            grant_achievement(user_id, ritem)
            bot.send_message(message.chat.id, f"🏅 Видано унікальне досягнення: <b>{ritem}</b>!", reply_markup=kb, parse_mode="HTML")
    else:
        # fallback до коштів (старий і новий формат)
        add_balance(user_id, float(reward))
        bot.send_message(
            message.chat.id,
            f"🎉 <b>Промокод активовано</b>\n💰 Нараховано: <b>{format_currency(reward)}₴</b>",
            reply_markup=kb,
            parse_mode="HTML"
        )

    # --- Сповіщення адмінам про використання промокоду ---
    try:
        from database import get_all_admins, get_promo_by_code, get_promo_usages, get_user
        admins = get_all_admins() or []
        if admins:
            user = get_user(user_id)
            user_name = user[1] if user else str(user_id)
            promo_row = get_promo_by_code(code)
            # Розпаковка кортежу: (code, reward_type, reward_value, max_uses, uses, expiry, item_type, item_value)
            if promo_row:
                _, _, _, max_uses_val, uses_val, _, _, _ = promo_row
                try:
                    uses_val = int(uses_val) if uses_val is not None else 0
                except Exception:
                    uses_val = 0
                try:
                    max_uses_val = int(max_uses_val) if max_uses_val is not None else None
                except Exception:
                    max_uses_val = None
            else:
                uses_val = 0
                max_uses_val = None
            remaining = (max_uses_val - uses_val) if isinstance(max_uses_val, int) else '∞'
            usages = get_promo_usages(code) or []
            used_by_count = len(usages)
            used_text = (
                f"🎟️ <b>ПРОМОКОД ВИКОРИСТАНО</b>\n"
                f"━━━━━━━━━━━━━━━━━━━━\n\n"
                f"👤 Користувач: <a href='tg://user?id={user_id}'><b>{user_name}</b></a> (ID: <code>{user_id}</code>)\n"
                f"🏷️ Код: <b>{code}</b>\n"
                f"📊 Використань: <b>{uses_val}</b> / <b>{max_uses_val if max_uses_val is not None else '∞'}</b> | Залишилось: <b>{remaining}</b>\n"
                f"👥 Унікальних користувачів: <b>{used_by_count}</b>"
            )
            for admin_id in admins:
                try:
                    bot.send_message(admin_id, used_text, parse_mode="HTML")
                except Exception:
                    pass
    except Exception as e:
        print(f"[DEBUG] promo admin notify error: {e}")

