def admin_create_promo_reward(message):
    code = message.text.strip().upper()
    
    # Валідація коду
    if len(code) < 3:
        error_msg = (
            "❌ <b>Код занадто короткий!</b>\n"
            "━━━━━━━━━━━━━━━━━━━━\n\n"
            "💡 <b>Код повинен містити:</b>\n"
            "• Мінімум 3 символи\n"
            "• Тільки латиниця та цифри\n\n"
            "🔄 <i>Спробуйте ще раз</i>"
        )
        bot.send_message(message.chat.id, error_msg, parse_mode="HTML")
        return
    
    if not code.replace("_", "").isalnum():
        error_msg = (
            "❌ <b>Недопустимі символи!</b>\n"
            "━━━━━━━━━━━━━━━━━━━━\n\n"
            "💡 <b>Код може містити:</b>\n"
            "• Латиницю (A-Z, a-z)\n"
            "• Цифри (0-9)\n"
            "• Підкреслення (_)\n\n"
            "🔄 <i>Спробуйте ще раз</i>"
        )
        bot.send_message(message.chat.id, error_msg, parse_mode="HTML")
        return
    
    user_id = message.from_user.id
    if not hasattr(bot, 'user_data'):
        bot.user_data = {}
    bot.user_data.setdefault(user_id, {}).setdefault('promo', {})['code'] = code
    
    msg = (
        "💰 <b>ВИНАГОРОДА ПРОМОКОДУ</b>\n"
        "━━━━━━━━━━━━━━━━━━━━\n\n"
        f"🎫 <b>Код:</b> <code>{code}</code>\n\n"
        "💡 <b>Введіть суму винагороди:</b>\n"
        "• Для грошей: сума в гривнях (наприклад: 50.5)\n"
        "• Для фруктів: кількість фруктів (наприклад: 10)\n"
        "• Для бустерів: кількість бустерів (наприклад: 5)\n\n"
        "💡 <i>Приклади: 100, 25.50, 50</i>"
    )
    
    # Кнопка скасування
    kb = InlineKeyboardMarkup()
    kb.add(InlineKeyboardButton("❌ Скасувати", callback_data="admin_promo_list"))
    
    bot.send_message(
        message.chat.id,
        msg,
        reply_markup=kb,
        parse_mode="HTML"
    )
    bot.register_next_step_handler_by_chat_id(message.chat.id, admin_create_promo_max_uses)

