def admin_achievement_edit_save(message, user_id, old_achievement, admin_msg_id):
    new_achievement = message.text.strip()
    from database import _db
    import time
    with _db() as con:
        con.execute("DELETE FROM achievements WHERE user_id=? AND achievement=?", (user_id, old_achievement))
        con.execute("INSERT OR IGNORE INTO achievements (user_id, achievement, achieved_at) VALUES (?, ?, ?)", (user_id, new_achievement, int(time.time())))
        con.commit()
    bot.edit_message_text(f"✏️ Досягнення оновлено на <b>{new_achievement}</b> для користувача <code>{user_id}</code>!", message.chat.id, admin_msg_id, parse_mode="HTML")
    # Повідомлення користувачу
    try:
        bot.send_message(user_id, f"✏️ <b>Ваше досягнення було змінено адміністратором:</b> <code>{old_achievement}</code> → <b>{new_achievement}</b>", parse_mode="HTML")
    except Exception:
        pass

