def get_task_type_name_uk(task_type: str) -> str:
    """Возвращает украинское название типа задания"""
    task_type_names = {
        'subscribe_channel': 'Підписка на канал',
        'subscribe_chat': 'Підписка на чат',
        'invite_users': 'Запросити друзів',
        'deposit': 'Поповнити баланс',
        'buy_tree': 'Купити дерево',
        'harvest': 'Зібрати урожай',
        'sell_fruits': 'Продати фрукты'
    }
    return task_type_names.get(task_type, task_type)

@bot.callback_query_handler(func=lambda c: c.data.startswith("admin_task_type_"))
def admin_task_create_type(call):
    """Обработка выбора типа задания"""
    if not is_admin(call.from_user.id):
        return bot.answer_callback_query(call.id, "❌ Немає доступу", show_alert=True)
    
    task_type = call.data.replace("admin_task_type_", "")
    task_type_name = get_task_type_name_uk(task_type)
    set_user_state(call.from_user.id, f"admin_task_create_title:{task_type}")
    
    bot.edit_message_text(
        f"📋 <b>СТВОРЕННЯ ЗАВДАННЯ</b>\n\n"
        f"Тип: <b>{task_type_name}</b>\n\n"
        f"Введіть <b>назву завдання</b>:",
        call.message.chat.id,
        call.message.message_id,
        parse_mode="HTML"
    )
    
    msg = bot.send_message(call.message.chat.id, "✏️ Введіть назву завдання:")
    bot.register_next_step_handler(msg, admin_task_create_title_step, task_type)

def admin_task_create_title_step(message, task_type):
    """Шаг 1: Название задания"""
    if not is_admin(message.from_user.id):
        return
    
    title = message.text.strip()
    if not title:
        msg = bot.send_message(message.chat.id, "❌ Назва не може бути порожньою. Спробуйте ще раз:")
        return bot.register_next_step_handler(msg, admin_task_create_title_step, task_type)
    
    set_user_state(message.from_user.id, f"admin_task_create_description:{task_type}:{title}")
    
    bot.send_message(
        message.chat.id,
        f"📝 Назва: <b>{title}</b>\n\n"
        f"Введіть <b>опис завдання</b> (або надішліть '-' для пропуску):",
        parse_mode="HTML"
    )
    
    msg = bot.send_message(message.chat.id, "✏️ Введіть опис:")
    bot.register_next_step_handler(msg, admin_task_create_description_step, task_type, title)

def admin_task_create_description_step(message, task_type, title):
    """Шаг 2: Описание задания"""
    if not is_admin(message.from_user.id):
        return
    
    description = message.text.strip()
    if description == "-":
        description = None
    
    set_user_state(message.from_user.id, f"admin_task_create_data:{task_type}:{title}:{description or ''}")
    
    # В зависимости от типа задания запрашиваем разные данные
    if task_type == "subscribe_channel":
        bot.send_message(
            message.chat.id,
            f"📢 Введіть <b>ID каналу</b> (наприклад: @channel або -1001234567890):",
            parse_mode="HTML"
        )
        msg = bot.send_message(message.chat.id, "✏️ Введіть ID каналу:")
        bot.register_next_step_handler(msg, admin_task_create_data_step, task_type, title, description)
    elif task_type == "subscribe_chat":
        bot.send_message(
            message.chat.id,
            f"💬 Введіть <b>ID чату</b> (наприклад: @chat або -1001234567890):",
            parse_mode="HTML"
        )
        msg = bot.send_message(message.chat.id, "✏️ Введіть ID чату:")
        bot.register_next_step_handler(msg, admin_task_create_data_step, task_type, title, description)
    elif task_type == "invite_users":
        bot.send_message(
            message.chat.id,
            f"👥 Введіть <b>кількість друзів</b>, яких потрібно запросити:",
            parse_mode="HTML"
        )
        msg = bot.send_message(message.chat.id, "✏️ Введіть кількість:")
        bot.register_next_step_handler(msg, admin_task_create_data_step, task_type, title, description)
    elif task_type == "deposit":
        bot.send_message(
            message.chat.id,
            f"💵 Введіть <b>мінімальну суму депозиту</b> (в гривнях):",
            parse_mode="HTML"
        )
        msg = bot.send_message(message.chat.id, "✏️ Введіть суму:")
        bot.register_next_step_handler(msg, admin_task_create_data_step, task_type, title, description)
    elif task_type == "buy_tree":
        bot.send_message(
            message.chat.id,
            f"🌳 Введіть <b>тип дерева</b> (apple, pear, cherry, peach):",
            parse_mode="HTML"
        )
        msg = bot.send_message(message.chat.id, "✏️ Введіть тип дерева:")
        bot.register_next_step_handler(msg, admin_task_create_data_step, task_type, title, description)
    elif task_type == "harvest":
        bot.send_message(
            message.chat.id,
            f"🍎 Введіть <b>кількість зборів урожаю</b>:",
            parse_mode="HTML"
        )
        msg = bot.send_message(message.chat.id, "✏️ Введіть кількість:")
        bot.register_next_step_handler(msg, admin_task_create_data_step, task_type, title, description)
    elif task_type == "sell_fruits":
        bot.send_message(
            message.chat.id,
            f"💰 Введіть <b>суму продажу фруктів</b> (в гривнях):",
            parse_mode="HTML"
        )
        msg = bot.send_message(message.chat.id, "✏️ Введіть суму:")
        bot.register_next_step_handler(msg, admin_task_create_data_step, task_type, title, description)
    else:
        # Для других типов пропускаем этот шаг
        admin_task_create_data_step(message, task_type, title, description, None)

def admin_task_create_data_step(message, task_type, title, description, data=None):
    """Шаг 3: Данные задания"""
    if not is_admin(message.from_user.id):
        return
    
    if data is None:
        data = message.text.strip()
    
    # Формируем task_data в зависимости от типа
    task_data = {}
    if task_type == "subscribe_channel":
        task_data = {"channel_id": data}
    elif task_type == "subscribe_chat":
        task_data = {"chat_id": data}
    elif task_type == "invite_users":
        try:
            task_data = {"count": int(data)}
        except ValueError:
            msg = bot.send_message(message.chat.id, "❌ Введіть число. Спробуйте ще раз:")
            return bot.register_next_step_handler(msg, admin_task_create_data_step, task_type, title, description, None)
    elif task_type == "deposit":
        try:
            task_data = {"amount": float(data)}
        except ValueError:
            msg = bot.send_message(message.chat.id, "❌ Введіть число. Спробуйте ще раз:")
            return bot.register_next_step_handler(msg, admin_task_create_data_step, task_type, title, description, None)
    elif task_type == "buy_tree":
        task_data = {"tree_type": data}
    elif task_type == "harvest":
        try:
            task_data = {"count": int(data)}
        except ValueError:
            msg = bot.send_message(message.chat.id, "❌ Введіть число. Спробуйте ще раз:")
            return bot.register_next_step_handler(msg, admin_task_create_data_step, task_type, title, description, None)
    elif task_type == "sell_fruits":
        try:
            task_data = {"amount": float(data)}
        except ValueError:
            msg = bot.send_message(message.chat.id, "❌ Введіть число. Спробуйте ще раз:")
            return bot.register_next_step_handler(msg, admin_task_create_data_step, task_type, title, description, None)
    
    set_user_state(message.from_user.id, f"admin_task_create_reward:{task_type}:{title}:{description or ''}:{str(task_data)}")
    
    bot.send_message(
        message.chat.id,
        f"💰 Введіть <b>нагороду</b> (в гривнях):",
        parse_mode="HTML"
    )
    msg = bot.send_message(message.chat.id, "✏️ Введіть суму нагороди:")
    bot.register_next_step_handler(msg, admin_task_create_reward_step, task_type, title, description, task_data)

def admin_task_create_reward_step(message, task_type, title, description, task_data):
    """Шаг 4: Награда"""
    if not is_admin(message.from_user.id):
        return
    
    try:
        reward_amount = float(message.text.strip())
        if reward_amount <= 0:
            raise ValueError
    except ValueError:
        msg = bot.send_message(message.chat.id, "❌ Введіть додатнє число. Спробуйте ще раз:")
        return bot.register_next_step_handler(msg, admin_task_create_reward_step, task_type, title, description, task_data)
    
    set_user_state(message.from_user.id, f"admin_task_create_max:{task_type}:{title}:{description or ''}:{str(task_data)}:{reward_amount}")
    
    bot.send_message(
        message.chat.id,
        f"🔢 Введіть <b>максимальну кількість виконань</b> (або 0 для безліміту):",
        parse_mode="HTML"
    )
    msg = bot.send_message(message.chat.id, "✏️ Введіть кількість:")
    bot.register_next_step_handler(msg, admin_task_create_max_step, task_type, title, description, task_data, reward_amount)

def admin_task_create_max_step(message, task_type, title, description, task_data, reward_amount):
    """Шаг 5: Максимальное количество выполнений"""
    if not is_admin(message.from_user.id):
        return
    
    try:
        max_completions = int(message.text.strip())
        if max_completions < 0:
            raise ValueError
        if max_completions == 0:
            max_completions = None
    except ValueError:
        msg = bot.send_message(message.chat.id, "❌ Введіть невід'ємне число. Спробуйте ще раз:")
        return bot.register_next_step_handler(msg, admin_task_create_max_step, task_type, title, description, task_data, reward_amount)
    
    # Создаем задание
    from database import create_task
    import json
    
    task_id = create_task(
        title=title,
        description=description,
        task_type=task_type,
        task_data=task_data,
        reward_amount=reward_amount,
        created_by=message.from_user.id,
        max_completions=max_completions
    )
    
    clear_user_state(message.from_user.id)
    
    task_type_name = get_task_type_name_uk(task_type)
    
    kb = InlineKeyboardMarkup(row_width=1)
    kb.add(InlineKeyboardButton("📋 Переглянути завдання", callback_data=f"admin_task_view:{task_id}"))
    kb.add(InlineKeyboardButton("📋 Всі завдання", callback_data="admin_tasks_list"))
    kb.add(InlineKeyboardButton("⬅️ В адмін-панель", callback_data="panel"))
    
    bot.send_message(
        message.chat.id,
        f"✅ <b>ЗАВДАННЯ СТВОРЕНО!</b>\n\n"
        f"📋 <b>Назва:</b> {title}\n"
        f"🏷 <b>Тип:</b> {task_type_name}\n"
        f"💰 <b>Нагорода:</b> {reward_amount:.2f} ₴\n"
        f"🆔 <b>ID:</b> <code>{task_id}</code>",
        parse_mode="HTML",
        reply_markup=kb
    )

@bot.callback_query_handler(func=lambda c: c.data == "admin_tasks_list")
def admin_tasks_list_handler(call):
    """Список всех заданий"""
    if not is_admin(call.from_user.id):
        return bot.answer_callback_query(call.id, "❌ Немає доступу", show_alert=True)
    
    from database import get_all_tasks
    from telebot.types import InlineKeyboardMarkup, InlineKeyboardButton
    
    tasks = get_all_tasks()
    
    if not tasks:
        bot.answer_callback_query(call.id, "😴 Немає завдань", show_alert=True)
        return
    
    text = f"📋 <b>ВСІ ЗАВДАННЯ</b> ({len(tasks)})\n\n"
    
    kb = InlineKeyboardMarkup(row_width=1)
    
    for task in tasks[:20]:  # Показываем первые 20
        status_emoji = {
            'active': '✅',
            'paused': '⏸',
            'completed': '✅',
            'expired': '⏰'
        }.get(task['status'], '❓')

        max_suffix = f"/{task['max_completions']}" if task.get('max_completions') else ""
        
        text += (
            f"{status_emoji} <b>{task['title']}</b>\n"
            f"💰 {task['reward_amount']:.2f} ₴ | "
            f"Виконань: {task['current_completions']}"
            f"{max_suffix}\n\n"
        )
        
        kb.add(InlineKeyboardButton(
            f"{status_emoji} {task['title'][:40]}",
            callback_data=f"admin_task_view:{task['id']}"
        ))
    
    if len(tasks) > 20:
        text += f"<i>... та ще {len(tasks) - 20} завдань</i>\n\n"
    
    kb.add(InlineKeyboardButton("⬅️ Назад", callback_data="admin_tasks_menu"))
    
    bot.edit_message_text(
        text,
        call.message.chat.id,
        call.message.message_id,
        reply_markup=kb,
        parse_mode="HTML"
    )

@bot.callback_query_handler(func=lambda c: c.data.startswith("admin_task_view:"))
def admin_task_view_handler(call):
    """Просмотр задания"""
    if not is_admin(call.from_user.id):
        return bot.answer_callback_query(call.id, "❌ Немає доступу", show_alert=True)
    
    try:
        task_id = int(call.data.split(":")[1])
    except ValueError:
        return bot.answer_callback_query(call.id, "❌ Помилка", show_alert=True)
    
    from database import get_task_by_id, get_task_completions_stats
    from telebot.types import InlineKeyboardMarkup, InlineKeyboardButton
    
    task = get_task_by_id(task_id)
    if not task:
        return bot.answer_callback_query(call.id, "❌ Завдання не знайдено", show_alert=True)
    
    stats = get_task_completions_stats(task_id)
    
    status_text = {
        'active': '✅ Активне',
        'paused': '⏸ На паузі',
        'completed': '✅ Завершене',
        'expired': '⏰ Прострочене'
    }.get(task['status'], '❓ Невідомо')

    max_completions_suffix = (
        f"/{task['max_completions']}" if task.get('max_completions') else " (безліміт)"
    )
    
    text = (
        f"📋 <b>ЗАВДАННЯ #{task_id}</b>\n\n"
        f"📝 <b>Назва:</b> {task['title']}\n"
        f"📄 <b>Опис:</b> {task.get('description', 'Немає')}\n"
        f"🏷 <b>Тип:</b> {task['task_type']}\n"
        f"💰 <b>Нагорода:</b> {task['reward_amount']:.2f} ₴\n"
        f"📊 <b>Статус:</b> {status_text}\n"
        f"🔢 <b>Виконань:</b> {task['current_completions']}"
        f"{max_completions_suffix}\n"
        f"👥 <b>Всього виконань:</b> {stats['completion_count']}\n"
    )
    
    kb = InlineKeyboardMarkup(row_width=2)
    if task['status'] == 'active':
        kb.add(InlineKeyboardButton("⏸ Призупинити", callback_data=f"admin_task_pause:{task_id}"))
    elif task['status'] == 'paused':
        kb.add(InlineKeyboardButton("▶️ Активувати", callback_data=f"admin_task_activate:{task_id}"))
    kb.add(InlineKeyboardButton("✏️ Редагувати", callback_data=f"admin_task_edit:{task_id}"))
    kb.add(InlineKeyboardButton("🗑 Видалити", callback_data=f"admin_task_delete:{task_id}"))
    kb.add(InlineKeyboardButton("📊 Статистика", callback_data=f"admin_task_stats:{task_id}"))
    kb.add(InlineKeyboardButton("⬅️ Назад", callback_data="admin_tasks_list"))
    
    bot.edit_message_text(
        text,
        call.message.chat.id,
        call.message.message_id,
        reply_markup=kb,
        parse_mode="HTML"
    )

