@bot.callback_query_handler(func=lambda c: c.data.startswith("admin_task_stats:"))
def admin_task_stats_handler(call):
    """Статистика выполнения задания"""
    if not is_admin(call.from_user.id):
        return bot.answer_callback_query(call.id, "❌ Немає доступу", show_alert=True)
    
    try:
        task_id = int(call.data.split(":")[1])
    except ValueError:
        return bot.answer_callback_query(call.id, "❌ Помилка", show_alert=True)
    
    from database import get_task_by_id, get_task_completions_stats
    from telebot.types import InlineKeyboardMarkup, InlineKeyboardButton
    import time
    
    task = get_task_by_id(task_id)
    if not task:
        return bot.answer_callback_query(call.id, "❌ Завдання не знайдено", show_alert=True)
    
    stats = get_task_completions_stats(task_id)
    
    text = (
        f"📊 <b>СТАТИСТИКА ЗАВДАННЯ</b>\n\n"
        f"📋 <b>{task['title']}</b>\n\n"
        f"👥 <b>Всього виконань:</b> {stats['completion_count']}\n\n"
    )
    
    if stats['users']:
        text += "<b>Останні виконання:</b>\n"
        from database import get_user
        
        for user_row in stats['users'][:10]:
            user_id, completed_at, reward_received = user_row
            date_str = time.strftime('%d.%m.%Y %H:%M', time.localtime(completed_at))
            
            # Отримуємо інформацію про користувача
            user_info = get_user(user_id)
            if user_info:
                user_name = user_info[1] or f"Користувач {user_id}"
                username = user_info[8] if len(user_info) > 8 else None
                
                # Формуємо ім'я з посиланням на профіль
                if username:
                    user_display = f"@{username}"
                else:
                    user_display = user_name
                
                # Використовуємо HTML посилання на профіль через tg://user
                text += f"• <a href=\"tg://user?id={user_id}\">{user_display}</a> — {reward_received:.2f} ₴ ({date_str})\n"
            else:
                # Якщо користувача не знайдено - показуємо ID
                text += f"• <code>{user_id}</code> — {reward_received:.2f} ₴ ({date_str})\n"
    
    kb = InlineKeyboardMarkup(row_width=1)
    kb.add(InlineKeyboardButton("⬅️ Назад", callback_data=f"admin_task_view:{task_id}"))
    
    bot.edit_message_text(
        text,
        call.message.chat.id,
        call.message.message_id,
        reply_markup=kb,
        parse_mode="HTML"
    )

