    def _humanize_delta(seconds: int) -> str:
        try:
            seconds = int(seconds)
        except Exception:
            return "—"
        m = seconds // 60
        h = m // 60
        d = h // 24
        if d > 0:
            return f"{d} д {h%24} год тому"
        if h > 0:
            return f"{h} год {m%60} хв тому"
        if m > 0:
            return f"{m} хв тому"
        return "щойно"
