from telebot.types import InlineKeyboardMarkup, InlineKeyboardButton

# Utility: try delete source message from a callback to avoid stacking old menus
def _try_delete_call_message(call):
    try:
        if getattr(call, 'message', None):
            bot.delete_message(call.message.chat.id, call.message.message_id)
    except Exception:
        pass

def cleanup_old_bot_messages(chat_id, keep_last_n=1):
    """
    Видаляє старі повідомлення бота в чаті, залишаючи тільки останні N.
    Зберігає ID повідомлень в пам'яті для кожного чату.
    
    Args:
        chat_id: ID чату
        keep_last_n: Скільки останніх повідомлень залишити (за замовчуванням 1)
    """
    try:
        # Ініціалізуємо словник для зберігання ID повідомлень, якщо його немає
        if not hasattr(bot, '_bot_message_ids'):
            bot._bot_message_ids = {}
        
        # Отримуємо список ID повідомлень для цього чату
        if chat_id not in bot._bot_message_ids:
            bot._bot_message_ids[chat_id] = []
        
        message_ids = bot._bot_message_ids[chat_id]
        
        # Якщо повідомлень більше ніж потрібно залишити - видаляємо старі
        if len(message_ids) > keep_last_n:
            # Видаляємо всі крім останніх keep_last_n
            ids_to_delete = message_ids[:-keep_last_n]
            for msg_id in ids_to_delete:
                try:
                    bot.delete_message(chat_id, msg_id)
                except Exception as e:
                    # Повідомлення вже видалене або недоступне - ігноруємо
                    pass
            
            # Оновлюємо список, залишаючи тільки останні keep_last_n
            bot._bot_message_ids[chat_id] = message_ids[-keep_last_n:]
    except Exception as e:
        # Якщо щось пішло не так - просто ігноруємо, щоб не порушити основну функціональність
        print(f"[CLEANUP] Помилка очищення повідомлень для чату {chat_id}: {e}")

def track_bot_message(chat_id, message_id):
    """
    Додає ID повідомлення до списку відстежуваних повідомлень бота.
    
    Args:
        chat_id: ID чату
        message_id: ID повідомлення
    """
    try:
        if not hasattr(bot, '_bot_message_ids'):
            bot._bot_message_ids = {}
        
        if chat_id not in bot._bot_message_ids:
            bot._bot_message_ids[chat_id] = []
        
        # Додаємо ID до списку (якщо його ще немає)
        if message_id not in bot._bot_message_ids[chat_id]:
            bot._bot_message_ids[chat_id].append(message_id)
    except Exception:
        pass

# Utility: route slash-commands manually from inside next_step handlers
def _route_slash_command(message):
    try:
        text = (message.text or "").strip()
        if not text.startswith('/'):
            return False
        cmd = text.split()[0].lower()
        mapping = {
            '/stars_admin': stars_admin_handler,
            '/stars_rate': stars_rate_handler,
            '/stars_min': stars_min_handler,
            '/stars_fee': stars_fee_handler,
            '/stars_toggle': stars_toggle_handler,
            '/stars_stats': stars_stats_handler,
            '/cryptobot_admin': cryptobot_admin_handler,
            '/cryptobot_token': cryptobot_token_handler,
            '/cryptobot_api': cryptobot_api_handler,
            '/cryptobot_rate': cryptobot_rate_handler,
            '/cryptobot_min': cryptobot_min_handler,
            '/cryptobot_fee': cryptobot_fee_handler,
            '/cryptobot_toggle': cryptobot_toggle_handler,
            '/cryptobot_currencies': cryptobot_currencies_handler,
            '/cryptobot_test': cryptobot_test_handler,
            '/cryptobot_webhook': cryptobot_webhook_handler,
            '/stars_payout': stars_payout_handler,
        }
        handler = mapping.get(cmd)
        if handler:
            try:
                # best-effort: clear any pending next_step
                bot.clear_step_handler_by_chat_id(message.chat.id)
            except Exception:
                pass
            handler(message)
            return True
        return False
    except Exception:
        return False

# Safe wrappers for next_step: allow slash-commands to break out of forms
def safe_register_next_step_handler(msg, callback, *args):
    def _wrapped(message, *a):
        if _route_slash_command(message):
            return
        return callback(message, *a)
    try:
        return bot.register_next_step_handler(msg, _wrapped, *args)
    except Exception:
        # fallback to direct
        return bot.register_next_step_handler(msg, callback, *args)

def safe_register_next_step_handler_by_chat_id(chat_id, callback, *args):
    def _wrapped(message, *a):
        if _route_slash_command(message):
            return
        return callback(message, *a)
    try:
        return bot.register_next_step_handler_by_chat_id(chat_id, _wrapped, *args)
    except Exception:
        return bot.register_next_step_handler_by_chat_id(chat_id, callback, *args)
