@bot.message_handler(commands=['unban'])
def unban_command(message):
    user_id = message.from_user.id
    
    # Тільки адміни можуть розбанювати
    if not is_admin(user_id):
        return bot.send_message(message.chat.id, "❌ У вас немає прав для використання цієї команди.")
    
    parts = message.text.split(maxsplit=1)
    if len(parts) < 2:
        return bot.send_message(message.chat.id, 
                               "📝 <b>Використання:</b>\n\n"
                               "🔹 <code>/unban 123456789</code>\n"
                               "🔹 <code>/unban @username</code>", 
                               parse_mode="HTML")
    
    target = parts[1]
    target_user_id = None
    target_display = target
    
    if target.startswith('@'):
        # Пошук по username
        from database import get_user_id_by_username
        target_user_id = get_user_id_by_username(target)
        if not target_user_id:
            return bot.send_message(message.chat.id, f"❌ Користувач {target} не знайдений в базі даних.")
        target_display = f"{target} (ID: {target_user_id})"
    else:
        try:
            target_user_id = int(target)
            target_display = f"ID: {target_user_id}"
        except ValueError:
            return bot.send_message(message.chat.id, "❌ Некоректний ID користувача або username.")
    
    from database import unban_user, is_user_banned, get_ban_info
    banned, ban_reason = is_user_banned(target_user_id)
    
    if not banned:
        return bot.send_message(message.chat.id, f"❌ Користувач {target_display} не забанений.")
    
    # Отримуємо інформацію про бан перед видаленням
    ban_info = get_ban_info(target_user_id)
    
    unban_user(target_user_id)
    bot.send_message(message.chat.id, 
                    f"✅ <b>КОРИСТУВАЧА РОЗБАНЕНО!</b>\n\n"
                    f"👤 <b>Користувач:</b> {target_display}\n"
                    f"💬 <b>Була причина:</b> {ban_reason or 'Не вказано'}\n"
                    f"👮 <b>Модератор:</b> <a href='tg://user?id={user_id}'>Admin</a>\n\n"
                    f"🔓 <b>Доступ до бота відновлено!</b>", 
                    parse_mode="HTML")

@bot.message_handler(commands=['ban'])
def ban_command(message):
    user_id = message.from_user.id
    
    # Тільки адміни можуть банювати
    if not is_admin(user_id):
        return bot.send_message(message.chat.id, "❌ У вас немає прав для використання цієї команди.")
    
    parts = message.text.split(maxsplit=3)
    if len(parts) < 3:
        return bot.send_message(message.chat.id, 
                               "📝 <b>Використання:</b>\n\n"
                               "🔹 <code>/ban 123456789 1d Спам</code>\n"
                               "🔹 <code>/ban @username 2h Порушення правил</code>\n"
                               "🔹 <code>/ban 123456789 permanent Постійний бан</code>\n\n"
                               "⏰ <b>Формати часу:</b>\n"
                               "• <code>30s</code> - 30 секунд\n"
                               "• <code>5m</code> - 5 хвилин\n"
                               "• <code>2h</code> - 2 години\n"
                               "• <code>3d</code> - 3 дні\n"
                               "• <code>1w</code> - 1 тиждень\n"
                               "• <code>1M</code> - 1 місяць\n"
                               "• <code>1y</code> - 1 рік\n"
                               "• <code>permanent</code> - постійний бан", 
                               parse_mode="HTML")
    
    target = parts[1]
    duration_str = parts[2]
    reason = parts[3] if len(parts) > 3 else "Не вказано"
    
    target_user_id = None
    target_display = target
    
    if target.startswith('@'):
        # Пошук по username
        from database import get_user_id_by_username
        target_user_id = get_user_id_by_username(target)
        if not target_user_id:
            return bot.send_message(message.chat.id, f"❌ Користувач {target} не знайдений в базі даних.")
        target_display = f"{target} (ID: {target_user_id})"
    else:
        try:
            target_user_id = int(target)
            target_display = f"ID: {target_user_id}"
        except ValueError:
            return bot.send_message(message.chat.id, "❌ Некоректний ID користувача або username.")
    
    # Парсимо тривалість
    duration_seconds = parse_duration(duration_str)
    if duration_seconds is False:
        return bot.send_message(message.chat.id, 
                               "❌ Некоректний формат часу!\n\n"
                               "⏰ <b>Приклади:</b>\n"
                               "• <code>30s</code> - 30 секунд\n"
                               "• <code>5m</code> - 5 хвилин\n"
                               "• <code>2h</code> - 2 години\n"
                               "• <code>3d</code> - 3 дні\n"
                               "• <code>1w</code> - 1 тиждень\n"
                               "• <code>1M</code> - 1 місяць\n"
                               "• <code>1y</code> - 1 рік\n"
                               "• <code>permanent</code> - постійний бан", 
                               parse_mode="HTML")
    
    # Перевіряємо чи користувач вже забанений
    from database import is_user_banned, ban_user, get_user
    banned, existing_reason = is_user_banned(target_user_id)
    
    if banned:
        return bot.send_message(message.chat.id, 
                               f"❌ Користувач {target_display} вже забанений!\n\n"
                               f"💬 <b>Причина:</b> {existing_reason or 'Не вказано'}\n"
                               f"🔓 Спочатку розбаніть користувача командою <code>/unban {target}</code>", 
                               parse_mode="HTML")
    
    # Перевіряємо чи існує користувач
    user_info = get_user(target_user_id)
    if not user_info:
        return bot.send_message(message.chat.id, f"❌ Користувач {target_display} не знайдений в базі даних.")
    
    # Банюємо користувача
    ban_user(target_user_id, user_id, reason, duration_seconds)
    
    # Форматуємо повідомлення
    if duration_seconds is None:
        duration_text = "♾️ <b>Постійний бан</b>"
    else:
        duration_text = f"⏰ <b>Тривалість:</b> {format_duration(duration_seconds)}"
    
    bot.send_message(message.chat.id, 
                    f"🚫 <b>КОРИСТУВАЧА ЗАБАНЕНО!</b>\n\n"
                    f"👤 <b>Користувач:</b> {target_display}\n"
                    f"💬 <b>Причина:</b> {reason}\n"
                    f"{duration_text}\n"
                    f"👮 <b>Модератор:</b> <a href='tg://user?id={user_id}'>Admin</a>\n\n"
                    f"🔒 <b>Доступ до бота заблоковано!</b>", 
                    parse_mode="HTML")

def parse_duration(duration_str):
    """Парсить рядок тривалості в секунди - приймає будь-який формат"""
    if not duration_str:
        return False
    
    duration_str = duration_str.lower().strip()
    
    # Постійний бан
    if duration_str in ["назавжди", "permanent", "forever", "∞"]:
        return None
    
    # Спеціальні ключові слова
    if duration_str in ["5хв", "5min", "5m"]:
        return 5 * 60
    elif duration_str in ["30хв", "30min", "30m"]:
        return 30 * 60
    elif duration_str in ["1год", "1h", "1hr"]:
        return 3600
    elif duration_str in ["2год", "2h", "2hr"]:
        return 2 * 3600
    elif duration_str in ["1день", "1day", "1d"]:
        return 86400
    elif duration_str in ["7днів", "7days", "7d"]:
        return 7 * 86400
    elif duration_str in ["1місяць", "1month", "1m"]:
        return 30 * 86400
    elif duration_str in ["1рік", "1year", "1y"]:
        return 365 * 86400
    
    # Спробуємо парсити числа з одиницями
    import re
    
    # Формат: число + одиниця (5хв, 30хв, 1год, 2год, 1день, 7днів, 1місяць, 1рік)
    patterns = [
        (r'^(\d+)\s*хв$', 60),           # хвилини
        (r'^(\d+)\s*год$', 3600),        # години
        (r'^(\d+)\s*днів$', 86400),      # дні
        (r'^(\d+)\s*день$', 86400),      # день
        (r'^(\d+)\s*місяців$', 2592000), # місяці
        (r'^(\d+)\s*місяць$', 2592000),  # місяць
        (r'^(\d+)\s*років$', 31536000),  # роки
        (r'^(\d+)\s*рік$', 31536000),    # рік
        (r'^(\d+)\s*хв$', 60),           # хвилини (альтернативний формат)
        (r'^(\d+)\s*год$', 3600),        # години (альтернативний формат)
    ]
    
    for pattern, multiplier in patterns:
        match = re.match(pattern, duration_str)
        if match:
            amount = int(match.group(1))
            return amount * multiplier
    
    # Якщо нічого не підійшло, спробуємо просто число (вважаємо за хвилини)
    try:
        amount = int(duration_str)
        return amount * 60  # За замовчуванням хвилини
    except ValueError:
        pass
    
    # Якщо нічого не спрацювало, повертаємо False
    return False

def format_duration(seconds):
    """Форматує секунди в читабельний формат"""
    units = [
        ('рік', 'роки', 'років', 31536000),
        ('місяць', 'місяці', 'місяців', 2592000),
        ('тиждень', 'тижні', 'тижнів', 604800),
        ('день', 'дні', 'днів', 86400),
        ('година', 'години', 'годин', 3600),
        ('хвилина', 'хвилини', 'хвилин', 60),
        ('секунда', 'секунди', 'секунд', 1)
    ]
    
    for single, few, many, unit_seconds in units:
        if seconds >= unit_seconds:
            count = seconds // unit_seconds
            if count == 1:
                return f"1 {single}"
            elif 2 <= count <= 4:
                return f"{count} {few}"
            else:
                return f"{count} {many}"
    return "0 секунд"

# --- Текстові швидкі команди для мут/бану ---
@bot.message_handler(func=lambda m: not m.reply_to_message and bool(m.text) and m.text.lower().startswith(("мут ", "mute ")))
def handle_text_mute(message):
    if not is_admin(message.from_user.id):
        return
    try:
        parts = message.text.split(maxsplit=3)
        # Очікуємо: Мут <id|@username> <термін> <причина>
        if len(parts) < 4:
            return bot.reply_to(message, "❗ Формат: Мут <ID|@username> <термін> <причина>")
        _, target, duration_str, reason = parts[0], parts[1], parts[2], parts[3]
        # Розв'язуємо target
        target_user_id = None
        if target.startswith('@'):
            from database import get_user_by_username
            row = get_user_by_username(target)
            if row:
                target_user_id = row[0]
        else:
            try:
                target_user_id = int(target)
            except Exception:
                pass
        if not target_user_id:
            return bot.reply_to(message, "❌ Користувача не знайдено")
        secs = parse_duration(duration_str)
        if secs is False:
            return bot.reply_to(message, "❌ Невірний формат терміну")
        res = mute_user(target_user_id, secs, reason, message.from_user.id)
        if res.get('success'):
            # Накладаємо обмеження в чаті, якщо це група/супергрупа
            try:
                if message.chat.type in ("group", "supergroup"):
                    import time as _t
                    until_date = int(_t.time()) + (secs if secs else 366*24*3600)
                    perms = ChatPermissions(can_send_messages=False)
                    bot.restrict_chat_member(message.chat.id, target_user_id, until_date=until_date, permissions=perms)
            except Exception:
                pass
            bot.reply_to(message, f"🔇 Замучено <a href='tg://user?id={target_user_id}'>користувача</a> на {('невизначений термін' if secs is None else format_duration(secs))}\nПричина: {reason}", parse_mode="HTML")
        else:
            bot.reply_to(message, f"❌ Помилка: {res.get('error','')}")
    except Exception as e:
        print(f"[DEBUG] handle_text_mute error: {e}")

