def auction_admin_ban(call):
    if not is_admin(call.from_user.id):
        return bot.answer_callback_query(call.id, "⛔️ Немає доступу", show_alert=True)
    parts = call.data.split(":")
    aid = int(parts[1]); uid = int(parts[2]); seconds = int(parts[3])
    # Якщо seconds == 0 — запитуємо довільний термін у хвилинах
    if seconds == 0:
        msg = bot.send_message(call.message.chat.id, "⏳ Введіть термін бана у хвилинах (наприклад 120):")
        bot.register_next_step_handler(msg, auction_admin_ban_custom_duration, aid, uid)
    else:
        msg = bot.send_message(call.message.chat.id, "📝 Вкажіть причину бана для участі в аукціонах:")
        bot.register_next_step_handler(msg, auction_admin_ban_apply, aid, uid, seconds)

def auction_admin_ban_custom_duration(message, aid, uid):
    try:
        minutes = int(str(message.text).strip())
        seconds = max(60, minutes * 60)
    except Exception:
        return bot.send_message(message.chat.id, "❌ Некоректне число хвилин")
    msg = bot.send_message(message.chat.id, "📝 Вкажіть причину бана для участі в аукціонах:")
    bot.register_next_step_handler(msg, auction_admin_ban_apply, aid, uid, seconds)

def auction_admin_ban_apply(message, aid, uid, seconds):
    reason = (message.text or '').strip() or 'Порушення правил аукціону'
    from database import set_auction_ban
    try:
        set_auction_ban(uid, seconds, reason)
        bot.send_message(message.chat.id, f"🚫 Заборонено участь користувача {uid} на {seconds//3600} год. Причина: {reason}")
        try:
            bot.send_message(uid, f"🚫 Вам заборонено участь в аукціонах на {seconds//3600} год. Причина: {reason}")
        except Exception:
            pass
    except Exception as e:
        bot.send_message(message.chat.id, f"❌ Помилка бана: {e}")

