def _auction_form_prompt(chat_id: int, text: str):
    """Показує/оновлює одне й те саме службове повідомлення під час створення лота і повертає Message для next_step_handler."""
    if not hasattr(bot, 'auction_form_prompts'):
        bot.auction_form_prompts = {}
    prev = bot.auction_form_prompts.get(chat_id)
    if prev:
        try:
            bot.edit_message_text(text, chat_id, prev.message_id, parse_mode="HTML")
        except Exception:
            try:
                prev = bot.send_message(chat_id, text, parse_mode="HTML")
                bot.auction_form_prompts[chat_id] = prev
            except Exception:
                pass
        return prev
    else:
        try:
            prev = bot.send_message(chat_id, text, parse_mode="HTML")
            bot.auction_form_prompts[chat_id] = prev
        except Exception:
            prev = None
        return prev

