# ======== Покрокові форми ========
def booster_title_step(message, booster_type, default_title):
    title = message.text.strip() if message.text.strip() else default_title
    msg = _auction_form_prompt(message.chat.id, "💵 <b>Стартова ціна</b> (грн):")
    bot.register_next_step_handler(msg, booster_start_price_step, booster_type, title)

def booster_start_price_step(message, booster_type, title):
    try:
        start_price = float(str(message.text).replace(',', '.'))
    except Exception:
        return _auction_form_prompt(message.chat.id, "❌ Вкажіть число")
    msg = _auction_form_prompt(message.chat.id, "📈 <b>Мінімальний крок</b> (грн):")
    bot.register_next_step_handler(msg, booster_min_step_step, booster_type, title, start_price)

def booster_min_step_step(message, booster_type, title, start_price):
    try:
        min_step = float(str(message.text).replace(',', '.'))
    except Exception:
        return _auction_form_prompt(message.chat.id, "❌ Вкажіть число")
    msg = _auction_form_prompt(message.chat.id, "🛒 <b>Buy-Now</b> (грн) або '-' для відсутності:")
    bot.register_next_step_handler(msg, booster_buynow_step, booster_type, title, start_price, min_step)

def booster_buynow_step(message, booster_type, title, start_price, min_step):
    txt = message.text.strip()
    buy_now = None if txt == '-' else float(str(txt).replace(',', '.')) if txt else None
    msg = _auction_form_prompt(message.chat.id, "⏳ <b>Тривалість</b> (хв):")
    bot.register_next_step_handler(msg, booster_duration_step, booster_type, title, start_price, min_step, buy_now)

def booster_duration_step(message, booster_type, title, start_price, min_step, buy_now):
    try:
        duration = int(message.text.strip())
    except Exception:
        return _auction_form_prompt(message.chat.id, "❌ Вкажіть ціле число хвилин")
    msg = _auction_form_prompt(message.chat.id, "🛡 <b>Анти-снайп</b> (сек, Enter для 15):")
    bot.register_next_step_handler(msg, booster_antisnipe_step, booster_type, title, start_price, min_step, buy_now, duration)

def booster_antisnipe_step(message, booster_type, title, start_price, min_step, buy_now, duration):
    txt = (message.text or '').strip()
    anti = int(txt) if txt else 15
    msg = _auction_form_prompt(message.chat.id, "📝 <b>Опис</b> (можна пропустити Enter):")
    bot.register_next_step_handler(msg, booster_desc_step, booster_type, title, start_price, min_step, buy_now, duration, anti)

def booster_desc_step(message, booster_type, title, start_price, min_step, buy_now, duration, anti):
    desc = (message.text or '').strip()
    # Видаляємо службовий промпт форми
    try:
        if hasattr(bot, 'auction_form_prompts') and bot.auction_form_prompts.get(message.chat.id):
            m = bot.auction_form_prompts.pop(message.chat.id)
            try:
                bot.delete_message(m.chat.id, m.message_id)
            except Exception:
                pass
    except Exception:
        pass
    
    # Зберігаємо дані тимчасово
    import uuid
    import time
    if not hasattr(bot, 'auction_temp_data'):
        bot.auction_temp_data = {}
    temp_id = str(uuid.uuid4())[:8]
    bot.auction_temp_data[temp_id] = {
        'type': 'booster',
        'booster_type': booster_type,
        'title': title,
        'desc': desc,
        'start_price': start_price,
        'min_step': min_step,
        'buy_now': buy_now,
        'duration': duration,
        'anti': anti,
        'created_at': time.time()
    }
    
    from database import get_auction_chat
    default_chat = get_auction_chat()
    kb = InlineKeyboardMarkup(row_width=1)
    if default_chat:
        try:
            chat_info = bot.get_chat(default_chat)
            chat_name = chat_info.title if hasattr(chat_info, 'title') else f"Канал {default_chat}"
            kb.add(InlineKeyboardButton(f"📣 {chat_name}", callback_data=f"auction_pub:{temp_id}:{default_chat}"))
        except Exception:
            kb.add(InlineKeyboardButton(f"📣 Канал {default_chat}", callback_data=f"auction_pub:{temp_id}:{default_chat}"))
    kb.add(InlineKeyboardButton("💬 Поточний чат", callback_data=f"auction_pub:{temp_id}:{message.chat.id}"))
    kb.add(InlineKeyboardButton("✏️ Ввести ID каналу", callback_data=f"auction_chat_input:{temp_id}"))
    
    chat_text = f"📣 <b>Оберіть канал для публікації:</b>\n\n"
    if default_chat:
        try:
            chat_info = bot.get_chat(default_chat)
            chat_name = chat_info.title if hasattr(chat_info, 'title') else f"Канал {default_chat}"
            chat_text += f"• Налаштований канал: <b>{chat_name}</b>\n"
        except Exception:
            chat_text += f"• Налаштований канал: <code>{default_chat}</code>\n"
    chat_text += f"• Поточний чат: <code>{message.chat.id}</code>"
    
    try:
        bot.send_message(message.chat.id, chat_text, parse_mode="HTML", reply_markup=kb)
    except Exception as e:
        print(f"[ERROR] booster_desc_step: {e}")
        import traceback
        traceback.print_exc()

@bot.callback_query_handler(func=lambda c: c.data.startswith("auction_pub:"))
def auction_publish_handler(call):
    if not is_admin(call.from_user.id):
        return bot.answer_callback_query(call.id, "⛔️ Немає доступу", show_alert=True)
    try:
        parts = call.data.split(":", 2)
        temp_id = parts[1]
        target_chat = int(parts[2])
        
        if not hasattr(bot, 'auction_temp_data') or temp_id not in bot.auction_temp_data:
            return bot.answer_callback_query(call.id, "❌ Дані не знайдено. Спробуйте створити лот знову.", show_alert=True)
        
        data = bot.auction_temp_data.pop(temp_id)
        
        from database import create_auction
        if data['type'] == 'booster':
            auction_id = create_auction(target_chat, "booster", f"booster:{data['booster_type']}", data['title'], data['desc'], 
                                      data['start_price'], data['min_step'], data['buy_now'], None, data['duration'], data['anti'])
        elif data['type'] == 'tree':
            auction_id = create_auction(target_chat, "tree", f"tree:{data['tree_type']}:{data['count']}", data['title'], data['desc'],
                                      data['start_price'], data['min_step'], data['buy_now'], None, data['duration'], data['anti'])
        elif data['type'] == 'level':
            auction_id = create_auction(target_chat, "level", f"level:{data['level']}", data['title'], data['desc'],
                                      data['start_price'], data['min_step'], data['buy_now'], None, data['duration'], data['anti'])
        elif data['type'] == 'balance':
            auction_id = create_auction(target_chat, "balance", f"balance:{data['balance_amount']}", data['title'], data['desc'],
                                      data['start_price'], data['min_step'], data['buy_now'], None, data['duration'], data['anti'])
        else:
            return bot.answer_callback_query(call.id, "❌ Невідомий тип лоту", show_alert=True)
        
        post_auction_message(target_chat, auction_id, announce_start=True)
        bot.answer_callback_query(call.id, f"✅ Аукціон #{auction_id} створено!", show_alert=True)
        try:
            bot.send_message(call.message.chat.id, f"✅ Аукціон створено і опубліковано в каналі <code>{target_chat}</code> як лот #{auction_id}", parse_mode="HTML")
        except Exception:
            pass
        try:
            bot.edit_message_reply_markup(call.message.chat.id, call.message.message_id, reply_markup=None)
        except Exception:
            pass
    except Exception as e:
        import traceback
        traceback.print_exc()
        bot.answer_callback_query(call.id, f"❌ Помилка: {e}", show_alert=True)

@bot.callback_query_handler(func=lambda c: c.data.startswith("auction_chat_input:"))
def auction_chat_input_handler(call):
    if not is_admin(call.from_user.id):
        return bot.answer_callback_query(call.id, "⛔️ Немає доступу", show_alert=True)
    temp_id = call.data.split(":", 1)[1]
    if not hasattr(bot, 'auction_temp_data') or temp_id not in bot.auction_temp_data:
        return bot.answer_callback_query(call.id, "❌ Дані не знайдено", show_alert=True)
    msg = bot.send_message(call.message.chat.id, "📣 Введіть ID каналу (або username з @):")
    bot.register_next_step_handler(msg, auction_chat_id_step, temp_id)

def auction_chat_id_step(message, temp_id):
    try:
        if not hasattr(bot, 'auction_temp_data') or temp_id not in bot.auction_temp_data:
            return bot.send_message(message.chat.id, "❌ Дані не знайдено. Спробуйте створити лот знову.")
        
        chat_input = message.text.strip()
        if chat_input.startswith('@'):
            chat_info = bot.get_chat(chat_input)
            target_chat = chat_info.id
        else:
            target_chat = int(chat_input)
        
        data = bot.auction_temp_data.pop(temp_id)
        
        from database import create_auction
        if data['type'] == 'booster':
            auction_id = create_auction(target_chat, "booster", f"booster:{data['booster_type']}", data['title'], data['desc'],
                                      data['start_price'], data['min_step'], data['buy_now'], None, data['duration'], data['anti'])
        elif data['type'] == 'tree':
            auction_id = create_auction(target_chat, "tree", f"tree:{data['tree_type']}:{data['count']}", data['title'], data['desc'],
                                      data['start_price'], data['min_step'], data['buy_now'], None, data['duration'], data['anti'])
        elif data['type'] == 'level':
            auction_id = create_auction(target_chat, "level", f"level:{data['level']}", data['title'], data['desc'],
                                      data['start_price'], data['min_step'], data['buy_now'], None, data['duration'], data['anti'])
        elif data['type'] == 'balance':
            auction_id = create_auction(target_chat, "balance", f"balance:{data['balance_amount']}", data['title'], data['desc'],
                                      data['start_price'], data['min_step'], data['buy_now'], None, data['duration'], data['anti'])
        else:
            return bot.send_message(message.chat.id, "❌ Невідомий тип лоту")
        
        post_auction_message(target_chat, auction_id, announce_start=True)
        bot.send_message(message.chat.id, f"✅ Аукціон створено і опубліковано в каналі <code>{target_chat}</code> як лот #{auction_id}", parse_mode="HTML")
    except Exception as e:
        import traceback
        traceback.print_exc()
        bot.send_message(message.chat.id, f"❌ Помилка: {e}. Спробуйте ще раз.")

# --- Tree form ---
def tree_title_step(message, tree_type, default_title):
    title = message.text.strip() if message.text.strip() else default_title
    msg = _auction_form_prompt(message.chat.id, "💵 <b>Стартова ціна</b> (грн):")
    bot.register_next_step_handler(msg, tree_start_price_step, tree_type, title)

def tree_start_price_step(message, tree_type, title):
    try:
        start_price = float(str(message.text).replace(',', '.'))
    except Exception:
        return _auction_form_prompt(message.chat.id, "❌ Вкажіть число")
    msg = _auction_form_prompt(message.chat.id, "📈 <b>Мінімальний крок</b> (грн):")
    bot.register_next_step_handler(msg, tree_min_step_step, tree_type, title, start_price)

def tree_min_step_step(message, tree_type, title, start_price):
    try:
        min_step = float(str(message.text).replace(',', '.'))
    except Exception:
        return _auction_form_prompt(message.chat.id, "❌ Вкажіть число")
    msg = _auction_form_prompt(message.chat.id, "🛒 <b>Buy-Now</b> (грн) або '-' для відсутності:")
    bot.register_next_step_handler(msg, tree_buynow_step, tree_type, title, start_price, min_step)

def tree_buynow_step(message, tree_type, title, start_price, min_step):
    txt = message.text.strip()
    buy_now = None if txt == '-' else float(str(txt).replace(',', '.')) if txt else None
    msg = _auction_form_prompt(message.chat.id, "⏳ <b>Тривалість</b> (хв):")
    bot.register_next_step_handler(msg, tree_duration_step, tree_type, title, start_price, min_step, buy_now)

def tree_duration_step(message, tree_type, title, start_price, min_step, buy_now):
    try:
        duration = int(message.text.strip())
    except Exception:
        return _auction_form_prompt(message.chat.id, "❌ Вкажіть ціле число хвилин")
    msg = _auction_form_prompt(message.chat.id, "🛡 <b>Анти-снайп</b> (сек, Enter для 15):")
    bot.register_next_step_handler(msg, tree_antisnipe_step, tree_type, title, start_price, min_step, buy_now, duration)

def tree_antisnipe_step(message, tree_type, title, start_price, min_step, buy_now, duration):
    txt = (message.text or '').strip()
    anti = int(txt) if txt else 15
    msg = _auction_form_prompt(message.chat.id, "🌳 <b>Кількість дерев</b> (шт):")
    bot.register_next_step_handler(msg, tree_count_step, tree_type, title, start_price, min_step, buy_now, duration, anti)

def tree_count_step(message, tree_type, title, start_price, min_step, buy_now, duration, anti):
    try:
        count = max(1, int(message.text.strip()))
    except Exception:
        return _auction_form_prompt(message.chat.id, "❌ Вкажіть ціле число")
    msg = _auction_form_prompt(message.chat.id, "📝 <b>Опис</b> (можна пропустити Enter):")
    bot.register_next_step_handler(msg, tree_desc_step, tree_type, title, start_price, min_step, buy_now, duration, anti, count)

def tree_desc_step(message, tree_type, title, start_price, min_step, buy_now, duration, anti, count):
    desc = (message.text or '').strip()
    # Видаляємо службовий промпт форми
    try:
        if hasattr(bot, 'auction_form_prompts') and bot.auction_form_prompts.get(message.chat.id):
            m = bot.auction_form_prompts.pop(message.chat.id)
            try:
                bot.delete_message(m.chat.id, m.message_id)
            except Exception:
                pass
    except Exception:
        pass
    
    # Зберігаємо дані тимчасово
    import uuid
    import time
    if not hasattr(bot, 'auction_temp_data'):
        bot.auction_temp_data = {}
    temp_id = str(uuid.uuid4())[:8]
    bot.auction_temp_data[temp_id] = {
        'type': 'tree',
        'tree_type': tree_type,
        'count': count,
        'title': title,
        'desc': desc,
        'start_price': start_price,
        'min_step': min_step,
        'buy_now': buy_now,
        'duration': duration,
        'anti': anti,
        'created_at': time.time()
    }
    
    from database import get_auction_chat
    default_chat = get_auction_chat()
    kb = InlineKeyboardMarkup(row_width=1)
    if default_chat:
        try:
            chat_info = bot.get_chat(default_chat)
            chat_name = chat_info.title if hasattr(chat_info, 'title') else f"Канал {default_chat}"
            kb.add(InlineKeyboardButton(f"📣 {chat_name}", callback_data=f"auction_pub:{temp_id}:{default_chat}"))
        except Exception:
            kb.add(InlineKeyboardButton(f"📣 Канал {default_chat}", callback_data=f"auction_pub:{temp_id}:{default_chat}"))
    kb.add(InlineKeyboardButton("💬 Поточний чат", callback_data=f"auction_pub:{temp_id}:{message.chat.id}"))
    kb.add(InlineKeyboardButton("✏️ Ввести ID каналу", callback_data=f"auction_chat_input:{temp_id}"))
    
    chat_text = f"📣 <b>Оберіть канал для публікації:</b>\n\n"
    if default_chat:
        try:
            chat_info = bot.get_chat(default_chat)
            chat_name = chat_info.title if hasattr(chat_info, 'title') else f"Канал {default_chat}"
            chat_text += f"• Налаштований канал: <b>{chat_name}</b>\n"
        except Exception:
            chat_text += f"• Налаштований канал: <code>{default_chat}</code>\n"
    chat_text += f"• Поточний чат: <code>{message.chat.id}</code>"
    
    try:
        bot.send_message(message.chat.id, chat_text, parse_mode="HTML", reply_markup=kb)
    except Exception as e:
        print(f"[ERROR] tree_desc_step: {e}")
        import traceback
        traceback.print_exc()


