def post_auction_message(chat_id: int, auction_id: int, announce_start: bool = False):
    from database import get_auction, get_current_price, get_top_bids, get_user, list_removed_users
    import html
    row = get_auction(auction_id)
    if not row:
        return
    # очікується порядок полів як у таблиці
    (_, chat_id_db, item_type, item_key, title, description, start_price, min_step, buy_now, reserve, started_at, ends_at, anti_snipe, status, winner_user_id, winner_price) = row
    cur_price = get_current_price(auction_id)
    top = get_top_bids(auction_id, 3)
    top_lines = []
    removed_map = {uid: reason for uid, reason, _ in list_removed_users(auction_id, 50)}
    for uid, amt, ts in top:
        urow = get_user(uid)
        uname = urow[1] if urow else str(uid)
        uname = html.escape(uname)
        if uid in removed_map:
            top_lines.append(f"• <a href='tg://user?id={uid}'>{uname}</a> — <b>0₴</b> (<i>видалений</i>)")
        else:
            top_lines.append(f"• <a href='tg://user?id={uid}'>{uname}</a> — <b>{format_currency(amt)}₴</b>")
    top_block = "\n".join(top_lines) if top_lines else "—"
    # Людське відображення лоту
    item_pretty = ""
    try:
        if item_type.startswith('booster') or item_key.startswith('booster:'):
            parts = item_key.split(':')
            btype = parts[1] if len(parts) > 1 else ''
            from garden_models import BOOSTERS
            info = next((b for b in BOOSTERS if b['type']==btype), None)
            emoji = info.get('emoji','⚡') if info else '⚡'
            name = info['name'] if info else btype
            item_pretty = f"{emoji} Бустер: <b>{html.escape(name)}</b>"
        elif item_type.startswith('tree') or item_key.startswith('tree:'):
            _, ttype, cnt = item_key.split(':')
            from garden_models import TREE_TYPES
            info = next((t for t in TREE_TYPES if t['type']==ttype), None)
            emoji = info.get('fruit_emoji','🌳') if info else '🌳'
            name = info['name'] if info else ttype
            item_pretty = f"{emoji} Дерева: <b>{int(cnt)}</b> × {html.escape(name)}"
        elif item_type.startswith('level') or item_key.startswith('level:'):
            _, lvl = item_key.split(':')
            from database import get_garden_level_info
            li = get_garden_level_info(int(lvl))
            lname = li['name'] if li else f"Рівень {lvl}"
            item_pretty = f"🏆 Рівень саду: <b>{html.escape(lname)}</b>"
        elif item_type.startswith('balance') or item_key.startswith('balance:'):
            _, balance_amt = item_key.split(':')
            try:
                balance_value = float(balance_amt)
                item_pretty = f"💰 Баланс: <b>{format_currency(balance_value)}₴</b>"
            except Exception:
                item_pretty = f"💰 Баланс: <b>{html.escape(balance_amt)}₴</b>"
        else:
            item_pretty = f"📦 Лот: <code>{html.escape(item_type)}</code>"
    except Exception:
        item_pretty = f"📦 Лот: <code>{html.escape(item_type)}</code>"
    kb = InlineKeyboardMarkup(row_width=3)
    kb.add(
        InlineKeyboardButton(f"+{int(min_step)}₴", callback_data=f"auc_bid_step:{auction_id}"),
        InlineKeyboardButton(f"×2 крок", callback_data=f"auc_bid_x2:{auction_id}"),
        InlineKeyboardButton("Ввести", callback_data=f"auc_bid_enter:{auction_id}")
    )
    if buy_now:
        kb.add(InlineKeyboardButton(f"Купити зараз {format_currency(buy_now)}₴", callback_data=f"auc_buy:{auction_id}"))
    # Банер-подія (перебиття тощо), якщо задано
    banner = ""
    try:
        if hasattr(bot, 'auction_notices'):
            notice = bot.auction_notices.get(auction_id)
            if notice:
                banner = f"{notice}\n\n"
    except Exception:
        pass
    text = (
        f"🧿 <b>АУКЦІОН</b> — {html.escape(title or '')}\n"
        f"━━━━━━━━━━━━━━━━━\n\n"
        f"{banner}"
        f"{item_pretty}\n"
        f"📝 <b>Опис:</b> {html.escape(description or '-') }\n\n"
        f"💵 <b>Поточна ціна:</b> <b>{format_currency(cur_price)}₴</b> (крок: {format_currency(min_step)}₴)\n"
        f"⏳ <b>Фініш:</b> <i>{format_kiev_time(ends_at)}</i> (анти-снайп: {anti_snipe}s)\n\n"
        f"🏁 <b>Топ ставки:</b>\n{top_block}"
    )
    # Якщо повідомлення вже є — оновлюємо його, інакше надсилаємо нове
    if not hasattr(bot, 'auction_msgs'):
        bot.auction_msgs = {}
    prev = bot.auction_msgs.get(auction_id)
    if prev and prev[0] == chat_id:
        try:
            bot.edit_message_text(text, chat_id, prev[1], parse_mode="HTML", reply_markup=kb)
        except Exception:
            try:
                sent = bot.send_message(chat_id, text, parse_mode="HTML", reply_markup=kb)
                bot.auction_msgs[auction_id] = (chat_id, sent.message_id)
            except Exception:
                pass
    else:
        sent = bot.send_message(chat_id, text, parse_mode="HTML", reply_markup=kb)
        bot.auction_msgs[auction_id] = (chat_id, sent.message_id)
    # Анонс старту лише один раз під час створення
    if announce_start:
        try:
            bot.send_message(chat_id, f"🔔 <b>Старт аукціону:</b> {html.escape(title)} — старт {format_currency(start_price)}₴", parse_mode="HTML")
        except Exception:
            pass

def _update_auction_message_text(auction_id: int, text: str, reply_markup=None):
    """Оновлює головне повідомлення аукціону без створення нових повідомлень."""
    if hasattr(bot, 'auction_msgs') and bot.auction_msgs.get(auction_id):
        chat_id, msg_id = bot.auction_msgs[auction_id]
        try:
            bot.edit_message_text(text, chat_id, msg_id, parse_mode="HTML", reply_markup=reply_markup)
            return True
        except Exception:
            return False
    return False

@bot.callback_query_handler(func=lambda c: c.data.startswith("auc_bid_"))
def handle_quick_bid(call):
    from database import get_auction, get_current_price, add_auction_bid, extend_auction, get_user
    if not call.message:
        return
    auction_id = int(call.data.split(":")[1])
    row = get_auction(auction_id)
    if not row:
        return bot.answer_callback_query(call.id, "Аукціон не знайдено", show_alert=True)
    (_, chat_id_db, item_type, item_key, title, description, start_price, min_step, buy_now, reserve, started_at, ends_at, anti_snipe, status, winner_user_id, winner_price) = row
    # Заборона ставок після завершення
    import time
    if int(ends_at) <= int(time.time()) or status != 'active':
        finalize_auction_now(auction_id)
        return bot.answer_callback_query(call.id, "⏰ Аукціон вже завершено", show_alert=True)
    if status != 'active':
        return bot.answer_callback_query(call.id, "Завершений", show_alert=True)
    uid = call.from_user.id
    # Перевірка банів на участь в аукціонах
    try:
        from database import get_active_auction_ban, is_user_removed_from_auction
        ban = get_active_auction_ban(uid)
        if ban:
            import time
            remaining = int(ban['until_ts'] - time.time())
            mins = max(1, remaining // 60)
            return bot.answer_callback_query(call.id, f"🚫 Заборонено участь на {mins} хв. Причина: {ban['reason']}", show_alert=True)
    except Exception:
        pass
    try:
        auction_id = int(call.data.split(":")[1])
        if is_user_removed_from_auction(auction_id, uid):
            return bot.answer_callback_query(call.id, "🚫 Ви видалені з цього аукціону", show_alert=True)
    except Exception:
        pass
    cur = get_current_price(auction_id)
    if call.data.startswith("auc_bid_step"):
        bid = cur + float(min_step)
    elif call.data.startswith("auc_bid_x2"):
        bid = cur + float(min_step) * 2
    else:
        # Увімкнемо ввід власної суми з показом балансу та anti-spam (оновлюємо одне повідомлення на користувача)
        try:
            from database import get_user
            urow = get_user(uid)
            user_balance = float(urow[2]) if urow else 0.0
        except Exception:
            user_balance = 0.0
        next_min = cur + float(min_step)
        prompt_text = (
            f"✏️ <b>ВВЕДІТЬ СУМУ СТАВКИ</b>\n"
            f"━━━━━━━━━━━━━━━━━━━━\n\n"
            f"💵 Поточна ціна: <b>{format_currency(cur)}₴</b>\n"
            f"📈 Мінімальна нова ставка: <b>{format_currency(next_min)}₴</b>\n"
            f"👛 Ваш баланс: <b>{format_currency(user_balance)}₴</b>\n\n"
            f"🔢 Введіть суму у гривнях:"
        )
        # Видаляємо попередній промпт цього користувача, щоб не спамити
        if not hasattr(bot, 'user_bid_prompts'):
            bot.user_bid_prompts = {}
        old = bot.user_bid_prompts.get(uid)
        if old:
            try:
                bot.delete_message(old[0], old[1])
            except Exception:
                pass
        msg = bot.send_message(call.message.chat.id, prompt_text, parse_mode="HTML")
        bot.user_bid_prompts[uid] = (msg.chat.id, msg.message_id)
        return bot.register_next_step_handler(msg, bid_custom_enter, auction_id)
    try:
        # Перевірка балансу і hold з поверненням попереднього
        from database import get_user, add_balance, get_auction_hold, set_auction_hold
        urow = get_user(uid)
        user_balance = float(urow[2]) if urow else 0.0
        need = bid - cur
        # Отримаємо попереднього лідера ДО запису нового hold
        prev_hold = get_auction_hold(auction_id)
        prev_leader_id = prev_hold[0] if prev_hold and prev_hold[0] != uid else None
        if user_balance < need:
            return bot.answer_callback_query(call.id, f"❌ Недостатньо балансу. Потрібно: {format_currency(need)}₴", show_alert=True)
        # Знімаємо різницю та записуємо новий hold на повну ставку
        add_balance(uid, -need)
        set_auction_hold(auction_id, uid, bid)
        add_auction_bid(auction_id, uid, bid)
        # анти-снайп
        import time
        if (int(ends_at) - int(time.time())) <= int(anti_snipe):
            extend_auction(auction_id, int(anti_snipe))
        # Інформативний апдейт + підготовка повідомлення про перебиту ставку
        prev_leader_id = None
        try:
            from database import get_auction_hold
            hold = get_auction_hold(auction_id)
            if hold and hold[0] != uid:
                prev_leader_id = hold[0]
        except Exception:
            prev_leader_id = None
        info_text = (
            f"✅ <b>Ставку прийнято</b>\n"
            f"👤 Ви: <a href='tg://user?id={uid}'>учасник</a>\n"
            f"💰 Нова ставка: <b>{format_currency(bid)}₴</b>\n"
            f"📈 Поточна ціна оновлена."
        )
        try:
            bot.edit_message_text(info_text, call.message.chat.id, call.message.message_id, parse_mode="HTML")
        except Exception:
            pass
        # Оновлюємо банер у головному пості: ім'я нового лідера
        try:
            if not hasattr(bot, 'auction_notices'):
                bot.auction_notices = {}
            import html
            new_name = html.escape(urow[1] if urow and urow[1] else 'учасник')
            bot.auction_notices[auction_id] = f"<i>📉 Ставку перебито. Новий лідер — <a href='tg://user?id={uid}'>{new_name}</a></i>"
        except Exception:
            pass
        post_auction_message(call.message.chat.id, auction_id)
        # Публічне повідомлення про перебиття + DM попередньому лідеру
        try:
            if prev_leader_id:
                import html
                prev_user = get_user(prev_leader_id)
                prev_name = html.escape(prev_user[1] if prev_user and prev_user[1] else 'учасник')
                new_name = html.escape(urow[1] if urow and urow[1] else 'учасник')
                bot.send_message(
                    call.message.chat.id,
                    f"📉 <b>Ставку перебито!</b> <a href='tg://user?id={prev_leader_id}'>{prev_name}</a> → <a href='tg://user?id={uid}'>{new_name}</a>\n"
                    f"💰 Нова ставка: <b>{format_currency(bid)}₴</b> (була: {format_currency(cur)}₴)",
                    parse_mode="HTML"
                )
                try:
                    bot.send_message(
                        prev_leader_id,
                        f"📉 <b>Вашу ставку перебито</b> у аукціоні '{title}'. Новий лідер — <a href='tg://user?id={uid}'>{new_name}</a> — <b>{format_currency(bid)}₴</b>.",
                        parse_mode="HTML"
                    )
                except Exception:
                    pass
        except Exception:
            pass
        # Особисте підтвердження новому лідеру (з ким і яку суму перебили)
        try:
            prev_user = get_user(prev_leader_id) if prev_leader_id else None
            import html
            prev_name = html.escape(prev_user[1] if prev_user and prev_user[1] else '—') if prev_leader_id else '—'
            bot.send_message(
                uid,
                (
                    f"📌 <b>Ваша ставка прийнята</b> у аукціоні '{title}'.\n"
                    f"📉 Ви перебили: <a href='tg://user?id={prev_leader_id}'>{prev_name}</a> — <b>{format_currency(cur)}₴</b>\n"
                    f"💰 Нова ставка: <b>{format_currency(bid)}₴</b>"
                ),
                parse_mode="HTML"
            )
        except Exception:
            pass
    except Exception as e:
        bot.answer_callback_query(call.id, f"❌ Помилка: {e}", show_alert=True)

def bid_custom_enter(message, auction_id):
    from database import get_auction, get_current_price, add_auction_bid, extend_auction
    try:
        amt = float(str(message.text).replace(',', '.').strip())
    except Exception:
        return bot.send_message(message.chat.id, "❌ Некоректна сума")
    row = get_auction(auction_id)
    if not row:
        return bot.send_message(message.chat.id, "Аукціон не знайдено")
    (_, chat_id_db, item_type, item_key, title, description, start_price, min_step, buy_now, reserve, started_at, ends_at, anti_snipe, status, winner_user_id, winner_price) = row
    import time
    if int(ends_at) <= int(time.time()) or status != 'active':
        finalize_auction_now(auction_id)
        return bot.send_message(message.chat.id, "⏰ Аукціон вже завершено")
    cur = get_current_price(auction_id)
    # Перевірка банів
    try:
        from database import get_active_auction_ban
        ban = get_active_auction_ban(message.from_user.id)
        if ban:
            import time
            remaining = int(ban['until_ts'] - time.time())
            mins = max(1, remaining // 60)
            return bot.send_message(message.chat.id, f"🚫 Заборонено участь на {mins} хв. Причина: {ban['reason']}")
    except Exception:
        pass
    if amt < cur + float(min_step):
        return bot.send_message(message.chat.id, f"❗ Мінімальна ставка: {format_currency(cur + float(min_step))}₴")
    # Hold: списуємо різницю до нової ставки і зберігаємо hold на повну суму
    from database import get_user, add_balance, set_auction_hold, is_user_removed_from_auction
    urow = get_user(message.from_user.id)
    user_balance = float(urow[2]) if urow else 0.0
    try:
        if is_user_removed_from_auction(auction_id, message.from_user.id):
            return bot.send_message(message.chat.id, "🚫 Ви видалені з цього аукціону")
    except Exception:
        pass
    need = amt - cur
    if user_balance < need:
        return bot.send_message(message.chat.id, f"❌ Недостатньо балансу. Потрібно: {format_currency(need)}₴")
    add_balance(message.from_user.id, -need)
    set_auction_hold(auction_id, message.from_user.id, amt)
    add_auction_bid(auction_id, message.from_user.id, amt)
    import time
    if (int(ends_at) - int(time.time())) <= int(anti_snipe):
        extend_auction(auction_id, int(anti_snipe))
    # Інформативний апдейт без сміття в чаті
    try:
        bot.edit_message_text(
            f"✅ <b>Ставку прийнято</b>\n"
            f"👤 Ви: <a href='tg://user?id={message.from_user.id}'>учасник</a>\n"
            f"💰 Нова ставка: <b>{format_currency(amt)}₴</b>",
            message.chat.id,
            message.message_id,
            parse_mode="HTML"
        )
    except Exception:
        try:
            bot.send_message(message.chat.id, f"✅ Ставку прийнято: {format_currency(amt)}₴", parse_mode="HTML")
        except Exception:
            pass
    # Повідомлення про перебиття: DM попередньому лідеру + DM новому лідеру з деталями
    try:
        from database import get_auction_hold
        hold = get_auction_hold(auction_id)
        prev_leader_id = hold[0] if hold and hold[0] != message.from_user.id else None
        if prev_leader_id:
            try:
                bot.send_message(prev_leader_id,
                    f"📉 <b>Вашу ставку перебито</b> у аукціоні '{title}'. Новий лідер — <b>{format_currency(amt)}₴</b>.",
                    parse_mode="HTML")
            except Exception:
                pass
            try:
                import html
                bot.send_message(
                    message.from_user.id,
                    (
                        f"📌 <b>Ваша ставка прийнята</b> у аукціоні '{title}'.\n"
                        f"📉 Ви перебили: <a href='tg://user?id={prev_leader_id}'>учасник</a>\n"
                        f"💰 Нова ставка: <b>{format_currency(amt)}₴</b>"
                    ),
                    parse_mode="HTML"
                )
            except Exception:
                pass
    except Exception:
        pass
    # Після введення видаляємо інформаційний промпт користувача, щоб не накопичувались повідомлення
    try:
        if hasattr(bot, 'user_bid_prompts') and bot.user_bid_prompts.get(message.from_user.id):
            ch_id, mid = bot.user_bid_prompts.pop(message.from_user.id)
            try:
                bot.delete_message(ch_id, mid)
            except Exception:
                pass
    except Exception:
        pass
    try:
        if not hasattr(bot, 'auction_notices'):
            bot.auction_notices = {}
        bot.auction_notices[auction_id] = f"<i>📉 Ставку перебито. Новий лідер — {format_currency(amt)}₴</i>"
    except Exception:
        pass
    post_auction_message(chat_id_db, auction_id)
    try:
        import html
        uname = (urow[1] if urow else 'Учасник')
        # В чат публікації
        bot.send_message(chat_id_db, f"📈 <a href='tg://user?id={message.from_user.id}'>{html.escape(uname)}</a> зробив ставку <b>{format_currency(amt)}₴</b>", parse_mode="HTML")
        # В особисті повідомлення
        bot.send_message(message.from_user.id, f"✅ Ваша ставка <b>{format_currency(amt)}₴</b> прийнята. Баланс оновлено.", parse_mode="HTML")
    except Exception:
        pass

@bot.callback_query_handler(func=lambda c: c.data.startswith("auc_buy:"))
def handle_buy_now(call):
    from database import get_auction, add_auction_bid, finish_auction, get_user, get_auction_hold, clear_auction_hold, add_balance, get_auction_settings
    row = get_auction(int(call.data.split(":")[1]))
    if not row:
        return bot.answer_callback_query(call.id, "Аукціон не знайдено", show_alert=True)
    (_, chat_id_db, item_type, item_key, title, description, start_price, min_step, buy_now, reserve, started_at, ends_at, anti_snipe, status, winner_user_id, winner_price) = row
    import time
    if int(ends_at) <= int(time.time()) or status != 'active':
        finalize_auction_now(row[0])
        return bot.answer_callback_query(call.id, "⏰ Аукціон вже завершено", show_alert=True)
    if not buy_now:
        return bot.answer_callback_query(call.id, "Buy-Now недоступно", show_alert=True)
    # Списуємо/перевіряємо баланс та фіналізуємо
    buyer_id = call.from_user.id
    urow = get_user(buyer_id)
    balance = float(urow[2]) if urow else 0.0
    cur_hold = get_auction_hold(row[0])
    # Потрібно мати баланс на різницю до buy_now
    cur_price = float(buy_now)  # фактично нова ціна
    if cur_hold and cur_hold[0] == buyer_id:
        need = max(0.0, float(buy_now) - cur_hold[1])
    else:
        need = float(buy_now) - (cur_hold[1] if cur_hold else 0.0)
    if balance < need:
        return bot.answer_callback_query(call.id, f"❌ Недостатньо балансу. Потрібно: {format_currency(need)}₴", show_alert=True)
    if need > 0:
        add_balance(buyer_id, -need)
    add_auction_bid(row[0], buyer_id, float(buy_now))
    finish_auction(row[0], buyer_id, float(buy_now))
    # Повертаємо hold попередньому лідеру, якщо був і це не покупець
    if cur_hold and cur_hold[0] != buyer_id:
        add_balance(cur_hold[0], cur_hold[1])
    clear_auction_hold(row[0])
    award_auction_prize(buyer_id, item_type, item_key)
    # Комісія
    settings = get_auction_settings()
    commission_pct = float(settings.get('commission_percent', 1.0))
    commission = float(buy_now) * (commission_pct / 100.0)
    net = float(buy_now) - commission
    # Виводимо фінальний текст в чаті публікації і DM переможцю
    final_text = (
        f"🏁 <b>Аукціон завершено</b>\n"
        f"👑 Переможець: <a href='tg://user?id={buyer_id}'>учасник</a>\n"
        f"💰 Сума: <b>{format_currency(float(buy_now))}₴</b>\n"
        f"🏦 Комісія: {format_currency(commission)}₴\n"
        f"🧾 До зарахування продавцю: {format_currency(net)}₴"
    )
    try:
        bot.edit_message_text(final_text, call.message.chat.id, call.message.message_id, parse_mode="HTML")
    except Exception:
        try:
            bot.send_message(call.message.chat.id, final_text, parse_mode="HTML")
        except Exception:
            pass
    # Замість декількох повідомлень: надсилаємо одне DM-повідомлення переможцю, без повторів
    try:
        bot.send_message(buyer_id, f"🎉 Вітаємо! Ви виграли аукціон '{title}' за {format_currency(float(buy_now))}₴.")
    except Exception:
        pass

def award_auction_prize(user_id: int, item_type: str, item_key: str):
    try:
        if item_type.startswith('booster') or item_type == 'booster':
            # key: booster:type or booster:type:hours
            parts = item_key.split(':')
            btype = parts[1]
            hours = 24
            try:
                if len(parts) >= 3:
                    hours = int(parts[2])
            except Exception:
                pass
            from database import grant_booster
            grant_booster(user_id, btype, hours*3600)
        elif item_type == 'tree' or item_type.startswith('tree'):
            # key: tree:type:count
            _, ttype, cnt = item_key.split(':')
            from database import grant_tree
            grant_tree(user_id, ttype, int(cnt))
        elif item_type == 'level' or item_type.startswith('level'):
            # key: level:number
            _, lvl = item_key.split(':')
            from database import set_user_garden_level
            set_user_garden_level(user_id, int(lvl))
        elif item_type == 'balance' or item_type.startswith('balance'):
            # key: balance:amount
            _, balance_amt = item_key.split(':')
            try:
                balance_value = float(balance_amt)
                from database import add_balance
                add_balance(user_id, balance_value, reason='auction_win', details=f'Виграш аукціону на баланс')
            except Exception as e:
                print(f"[ERROR] award_auction_prize balance: {e}")
    except Exception as e:
        print(f"[ERROR] award_auction_prize: {e}")
        pass

# --- Швидка фіналізація аукціону (коли час вийшов) ---
def finalize_auction_now(auction_id: int):
    from database import get_auction, get_highest_valid_bid, finish_auction, get_auction_settings
    from database import get_auction_hold, clear_auction_hold, add_balance
    row = get_auction(auction_id)
    if not row:
        return False
    (aid, chat_id_db, item_type, item_key, title, description, start_price, min_step, buy_now, reserve, started_at, ends_at, anti_snipe, status, winner_user_id, winner_price) = row
    top = get_highest_valid_bid(aid)
    if not top:
        finish_auction(aid, None, None)
        try:
            bot.send_message(chat_id_db, f"🏁 Аукціон '{title}' завершено. Ставок не було.")
        except Exception:
            pass
        clear_auction_hold(aid)
        return True
    win_user, win_price = top
    hold = get_auction_hold(aid)
    if hold and hold[0] != win_user:
        try:
            add_balance(hold[0], hold[1])
        except Exception:
            pass
    finish_auction(aid, win_user, win_price)
    clear_auction_hold(aid)
    # повідомлення
    settings = get_auction_settings()
    commission_pct = float(settings.get('commission_percent', 1.0))
    commission = float(win_price or 0.0) * (commission_pct / 100.0)
    net = float(win_price or 0.0) - commission
    try:
        bot.send_message(chat_id_db,
            f"🏁 <b>Аукціон завершено</b>\n"
            f"👑 Переможець: <a href='tg://user?id={win_user}'>учасник</a>\n"
            f"💰 Сума: <b>{format_currency(float(win_price))}₴</b>\n"
            f"🏦 Комісія: {format_currency(commission)}₴\n"
            f"🧾 До зарахування продавцю: {format_currency(net)}₴",
            parse_mode="HTML")
    except Exception:
        pass
    try:
        bot.send_message(win_user, f"🎉 Вітаємо! Ви виграли аукціон '{title}' за {format_currency(float(win_price))}₴.")
    except Exception:
        pass
    try:
        award_auction_prize(win_user, item_type, item_key)
    except Exception:
        pass
    return True

# =====================
# 💬 КОМАНДИ ДЛЯ СТАВОК В КАНАЛІ
# =====================
@bot.message_handler(commands=['bid', 'ставка', 'бид'])
def bid_command_handler(message):
    """Обробка команд /bid, /ставка, /бид для ставок в каналі"""
    try:
        # Перевірка, що це канал або група
        if message.chat.type not in ['channel', 'supergroup', 'group']:
            return
        
        # Отримуємо суму з команди
        text = (message.text or "").strip()
        parts = text.split()
        if len(parts) < 2:
            try:
                bot.reply_to(message, "❌ Використання: <code>/bid &lt;сума&gt;</code>\nНаприклад: <code>/bid 100</code>", parse_mode="HTML")
            except Exception:
                pass
            return
        
        try:
            bid_amount = float(parts[1].replace(',', '.'))
        except ValueError:
            try:
                bot.reply_to(message, "❌ Некоректна сума. Введіть число, наприклад: <code>/bid 100</code>", parse_mode="HTML")
            except Exception:
                pass
            return
        
        if bid_amount <= 0:
            try:
                bot.reply_to(message, "❌ Сума повинна бути більше 0", parse_mode="HTML")
            except Exception:
                pass
            return
        
        # Шукаємо активний аукціон в цьому чаті
        from database import list_active_auctions, get_auction, get_current_price, add_auction_bid
        from database import get_user, add_balance, get_auction_hold, set_auction_hold, extend_auction
        from database import get_active_auction_ban, is_user_removed_from_auction
        import time
        import html
        
        active_auctions = list_active_auctions(100)
        auction_id = None
        auction_row = None
        
        # Шукаємо аукціон в цьому чаті
        for row in active_auctions:
            (aid, chat_id_db, item_type, item_key, title, description, start_price, min_step, buy_now, reserve, started_at, ends_at, anti_snipe, status, winner_user_id, winner_price) = row
            if chat_id_db == message.chat.id:
                auction_id = aid
                auction_row = row
                break
        
        if not auction_id or not auction_row:
            try:
                bot.reply_to(message, "❌ Активних аукціонів в цьому чаті не знайдено", parse_mode="HTML")
            except Exception:
                pass
            return
        
        (aid, chat_id_db, item_type, item_key, title, description, start_price, min_step, buy_now, reserve, started_at, ends_at, anti_snipe, status, winner_user_id, winner_price) = auction_row
        
        # Перевірка статусу
        if int(ends_at) <= int(time.time()) or status != 'active':
            finalize_auction_now(auction_id)
            try:
                bot.reply_to(message, "⏰ Аукціон вже завершено", parse_mode="HTML")
            except Exception:
                pass
            return
        
        uid = message.from_user.id
        
        # Перевірка банів
        ban = get_active_auction_ban(uid)
        if ban:
            remaining = int(ban['until_ts'] - time.time())
            mins = max(1, remaining // 60)
            try:
                bot.reply_to(message, f"🚫 Заборонено участь на {mins} хв. Причина: {ban['reason']}", parse_mode="HTML")
            except Exception:
                pass
            return
        
        if is_user_removed_from_auction(auction_id, uid):
            try:
                bot.reply_to(message, "🚫 Ви видалені з цього аукціону", parse_mode="HTML")
            except Exception:
                pass
            return
        
        cur_price = get_current_price(auction_id)
        min_bid = cur_price + float(min_step)
        
        if bid_amount < min_bid:
            try:
                bot.reply_to(message, f"❗ Мінімальна ставка: <b>{format_currency(min_bid)}₴</b> (поточна ціна: {format_currency(cur_price)}₴ + крок: {format_currency(min_step)}₴)", parse_mode="HTML")
            except Exception:
                pass
            return
        
        # Перевірка балансу
        urow = get_user(uid)
        if not urow:
            try:
                bot.reply_to(message, "❌ Користувача не знайдено. Спочатку запустіть бота: /start", parse_mode="HTML")
            except Exception:
                pass
            return
        
        user_balance = float(urow[2])
        need = bid_amount - cur_price
        
        if user_balance < need:
            try:
                bot.reply_to(message, f"❌ Недостатньо балансу. Потрібно: <b>{format_currency(need)}₴</b>, у вас: <b>{format_currency(user_balance)}₴</b>", parse_mode="HTML")
            except Exception:
                pass
            return
        
        # Отримуємо попереднього лідера
        prev_hold = get_auction_hold(auction_id)
        prev_leader_id = prev_hold[0] if prev_hold and prev_hold[0] != uid else None
        
        # Списуємо кошти та робимо ставку
        add_balance(uid, -need)
        set_auction_hold(auction_id, uid, bid_amount)
        add_auction_bid(auction_id, uid, bid_amount)
        
        # Анти-снайп
        if (int(ends_at) - int(time.time())) <= int(anti_snipe):
            extend_auction(auction_id, int(anti_snipe))
        
        # Оновлюємо повідомлення аукціону
        post_auction_message(message.chat.id, auction_id)
        
        # Публічне повідомлення про ставку
        user_name = html.escape(urow[1] if urow[1] else 'учасник')
        reply_text = (
            f"✅ <b>Ставку прийнято!</b>\n"
            f"👤 <a href='tg://user?id={uid}'>{user_name}</a>\n"
            f"💰 Нова ставка: <b>{format_currency(bid_amount)}₴</b>"
        )
        
        try:
            bot.reply_to(message, reply_text, parse_mode="HTML")
        except Exception:
            pass
        
        # Повідомлення попередньому лідеру
        if prev_leader_id and prev_leader_id != uid:
            try:
                prev_user = get_user(prev_leader_id)
                prev_name = html.escape(prev_user[1] if prev_user and prev_user[1] else 'учасник')
                bot.send_message(
                    message.chat.id,
                    f"📉 <b>Ставку перебито!</b> <a href='tg://user?id={prev_leader_id}'>{prev_name}</a> → <a href='tg://user?id={uid}'>{user_name}</a>\n"
                    f"💰 Нова ставка: <b>{format_currency(bid_amount)}₴</b>",
                    parse_mode="HTML"
                )
                try:
                    bot.send_message(
                        prev_leader_id,
                        f"📉 <b>Вашу ставку перебито</b> у аукціоні '{title}'. Новий лідер — <a href='tg://user?id={uid}'>{user_name}</a> — <b>{format_currency(bid_amount)}₴</b>.",
                        parse_mode="HTML"
                    )
                except Exception:
                    pass
            except Exception:
                pass
        
        # Оновлюємо банер у головному пості
        try:
            if not hasattr(bot, 'auction_notices'):
                bot.auction_notices = {}
            bot.auction_notices[auction_id] = f"<i>📉 Ставку перебито. Новий лідер — <a href='tg://user?id={uid}'>{user_name}</a></i>"
        except Exception:
            pass
        
    except Exception as e:
        import traceback
        print(f"[ERROR] bid_command_handler: {e}")
        traceback.print_exc()
        try:
            bot.reply_to(message, "❌ Помилка при обробці ставки. Спробуйте ще раз.", parse_mode="HTML")
        except Exception:
            pass

# =====================
# ⏱ Авто-фіналізація аукціонів
# =====================
def _auction_watcher_loop():
    from database import list_expired_auctions, get_highest_valid_bid, finish_auction, get_auction_settings
    from database import get_auction_hold, clear_auction_hold, add_balance
    from database import _db, list_removed_users
    import time as _t
    while True:
        try:
            expired = list_expired_auctions()
            for row in expired:
                (aid, chat_id_db, item_type, item_key, title, description, start_price, min_step, buy_now, reserve, started_at, ends_at, anti_snipe, status, winner_user_id, winner_price) = row
                top = get_highest_valid_bid(aid)
                if not top:
                    finish_auction(aid, None, None)
                    # Визначимо, чи були коли-небудь ставки
                    had_bids = 0
                    try:
                        with _db() as con2:
                            had_bids = con2.execute("SELECT COUNT(*) FROM auction_bids WHERE auction_id=?", (aid,)).fetchone()[0]
                    except Exception:
                        had_bids = 0
                    # Чи були видалені учасники
                    removed = []
                    try:
                        removed = list_removed_users(aid, 5) or []
                    except Exception:
                        removed = []
                    try:
                        if had_bids:
                            extra = " (усі ставки анульовано)" if removed else ""
                            bot.send_message(chat_id_db, f"🏁 Аукціон '{title}' завершено <b>без переможця</b>{extra}.", parse_mode="HTML")
                        else:
                            bot.send_message(chat_id_db, f"🏁 Аукціон '{title}' завершено. Ставок не було.")
                    except Exception:
                        pass
                    clear_auction_hold(aid)
                    continue
                win_user, win_price = top
                # Повернення hold попереднього лідера якщо не збігається
                hold = get_auction_hold(aid)
                if hold and hold[0] != win_user:
                    try:
                        add_balance(hold[0], hold[1])
                    except Exception:
                        pass
                # Якщо переможець є (ставка > 0) — фіналізуємо, інакше без переможця
                if win_user is not None and float(win_price or 0) > 0:
                    finish_auction(aid, win_user, win_price)
                else:
                    finish_auction(aid, None, None)
                clear_auction_hold(aid)
                # Комісія
                settings = get_auction_settings()
                commission_pct = float(settings.get('commission_percent', 1.0))
                commission = float(win_price or 0.0) * (commission_pct / 100.0)
                net = float(win_price or 0.0) - commission
                # Повідомлення
                try:
                    if win_user is not None and float(win_price or 0) > 0:
                        bot.send_message(chat_id_db,
                        f"🏁 <b>Аукціон завершено</b>\n"
                        f"👑 Переможець: <a href='tg://user?id={win_user}'>учасник</a>\n"
                        f"💰 Сума: <b>{format_currency(float(win_price))}₴</b>\n"
                        f"🏦 Комісія: {format_currency(commission)}₴\n"
                        f"🧾 До зарахування продавцю: {format_currency(net)}₴",
                        parse_mode="HTML")
                    else:
                        bot.send_message(chat_id_db, f"🏁 Аукціон '{title}' завершено <b>без переможця</b>.", parse_mode="HTML")
                except Exception:
                    pass
                try:
                    if win_user is not None and float(win_price or 0) > 0:
                        bot.send_message(win_user, f"🎉 Вітаємо! Ви виграли аукціон '{title}' за {format_currency(float(win_price))}₴.")
                except Exception:
                    pass
                try:
                    if win_user is not None and float(win_price or 0) > 0:
                        award_auction_prize(win_user, item_type, item_key)
                except Exception:
                    pass
        except Exception:
            pass
        _t.sleep(10)

def start_auction_watcher():
    th = threading.Thread(target=_auction_watcher_loop, name="auction-watcher", daemon=True)
    th.start()

# --- Захист від спаму перевірки підписки ---
subscription_check_attempts = {}

# --- Функція для парсингу дати створення заявки ---
def parse_created_at(created_at):
    """Парсить created_at з бази даних та конвертує у потрібний формат"""
    try:
        if created_at:
            # Конвертуємо з формату SQLite datetime до потрібного формату
            dt = datetime.datetime.strptime(created_at, "%Y-%m-%d %H:%M:%S")
            return dt.strftime("%d.%m.%Y %H:%M")
        else:
            return "—"
    except (ValueError, TypeError):
        return str(created_at) if created_at else "—"

def format_booster_time(end_timestamp):
    """Форматує час залишку бустера"""
    if not end_timestamp:
        return "♾️ Безстроково"
    
    import time
    remaining = int(end_timestamp - time.time())
    
    if remaining <= 0:
        return "⏰ Закінчився"
    
    hours = remaining // 3600
    minutes = (remaining % 3600) // 60
    
    if hours > 0:
        return f"⏳ {hours}г {minutes}хв"
    else:
        return f"⏳ {minutes}хв"

def format_boosters_display(boosters):
    """Форматує список активних бустерів для відображення"""
    if not boosters:
        return "😴 <b>Немає активних бустерів</b>"
    
    from garden_models import BOOSTERS
    booster_lines = []
    
    for booster_type, end_time in boosters:
        # Знаходимо інформацію про бустер по типу
        booster_info = next((b for b in BOOSTERS if b['type'] == booster_type), None)
        
        if booster_info:
            emoji = booster_info['emoji']
            name = booster_info['name']
            effect = booster_info['effect']
            time_str = format_booster_time(end_time)
            
            booster_lines.append(
                f"├ {emoji} <b>{name}</b>\n"
                f"│   💫 <i>{effect}</i>\n"
                f"└   ⏳ {time_str}"
            )
        else:
            # Fallback для старих бустерів
            time_str = format_booster_time(end_time)
            booster_lines.append(f"├ ⚡ <b>{booster_type}</b>\n└   ⏳ {time_str}")
    
    return "🚀 <b>АКТИВНІ БУСТЕРИ:</b>\n" + "\n\n".join(booster_lines)

