def process_required_channel(message):
    channel_username = message.text.strip()
    
    if not channel_username.startswith('@'):
        return bot.send_message(message.chat.id, "❌ Username каналу має починатися з @")
    
    from database import set_required_channel
    set_required_channel(channel_username)
    
    bot.send_message(message.chat.id, 
                    f"✅ <b>Обов'язковий канал встановлено!</b>\n\n"
                    f"📢 Канал: <b>{channel_username}</b>\n"
                    f"🔒 Тепер всі користувачі мають підписатися для доступу!\n\n"
                    f"💡 Адміни проходять без перевірки.", 
                    parse_mode="HTML")

