@bot.callback_query_handler(func=lambda c: c.data == "list_blocked_users")
def list_blocked_users_handler(call):
    if not is_admin(call.from_user.id):
        return bot.answer_callback_query(call.id, "⛔️ Немає доступу", show_alert=True)
    from database import get_all_blocked_users
    rows = get_all_blocked_users() or []
    if not rows:
        return bot.answer_callback_query(call.id, "Немає заблокованих", show_alert=True)
    text_lines = ["👥 <b>Заблоковані через відписку</b>\n"]
    kb = InlineKeyboardMarkup(row_width=2)
    for user_id, reason, chat_title, blocked_at, block_type in rows[:30]:
        text_lines.append(f"• <code>{user_id}</code> — {chat_title} ({'канал' if block_type=='channel_leave' else 'чат'})")
        kb.add(InlineKeyboardButton(f"🔓 Розблокувати {user_id}", callback_data=f"unblock_user:{user_id}"))
    kb.add(InlineKeyboardButton("⬅️ Назад", callback_data="manage_channels"))
    try:
        bot.edit_message_text("\n".join(text_lines), call.message.chat.id, call.message.message_id, reply_markup=kb, parse_mode="HTML")
    except Exception:
        bot.send_message(call.message.chat.id, "\n".join(text_lines), reply_markup=kb, parse_mode="HTML")

@bot.callback_query_handler(func=lambda c: c.data.startswith("unblock_user:"))
def unblock_user_handler(call):
    if not is_admin(call.from_user.id):
        return bot.answer_callback_query(call.id, "⛔️ Немає доступу", show_alert=True)
    try:
        target_id = int(call.data.split(":",1)[1])
    except Exception:
        return bot.answer_callback_query(call.id)
    from database import unblock_user
    unblock_user(target_id)
    try:
        bot.answer_callback_query(call.id, "✅ Розблоковано")
    except Exception:
        pass
    try:
        list_blocked_users_handler(call)
    except Exception:
        pass

def process_add_channel(message):
    channel_username = message.text.strip()
    
    if not channel_username.startswith('@'):
        return bot.send_message(message.chat.id, "❌ Username каналу має починатися з @")
    
    from database import add_required_channel
    add_required_channel(channel_username)
    
    bot.send_message(message.chat.id, 
                    f"✅ <b>Публічний канал додано!</b>\n\n"
                    f"📢 Канал: <b>{channel_username}</b>\n"
                    f"🔒 Тепер користувачі мають підписатися на всі канали!\n\n"
                    f"💡 Адміни проходять без перевірки.", 
                    parse_mode="HTML")

def process_add_private_group(message):
    group_id = message.text.strip()
    
    try:
        group_id = int(group_id)
        if group_id > 0:
            return bot.send_message(message.chat.id, "❌ ID групи має бути від'ємним числом")
    except ValueError:
        return bot.send_message(message.chat.id, "❌ ID групи має бути числом")
    
    # Перевіряємо чи бот може отримати інформацію про групу
    try:
        chat_info = bot.get_chat(group_id)
        from database import add_required_chat
        add_required_chat(str(group_id))
        
        bot.send_message(message.chat.id, 
                        f"✅ <b>Приватна група додана!</b>\n\n"
                        f"👥 Група: <b>{chat_info.title}</b>\n"
                        f"🆔 ID: <code>{group_id}</code>\n"
                        f"🔒 Тепер бот перевіряє участь у групі!\n\n"
                        f"💡 Адміни проходять без перевірки.", 
                        parse_mode="HTML")
    except Exception as e:
        bot.send_message(message.chat.id, 
                        f"❌ <b>Помилка додавання групи!</b>\n\n"
                        f"🔍 Перевірте:\n"
                        f"• Бот доданий як адміністратор\n"
                        f"• Надано права на перегляд учасників\n"
                        f"• ID групи правильний\n\n"
                        f"⚠️ Помилка: {str(e)}", 
                        parse_mode="HTML")

