def process_delete_user_input(message):
    """Обробляє введення ID/username для видалення"""
    if not is_admin(message.from_user.id):
        return bot.send_message(message.chat.id, "❌ У вас немає прав.")
    
    target = message.text.strip()
    
    # Визначаємо чи це username чи ID
    if target.startswith('@'):
        from database import get_user_id_by_username
        target_user_id = get_user_id_by_username(target)
        if not target_user_id:
            kb = InlineKeyboardMarkup()
            kb.add(InlineKeyboardButton("🔙 Назад", callback_data="panel"))
            return bot.send_message(message.chat.id, 
                                   f"❌ Користувача {target} не знайдено в базі.\n\n"
                                   f"💡 Можливо він ще не користувався ботом.", 
                                   reply_markup=kb)
        target_display = f"{target} (ID: {target_user_id})"
    else:
        try:
            target_user_id = int(target)
            target_display = f"ID: {target_user_id}"
        except ValueError:
            kb = InlineKeyboardMarkup()
            kb.add(InlineKeyboardButton("🔙 Назад", callback_data="panel"))
            return bot.send_message(message.chat.id, 
                                   "❌ Некоректний ID користувача або username.\n\n"
                                   "📝 Приклади: <code>123456789</code> або <code>@username</code>",
                                   reply_markup=kb, parse_mode="HTML")
    
    # Перевіряємо чи користувач існує
    from database import get_user_exists
    if not get_user_exists(target_user_id):
        kb = InlineKeyboardMarkup()
        kb.add(InlineKeyboardButton("🔙 Назад", callback_data="panel"))
        return bot.send_message(message.chat.id, 
                                f"❌ Користувача {target_display} не знайдено в базі.\n\n"
                                f"💡 Можливо він ще не користувався ботом.",
                                reply_markup=kb)
    
    # Перевіряємо чи це не адмін
    if is_admin(target_user_id):
        kb = InlineKeyboardMarkup()
        kb.add(InlineKeyboardButton("🔙 Назад", callback_data="panel"))
        return bot.send_message(message.chat.id, 
                                f"❌ Неможливо видалити адміністратора!\n\n"
                                f"👤 {target_display} — адміністратор системи.",
                                reply_markup=kb)
    
    # Показуємо підтвердження з вибором дій
    kb = InlineKeyboardMarkup(row_width=1)
    kb.add(
        InlineKeyboardButton("🗑️ ВИДАЛИТИ ПОВНІСТЮ", 
                           callback_data=f"confirm_delete_user:{target_user_id}"),
        InlineKeyboardButton("🚫 Заблокувати + Видалити", 
                           callback_data=f"ban_and_delete_user:{target_user_id}"),
        InlineKeyboardButton("❌ Відмінити", callback_data="panel")
    )
    
    bot.send_message(message.chat.id,
                    f"⚠️ <b>ОСТАТОЧНЕ ПІДТВЕРДЖЕННЯ</b>\n"
                    f"━━━━━━━━━━━━━━━━━━━━\n\n"
                    f"👤 <b>Користувач:</b> {target_display}\n\n"
                    f"🔥 <b>Виберіть дію:</b>\n\n"
                    f"🗑️ <b>ВИДАЛИТИ ПОВНІСТЮ</b>\n"
                    f"• Повне видалення з бази\n"
                    f"• Користувач зможе заново зареєструватись\n\n"
                    f"🚫 <b>ЗАБЛОКУВАТИ + ВИДАЛИТИ</b>\n"
                    f"• Спочатку заблокує назавжди\n"
                    f"• Потім видалить всі дані\n"
                    f"• Користувач не зможе повернутись\n\n"
                    f"⚠️ <b>Обидві дії незворотні!</b>",
                    reply_markup=kb, parse_mode="HTML")

@bot.callback_query_handler(func=lambda c: c.data.startswith("confirm_delete_user:"))
def confirm_delete_user_handler(call):
    if check_maintenance(call): return
    if not is_admin(call.from_user.id):
        return bot.answer_callback_query(call.id, "Нема доступу", show_alert=True)
    
    user_id_to_delete = int(call.data.split(":")[1])
    
    from database import delete_user_completely, get_user
    
    # Отримуємо інформацію про користувача перед видаленням
    user_info = get_user(user_id_to_delete)
    user_name = user_info[1] if user_info else 'Невідомий'  # user_name - второй элемент кортежа
    
    # Видаляємо користувача
    delete_user_completely(user_id_to_delete)
    
    kb = InlineKeyboardMarkup()
    kb.add(InlineKeyboardButton("🔙 Адмін панель", callback_data="panel"))
    
    bot.edit_message_text(
        f"✅ <b>КОРИСТУВАЧА ВИДАЛЕНО!</b>\n"
        f"━━━━━━━━━━━━━━━━━━━━\n\n"
        f"🗑️ <b>Видалений користувач:</b>\n"
        f"👤 {user_name} (ID: {user_id_to_delete})\n\n"
        f"🔥 <b>Що було видалено:</b>\n"
        f"• Профіль та баланс\n"
        f"• Сад та дерева\n"
        f"• Транзакції та історія\n"
        f"• Реферальні зв'язки\n"
        f"• Номер телефону\n"
        f"• Всі ігрові дані\n\n"
        f"💡 <b>Користувач може заново зареєструватись</b>\n"
        f"👮 <b>Модератор:</b> <a href='tg://user?id={call.from_user.id}'>Admin</a>",
        call.message.chat.id,
        call.message.message_id,
        reply_markup=kb,
        parse_mode="HTML"
    )
    bot.answer_callback_query(call.id, "Користувача видалено!", show_alert=True)

@bot.callback_query_handler(func=lambda c: c.data.startswith("ban_and_delete_user:"))
def ban_and_delete_user_handler(call):
    if check_maintenance(call): return
    if not is_admin(call.from_user.id):
        return bot.answer_callback_query(call.id, "Нема доступу", show_alert=True)
    
    user_id_to_delete = int(call.data.split(":")[1])
    
    from database import ban_user, delete_user_completely, get_user
    
    # Отримуємо інформацію про користувача перед видаленням
