# --- Команда видалення користувача ---
@bot.message_handler(commands=['deleteuser'])
def delete_user_command(message):
    user_id = message.from_user.id
    
    # Тільки адміни можуть видаляти
    if not is_admin(user_id):
        return bot.send_message(message.chat.id, "❌ У вас немає прав для використання цієї команди.")
    
    # Парсимо команду: /deleteuser @username|id
    parts = message.text.split(maxsplit=1)
    if len(parts) < 2:
        return bot.send_message(message.chat.id, 
                               "📝 <b>Використання команди /deleteuser:</b>\n\n"
                               "🔹 <code>/deleteuser @username</code>\n"
                               "🔹 <code>/deleteuser 123456789</code>\n\n"
                               "⚠️ <b>УВАГА!</b> Дія незворотна!\n"
                               "🗑️ Користувач буде повністю видалений з бази",
                               parse_mode="HTML")
    
    target = parts[1].strip()
    
    # Симулюємо callback для використання існуючої логіки
    fake_message = type('obj', (object,), {
        'text': target,
        'from_user': message.from_user,
        'chat': message.chat
    })
    
    process_delete_user_input(fake_message)

