@bot.callback_query_handler(func=lambda c: c.data == "admin_booster_multipliers")
def admin_booster_multipliers(call):
    if not is_admin(call.from_user.id):
        return bot.answer_callback_query(call.id, "⛔️ Немає доступу", show_alert=True)
    from database import get_game_setting
    def _get(key, default):
        try:
            return get_game_setting(key, str(default))
        except Exception:
            return str(default)
    try:
        min_days = int(float(_get('booster_min_days', '4')))
    except Exception:
        min_days = 4
    try:
        mult_min = float(_get(f'booster_mult_{min_days}d', str(float(min_days))))
    except Exception:
        mult_min = float(min_days)
    def _to_float(v, d):
        try:
            return float(v)
        except Exception:
            return d
    mult_7d = _to_float(_get('booster_mult_7d', '4.0'), 4.0)
    mult_30d = _to_float(_get('booster_mult_30d', '15.0'), 15.0)
    mult_365d = _to_float(_get('booster_mult_365d', '150.0'), 150.0)

    msg = (
        "⚙️ <b>Коефіцієнти та мінімальний строк</b>\n"
        "━━━━━━━━━━━━━━━━━\n\n"
        f"🗓 Мінімальний строк: <b>{min_days}д</b>\n"
        f"✖️ Множник для {min_days}д: <b>{mult_min}</b>\n"
        f"✖️ 7 днів: <b>{mult_7d}</b>\n"
        f"✖️ 30 днів: <b>{mult_30d}</b>\n"
        f"✖️ 365 днів: <b>{mult_365d}</b>\n\n"
        "ℹ️ Базова ціна задається за 1 день. Вартість пакету = базова × множник."
    )
    kb = InlineKeyboardMarkup(row_width=2)
    kb.add(
        InlineKeyboardButton("🗓 Змінити мінімум", callback_data="bm_set_min_days"),
        InlineKeyboardButton(f"✖️ {min_days}д", callback_data=f"bm_set_min_mult:{min_days}")
    )
    kb.add(
        InlineKeyboardButton("✖️ 7д", callback_data="bm_set_7d"),
        InlineKeyboardButton("✖️ 30д", callback_data="bm_set_30d")
    )
    kb.add(
        InlineKeyboardButton("✖️ 365д", callback_data="bm_set_365d"),
        InlineKeyboardButton("⬅️ Назад", callback_data="admin_manage_boosters")
    )
    bot.edit_message_text(msg, call.message.chat.id, call.message.message_id, reply_markup=kb, parse_mode="HTML")

@bot.callback_query_handler(func=lambda c: c.data in ("bm_set_min_days","bm_set_7d","bm_set_30d","bm_set_365d") or c.data.startswith("bm_set_min_mult:"))
def admin_booster_multipliers_set(call):
    if not is_admin(call.from_user.id):
        return bot.answer_callback_query(call.id, "⛔️ Немає доступу", show_alert=True)
    action = call.data
    if action == "bm_set_min_days":
        msg = bot.send_message(call.message.chat.id, "🗓 Введіть мінімальний строк у днях (ціле число, напр.: 4)")
        return bot.register_next_step_handler(msg, _bm_apply_min_days)
    if action.startswith("bm_set_min_mult:"):
        d = int(action.split(":",1)[1])
        msg = bot.send_message(call.message.chat.id, f"✖️ Введіть множник для {d}д (напр.: {d}.0)")
        return bot.register_next_step_handler(msg, _bm_apply_mult, f"booster_mult_{d}d")
    if action == "bm_set_7d":
        msg = bot.send_message(call.message.chat.id, "✖️ Введіть множник для 7д (напр.: 4)")
        return bot.register_next_step_handler(msg, _bm_apply_mult, "booster_mult_7d")
    if action == "bm_set_30d":
        msg = bot.send_message(call.message.chat.id, "✖️ Введіть множник для 30д (напр.: 15)")
        return bot.register_next_step_handler(msg, _bm_apply_mult, "booster_mult_30d")
    if action == "bm_set_365d":
        msg = bot.send_message(call.message.chat.id, "✖️ Введіть множник для 365д (напр.: 150)")
        return bot.register_next_step_handler(msg, _bm_apply_mult, "booster_mult_365d")

def _bm_apply_min_days(message):
    try:
        nd = int(str(message.text).strip())
        from database import set_game_setting
        nd = max(1, nd)
        set_game_setting('booster_min_days', str(nd))
        try:
            set_game_setting(f'booster_mult_{nd}d', str(float(nd)))
        except Exception:
            pass
        bot.send_message(message.chat.id, f"✅ Мінімальний строк встановлено: {nd}д")
    except Exception:
        bot.send_message(message.chat.id, "❌ Помилка. Введіть ціле число днів.")
    class _D: pass
    d=_D(); d.data="admin_booster_multipliers"; d.from_user=message.from_user; d.message=type('M',(),{'chat':message.chat,'message_id':message.message_id})()
    admin_booster_multipliers(d)

def _bm_apply_mult(message, key):
    try:
        val = float(str(message.text).strip().replace(',', '.'))
        from database import set_game_setting
        set_game_setting(key, str(max(0.1, val)))
        bot.send_message(message.chat.id, f"✅ Множник для <code>{key}</code> встановлено: {val}", parse_mode="HTML")
    except Exception:
        bot.send_message(message.chat.id, "❌ Помилка. Введіть число (напр.: 4, 15, 150)")
    class _D: pass
    d=_D(); d.data="admin_booster_multipliers"; d.from_user=message.from_user; d.message=type('M',(),{'chat':message.chat,'message_id':message.message_id})()
    admin_booster_multipliers(d)

