def admin_give_booster_step1(message):
    if not is_admin(message.from_user.id):
        return bot.send_message(message.chat.id, "⛔️ Немає доступу")
    
    text = message.text.strip()
    user_id = None
    
    from database import get_user_by_username, get_user
    
    if text.startswith('@'):
        user = get_user_by_username(text)
        if user:
            user_id = user[0]
        else:
            return bot.send_message(message.chat.id, "❌ Користувача з таким username не знайдено.")
    else:
        try:
            user_id = int(text)
        except ValueError:
            return bot.send_message(message.chat.id, "❌ Некоректний ID користувача.")
    
    # Перевіряємо що користувач існує
    user = get_user(user_id)
    if not user:
        return bot.send_message(message.chat.id, f"❌ Користувача з ID {user_id} не знайдено в базі.")
    
    user_name = user[1]
    
    # Показуємо меню бустерів для вибору
    from garden_models import BOOSTERS
    kb = InlineKeyboardMarkup(row_width=1)
    
    for b in BOOSTERS:
        duration_text = f"{b['duration_hours']}г" if b['duration_hours'] >= 1 else f"{int(b['duration_hours'] * 60)}хв"
        kb.add(InlineKeyboardButton(
            f"{b['emoji']} {b['name']} ({duration_text})",
            callback_data=f"admin_give_booster_confirm_{user_id}_{b['type']}"
        ))
    
    kb.add(InlineKeyboardButton("❌ Скасувати", callback_data="admin_manage_boosters"))
    
    bot.send_message(message.chat.id, 
                    f"🎁 <b>Видача бустера користувачу:</b>\n"
                    f"👤 <b>Користувач:</b> {user_name} (ID: {user_id})\n\n"
                    f"🚀 <b>Оберіть бустер для видачі:</b>",
                    reply_markup=kb, parse_mode="HTML")

@bot.callback_query_handler(func=lambda c: c.data.startswith("admin_give_booster_confirm_"))
def admin_give_booster_confirm_handler(call):
    if not is_admin(call.from_user.id):
        return bot.answer_callback_query(call.id, "⛔️ Немає доступу", show_alert=True)
    
    parts = call.data.split("_")
    user_id = int(parts[4])
    booster_type = parts[5]
    
    from garden_models import BOOSTERS
    from database import get_user, _db
    import time
    
    booster = next((b for b in BOOSTERS if b['type'] == booster_type), None)
    if not booster:
        return bot.answer_callback_query(call.id, "❌ Невідомий тип бустера!", show_alert=True)
    
    user = get_user(user_id)
    if not user:
        return bot.answer_callback_query(call.id, "❌ Користувача не знайдено!", show_alert=True)
    
    user_name = user[1]
    admin_name = get_user(call.from_user.id)[1] if get_user(call.from_user.id) else "Адмін"
    
    # Розраховуємо час дії
    duration_seconds = int(booster['duration_hours'] * 3600)
    end_time = int(time.time()) + duration_seconds
    duration_text = f"{booster['duration_hours']}г" if booster['duration_hours'] >= 1 else f"{int(booster['duration_hours'] * 60)}хв"
    
    # Додаємо бустер
    with _db() as con:
        con.execute(
            "INSERT INTO boosters (user_id, type, expires_at) VALUES (?, ?, ?)",
            (user_id, booster_type, end_time)
        )
        con.commit()
    
    # Повідомлення адміну
    admin_msg = (
        f"✅ <b>БУСТЕР ВИДАНО!</b>\n"
        f"━━━━━━━━━━━━━━━━━━━━\n\n"
        f"🎁 <b>Бустер:</b> {booster['emoji']} {booster['name']}\n"
        f"👤 <b>Отримувач:</b> <a href='tg://user?id={user_id}'>{user_name}</a>\n"
        f"🆔 <b>ID:</b> <code>{user_id}</code>\n"
        f"⏰ <b>Тривалість:</b> <b>{duration_text}</b>\n"
        f"💫 <b>Ефект:</b> <i>{booster['effect']}</i>\n"
        f"👤 <b>Видав:</b> <b>{admin_name}</b>\n\n"
        f"📬 <i>Користувача повідомлено!</i>"
    )
    
    # Повідомлення користувачу
    user_msg = (
        f"🎉🎁 <b>ВИ ОТРИМАЛИ БУСТЕР!</b> 🎁🎉\n"
        f"━━━━━━━━━━━━━━━━━\n\n"
        f"{booster['emoji']} <b>{booster['name']}</b>\n\n"
        f"💫 <b>Ефект:</b> <i>{booster['effect']}</i>\n"
        f"⏰ <b>Тривалість:</b> <b>{duration_text}</b>\n"
        f"📝 <b>Опис:</b> <i>{booster['description']}</i>\n\n"
        f"🎁 <b>Видав адміністратор:</b> <b>{admin_name}</b>\n\n"
        f"🚀 <b>Використовуйте бустер максимально ефективно!</b>\n"
        f"💎 <i>Цей подарунок допоможе вам швидше розвиватися!</i>"
    )
    
    try:
        bot.send_message(user_id, user_msg, parse_mode="HTML")
    except Exception:
        admin_msg += f"\n\n⚠️ <i>Не вдалося відправити повідомлення користувачу</i>"
    
    kb = InlineKeyboardMarkup()
    kb.add(InlineKeyboardButton("🎁 Видати ще", callback_data="admin_give_booster"))
    kb.add(InlineKeyboardButton("⬅️ Управління бустерами", callback_data="admin_manage_boosters"))
    
    bot.edit_message_text(admin_msg, call.message.chat.id, call.message.message_id, reply_markup=kb, parse_mode="HTML")
    bot.answer_callback_query(call.id, "✅ Бустер видано!", show_alert=False)

