def admin_view_boosters_step(message):
    if not is_admin(message.from_user.id):
        return bot.send_message(message.chat.id, "⛔️ Немає доступу")
    
    text = message.text.strip()
    user_id = None
    
    from database import get_user_by_username, get_user, get_active_boosters
    
    if text.startswith('@'):
        user = get_user_by_username(text)
        if user:
            user_id = user[0]
        else:
            return bot.send_message(message.chat.id, "❌ Користувача з таким username не знайдено.")
    else:
        try:
            user_id = int(text)
        except ValueError:
            return bot.send_message(message.chat.id, "❌ Некоректний ID користувача.")
    
    user = get_user(user_id)
    if not user:
        return bot.send_message(message.chat.id, f"❌ Користувача з ID {user_id} не знайдено в базі.")
    
    user_name = user[1]
    boosters = get_active_boosters(user_id)
    
    if not boosters:
        msg = (
            f"😴 <b>АКТИВНІ БУСТЕРИ</b>\n"
            f"━━━━━━━━━━━━━━━━━━━━\n\n"
            f"👤 <b>Користувач:</b> {user_name} (ID: {user_id})\n\n"
            f"😴 <i>У користувача немає активних бустерів</i>"
        )
    else:
        boosters_display = format_boosters_display(boosters)
        msg = (
            f"🚀 <b>АКТИВНІ БУСТЕРИ</b>\n"
            f"━━━━━━━━━━━━━━━━━━━━\n\n"
            f"👤 <b>Користувач:</b> {user_name} (ID: {user_id})\n\n"
            f"{boosters_display}"
        )
    
    kb = InlineKeyboardMarkup()
    kb.add(InlineKeyboardButton("🔍 Переглянути іншого", callback_data="admin_view_boosters"))
    if boosters:
        kb.add(InlineKeyboardButton("❌ Видалити бустер", callback_data="admin_remove_booster"))
    kb.add(InlineKeyboardButton("⬅️ Управління бустерами", callback_data="admin_manage_boosters"))
    
    bot.send_message(message.chat.id, msg, reply_markup=kb, parse_mode="HTML")

