import random

# Команда /random - тепер працює в групах
@bot.message_handler(commands=['random', 'game', 'гра'])
def random_command_handler(message):
    # Перевіряємо чи увімкнені ігри
    if not are_games_enabled():
        if message.chat.type == 'private':
            bot.send_message(message.chat.id, "🚫 Ігри тимчасово вимкнені адміністратором.")
        return
    
    # Отримуємо ім'я користувача
    user_name = message.from_user.first_name or "Гравець"
    
    # Перевіряємо тип чату
    if message.chat.type == 'private':
        # Приватний чат - показуємо повне меню
        show_private_betting_menu(message)
    else:
        # Груповий чат - показуємо інформацію з кнопкою переходу в бот
        show_group_game_info(message, user_name)

# Обробник текстових повідомлень для фраз "бот рандом" та "гра рандом"
@bot.message_handler(func=lambda m: m.text and (
    m.text.lower().strip() in ['бот рандом', 'гра рандом', 'bot random', 'game random'] or
    m.text.lower().strip().startswith('бот рандом ') or
    m.text.lower().strip().startswith('гра рандом ')
))
def random_text_handler(message):
    if not are_games_enabled():
        return
    
    text = message.text.lower().strip()
    if text in ['бот рандом', 'гра рандом', 'bot random', 'game random']:
        random_command_handler(message)
    elif text.startswith('бот рандом ') or text.startswith('гра рандом '):
        random_command_handler(message)

