# Решта системи ігор залишається така ж, але з використанням динамічних коефіцієнтів
@bot.callback_query_handler(func=lambda c: c.data.startswith("bet_"))
def bet_game_handler(call):
    game_type = call.data.split("_")[1]
    
    # Перевіряємо чи увімкнена конкретна гра
    if not is_game_enabled(game_type):
        bot.answer_callback_query(call.id, f"❌ Гра {game_type} вимкнена адміністратором!", show_alert=True)
        return
    
    from database import get_user
    user_data = get_user(call.from_user.id)
    balance = user_data[2] if user_data else 0
    
    min_bet = float(get_game_setting('min_bet', '1.0'))
    
    if balance < min_bet:
        bot.answer_callback_query(call.id, f"❌ Недостатньо коштів! Мінімум {format_currency(min_bet)}₴", show_alert=True)
        return
    
    # Зберігаємо тип гри
    if not hasattr(bot, 'user_betting_data'):
        bot.user_betting_data = {}
    bot.user_betting_data[call.from_user.id] = {'game_type': game_type}
    
    max_bet = min(balance, float(get_game_setting('max_bet', '1000.0')))
    
    message_text = (
        f"💰 <b>СТАВКА НА ГРУ</b>\n"
        f"━━━━━━━━━━━━━━━━━━━━\n\n"
        f"💳 <b>Ваш баланс:</b> <b>{format_currency(balance)}₴</b>\n\n"
        f"💸 <b>Введіть суму ставки:</b>\n"
        f"• Мінімум: <b>{format_currency(min_bet)}₴</b>\n"
        f"• Максимум: <b>{format_currency(max_bet)}₴</b>\n\n"
        f"💡 <i>Напишіть число (наприклад: 10)</i>"
    )
    
    kb = InlineKeyboardMarkup()
    # Швидкі ставки на основі налаштувань
    quick_bets = []
    possible_bets = [1, 5, 10, 25, 50, 100, 250, 500]
    
    for bet in possible_bets:
        if bet >= min_bet and bet <= max_bet:
            quick_bets.append(f"{bet}₴")
        if len(quick_bets) >= 6:  # Максимум 6 швидких ставок
            break
    
    if quick_bets:
        for i in range(0, len(quick_bets), 3):
            row_bets = quick_bets[i:i+3]
            kb.add(*[InlineKeyboardButton(bet, callback_data=f"quick_bet_{bet[:-1]}") for bet in row_bets])
    
    kb.add(InlineKeyboardButton("❌ Скасувати", callback_data="random_again"))
    
    msg = bot.send_message(call.message.chat.id, message_text, reply_markup=kb, parse_mode="HTML")
    bot.register_next_step_handler(msg, process_bet_amount, game_type)
    bot.answer_callback_query(call.id)

# Решта функцій залишається переважно така ж, але з динамічними коефіцієнтами
@bot.callback_query_handler(func=lambda c: c.data.startswith("quick_bet_"))
def quick_bet_handler(call):
    amount = float(call.data.split("_")[2])
    game_type = bot.user_betting_data.get(call.from_user.id, {}).get('game_type', 'dice')
    
    class FakeMessage:
        def __init__(self, text, user_id, chat_id, user_first_name):
            self.text = str(text)
            self.from_user = type('obj', (object,), {
                'id': user_id,
                'first_name': user_first_name
            })
            self.chat = type('obj', (object,), {'id': chat_id})
    
    fake_msg = FakeMessage(amount, call.from_user.id, call.message.chat.id, call.from_user.first_name)
    process_bet_amount(fake_msg, game_type)
    bot.answer_callback_query(call.id)

def process_bet_amount(message, game_type):
    """Обробляє суму ставки з урахуванням налаштувань"""
    try:
        amount = float(message.text.strip())
    except ValueError:
        bot.send_message(message.chat.id, "❌ Некоректна сума! Введіть число.")
        return

    from database import get_user, add_balance
    user_data = get_user(message.from_user.id)
    
    if not user_data:
        bot.send_message(message.chat.id, "❌ Користувача не знайдено!")
        return
    
    balance = user_data[2]
    min_bet = float(get_game_setting('min_bet', '1.0'))
    max_bet = min(balance, float(get_game_setting('max_bet', '1000.0')))
    
    if amount < min_bet:
        bot.send_message(message.chat.id, f"❌ Мінімальна ставка: {format_currency(min_bet)}₴")
        return
    
    if amount > max_bet:
        bot.send_message(message.chat.id, f"❌ Максимальна ставка: {format_currency(max_bet)}₴")
        return
    
    # Знімаємо ставку
    add_balance(message.from_user.id, -amount)
    
    # Запускаємо гру з динамічними коефіцієнтами
    if game_type == "dice":
        play_dice_game_dynamic(message, amount)
    elif game_type == "coin":
        play_coin_game_dynamic(message, amount)
    elif game_type == "number":
        play_number_game_dynamic(message, amount)
    elif game_type == "slot":
        play_slot_game_dynamic(message, amount)

