@bot.callback_query_handler(func=lambda c: c.data.startswith("number_game_start_"))
def number_game_start_handler(call):
    """Обробник для повернення до початкового меню number game"""
    if check_maintenance(call): return
    
    try:
        parts = call.data.split('_')
        bet_amount = float(parts[3])
        
        # Очищаємо стан користувача якщо він є
        try:
            bot.delete_state(call.from_user.id, call.message.chat.id)
        except:
            pass
        
        # Створюємо псевдо-message для початкового меню
        class FakeMessage:
            def __init__(self, chat_id, user_id, first_name):
                self.chat = type('obj', (object,), {'id': chat_id})
                self.from_user = type('obj', (object,), {'id': user_id, 'first_name': first_name})
        
        fake_message = FakeMessage(call.message.chat.id, call.from_user.id, call.from_user.first_name)
        
        # Видаляємо поточне повідомлення
        try:
            bot.delete_message(call.message.chat.id, call.message.message_id)
        except:
            pass
        
        # Показуємо початкове меню number game
        play_number_game_dynamic(fake_message, bet_amount)
        
    except (ValueError, IndexError) as e:
        bot.answer_callback_query(call.id, "❌ Помилка повернення до меню", show_alert=True)

def execute_number_game(call, chosen_number, bet_amount):
    """Виконання гри в число з епічною анімацією!"""
    import random, time
    
    user_id = call.from_user.id
    user_name = call.from_user.first_name or "Гравець"
    
    # Генеруємо таємне число
    secret_number = random.randint(1, 100)
    
    # Розраховуємо відстань та результат
    distance = abs(chosen_number - secret_number)
    
    # Визначаємо результат та множник з налаштувань бази даних
    if distance == 0:
        result_type = "BULLS_EYE"
        multiplier = float(get_game_setting('number_bulls_eye_multiplier', '50.0'))
        zone_emoji = "🎯"
        zone_name = "ТОЧНЕ ПОПАДАННЯ"
        result_emoji = "🎊🎉🎊"
    elif distance <= 3:
        result_type = "HOT"
        multiplier = float(get_game_setting('number_hot_multiplier', '10.0'))
        zone_emoji = "🔥"
