# --- Slash-команди для адмінів (працюють із privacy mode) ---
@bot.message_handler(commands=['ahelp','adminhelp','modhelp'])
def admin_help_cmd(message):
    if not is_admin(message.from_user.id):
        return
    text = (
        "🎛️ <b>АДМІН-КОМАНДИ</b> (через /):\n\n"
        "💰 Баланс: /give 100 [@user|id] | /take 50 [@user|id]\n"
        "🌳 🌳 Дерев: <b>3 шт</b> [@user|id]\n"
        "⚡ Бустер: /booster autowater 12 [@user|id]\n"
        "🍎 Фрукти: /fruit apple 20 [@user|id]\n\n"
        "💡 Можна надіслати у відповідь на повідомлення — тоді користувач береться з відповіді."
    )
    try:
        bot.reply_to(message, text, parse_mode="HTML")
    except Exception:
        pass

def _parse_target_from_args(message, args):
    # Якщо відповіли на повідомлення — беремо звідти
    if getattr(message, 'reply_to_message', None) and getattr(message.reply_to_message, 'from_user', None):
        return message.reply_to_message.from_user.id
    # Інакше шукаємо @username або id в args
    if not args:
        return None
    last = args[-1]
    if last.startswith('@'):
        try:
            from database import get_user_by_username
            row = get_user_by_username(last)
            return row[0] if row else None
        except Exception:
            return None
    try:
        return int(last)
    except Exception:
        return None

def _notify_balance_updates(admin_id, target_id, delta_amount):
    try:
        sign = '+' if delta_amount >= 0 else '−'
        from utils import format_currency as _fc
    except Exception:
        def _fc(x): return f"{float(x):.2f}"
    # Користувачу
    try:
        bot.send_message(target_id, f"💳 <b>Зміна балансу</b>\n{sign}{_fc(abs(delta_amount))}₴ через чат адміністратором.", parse_mode="HTML")
    except Exception:
        pass
    # Адміну
    try:
        bot.send_message(admin_id, f"✅ Баланс користувача {target_id} змінено на {sign}{_fc(abs(delta_amount))}₴", parse_mode="HTML")
    except Exception:
        pass

@bot.message_handler(commands=['give','take'])
def admin_balance_cmd(message):
    if not is_admin(message.from_user.id):
        return
    parts = (message.text or '').split()
    if len(parts) < 2:
        return bot.reply_to(message, "❌ Формат: /give 100 [@user|id] або у відповіді на повідомлення", parse_mode="HTML")
    try:
        amt = float(parts[1].replace(',', '.'))
    except Exception:
        return bot.reply_to(message, "❌ Некоректна сума", parse_mode="HTML")
    is_take = message.text.split()[0].lstrip('/').lower() == 'take'
    delta = -abs(amt) if is_take else abs(amt)
    target = _parse_target_from_args(message, parts[2:])
    if not target:
        return bot.reply_to(message, "❌ Не вказано користувача. Зробіть відповідь на повідомлення або додайте @user/id.", parse_mode="HTML")
    from database import add_balance
    add_balance(target, delta, reason=("admin_chat_penalty" if is_take else "admin_chat_gift"), details=f"by {message.from_user.id} in chat {getattr(message.chat,'id',None)}")
    _notify_balance_updates(message.from_user.id, target, delta)
    try:
        from utils import format_currency as _fc
    except Exception:
        _fc = lambda x: f"{float(x):.2f}"
    bot.reply_to(message, f"✅ Виконано: {('списано' if is_take else 'видано')} <b>{_fc(abs(delta))}₴</b>", parse_mode="HTML")

@bot.message_handler(commands=['tree'])
def admin_tree_cmd(message):
    if not is_admin(message.from_user.id):
        return
    parts = (message.text or '').split()
    if len(parts) < 3:
        return bot.reply_to(message, "❌ Формат: /tree apple 3 [@user|id]", parse_mode="HTML")
    tree_type = parts[1].lower();
    try:
        count = int(parts[2])
    except Exception:
        return bot.reply_to(message, "❌ Кількість має бути числом", parse_mode="HTML")
    target = _parse_target_from_args(message, parts[3:])
    if not target:
        return bot.reply_to(message, "❌ Не вказано користувача. Зробіть відповідь або додайте @user/id.", parse_mode="HTML")
    if tree_type not in ['apple','pear','cherry','peach'] or count <= 0:
        return bot.reply_to(message, "❌ Невірний тип або кількість", parse_mode="HTML")
    from database import grant_tree
    for _ in range(count):
        grant_tree(target, tree_type, 1)
    bot.reply_to(message, f"✅ Видано {count} {tree_type}")

