@bot.message_handler(func=lambda m: get_user_state(m.from_user.id) and get_user_state(m.from_user.id).startswith("mute:"))
def mute_reason_step(message):
    if not is_admin(message.from_user.id):
        return bot.reply_to(message, "❌ Немає прав")
    state = get_user_state(message.from_user.id)
    _, scope, target = state.split(":", 2)
    target_user_id = int(target)
    parts = (message.text or "").strip().split(maxsplit=1)
    if len(parts) < 2:
        return bot.reply_to(message, "❗ Формат: <термін> <причина> (наприклад: 1год Спам)")
    duration_str, reason = parts[0], parts[1]
    seconds = parse_duration(duration_str)
    if seconds is False:
        return bot.reply_to(message, "❌ Невірний формат терміну")
    # Виконуємо мут у боті (як мінімум)
    result = mute_user(target_user_id, seconds, reason, message.from_user.id)
    if result.get('success'):
        bot.reply_to(
            message,
            f"🔇 Замучено <code>{target_user_id}</code> на {format_duration(seconds) if seconds else 'невизначений термін'}\nПричина: {reason}",
            parse_mode="HTML"
        )
    else:
        bot.reply_to(message, f"❌ Помилка: {result.get('error','')}")
    clear_user_state(message.from_user.id)

