# Обробник для попередження користувача
@bot.message_handler(func=lambda m: get_user_state(m.from_user.id) and get_user_state(m.from_user.id).startswith("warn_user:"))
def warn_user_reason_step(message):
    """Приймає текст причини від адміністратора та надсилає попередження користувачу"""
    if not is_admin(message.from_user.id):
        return bot.reply_to(message, "❌ У вас немає прав")
    state = get_user_state(message.from_user.id)
    try:
        target_user_id = int(state.split(":")[1])
    except Exception:
        clear_user_state(message.from_user.id)
        return bot.reply_to(message, "❌ Помилковий стан. Спробуйте ще раз.")

    reason = (message.text or "").strip()
    if not reason or reason.startswith("/"):
        return bot.reply_to(message, "❗ Введіть текст причини (не команда)")

    # Лічильник попереджень і автобан на 3-є попередження
    try:
        from database import _db, get_user
        import html
        with _db() as con:
            con.execute("CREATE TABLE IF NOT EXISTS user_warnings (user_id INTEGER PRIMARY KEY, warnings INTEGER DEFAULT 0)")
            con.execute("INSERT INTO user_warnings (user_id, warnings) VALUES (?, COALESCE((SELECT warnings FROM user_warnings WHERE user_id=?),0)) ON CONFLICT(user_id) DO NOTHING", (target_user_id, target_user_id))
            con.execute("UPDATE user_warnings SET warnings = warnings + 1 WHERE user_id = ?", (target_user_id,))
            warnings = con.execute("SELECT warnings FROM user_warnings WHERE user_id = ?", (target_user_id,)).fetchone()[0]
        # Відправляємо користувачу попередження
        try:
            bot.send_message(
                target_user_id,
                f"⚠️ <b>Вам було видано ПОПЕРЕДЖЕННЯ</b>\n\n"
                f"📝 <b>Причина:</b> {html.escape(reason)}\n"
                f"📊 <b>Попереджень:</b> {warnings}/3\n"
                f"👮 <b>Адміністратор:</b> <a href='tg://user?id={message.from_user.id}'>{message.from_user.first_name}</a>\n\n"
                f"ℹ️ Після 3-х попереджень доступ до бота блокується.",
                parse_mode="HTML"
            )
        except Exception:
            pass
        # Повідомляємо в поточному чаті з ніком
        user_info = get_user(target_user_id)
        display_name = html.escape(user_info[1]) if user_info and user_info[1] else str(target_user_id)
        chat_msg = (
            "⚠️ <b>ПОПЕРЕДЖЕННЯ ВИДАНО</b>\n\n"
            f"👤 Користувач: <a href='tg://user?id={target_user_id}'>{display_name}</a>\n"
            f"📝 Причина: {html.escape(reason)}\n"
            f"📊 Попереджень: <b>{warnings}/3</b>\n"
            f"🔒 Після 3-х попереджень — автоматичний бан."
        )
        bot.reply_to(message, chat_msg, parse_mode="HTML")
        if warnings >= 3:
            # Автобан в боті
            ban_user(target_user_id, None, f"3 попередження. Останнє: {reason}", message.from_user.id)
            try:
                bot.send_message(
                    target_user_id,
                    "🚫 <b>ДОСТУП ЗАБЛОКОВАНО</b>\n\n"
                    "❗ Ви отримали 3 попередження і тимчасово не можете користуватись ботом.\n"
                    f"📝 <b>Остання причина:</b> {html.escape(reason)}\n\n"
                    "📩 Якщо вважаєте це помилкою — зверніться до власника: @palmaron",
                    parse_mode="HTML"
                )
            except Exception:
                pass
            bot.reply_to(message, "🚫 Користувача заблоковано через 3 попередження.")
    except Exception:
        pass
    clear_user_state(message.from_user.id)

# Обробник для команди бану
@bot.message_handler(commands=['ban'])
def ban_command_handler(message):
    """Команда для бану користувача з терміном та причиною"""
    if not is_admin(message.from_user.id):
        bot.reply_to(message, "❌ У вас немає прав для цієї команди")
        return
    
    try:
        # Перевіряємо чи є відповідь на повідомлення
        if not message.reply_to_message:
            bot.reply_to(message, 
                "📝 <b>Використання команди:</b>\n"
                "/ban <b>термін</b> <b>причина</b>\n\n"
                "💡 <b>Приклади:</b>\n"
                "/ban 1год Спам\n"
                "/ban 7днів Порушення правил\n"
                "/ban назавжди Серйозне порушення\n\n"
                "⏰ <b>Формати терміну:</b>\n"
                "• Будь-який термін: 5хв, 30хв, 1год, 2год\n"
                "• 1день, 7днів, 1місяць, 1рік\n"
                "• назавжди, або просто число (хвилини)", 
                parse_mode="HTML")
            return
        
        # Парсимо аргументи команди
        args = message.text.split()[1:]  # Пропускаємо /ban
        if len(args) < 2:
            bot.reply_to(message, 
                "❌ <b>Недостатньо аргументів!</b>\n\n"
                "📝 <b>Формат:</b> /ban <b>термін</b> <b>причина</b>\n"
                "💡 <b>Приклад:</b> /ban 1год Спам", 
                parse_mode="HTML")
            return
        
        # Отримуємо термін та причину
        duration_str = args[0]
        reason = ' '.join(args[1:])
        
        # Парсимо термін
        duration_seconds = parse_duration(duration_str)
        if duration_seconds is None:
            bot.reply_to(message, 
                "❌ <b>Неправильний формат терміну!</b>\n\n"
                "⏰ <b>Доступні формати:</b>\n"
                "• 5хв, 30хв, 1год, 2год\n"
                "• 1день, 7днів, 1місяць\n"
                "• 1рік, назавжди", 
                parse_mode="HTML")
            return
        
        # Отримуємо користувача
        target_user = message.reply_to_message.from_user
        target_user_id = target_user.id
        target_user_name = target_user.first_name or target_user.username or "Невідомий"
        
        # Виконуємо бан
        ban_result = ban_user(target_user_id, duration_seconds, reason, message.from_user.id)
        
        if ban_result['success']:
            # Формуємо повідомлення про бан
            ban_msg = f"🚫 <b>КОРИСТУВАЧА ЗАБЛОКОВАНО</b> 🚫\n\n"
            ban_msg += f"👤 <b>Користувач:</b> {target_user_name}\n"
            ban_msg += f"🆔 <b>ID:</b> <code>{target_user_id}</code>\n"
            ban_msg += f"⏰ <b>Термін:</b> {ban_result['duration_text']}\n"
            ban_msg += f"📝 <b>Причина:</b> {reason}\n"
            ban_msg += f"👮 <b>Заблоковано:</b> {message.from_user.first_name}\n"
            ban_msg += f"🕐 <b>Дата:</b> {ban_result['date']}\n\n"
            ban_msg += f"🔒 <b>Тип блокування:</b> {ban_result['ban_type']}"
            
            # Відправляємо повідомлення в чат
            bot.reply_to(message, ban_msg, parse_mode="HTML")
            
            # Відправляємо повідомлення заблокованому користувачу
            try:
                user_notification = f"🚫 <b>ВИ ЗАБЛОКОВАНІ</b> 🚫\n\n"
                user_notification += f"⏰ <b>Термін:</b> {ban_result['duration_text']}\n"
                user_notification += f"📝 <b>Причина:</b> {reason}\n"
                user_notification += f"👮 <b>Заблоковано:</b> {message.from_user.first_name}\n"
                user_notification += f"🕐 <b>Дата:</b> {ban_result['date']}\n\n"
                user_notification += f"ℹ️ <b>Якщо вважаєте це помилкою, зверніться до адміністрації</b>"
                
                bot.send_message(target_user_id, user_notification, parse_mode="HTML")
            except:
                pass  # Якщо не вдалося відправити повідомлення користувачу
        else:
            bot.reply_to(message, f"❌ Помилка: {ban_result['error']}")
            
    except Exception as e:
        print(f"[DEBUG] Помилка в ban_command_handler: {e}")
        bot.reply_to(message, "❌ Помилка при виконанні команди")

