# Обробник для введення кількості фруктів вручну
@bot.message_handler(func=lambda message: get_user_state(message.from_user.id) and get_user_state(message.from_user.id).startswith("quest_custom_amount:"))
def quest_custom_amount_handler(message):
    """Обробка введення кількості фруктів вручну"""
    print(f"[DEBUG] quest_custom_amount_handler викликано для користувача {message.from_user.id}")
    print(f"[DEBUG] Стан користувача: {get_user_state(message.from_user.id)}")
    print(f"[DEBUG] Текст повідомлення: {message.text}")
    
    if not is_admin(message.from_user.id):
        print(f"[DEBUG] Користувач {message.from_user.id} не є адміном")
        return
    
    try:
        # Отримуємо вибраний фрукт зі стану
        state = get_user_state(message.from_user.id)
        fruit_type = state.split(":")[1]
        
        # Перевіряємо чи це число
        try:
            amount = int(message.text)
        except ValueError:
            bot.reply_to(message, "❌ Помилка: Введіть число!\n\n💡 Приклад: 42")
            return
        
        # Перевіряємо діапазон
        if amount < 1 or amount > 1000:
            bot.reply_to(message, "❌ Помилка: Кількість має бути від 1 до 1000!\n\n💡 Приклад: 42")
            return
        
        fruit_names = {
            'apple': '🍎 Яблуко',
            'pear': '🍐 Груша', 
            'orange': '🍊 Апельсин',
            'grape': '🍇 Виноград'
        }
        
        # Встановлюємо стан для вибору часу очікування
        set_user_state(message.from_user.id, f"quest_setup:{fruit_type}:{amount}")
        
        kb = InlineKeyboardMarkup(row_width=2)
        kb.add(
            InlineKeyboardButton("2 хв", callback_data="quest_wait_120"),
            InlineKeyboardButton("3 хв", callback_data="quest_wait_180"),
            InlineKeyboardButton("5 хв", callback_data="quest_wait_300")
        )
        kb.add(InlineKeyboardButton("🔙 Назад", callback_data="admin_start_quest"))
        
        msg = f"🍎 <b>ВИБЕРІТЬ ЧАС ОЧІКУВАННЯ</b> 🍎\n\n"
        msg += f"Фрукт: {fruit_names.get(fruit_type, fruit_type)}\n"
        msg += f"Кількість: {amount}\n"
        msg += "Через скільки хвилин почне падати фрукт?"
        
        bot.reply_to(message, msg, reply_markup=kb, parse_mode="HTML")
        print(f"[DEBUG] Успішно оброблено кількість фруктів: {amount}")
        
    except Exception as e:
        print(f"[DEBUG] Помилка в quest_custom_amount_handler: {e}")
        bot.reply_to(message, f"❌ Помилка: {e}")
        clear_user_state(message.from_user.id)

