ADMIN_ID = 6029312631  # ID головного адміністратора

@bot.message_handler(func=lambda m: get_user_state(m.from_user.id) == "admin_chat" and m.text and not m.text.startswith('/'), content_types=['text'])
def user_admin_chat_message(message):
    user_id = message.from_user.id
    print(f"[DEBUG] Отримано повідомлення від користувача {user_id} в режимі admin_chat")
    print(f"[DEBUG] Текст повідомлення: {message.text}")
    
    set_user_state(user_id, None)  # Скидаємо стан після звернення
    
    text = f"<b>Звернення від користувача</b>\n" \
           f"ID: <code>{user_id}</code>\n" \
           f"Username: @{message.from_user.username if message.from_user.username else '-'}\n" \
           f"\n<b>Текст:</b>\n{message.text}"
    
    try:
        print(f"[DEBUG] Намагаємося надіслати повідомлення адміну {ADMIN_ID}")
        
        # Створюємо кнопку для відповіді
        reply_kb = InlineKeyboardMarkup()
        reply_kb.add(InlineKeyboardButton("💬 Відповісти користувачу", callback_data=f"reply_to_user_{user_id}"))
        
        bot.send_message(
            ADMIN_ID,
            text,
            parse_mode="HTML",
            reply_markup=reply_kb
        )
        print(f"[DEBUG] Повідомлення успішно надіслано адміну")
        
        bot.send_message(
            user_id,
            "✅ Ваше звернення надіслано адміністратору! Очікуйте відповідь тут."
        )
        print(f"[DEBUG] Підтвердження надіслано користувачу {user_id}")
        
    except Exception as e:
        print(f"[ERROR] Помилка надсилання повідомлення адміну: {e}")
        bot.send_message(
            user_id,
            "❌ Помилка надсилання звернення. Спробуйте пізніше або зверніться до підтримки."
        )

@bot.callback_query_handler(func=lambda c: c.data.startswith("reply_to_user_"))
def admin_reply_button_handler(call):
    if call.from_user.id != ADMIN_ID:
        bot.answer_callback_query(call.id, "❌ Доступ заборонено", show_alert=True)
        return
    
    # Отримуємо ID користувача з callback_data
    user_id = int(call.data.split("_")[-1])
    
    # Встановлюємо стан для адміна
    set_user_state(ADMIN_ID, f"admin_reply_{user_id}")
    
    bot.answer_callback_query(call.id)
    bot.edit_message_text(
        f"✍️ <b>Напишіть відповідь користувачу {user_id}:</b>\n\n"
        "Відправте повідомлення, і воно буде надіслано користувачу.\n"
        "Для скасування напишіть /cancel",
        call.message.chat.id,
        call.message.message_id,
        parse_mode="HTML"
    )

@bot.message_handler(func=lambda m: get_user_state(m.from_user.id) and get_user_state(m.from_user.id).startswith("admin_reply_"))
def admin_reply_message_handler(message):
    if message.from_user.id != ADMIN_ID:
        return
    
    if message.text == "/cancel":
        set_user_state(ADMIN_ID, None)
        bot.reply_to(message, "❌ Відповідь скасовано")
        return
    
    # Отримуємо ID користувача зі стану
    user_id = int(get_user_state(ADMIN_ID).split("_")[-1])
    
    try:
        # Надсилаємо відповідь користувачу
        bot.send_message(
            user_id,
            f"💬 <b>Відповідь адміністратора:</b>\n\n{message.text}",
            parse_mode="HTML"
        )
        
        # Скидаємо стан адміна
        set_user_state(ADMIN_ID, None)
        
        # Підтверджуємо адміну
        bot.reply_to(message, f"✅ Відповідь надіслано користувачу {user_id}!")
        
    except Exception as e:
        bot.reply_to(message, f"❌ Помилка надсилання відповіді: {e}")
        set_user_state(ADMIN_ID, None)


# Обробник для введення власного числа
@bot.message_handler(func=lambda message: True)
def handle_admin_states(message):
    """Обробник для state-based введення даних"""
    # Не перехватывать команды, дать отработать хендлерам команд
    if getattr(message, 'text', '').startswith('/'):
        return
    
    # Не перехватывать повідомлення для P2P простих операцій
    try:
        from database import get_user_state
        user_state = get_user_state(message.from_user.id)
        if user_state and (user_state.startswith('p2p_') or user_state.startswith('p2p_waiting_') or user_state.startswith('simple_move_')):
            # Даем обработать final_global_handler
            return
    except:
        pass
    
    user_id = message.from_user.id
    
    try:
        user_state = bot.get_state(user_id, message.chat.id)
        
        # Якщо немає активного стану - не обробляємо повідомлення
        if not user_state:
            return
        
        if user_state == "number_input":
            # Обробка введення числа для number game
            try:
                chosen_number = int(message.text.strip())
                
                if chosen_number < 1 or chosen_number > 100:
                    bot.send_message(
                        message.chat.id, 
                        "❌ Число має бути від 1 до 100!\nСпробуйте ще раз:"
                    )
                    return
                
                # Отримуємо збережені дані
                with bot.retrieve_data(user_id, message.chat.id) as data:
                    bet_amount = data.get('bet_amount')
                    original_message_id = data.get('original_message_id')
                
                if not bet_amount:
                    bot.send_message(message.chat.id, "❌ Помилка: дані про ставку втрачено")
                    return
                
                # Очищаємо стан
                bot.delete_state(user_id, message.chat.id)
                
                # Створюємо псевдо-call для execute_number_game
                class FakeCall:
                    def __init__(self, user_id, chat_id, message_id):
                        self.from_user = type('obj', (object,), {'id': user_id, 'first_name': message.from_user.first_name})
                        self.message = type('obj', (object,), {'chat': type('obj', (object,), {'id': chat_id}), 'message_id': message_id})
                
                # Видаляємо повідомлення з введенням числа
                try:
                    bot.delete_message(message.chat.id, message.message_id)
                except:
                    pass
                
                fake_call = FakeCall(user_id, message.chat.id, original_message_id)
                execute_number_game(fake_call, chosen_number, bet_amount)
                
            except ValueError:
                bot.send_message(
                    message.chat.id, 
                    "❌ Введіть коректне число!\n💡 Наприклад: 42"
                )
                return
                
        elif user_state == "admin_min_bet_change":
            # Обробка зміни мінімальної ставки
            process_min_bet_change_state(message)
            
        elif user_state == "admin_max_bet_change":
            # Обробка зміни максимальної ставки  
            process_max_bet_change_state(message)
            
        elif user_state == "admin_dice_multiplier_change":
            # Обробка зміни коефіцієнта кубика
            process_dice_multiplier_state(message)
            
        elif user_state == "admin_number_bulls_eye_change":
            # Обробка зміни множника точного попадання
            process_number_bulls_eye_state(message)
            
        elif user_state == "admin_number_hot_change":
            # Обробка зміни множника "гаряче"
            process_number_hot_state(message)
            
        elif user_state == "admin_number_close_change":
            # Обробка зміни множника "близько"
            process_number_close_state(message)
            
        elif user_state == "admin_number_warm_change":
            # Обробка зміни множника "тепло"
            process_number_warm_state(message)
            
        # Інші states можна додати тут...
            
    except Exception as e:
        print(f"[DEBUG] Помилка в handle_admin_states: {e}")

# Обробник для перевірки муту в чаті
@bot.message_handler(func=lambda message: True)
def check_muted_users(message):
    """Перевіряє чи замучений користувач в чаті"""
    # Не гасим команды
    if getattr(message, 'text', '').startswith('/'):
        return
    try:
        # Перевіряємо чи це груповий чат
        if message.chat.type not in ['group', 'supergroup']:
            return
        
        # Перевіряємо чи замучений користувач
        from database import is_user_muted_in_chat
        if is_user_muted_in_chat(message.from_user.id, message.chat.id):
            # Видаляємо повідомлення
            try:
                bot.delete_message(message.chat.id, message.message_id)
                
                # Відправляємо повідомлення про мут
                from database import get_user_chat_mute_info
                mute_info = get_user_chat_mute_info(message.from_user.id, message.chat.id)
                if mute_info:
                    remaining_time = mute_info[4] - int(time.time()) if mute_info[4] > 0 else 0
                    if remaining_time > 0:
                        duration_text = format_duration(remaining_time)
                        bot.send_message(message.chat.id, 
                            f"🔇 <b>Користувач замучений!</b>\n\n"
                            f"👤 Користувач: {message.from_user.first_name}\n"
                            f"⏰ Залишилось: {duration_text}\n"
                            f"📝 Причина: {mute_info[5]}", 
                            parse_mode="HTML")
            except:
                pass
    except Exception as e:
        print(f"[DEBUG] Помилка в check_muted_users: {e}")
        pass

def process_min_bet_change_state(message):
    """Обробка зміни мінімальної ставки через state"""
    if not is_admin(message.from_user.id):
        return
    
    try:
        min_bet = float(message.text.strip())
        if min_bet < 0.1:
            bot.send_message(message.chat.id, "❌ Мінімальна ставка не може бути менше 0.1₴")
            return
        if min_bet > 100.0:
            bot.send_message(message.chat.id, "❌ Мінімальна ставка не може бути більше 100₴")
            return
        
        # Перевіряємо, щоб мін ставка не була більше макс
        max_bet = float(get_game_setting('max_bet', '1000.0'))
        if min_bet > max_bet:
            bot.send_message(message.chat.id, f"❌ Мінімальна ставка не може бути більше максимальної ({format_currency(max_bet)}₴)")
            return
        
        set_game_setting('min_bet', str(min_bet))
        
        # Очищаємо стан
        bot.delete_state(message.from_user.id, message.chat.id)
        
        kb = InlineKeyboardMarkup()
        kb.add(InlineKeyboardButton("⬅️ Повернутися", callback_data="admin_bet_limits"))
        
        bot.send_message(
            message.chat.id,
            f"✅ Мінімальна ставка змінена на {format_currency(min_bet)}₴",
            reply_markup=kb
        )
        
    except ValueError:
        bot.send_message(message.chat.id, "❌ Некоректне число! Введіть число (наприклад: 5)")

