@bot.message_handler(state="admin_dice_multiplier_change")
def process_dice_multiplier(message):
    if not is_admin(message.from_user.id):
        bot.delete_state(message.from_user.id, message.chat.id)
        return
    
    try:
        multiplier = float(message.text.strip())
        if multiplier < 1.1:
            bot.send_message(message.chat.id, "❌ Коефіцієнт не може бути менше 1.1\nСпробуйте ще раз:")
            return
        if multiplier > 50.0:
            bot.send_message(message.chat.id, "❌ Коефіцієнт не може бути більше 50.0\nСпробуйте ще раз:")
            return
        
        set_game_setting('dice_multiplier', str(multiplier))
        
        # Очищаємо стан після успішної зміни
        bot.delete_state(message.from_user.id, message.chat.id)
        
        bot.send_message(
            message.chat.id,
            f"✅ Коефіцієнт кубика змінено на x{multiplier}",
            reply_markup=InlineKeyboardMarkup().add(
                InlineKeyboardButton("⬅️ Повернутися", callback_data="admin_game_dice")
            )
        )
        
    except ValueError:
        bot.send_message(message.chat.id, "❌ Некоректне число! Введіть число (наприклад: 5.5)\nСпробуйте ще раз:")

# Зміна мінімальної ставки
@bot.callback_query_handler(func=lambda c: c.data == "admin_change_min_bet")
def admin_change_min_bet_handler(call):
    if not is_admin(call.from_user.id):
        return bot.answer_callback_query(call.id, "⛔️ Немає доступу", show_alert=True)
    
    current_min_bet = float(get_game_setting('min_bet', '1.0'))
    
    message_text = (
        f"📉 <b>МІНІМАЛЬНА СТАВКА</b>\n"
        f"━━━━━━━━━━━━━━━━━━━━\n\n"
        f"💸 <b>Поточна мінімальна ставка:</b> {format_currency(current_min_bet)}₴\n\n"
        f"💡 <b>Введіть нову мінімальну ставку:</b>\n"
        f"• Рекомендуємо: 1₴ - 10₴\n"
        f"• Мінімум: 0.1₴\n"
        f"• Максимум: 100₴\n\n"
        f"💰 <i>Напишіть число (наприклад: 5)</i>"
    )
    
    kb = InlineKeyboardMarkup()
    kb.add(InlineKeyboardButton("❌ Скасувати", callback_data="admin_cancel_bet_change"))
    
    bot.edit_message_text(
        message_text,
        call.message.chat.id,
        call.message.message_id,
        reply_markup=kb,
        parse_mode="HTML"
    )
    
    # Використовуємо state machine замість next_step_handler
    bot.set_state(call.from_user.id, "admin_min_bet_change", call.message.chat.id)
    bot.answer_callback_query(call.id)

# Обробник станів для адмін панелі
@bot.message_handler(state="admin_min_bet_change")
def process_min_bet_change(message):
    if not is_admin(message.from_user.id):
        bot.delete_state(message.from_user.id, message.chat.id)
        return
    
    try:
        min_bet = float(message.text.strip())
        if min_bet < 0.1:
            bot.send_message(message.chat.id, "❌ Мінімальна ставка не може бути менше 0.1₴\nСпробуйте ще раз:")
            return
        if min_bet > 100.0:
            bot.send_message(message.chat.id, "❌ Мінімальна ставка не може бути більше 100₴\nСпробуйте ще раз:")
            return
        
        # Перевіряємо, щоб мін ставка не була більше макс
        max_bet = float(get_game_setting('max_bet', '1000.0'))
        if min_bet > max_bet:
            bot.send_message(message.chat.id, f"❌ Мінімальна ставка не може бути більше максимальної ({format_currency(max_bet)}₴)\nСпробуйте ще раз:")
            return
        
        set_game_setting('min_bet', str(min_bet))
        
        # Очищаємо стан після успішної зміни
        bot.delete_state(message.from_user.id, message.chat.id)
        
        bot.send_message(
            message.chat.id,
            f"✅ Мінімальна ставка змінена на {format_currency(min_bet)}₴",
            reply_markup=InlineKeyboardMarkup().add(
                InlineKeyboardButton("⬅️ Повернутися", callback_data="admin_bet_limits")
            )
        )
        
    except ValueError:
        bot.send_message(message.chat.id, "❌ Некоректне число! Введіть число (наприклад: 5)\nСпробуйте ще раз:")

