@bot.callback_query_handler(func=lambda c: c.data == "admin_cancel_bet_change")
def admin_cancel_bet_change_handler(call):
    if not is_admin(call.from_user.id):
        return bot.answer_callback_query(call.id, "⛔️ Немає доступу", show_alert=True)
    
    # Очищаємо стан користувача
    bot.delete_state(call.from_user.id, call.message.chat.id)
    
    # Повертаємося до меню налаштувань меж ставок
    admin_bet_limits_handler(call)

