# Увімкнення/вимкнення монетки
@bot.callback_query_handler(func=lambda c: c.data == "admin_toggle_coin")
def admin_toggle_coin_handler(call):
    if not is_admin(call.from_user.id):
        return bot.answer_callback_query(call.id, "⛔️ Немає доступу", show_alert=True)
    
    current_state = is_game_enabled('coin')
    new_state = "0" if current_state else "1"
    set_game_setting('coin_enabled', new_state)
    
    status_text = "увімкнено" if new_state == "1" else "вимкнено"
    bot.answer_callback_query(call.id, f"🪙 Монетку {status_text}!")
    
    admin_game_coin_handler(call)

# Налаштування Number Game (гра в число)
@bot.callback_query_handler(func=lambda c: c.data == "admin_game_number")
def admin_game_number_handler(call):
    if not is_admin(call.from_user.id):
        return bot.answer_callback_query(call.id, "⛔️ Немає доступу", show_alert=True)
    
    # Отримуємо поточні налаштування
    number_enabled = is_game_enabled('number')
    number_status = "🟢 Увімкнена" if number_enabled else "🔴 Вимкнена"
    
    # Отримуємо множники для різних зон
    bulls_eye_multiplier = float(get_game_setting('number_bulls_eye_multiplier', '50.0'))
    hot_multiplier = float(get_game_setting('number_hot_multiplier', '10.0'))
    close_multiplier = float(get_game_setting('number_close_multiplier', '5.0'))
    warm_multiplier = float(get_game_setting('number_warm_multiplier', '2.0'))
    
    message_text = (
        f"🎯 <b>НАЛАШТУВАННЯ ГРИ В ЧИСЛО</b>\n"
        f"━━━━━━━━━━━━━━━━━━━━\n\n"
        f"📊 <b>Поточний стан:</b> {number_status}\n\n"
        f"🏆 <b>МНОЖНИКИ ЗОН:</b>\n"
        f"🎯 Точне попадання: <b>x{bulls_eye_multiplier:.1f}</b>\n"
        f"🔥 Гаряче (±3): <b>x{hot_multiplier:.1f}</b>\n"
        f"⚡ Близько (±7): <b>x{close_multiplier:.1f}</b>\n"
        f"💫 Тепло (±15): <b>x{warm_multiplier:.1f}</b>\n"
        f"❄️ Холодно: <b>x0</b> (програш)\n\n"
        f"🎮 <b>Концепція гри:</b>\n"
        f"• Гравець обирає число 1-100\n"
        f"• Бот генерує секретне число 1-100\n"
        f"• Чим ближче числа - тим більший виграш!"
    )
    
    kb = InlineKeyboardMarkup(row_width=1)
    
    # Кнопка вкл/викл гри
    toggle_text = "🔴 Вимкнути гру" if number_enabled else "🟢 Увімкнути гру"
    kb.add(InlineKeyboardButton(toggle_text, callback_data="admin_toggle_number"))
    
    # Налаштування множників
    kb.add(InlineKeyboardButton("🎯 Змінити множник точного попадання", callback_data="admin_number_bulls_eye"))
    kb.add(InlineKeyboardButton("🔥 Змінити множник 'Гаряче'", callback_data="admin_number_hot"))
    kb.add(InlineKeyboardButton("⚡ Змінити множник 'Близько'", callback_data="admin_number_close"))
    kb.add(InlineKeyboardButton("💫 Змінити множник 'Тепло'", callback_data="admin_number_warm"))
    
    # Тестування гри  
    kb.add(InlineKeyboardButton("🧪 Тестувати гру", callback_data="admin_test_number"))
    
    kb.add(InlineKeyboardButton("⬅️ Назад до ігор", callback_data="admin_games_menu"))
    
    bot.edit_message_text(
        message_text,
        call.message.chat.id,
        call.message.message_id,
        reply_markup=kb,
        parse_mode="HTML"
    )
    bot.answer_callback_query(call.id)

@bot.callback_query_handler(func=lambda c: c.data == "admin_toggle_number")
def admin_toggle_number_handler(call):
    if not is_admin(call.from_user.id):
        return bot.answer_callback_query(call.id, "⛔️ Немає доступу", show_alert=True)
    
    current_status = is_game_enabled('number')
    new_status = not current_status
    
