import threading
import time as time_module

def auto_check_inactive_beta_testers():
    """Автоматична перевірка неактивних бета-тестерів кожні 6 годин"""
    while True:
        try:
            from database import get_inactive_beta_testers, get_beta_testers_stats, _db, cleanup_old_garden_history
            import datetime
            
            stats = get_beta_testers_stats()
            inactive_testers = get_inactive_beta_testers(24)
            
            # Автоматичне очищення старої історії саду (раз на тиждень)
            current_hour = datetime.datetime.now().hour
            if current_hour == 3:  # О 3 ранку
                try:
                    deleted_count = cleanup_old_garden_history(90)  # Видаляємо записи старіше 90 днів
                    if deleted_count > 0:
                        print(f"🧹 Автоматично видалено {deleted_count} старих записів історії саду")
                except Exception as e:
                    print(f"Помилка автоматичного очищення історії саду: {e}")
            
            # Якщо є неактивні бета-тестери, надсилаємо нагадування всім адмінам
            if inactive_testers and stats['total'] > 0:
                # Отримуємо список адмінів
                with _db() as con:
                    admin_rows = con.execute("SELECT user_id FROM admins").fetchall()
                
                if admin_rows:
                    current_time = get_kiev_time()
                    
                    notification_message = (
                        f"🚨 <b>АВТОМАТИЧНЕ НАГАДУВАННЯ</b>\n"
                        f"━━━━━━━━━━━━━━━━━━━━\n\n"
                        f"⚠️ <b>Виявлено неактивних бета-тестерів!</b>\n\n"
                        f"📊 <b>Статистика:</b>\n"
                        f"👥 Всього бета-тестерів: <b>{stats['total']}</b>\n"
                                f"🟢 Активних (24г): <b>{stats['active_12h']}</b>\n"
        f"🔴 Неактивних: <b>{stats['inactive_12h']}</b>\n\n"
        f"😴 <b>Неактивні більше 24 годин:</b>\n"
                    )
                    
                    # Додаємо перших 3 неактивних для прикладу
                    for i, tester in enumerate(inactive_testers[:3]):
                        user_id, added_by, added_at, user_name, username, last_active, date_joined = tester
                        
                        if last_active:
                            time_diff = datetime.datetime.now() - datetime.datetime.fromtimestamp(last_active)
                            if time_diff.days > 0:
                                inactive_time = f"{time_diff.days}д {time_diff.seconds//3600}г"
                            else:
                                inactive_time = f"{time_diff.seconds//3600}г {(time_diff.seconds//60)%60}хв"
                        else:
                            inactive_time = "Ніколи не заходив"
                            
                        notification_message += f"• <b>{user_name or 'Невідомий'}</b> - {inactive_time}\n"
                    
                    if len(inactive_testers) > 3:
                        notification_message += f"... та ще {len(inactive_testers) - 3} користувачів\n"
                    
                    notification_message += (
                        f"\n🔧 <b>Рекомендовані дії:</b>\n"
                        f"• Використайте команду /cleanup_beta\n"
                        f"• Перейдіть в адмін-панель → Бета-тестери\n"
                        f"• Розгляньте можливість видалення неактивних\n\n"
                        f"⏰ <i>Перевірено: {current_time}</i>\n"
                        f"🤖 <i>Автоматичне нагадування кожні 6 годин</i>"
                    )
                    
                    kb = InlineKeyboardMarkup(row_width=2)
                    kb.add(
                        InlineKeyboardButton("📊 Статистика", callback_data="admin_beta_stats"),
                        InlineKeyboardButton("🧹 Очистити", callback_data="admin_beta_cleanup")
                    )
                    kb.add(InlineKeyboardButton("🏠 Адмін панель", callback_data="panel"))
                    
                    # Надсилаємо повідомлення всім адмінам
                    for admin_row in admin_rows:
                        admin_id = admin_row[0]
                        try:
                            bot.send_message(admin_id, notification_message, 
                                           reply_markup=kb, parse_mode="HTML")
                        except Exception as e:
                            print(f"[AUTO-NOTIFICATION] Не вдалося надіслати нагадування адміну {admin_id}: {e}")
                            
        except Exception as e:
            print(f"[AUTO-CHECK] Помилка автоматичної перевірки: {e}")
        
        # Wait 6 hours until next check
        time_module.sleep(6 * 3600)

def start_auto_notification_system():
    """Запускає автоматичну систему нагадувань та квестів в окремому потоці"""
    def auto_system():
        while True:
            try:
                # Перевірка неактивних бета-тестерів
                auto_check_inactive_beta_testers()
                
                # Обробка квестів
                process_quests()
                
                # Wait 30 seconds until next check
                time.sleep(30)
            except Exception as e:
                print(f"[DEBUG] Error in auto_system: {e}")
                time.sleep(60)
    
    notification_thread = threading.Thread(target=auto_system, daemon=True)
    notification_thread.start()
    print("[AUTO] Notification and quest system started!")

def process_quests():
    """Обробляє квести які потребують уваги"""
    try:
        from database import get_quests_to_process, mark_quest_warning_sent, mark_quest_drop_sent, update_quest_status, save_warning_message_id
        
        warning_quests, drop_quests = get_quests_to_process()
        
        # Логируем только если есть квесты для обработки
        if warning_quests or drop_quests:
            print(f"[DEBUG] Знайдено {len(warning_quests)} квестів для попередження, {len(drop_quests)} для падіння")
        
        # Обробляємо попередження
        for quest in warning_quests:
            quest_id, fruit_type, amount, activation_time, chat_id = quest
            
            fruit_names = {
                'apple': '🍎 Яблуко',
                'pear': '🍐 Груша', 
                'orange': '🍊 Апельсин',
                'grape': '🍇 Виноград'
            }
            
            fruit_name = fruit_names.get(fruit_type, fruit_type)
            
            # Перевіряємо чи activation_time не None
            if activation_time is None:
                print(f"[DEBUG] Помилка: activation_time is None для квесту {quest_id}")
                continue
                
            current_time = int(time.time())
            wait_time_seconds = max(0, activation_time - current_time)
            wait_time_minutes = wait_time_seconds // 60
            wait_time_remaining_seconds = wait_time_seconds % 60
            
            msg = f"🎯 <b>КВЕСТ СКОРО ПОЧНЕТЬСЯ!</b> 🎯\n\n"
            msg += f"🍎 <b>Фрукт:</b> {fruit_name}\n"
            msg += f"📦 <b>Кількість:</b> {amount}\n"
            msg += f"⏰ <b>Час очікування:</b> {wait_time_minutes}хв {wait_time_remaining_seconds}с\n\n"
            msg += f"🎮 <b>Готуйтесь до квесту!</b>\n"
            msg += f"💡 <b>Що робити:</b>\n"
            msg += f"• Зачекайте поки з'явиться кнопка 'Зловити фрукт'\n"
            msg += f"• Натисніть кнопку якомога швидше\n"
            msg += f"• Перший хто зловить - отримає весь приз!\n\n"
            msg += f"⚡ <b>Поради:</b>\n"
            msg += f"• Будьте готові до швидкої реакції\n"
            msg += f"• Переконайтеся що у вас стабільне з'єднання\n"
            msg += f"• Квест триває дуже коротко!"
            
            try:
                sent_message = bot.send_message(chat_id, msg, parse_mode="HTML")
                save_warning_message_id(quest_id, sent_message.message_id)
                mark_quest_warning_sent(quest_id)
                print(f"[DEBUG] Попередження про квест відправлено в чат {chat_id}")
            except Exception as e:
                print(f"[DEBUG] Помилка відправки попередження квесту: {e}")
        
        # Обробляємо падіння фруктів
        for quest in drop_quests:
            quest_id, fruit_type, amount, activation_time, chat_id = quest
            
            fruit_names = {
                'apple': '🍎 Яблуко',
                'pear': '🍐 Груша', 
                'orange': '🍊 Апельсин',
                'grape': '🍇 Виноград'
            }
            
            fruit_name = fruit_names.get(fruit_type, fruit_type)
            
            # Перевіряємо чи всі дані не None
            if activation_time is None or chat_id is None:
                print(f"[DEBUG] Помилка: activation_time або chat_id is None для квесту {quest_id}")
                continue
            
            # Оновлюємо статус квесту на активний
            update_quest_status(quest_id, 'active')
            
            kb = InlineKeyboardMarkup()
            kb.add(InlineKeyboardButton("🎯 Зловити фрукт!", callback_data=f"catch_fruit_{quest_id}"))
            
            msg = f"🍎 <b>ПАДАЄ {fruit_name.upper()}!</b> 🍎\n\n"
            msg += f"📦 <b>Приз:</b> {amount} {fruit_name}\n"
            msg += f"⚡ <b>Хто перший зловить - отримає все!</b>\n\n"
            msg += f"🎯 <b>Натисніть кнопку щоб зловити!</b>\n"
            msg += f"💨 <b>Швидкість - це все!</b>"
            
            try:
                bot.send_message(chat_id, msg, reply_markup=kb, parse_mode="HTML")
                mark_quest_drop_sent(quest_id)
                print(f"[DEBUG] Кнопка 'Зловити фрукт' відправлена в чат {chat_id}")
            except Exception as e:
                print(f"[DEBUG] Помилка відправки падіння фрукту: {e}")
        
        # Очищуємо закінчені квести
        from database import cleanup_expired_quests
        expired_count = cleanup_expired_quests()
        if expired_count > 0:
            print(f"[DEBUG] Очищено {expired_count} закінчених квестів")
            
    except Exception as e:
        print(f"[DEBUG] Помилка в process_quests: {e}")

def update_quest_countdown():
    """Оновлює відлік часу для активних квестів"""
    try:
        from database import get_quests_for_countdown
        
        quests = get_quests_for_countdown()
        # Логируем только если есть квесты (чтобы не спамить)
        # if quests:
        #     print(f"[DEBUG] Оновлення відліку: знайдено {len(quests)} квестів")
        
        for quest in quests:
            quest_id, fruit_type, amount, activation_time, chat_id, message_id = quest
            
            if not message_id:
                continue
                
            fruit_names = {
                'apple': '🍎 Яблуко',
                'pear': '🍐 Груша', 
                'orange': '🍊 Апельсин',
                'grape': '🍇 Виноград'
            }
            
            fruit_name = fruit_names.get(fruit_type, fruit_type)
            
            current_time = int(time.time())
            wait_time_seconds = max(0, activation_time - current_time)
            wait_time_minutes = wait_time_seconds // 60
            wait_time_remaining_seconds = wait_time_seconds % 60
            
            print(f"[DEBUG] Відлік квесту {quest_id}: activation_time={activation_time}, current_time={current_time}, wait_time={wait_time_seconds}с ({wait_time_minutes}хв {wait_time_remaining_seconds}с)")
            
            # Якщо час вийшов, одразу активуємо квест
            if wait_time_seconds == 0:
                print(f"[DEBUG] Час квесту {quest_id} вийшов, активуємо кнопку!")
                from database import update_quest_status, mark_quest_drop_sent
                
                # Активуємо квест
                update_quest_status(quest_id, 'active')
                
                # Створюємо кнопку
                from telebot.types import InlineKeyboardMarkup, InlineKeyboardButton
                kb = InlineKeyboardMarkup()
                kb.add(InlineKeyboardButton("🎯 Зловити фрукт!", callback_data=f"catch_fruit_{quest_id}"))
                
                msg = f"🍎 <b>ПАДАЄ {fruit_name.upper()}!</b> 🍎\n\n"
                msg += f"📦 <b>Приз:</b> {amount} {fruit_name}\n"
                msg += f"⚡ <b>Хто перший зловить - отримає все!</b>\n\n"
                msg += f"🎯 <b>Натисніть кнопку щоб зловити!</b>\n"
                msg += f"💨 <b>Швидкість - це все!</b>"
                
                try:
                    bot.edit_message_text(msg, chat_id, message_id, reply_markup=kb, parse_mode="HTML")
                    mark_quest_drop_sent(quest_id)
                    print(f"[DEBUG] Кнопка 'Зловити фрукт' активована для квесту {quest_id}")
                    continue  # Переходимо до наступного квесту
                except Exception as e:
                    print(f"[DEBUG] Помилка активації квесту {quest_id}: {e}")
            
            # Якщо час ще не вийшов, показуємо відлік
            msg = f"🎯 <b>КВЕСТ СКОРО ПОЧНЕТЬСЯ!</b> 🎯\n\n"
            msg += f"🍎 <b>Фрукт:</b> {fruit_name}\n"
            msg += f"📦 <b>Кількість:</b> {amount}\n"
            msg += f"⏰ <b>Час очікування:</b> {wait_time_minutes}хв {wait_time_remaining_seconds}с\n\n"
            msg += f"🎮 <b>Готуйтесь до квесту!</b>\n"
            msg += f"💡 <b>Що робити:</b>\n"
            msg += f"• Зачекайте поки з'явиться кнопка 'Зловити фрукт'\n"
            msg += f"• Натисніть кнопку якомога швидше\n"
            msg += f"• Перший хто зловить - отримає весь приз!\n\n"
            msg += f"⚡ <b>Поради:</b>\n"
            msg += f"• Будьте готові до швидкої реакції\n"
            msg += f"• Переконайтеся що у вас стабільне з'єднання\n"
            msg += f"• Квест триває дуже коротко!"
            
            try:
                bot.edit_message_text(msg, chat_id, message_id, parse_mode="HTML")
                print(f"[DEBUG] Відлік квесту {quest_id} оновлено: {wait_time_minutes}хв {wait_time_remaining_seconds}с")
            except Exception as e:
                if "Too Many Requests" in str(e):
                    print(f"[DEBUG] Telegram API обмеження для квесту {quest_id}, чекаємо...")
                    time.sleep(30)  # Wait 30 seconds on rate limit
                elif "message is not modified" in str(e):
                    # Повідомлення не змінилося - це нормально
                    print(f"[DEBUG] Повідомлення квесту {quest_id} не змінилося")
                else:
                    print(f"[DEBUG] Помилка оновлення відліку квесту {quest_id}: {e}")
                
    except Exception as e:
        print(f"[DEBUG] Помилка в update_quest_countdown: {e}")

# Автоматичний виклик process_quests кожні 30 секунд та оновлення відліку кожну секунду
def auto_process_quests():
    """Автоматично обробляє квести кожні 30 секунд та оновлює відлік кожну секунду"""
    import threading
    import time
    
    def process_loop():
        # print("[DEBUG] Auto quest processing started!")
        while True:
            try:
                process_quests()
                time.sleep(5)  # Wait 5 seconds instead of 30
            except Exception as e:
                print(f"[ERROR] Error in auto_process_quests: {e}")
                time.sleep(5)
    
    def countdown_loop():
        # print("[DEBUG] Auto countdown update started!")
        loop_count = 0
        while True:
            try:
                loop_count += 1
                # Убрали логирование каждые 10 секунд - слишком много спама
                
                update_quest_countdown()
                time.sleep(1)  # Update every second for accuracy
            except Exception as e:
                print(f"[ERROR] Error in countdown_loop: {e}")
                time.sleep(5)  # Wait 5 seconds on error
    
    # Start in separate thread
    quest_thread = threading.Thread(target=process_loop, daemon=True)
    quest_thread.start()
    # print("[DEBUG] Auto quest processing thread created!")
    
    # Start countdown update thread
    countdown_thread = threading.Thread(target=countdown_loop, daemon=True)
    countdown_thread.start()
    # print("[DEBUG] Countdown update thread created!")

# =============================================================================
# End of AUTO NOTIFICATIONS block
# =============================================================================

# --- Test command for channel checking ---
@bot.message_handler(commands=['test_channels'])
def test_channels_command(message):
    try:
        if not is_admin(message.from_user.id):
            bot.send_message(message.chat.id, "❌ Немає доступу")
            return
        
        from database import get_required_channels, get_required_channel
        channels = get_required_channels()
        old_channel = get_required_channel()
        
        response = f"🔍 <b>ТЕСТ КАНАЛІВ</b>\n\n"
        response += f"📢 <b>Нова система (get_required_channels):</b>\n"
        if channels:
            for i, channel in enumerate(channels, 1):
                response += f"{i}. <code>{channel}</code>\n"
        else:
            response += "❌ Канали не встановлено\n"
        
        response += f"\n📢 <b>Стара система (get_required_channel):</b>\n"
        if old_channel:
            response += f"<code>{old_channel}</code>\n"
        else:
            response += "❌ Канал не встановлено\n"
        
        # Тестуємо перевірку підписки
        response += f"\n🔍 <b>ТЕСТ ПІДПИСКИ:</b>\n"
        if channels:
            for channel in channels:
                try:
                    member = bot.get_chat_member(channel, message.from_user.id)
                    status = member.status
                    response += f"📱 {channel}: <code>{status}</code>\n"
                except Exception as e:
                    response += f"📱 {channel}: <code>Помилка: {e}</code>\n"
        else:
            response += "❌ Немає каналів для перевірки\n"
        
        bot.send_message(message.chat.id, response, parse_mode="HTML")
    except Exception as e:
        bot.send_message(message.chat.id, f"❌ Помилка: {e}")

