# --- Тестова команда для перевірки декоратора підписки ---
@bot.message_handler(commands=['test_sub'])
def test_subscription_command(message):
    try:
        if not is_admin(message.from_user.id):
            bot.send_message(message.chat.id, "❌ Немає доступу")
            return
        
        from database import get_required_channels
        channels = get_required_channels()
        
        response = f"🔍 <b>ТЕСТ ДЕКОРАТОРА ПІДПИСКИ</b>\n\n"
        response += f"📢 <b>Канали для перевірки:</b>\n"
        if channels:
            for i, channel in enumerate(channels, 1):
                response += f"{i}. <code>{channel}</code>\n"
        else:
            response += "❌ Канали не встановлено\n"
            bot.send_message(message.chat.id, response, parse_mode="HTML")
            return
        
        response += f"\n🔍 <b>Перевірка підписки:</b>\n"
        not_subscribed = []
        
        for channel in channels:
            try:
                member = bot.get_chat_member(channel, message.from_user.id)
                status = member.status
                response += f"📱 {channel}: <code>{status}</code>\n"
                if status in ['left', 'kicked']:
                    not_subscribed.append(channel)
            except Exception as e:
                response += f"📱 {channel}: <code>Помилка: {e}</code>\n"
        
        if not_subscribed:
            response += f"\n❌ <b>НЕ ПІДПИСАНІ:</b>\n"
            for channel in not_subscribed:
                response += f"• <code>{channel}</code>\n"
        else:
            response += f"\n✅ <b>ПІДПИСАНИЙ НА ВСІ КАНАЛИ!</b>\n"
        
        bot.send_message(message.chat.id, response, parse_mode="HTML")
    except Exception as e:
        bot.send_message(message.chat.id, f"❌ Помилка: {e}")

