# Простий обробник для модерації через команди
@bot.message_handler(func=lambda message: message.text and message.text.startswith(('Мут', 'Бан')))
def handle_moderation_commands(message):
    """Простий обробник для модерації через команди"""
    if not is_admin(message.from_user.id):
        bot.reply_to(message, "❌ У вас немає прав для цієї команди")
        return
    
    try:
        # Парсимо команду: Мут ID термін причина
        parts = message.text.split()
        if len(parts) < 4:
            bot.reply_to(message, 
                "❌ Неправильний формат!\n\n"
                "📝 Використання:\n"
                "Мут ID термін причина\n"
                "Бан ID термін причина\n\n"
                "💡 Приклади:\n"
                "Мут 575740293 1год Спам\n"
                "Бан 575740293 1день Порушення")
            return
        
        command = parts[0]  # Мут або Бан
        target_user_id = int(parts[1])
        duration_str = parts[2]
        reason = ' '.join(parts[3:])
        
        # Отримуємо користувача
        user = get_user(target_user_id)
        user_name = user[1] if user else "Невідомий"
        
        # Парсимо термін
        duration_seconds = parse_duration(duration_str)
        if duration_seconds is None:
            bot.reply_to(message, "❌ Неправильний термін! Спробуйте: 5хв, 30хв, 1год, 1день, назавжди")
            return
        
        # Виконуємо дію
        if command == 'Бан':
            # Баним в чаті
            from database import ban_user_in_chat
            result = ban_user_in_chat(target_user_id, message.chat.id, duration_seconds, reason, message.from_user.id)
            action_name = "ЗАБЛОКОВАНО"
            action_emoji = "🚫"
        else:  # Мут
            # Мутим в чаті
            from database import mute_user_in_chat
            result = mute_user_in_chat(target_user_id, message.chat.id, duration_seconds, reason, message.from_user.id)
            action_name = "ЗАМУЧЕНО"
            action_emoji = "🔇"
        
        if result['success']:
            # Повідомлення про успіх
            msg = f"{action_emoji} <b>{action_name}</b> {action_emoji}\n\n"
            msg += f"👤 Користувач: {user_name}\n"
            msg += f"🆔 ID: {target_user_id}\n"
            msg += f"⏰ Термін: {result['duration_text']}\n"
            msg += f"📝 Причина: {reason}\n"
            msg += f"👮 Виконано: {message.from_user.first_name}"
            
            bot.reply_to(message, msg, parse_mode="HTML")
            
            # Повідомлення користувачу
            try:
                user_msg = f"{action_emoji} <b>ВИ {action_name}</b> {action_emoji}\n\n"
                user_msg += f"⏰ Термін: {result['duration_text']}\n"
                user_msg += f"📝 Причина: {reason}\n"
                user_msg += f"👮 Виконано: {message.from_user.first_name}"
                bot.send_message(target_user_id, user_msg, parse_mode="HTML")
            except:
                pass
            
            print(f"[DEBUG] Модерація завершена успішно")
            
        else:
            bot.reply_to(message, f"❌ Помилка: {result['error']}")
            
    except Exception as e:
        print(f"[DEBUG] Помилка: {e}")
        bot.reply_to(message, "❌ Помилка при обробці")

