# --- Налаштування вітального чату після верифікації ---
@bot.message_handler(commands=['set_welcome_chat'])
def set_welcome_chat_command(message):
    try:
        # Тимчасово дозволяємо налаштовувати з групи без прав бота-адміна
        # Якщо команда виконується у групі/супергрупі — перевіряємо, що відправник є адміном групи
        if getattr(message.chat, 'type', 'private') in ('group', 'supergroup'):
            try:
                m = bot.get_chat_member(message.chat.id, message.from_user.id)
                if m.status not in ('creator', 'administrator'):
                    return bot.reply_to(message, "⛔️ Лише адміністратори групи можуть змінювати вітальний чат")
            except Exception:
                # Якщо не вдалося перевірити — не блокуємо, але логуємо
                print(f"[WARN] Не вдалося перевірити права користувача {message.from_user.id} у чаті {message.chat.id}")
        # У приватному чаті — без перевірки is_admin
        from database import set_setting
        parts = message.text.split()
        if len(parts) > 1:
            target_id = parts[1]
        else:
            # Якщо параметр не задано — використовуємо поточний чат
            target_id = str(message.chat.id)
        # Зберігаємо як ідентифікатор, так і як username (якщо передано @...)
        set_setting('welcome_chat_id', str(target_id))
        if str(target_id).startswith('@'):
            set_setting('welcome_chat', str(target_id))
        bot.reply_to(message, f"✅ Вітальний чат налаштовано: <code>{target_id}</code>", parse_mode="HTML")
    except Exception as e:
        bot.reply_to(message, f"❌ Помилка: {e}")

