# Команди для зміни налаштувань поливу
@bot.message_handler(commands=['set_watering_interval'])
def set_watering_interval_command(message):
    """Встановлює інтервал поливу"""
    if not is_admin(message.from_user.id):
        bot.reply_to(message, "❌ У вас немає прав для цієї команди")
        return
    
    try:
        args = message.text.split()
        if len(args) != 2:
            bot.reply_to(message, "📝 Використання: /set_watering_interval <хвилини>")
            return
        
        minutes = int(args[1])
        seconds = minutes * 60
        
        from database import set_watering_setting
        set_watering_setting('watering_interval', seconds)
        
        bot.reply_to(message, f"✅ Інтервал поливу встановлено: {minutes} хвилин")
        
    except ValueError:
        bot.reply_to(message, "❌ Помилка: введіть число хвилин")
    except Exception as e:
        print(f"[DEBUG] Помилка в set_watering_interval_command: {e}")
        bot.reply_to(message, f"❌ Помилка: {e}")

