def admin_quest_wait_handler(call):
    """Обробка вибору часу очікування та запуск квесту"""
    if not is_admin(call.from_user.id):
        return bot.answer_callback_query(call.id, "❌ Немає доступу", show_alert=True)
    
    wait_time = int(call.data.split("_")[2])
    
    # Отримуємо вибрані параметри
    state = get_user_state(call.from_user.id)
