# Команда для отримання ID чату
@bot.message_handler(commands=['chat_id'])
def chat_id_command(message):
    """Показує ID поточного чату"""
    if not is_admin(message.from_user.id):
        bot.reply_to(message, "❌ У вас немає прав для цієї команди")
        return
    
    try:
        chat_type = message.chat.type
        chat_id = message.chat.id
        chat_title = message.chat.title or message.chat.first_name or "Особистий чат"
        
        from database import is_gaming_chat, is_quest_chat
        
        msg = f"📋 <b>ІНФОРМАЦІЯ ПРО ЧАТ</b> 📋\n\n"
        msg += f"💬 <b>Назва:</b> {chat_title}\n"
        msg += f"🆔 <b>ID чату:</b> <code>{chat_id}</code>\n"
        msg += f"📝 <b>Тип:</b> {chat_type}\n"
        msg += f"🎮 <b>Ігровий чат:</b> {'✅ Так' if is_gaming_chat(chat_id) else '❌ Ні'}\n"
        msg += f"🍎 <b>Чат для квестів:</b> {'✅ Так' if is_quest_chat(chat_id) else '❌ Ні'}\n\n"
        msg += f"💡 <b>Використання ID:</b>\n"
        msg += f"• Для квестів: {chat_id}\n"
        msg += f"• Для ігор: {chat_id}\n"
        msg += f"• Для статистики: {chat_id}"
        
        bot.reply_to(message, msg, parse_mode="HTML")
        
    except Exception as e:
        print(f"[DEBUG] Помилка в chat_id_command: {e}")
        bot.reply_to(message, f"❌ Помилка: {e}")



