# Обробник для введення ID чату для квестів (спрощена версія на основі ігрових чатів)
@bot.message_handler(func=lambda message: get_user_state(message.from_user.id) == "adding_quest_chat")
def add_quest_chat_input_handler(message):
    """Обробляє введення ID чату для квестів"""
    print(f"[DEBUG] Отримано повідомлення для додавання чату квестів від {message.from_user.id}: {message.text}")
    
    if not is_admin(message.from_user.id):
        print(f"[DEBUG] Користувач {message.from_user.id} не є адміном")
        return
    
    try:
        chat_id = int(message.text.strip())
        print(f"[DEBUG] Парсинг quest_chat_id: {chat_id}")
        
        if is_quest_chat(chat_id):
            print(f"[DEBUG] Чат {chat_id} вже доданий для квестів")
            bot.reply_to(message, "❌ Цей чат вже доданий для квестів!")
            clear_user_state(message.from_user.id)
            return
        
        # Додаємо чат
        print(f"[DEBUG] Додаємо чат {chat_id} для квестів")
        add_quest_chat(chat_id, f"Чат {chat_id}", message.from_user.id)
        
        kb = InlineKeyboardMarkup()
        kb.add(InlineKeyboardButton("🔙 Назад до меню", callback_data="admin_quest_chats"))
        
        msg = "💬 <b>ЧАТ ДОДАНО</b> 💬\n\n"
        msg += f"✅ Чат з ID <code>{chat_id}</code> успішно додано для квестів.\n\n"
        msg += "🎯 Тепер в цьому чаті можна запускати квести!"
        
        print(f"[DEBUG] Відправляємо повідомлення про успіх")
        bot.reply_to(message, msg, reply_markup=kb, parse_mode="HTML")
        clear_user_state(message.from_user.id)
        
    except ValueError:
        print(f"[DEBUG] Помилка парсингу quest_chat_id: {message.text}")
        bot.reply_to(message, "❌ Помилка: ID чату має бути числом!\n\n💡 Приклад: -1001234567890")
    except Exception as e:
        print(f"[DEBUG] Помилка в add_quest_chat_input_handler: {e}")
        bot.reply_to(message, f"❌ Помилка: {e}")
        clear_user_state(message.from_user.id)

