# Простий обробник для прямого додавання чату квестів
@bot.message_handler(commands=['add_quest_chat'])
def direct_add_quest_chat_handler(message):
    """Пряме додавання чату квестів через команду"""
    if not is_admin(message.from_user.id):
        return
    
    try:
        # Розбиваємо повідомлення на частини
        parts = message.text.split()
        if len(parts) != 2:
            bot.reply_to(message, "❌ Використання: /add_quest_chat <ID_чату>\n\n💡 Приклад: /add_quest_chat -1002218982939")
            return
        
        chat_id = int(parts[1])
        
        if is_quest_chat(chat_id):
            bot.reply_to(message, f"❌ Чат {chat_id} вже доданий для квестів!")
            return
        
        # Додаємо чат
        add_quest_chat(chat_id, f"Чат {chat_id}", message.from_user.id)
        
        msg = "💬 <b>ЧАТ ДОДАНО</b> 💬\n\n"
        msg += f"✅ Чат з ID <code>{chat_id}</code> успішно додано для квестів.\n\n"
        msg += "🎯 Тепер в цьому чаті можна запускати квести!"
        
        bot.reply_to(message, msg, parse_mode="HTML")
        
    except ValueError:
        bot.reply_to(message, "❌ Помилка: ID чату має бути числом!\n\n💡 Приклад: /add_quest_chat -1002218982939")
    except Exception as e:
        bot.reply_to(message, f"❌ Помилка: {e}")


