def apply_global_handlers():
    """Застосовує глобальні обробники для всіх повідомлень та колбеків"""
    from subscription_utils import apply_subscription_guards
    
    # Застосовуємо глобальні перевірки підписок
    apply_subscription_guards(bot)
    
    # ВАЖЛИВО: не реєструємо catch‑all хендлер, щоб не перехватывать команды
    
    # Додаємо обробник для команди /subscription_status
    @bot.message_handler(commands=['subscription_status'])
    def subscription_status_command(message):
        """Показує поточний статус підписки"""
        from subscription_system import check_subscription_before_action
        user_id = message.from_user.id
        is_subscribed = check_subscription_before_action(message, bot)
        
        if is_subscribed:
            bot.reply_to(message, "✅ Ви підписані на всі необхідні канали/чати!")
        else:
            from subscription_system import send_subscription_required_message
            send_subscription_required_message(message, user_id, bot)

@bot.callback_query_handler(func=lambda c: c.data == "stars_deposit")
def stars_deposit_handler(call):
    """Обработчик пополнения через Stars с ручным вводом суммы"""
    uid = call.from_user.id
    
    # Проверка блокировки
    if check_user_block_before_action(call, bot):
        return
    
    # Проверка спама
    is_spam, spam_message = check_button_spam(uid, "stars_deposit")
    if is_spam:
        bot.answer_callback_query(call.id, text=spam_message, show_alert=True)
        return
    
    bot.answer_callback_query(call.id)
    
    try:
        settings = get_stars_settings()
        if not settings['enabled']:
            bot.send_message(call.message.chat.id, "❌ Поповнення через Stars тимчасово відключено")
            return
        
        exchange_rate = settings['exchange_rate']
        min_deposit = settings['min_deposit']
        admin_fee = settings.get('admin_fee_percent', 0)
        
        # Просим ввести сумму вручную
        from telebot.types import ReplyKeyboardMarkup, KeyboardButton
        kb = ReplyKeyboardMarkup(resize_keyboard=True, one_time_keyboard=True)
        # kb.add(KeyboardButton("⬅️ Відміна"))  # Removed as requested
        text = (
            "🌟 <b>Поповнення через Telegram Stars</b>\n\n"
            f"💰 <b>Курс:</b> {exchange_rate} Stars = 1₴\n"
            f"💸 <b>Мінімальна сума:</b> {min_deposit} Stars\n"
            f"📊 <b>Комісія адміна:</b> {admin_fee}%\n\n"
            "Введіть кількість Stars для поповнення (число).\n"
            "Введіть кількість Stars для поповнення."
        )
        msg = bot.send_message(call.message.chat.id, text, parse_mode="HTML", reply_markup=kb)
        bot.register_next_step_handler(msg, stars_deposit_amount_input)
    except Exception as e:
        print(f"[stars_deposit] error: {e}")
        bot.send_message(call.message.chat.id, "❌ Помилка завантаження налаштувань Stars")

@bot.callback_query_handler(func=lambda c: c.data.startswith("stars_amount:"))
def stars_amount_handler(call):
    """Обработчик выбора суммы Stars"""
    uid = call.from_user.id
    
    # Проверка блокировки
    if check_user_block_before_action(call, bot):
        return
    
    try:
        stars_amount = int(call.data.split(":")[1])
        settings = get_stars_settings()
        
        exchange_rate = settings['exchange_rate']
        admin_fee = settings.get('admin_fee_percent', 0)
        
        # Рассчитываем сумму в гривнах с учетом комиссии
        uah_amount = (stars_amount / exchange_rate) * (1 - admin_fee / 100)
        
        # Создаем транзакцию Stars
        transaction_id = create_stars_transaction(uid, stars_amount, uah_amount)
        
        # Генерируем инвойс (XTR)
        from telebot.types import LabeledPrice
        prices = [LabeledPrice(label="Stars", amount=stars_amount)]
        bot.send_invoice(
            call.message.chat.id,
            "Поповнення баланса через Stars",
            f"Поповнення на {uah_amount:.2f}₴ через {stars_amount} Telegram Stars",
            f"stars_deposit:{transaction_id}",  # invoice_payload
            "",  # provider_token пустой для цифровых товаров (Telegram Stars)
            "XTR",  # валюта
            prices,
            start_parameter=f"stars_{transaction_id}"
        )
        
        bot.answer_callback_query(call.id, f"✅ Інвойс на {stars_amount} Stars створений")
        
    except Exception as e:
        print(f"[stars_amount] error: {e}")
        bot.answer_callback_query(call.id, "❌ Помилка створення інвойса", show_alert=True)

@bot.message_handler(func=lambda m: m.text is not None and m.text.lower() in ["відміна", "отмена", "cancel"])
def stars_deposit_cancel(message):
    """Обработчик отмены ввода суммы Stars"""
    try:
        from telebot.types import ReplyKeyboardRemove
        bot.send_message(message.chat.id, "❎ Скасовано.", reply_markup=ReplyKeyboardRemove())
    except Exception:
        pass

def stars_deposit_amount_input(message):
    """Обрабатывает ручной ввод суммы Stars и отправляет инвойс"""
    try:
        from telebot.types import ReplyKeyboardRemove, LabeledPrice
        settings = get_stars_settings()
        min_deposit = settings['min_deposit']
        exchange_rate = settings['exchange_rate']
        admin_fee = settings.get('admin_fee_percent', 0)
        
        text_raw = (message.text or "").strip().replace(" ", "")
        if text_raw.lower() in ["відміна", "отмена", "cancel"]:
            return bot.send_message(message.chat.id, "❎ Скасовано.", reply_markup=ReplyKeyboardRemove())
        
        if not text_raw.isdigit():
            msg = bot.send_message(message.chat.id, "❌ Введіть ціле число Stars.")
            return bot.register_next_step_handler(msg, stars_deposit_amount_input)
        
        stars_amount = int(text_raw)
        if stars_amount < int(min_deposit):
            msg = bot.send_message(message.chat.id, f"❌ Мінімум: {min_deposit} Stars. Введіть іншу суму.")
            return bot.register_next_step_handler(msg, stars_deposit_amount_input)
        
        uah_amount = (stars_amount / exchange_rate) * (1 - admin_fee / 100)
        uid = message.from_user.id
        transaction_id = create_stars_transaction(uid, stars_amount, uah_amount)
        prices = [LabeledPrice(label="Stars", amount=stars_amount)]
        bot.send_invoice(
            message.chat.id,
            "Поповнення баланса через Stars",
            f"Поповнення на {uah_amount:.2f}₴ через {stars_amount} Telegram Stars",
            f"stars_deposit:{transaction_id}",  # invoice_payload
            "",  # provider_token пустой для цифровых товаров (Telegram Stars)
            "XTR",  # валюта
            prices,
            start_parameter=f"stars_{transaction_id}"
        )
        bot.send_message(message.chat.id, "✅ Інвойс створено, завершіть оплату в інтерфейсі Telegram.", reply_markup=ReplyKeyboardRemove())
    except Exception as e:
        print(f"[stars_manual_amount] error: {e}")
        try:
            from telebot.types import ReplyKeyboardRemove
            bot.send_message(message.chat.id, "❌ Помилка створення інвойса", reply_markup=ReplyKeyboardRemove())
        except Exception:
            bot.send_message(message.chat.id, "❌ Помилка створення інвойса")

@bot.callback_query_handler(func=lambda c: c.data == "cryptobot_deposit")
def cryptobot_deposit_handler(call):
    """Обробник поповнення через CryptoBot"""
    uid = call.from_user.id
    
    # Перевірка блокування
    if check_user_block_before_action(call, bot):
        return
    
    # Перевірка спаму
    is_spam, spam_message = check_button_spam(uid, "cryptobot_deposit")
    if is_spam:
        bot.answer_callback_query(call.id, text=spam_message, show_alert=True)
        return
    
    bot.answer_callback_query(call.id)
    
    try:
        settings = get_cryptobot_settings()
        if not settings['enabled']:
            bot.send_message(call.message.chat.id, "❌ Поповнення через CryptoBot тимчасово відключено")
            return
        
        if not CRYPTOBOT_AVAILABLE or CryptoPayAPI is None:
            bot.send_message(call.message.chat.id, "❌ CryptoBot не налаштовано. Модуль cryptobot_api недоступен. Зверніться до адміністратора")
            return
        
        if not settings.get('api_key'):
            bot.send_message(call.message.chat.id, "❌ CryptoBot не налаштовано. Зверніться до адміністратора")
            return
        
        # Преобразуем значения в числа, так как из базы они могут приходить как строки
        exchange_rate = float(settings.get('exchange_rate', 0.025))
        min_deposit = float(settings.get('min_deposit', 10))
        admin_fee = float(settings.get('admin_fee_percent', 0))
        
        # Просимо ввести суму в гривнах
        from telebot.types import ReplyKeyboardMarkup, KeyboardButton
        kb = ReplyKeyboardMarkup(resize_keyboard=True, one_time_keyboard=True)
        
        text = (
            f"₿ <b>Поповнення через CryptoBot</b>\n\n"
            f"💎 <b>Швидко та безпечно</b> — оплата криптовалютою\n\n"
            f"💸 <b>Мінімальна сума:</b> <b>{min_deposit:.0f} ₴</b>\n"
            f"📊 <b>Комісія проекту:</b> <b>{admin_fee:.1f}%</b>\n\n"
            f"<b>Введіть суму поповнення в гривнях (₴):</b>\n"
            f"Наприклад: <code>100</code>"
        )
        
        msg = bot.send_message(call.message.chat.id, text, parse_mode="HTML", reply_markup=kb)
        bot.register_next_step_handler(msg, cryptobot_uah_amount_input)
    except Exception as e:
        print(f"[cryptobot_deposit] error: {e}")
        import traceback
        traceback.print_exc()
        bot.send_message(call.message.chat.id, "❌ Помилка завантаження налаштувань CryptoBot")

