@bot.message_handler(content_types=['successful_payment'])
def successful_payment_handler(message):
    """Обработчик успешного платежа"""
    uid = message.from_user.id
    
    try:
        payment = message.successful_payment
        payload = payment.invoice_payload
        
        if payload.startswith("stars_deposit:"):
            # Обработка платежа Stars
            transaction_id = int(payload.split(":")[1])
            
            # Получаем данные транзакции
            transaction = get_stars_transaction(transaction_id)
            if not transaction:
                bot.send_message(message.chat.id, "❌ Транзакция не найдена")
                return
            
            # Обновляем статус транзакции
            update_stars_transaction(
                transaction_id,
                payment.telegram_payment_charge_id,
                payment.provider_payment_charge_id,
                'completed'
            )
            
            # Зачисляем средства на баланс
            uah_amount = transaction[3]  # uah_amount из базы
            # add_balance(uid, amount, force_admin=False, reason=None, details=None)
            from database import check_deposit_tasks, add_deposit
            add_balance(uid, uah_amount, False, "stars_deposit", f"Поповнення через {transaction[2]} Stars")
            # Обновляем сумму депозитов (только реальная сумма пополнения)
            add_deposit(uid, uah_amount)
            
            # Перевіряємо завдання типу deposit
            check_deposit_tasks(uid, uah_amount)
            
            # Уведомляем пользователя
            bot.send_message(
                message.chat.id,
                (
                    f"✅ <b>Поповнення успішно!</b>\\n\\n"
                    f"💰 Зараховано: {uah_amount:.2f}₴\\n"
                    f"🌟 Витрачено: {transaction[2]} Stars\\n"
                    f"🆔 ID транзакції: {transaction_id}"
                ),
                parse_mode="HTML"
            )
            
            # Уведомляем админов
            try:
                admin_text = (
                    f"💰 <b>Поповнення через Stars</b>\\n\\n"
                    f"👤 Користувач: {message.from_user.first_name} (@{message.from_user.username or 'N/A'})\\n"
                    f"🆔 ID: {uid}\\n"
                    f"💵 Сума: {uah_amount:.2f}₴\\n"
                    f"🌟 Stars: {transaction[2]}\\n"
                    f"🆔 Транзакція: {transaction_id}"
                )
                
                # Отправляем всем админам
                from database import get_admins
                for admin_id in get_admins():
                    try:
                        bot.send_message(admin_id, admin_text, parse_mode="HTML")
                    except:
                        pass
            except Exception as e:
                print(f"[stars_admin_notify] error: {e}")
        
        else:
            # Стандартная обработка других платежей
            pass
            
    except Exception as e:
        print(f"[successful_payment] error: {e}")
        bot.send_message(message.chat.id, "❌ Ошибка при обработке платежа")

# === CRYPTOBOT WEBHOOK HANDLERS ===

@bot.message_handler(commands=['cryptobot_webhook'])
def cryptobot_webhook_handler(message):
    """Обробник webhook від CryptoBot для перевірки статусу платежів"""
    if not is_admin(message.from_user.id):
        return
    
    try:
        # Отримуємо всі очікуючі транзакції
        from database import _db
        with _db() as con:
            pending_txs = con.execute("""
                SELECT id, user_id, crypto_amount, crypto_currency, uah_amount, invoice_id, created_at
                FROM cryptobot_transactions 
                WHERE status='pending' AND invoice_id IS NOT NULL
                ORDER BY created_at DESC
                LIMIT 50
            """).fetchall()
        
        if not pending_txs:
            bot.reply_to(message, "⏳ Немає очікуючих транзакцій CryptoBot")
            return
        
        # Перевіряємо статус кожної транзакції
        from cryptobot_api import CryptoBotAPI
        settings = get_cryptobot_settings()
        
        if not settings.get('api_key'):
            bot.reply_to(message, "❌ CryptoBot не налаштовано")
            return
        
        from cryptobot_api import CryptoPayAPI
        crypto_api = CryptoPayAPI(settings['api_key'])
        updated_count = 0
        
        for tx in pending_txs:
            tx_id, user_id, crypto_amount, currency, uah_amount, invoice_id, created_at = tx
            
            # Перевіряємо статус інвойса
            invoice_result = crypto_api.get_invoices(invoice_ids=[int(invoice_id)])
            
            if invoice_result.get('ok') and invoice_result.get('result'):
                invoice_data = invoice_result['result'][0]
                status = invoice_data.get('status', 'pending')
                
                if status == 'paid':
                    # Платіж успішний - зараховуємо кошти
                    try:
                        # Оновлюємо статус транзакції
                        update_cryptobot_transaction_status(tx_id, 'completed')
                        
                        # Додаємо кошти на баланс
                        from database import check_deposit_tasks, add_deposit
                        add_balance(user_id, uah_amount, reason='cryptobot_deposit', 
                                  details=f'Поповнення через CryptoBot {currency} - транзакція #{tx_id}')
                        # Обновляем сумму депозитов (только реальная сумма пополнения)
                        add_deposit(user_id, uah_amount)
                        
                        # Перевіряємо завдання типу deposit
                        check_deposit_tasks(user_id, uah_amount)
                        
                        # Повідомляємо користувача
                        try:
                            bot.send_message(
                                user_id,
                                f"✅ <b>Поповнення успішне!</b>\n\n"
                                f"💰 <b>Сума:</b> {uah_amount:.2f}₴\n"
                                f"₿ <b>Валюта:</b> {currency}\n"
                                f"🆔 <b>Транзакція:</b> #{tx_id}\n\n"
                                f"🎉 <b>Кошти зараховано на баланс!</b>",
                                parse_mode="HTML"
                            )
                        except Exception:
                            pass
                        
                        # Повідомляємо адмінів
                        try:
                            from database import get_admins
                            admin_text = (
                                f"✅ <b>Поповнення через CryptoBot</b>\n\n"
                                f"👤 <b>Користувач:</b> {user_id}\n"
                                f"💰 <b>Сума:</b> {uah_amount:.2f}₴\n"
                                f"₿ <b>Валюта:</b> {currency}\n"
                                f"🆔 <b>Транзакція:</b> #{tx_id}\n"
                                f"🆔 <b>Інвойс:</b> {invoice_id}"
                            )
                            
                            for admin_id in get_admins():
                                try:
                                    bot.send_message(admin_id, admin_text, parse_mode="HTML")
                                except Exception:
                                    pass
                        except Exception:
                            pass
                        
                        updated_count += 1
                        
                    except Exception as e:
                        print(f"[cryptobot_complete] error for tx {tx_id}: {e}")
                
                elif status == 'expired':
                    # Інвойс прострочений
                    update_cryptobot_transaction_status(tx_id, 'failed')
                    updated_count += 1
                
                elif status == 'cancelled':
                    # Платіж скасований
                    update_cryptobot_transaction_status(tx_id, 'failed')
                    updated_count += 1
            
            # Невелика затримка між запитами
            import time
            time.sleep(0.5)
        
        bot.reply_to(message, f"✅ Перевірено {len(pending_txs)} транзакцій, оновлено {updated_count}")
        
    except Exception as e:
        print(f"[cryptobot_webhook] error: {e}")
        bot.reply_to(message, f"❌ Помилка перевірки: {e}")

@bot.message_handler(commands=['cryptobot_test'])
def cryptobot_test_handler(message):
    """Тестирование подключения Crypto Pay API"""
    if not is_admin(message.from_user.id):
        return
    
    try:
        from cryptobot_api import CryptoPayAPI
        settings = get_cryptobot_settings()
        
        if not settings.get('api_key'):
            bot.reply_to(message, "❌ Сначала настройте API ключ:\n/cryptobot_api [ключ]")
            return
        
        # Test mainnet
        api_mainnet = CryptoPayAPI(settings['api_key'], testnet=False)
        result_mainnet = api_mainnet.test_connection()
        
        # Test testnet
        api_testnet = CryptoPayAPI(settings['api_key'], testnet=True)
        result_testnet = api_testnet.test_connection()
        
        response = "🔧 <b>Результаты тестирования Crypto Pay API:</b>\n\n"
        
        if result_mainnet.get('ok'):
            response += f"✅ <b>Mainnet:</b> Подключено\n"
            response += f"📱 App ID: {result_mainnet.get('app_id')}\n"
            response += f"📝 Название: {result_mainnet.get('name')}\n"
            response += f"🤖 Бот: {result_mainnet.get('payment_processing_bot_username')}\n\n"
        else:
            response += f"❌ <b>Mainnet:</b> {result_mainnet.get('error', 'Ошибка подключения')}\n\n"
        
        if result_testnet.get('ok'):
            response += f"✅ <b>Testnet:</b> Подключено\n"
            response += f"📱 App ID: {result_testnet.get('app_id')}\n"
            response += f"📝 Название: {result_testnet.get('name')}\n"
            response += f"🤖 Бот: {result_testnet.get('payment_processing_bot_username')}\n"
        else:
            response += f"❌ <b>Testnet:</b> {result_testnet.get('error', 'Ошибка подключения')}\n"
        
        # Add current settings
        response += f"\n🔧 <b>Текущие настройки:</b>\n"
        response += f"• Курс: {settings.get('exchange_rate', 0.025)} USD за 1₴\n"
        response += f"• Минимум: {settings.get('min_deposit', 10)}₴\n"
        response += f"• Валюты: {', '.join(settings.get('supported_currencies', ['USDT', 'TON', 'BTC']))}\n"
        response += f"• Комиссия: {settings.get('admin_fee_percent', 2)}%"
        
        bot.reply_to(message, response, parse_mode="HTML")
            
    except Exception as e:
        print(f"[cryptobot_test] error: {e}")
        bot.reply_to(message, f"❌ Ошибка тестирования: {str(e)}")

