@bot.message_handler(commands=['stars_payout'])
def stars_payout_handler(message):
    """Создание выплаты Stars пользователю (админ). Формат: /stars_payout <user_id> <stars> [описание]"""
    if not is_admin(message.from_user.id):
        return
    try:
        parts = message.text.split(maxsplit=3)
        if len(parts) < 3:
            return bot.reply_to(message, "Використання: /stars_payout <user_id> <stars> [опис]")
        target_id = int(parts[1])
        stars_amt = int(parts[2])
        desc = parts[3] if len(parts) > 3 else "Адмінська виплата"
        if stars_amt <= 0:
            return bot.reply_to(message, "Сума Stars має бути > 0")
        payout_id = create_stars_payout(target_id, stars_amt, desc)
        bot.reply_to(message, f"✅ Створено виплату Stars #{payout_id} користувачу {target_id} на {stars_amt} ⭐")
    except Exception as e:
        print(f"[stars_payout] error: {e}")
        bot.reply_to(message, "❌ Помилка створення виплати")

