@bot.message_handler(commands=['stars_stats'])
def stars_stats_handler(message):
    """Статистика Stars"""
    if not is_admin(message.from_user.id):
        return
    try:
        from database import _db, get_stars_settings
        settings = get_stars_settings() or {}
        rate = int(settings.get('exchange_rate', 100))
        min_dep = int(settings.get('min_deposit', 100))
        enabled = bool(int(settings.get('enabled', 1))) if str(settings.get('enabled', 1)).isdigit() else bool(settings.get('enabled', 1))
        fee_pct = float(settings.get('admin_fee_percent', 0) or 0)

        with _db() as con:
            # Загальні показники
            row_total = con.execute("SELECT COUNT(*), SUM(stars_amount), SUM(uah_amount) FROM stars_transactions").fetchone()
            total_cnt = int(row_total[0] or 0)
            total_stars = int(row_total[1] or 0)
            total_uah = float(row_total[2] or 0.0)

            # За статусами
            row_c = con.execute("SELECT COUNT(*), SUM(stars_amount), SUM(uah_amount) FROM stars_transactions WHERE status='completed'").fetchone()
            comp_cnt = int(row_c[0] or 0)
            comp_stars = int(row_c[1] or 0)
            comp_uah = float(row_c[2] or 0.0)

            row_p = con.execute("SELECT COUNT(*) FROM stars_transactions WHERE status='pending'").fetchone()
            pend_cnt = int(row_p[0] or 0)
            row_f = con.execute("SELECT COUNT(*) FROM stars_transactions WHERE status NOT IN ('pending','completed')").fetchone()
            fail_cnt = int(row_f[0] or 0)

            # Топ-5 користувачів за обсягом UAH (completed)
            top_rows = con.execute(
                """
                SELECT t.user_id, IFNULL(u.user_name, COALESCE(u.username, CAST(t.user_id AS TEXT))) AS name,
                       SUM(t.uah_amount) AS sum_uah, SUM(t.stars_amount) AS sum_stars, COUNT(*) AS tx
                FROM stars_transactions t
                LEFT JOIN users u ON u.user_id = t.user_id
                WHERE t.status='completed'
                GROUP BY t.user_id
                ORDER BY sum_uah DESC
                LIMIT 5
                """
            ).fetchall() or []

            # Останні 10 транзакцій
            last_rows = con.execute(
                """
                SELECT id, user_id, stars_amount, uah_amount, status, timestamp
                FROM stars_transactions
                ORDER BY id DESC
                LIMIT 10
                """
            ).fetchall() or []

        conv = (comp_cnt / total_cnt * 100.0) if total_cnt > 0 else 0.0
        est_admin_fee = comp_uah * max(0.0, fee_pct)

        # Текст
        lines = [
            "🌟 <b>СТАТИСТИКА TELEGRAM STARS</b>",
            "━━━━━━━━━━━━━━━━━━━━",
            f"⚙️ <b>Налаштування</b>: курс <b>1 XTR ≈ {rate}₴</b> | мін.деп: <b>{min_dep} XTR</b> | комісія адміна: <b>{int(fee_pct*100)}%</b> | статус: <b>{'✅ Увімкнено' if enabled else '❌ Вимкнено'}</b>",
            "",
            "📦 <b>Загалом</b>",
            f"• Транзакцій: <b>{total_cnt}</b>",
            f"• Сума: <b>{total_stars}</b> XTR ≈ <b>{format_currency(total_uah)}₴</b>",
            "",
            "✅ <b>Успішні</b>",
            f"• Кількість: <b>{comp_cnt}</b> ({conv:.1f}%)",
            f"• Сума: <b>{comp_stars}</b> XTR ≈ <b>{format_currency(comp_uah)}₴</b>",
            (f"• Очікуваний адмін.доход: <b>{format_currency(est_admin_fee)}₴</b>" if fee_pct > 0 else ""),
            "",
            "⏳ <b>В очікуванні</b>",
            f"• Кількість: <b>{pend_cnt}</b>",
            "",
            "❌ <b>Помилки/скасовані</b>",
            f"• Кількість: <b>{fail_cnt}</b>",
        ]

        if top_rows:
            lines += ["", "🏆 <b>ТОП‑5 КОРИСТУВАЧІВ (UAH)</b>"]
            place = 1
            for uid, name, sum_uah, sum_stars, tx in top_rows:
                medal = '🥇' if place==1 else '🥈' if place==2 else '🥉' if place==3 else '🏅'
                lines.append(f"{medal} {place}. <a href='tg://user?id={uid}'>{name}</a> — <b>{format_currency(sum_uah)}</b>₴ ({int(sum_stars)} XTR, {tx} тx)")
                place += 1

        if last_rows:
            lines += ["", "🕒 <b>ОСТАННІ 10</b>"]
            import time
            for row in last_rows:
                rid, uid, s_amt, u_amt, st, ts = row
                tstr = time.strftime('%d.%m %H:%M', time.localtime(int(ts or 0)))
                lines.append(f"• #{rid} | {tstr} | UID {uid} | {int(s_amt)} XTR → {format_currency(u_amt)}₴ | {st}")

        text = "\n".join([ln for ln in lines if ln is not None])

        from telebot.types import InlineKeyboardMarkup, InlineKeyboardButton
        kb = InlineKeyboardMarkup()
        kb.add(InlineKeyboardButton("⬅️ Назад", callback_data="panel"))

        try:
            # Короткий банер у шапці (без перезавантаження екрану)
            send_banner_with_caption(message.chat.id, "Telegram Stars", "🌟", build_caption_from_text(text, 1024), reply_markup=kb, parse_mode="HTML", subtitle="Статистика поповнень і налаштування")
        except Exception:
            bot.send_message(message.chat.id, text, reply_markup=kb, parse_mode="HTML")
    except Exception as e:
        print(f"[stars_stats] error: {e}")
        bot.send_message(message.chat.id, "❌ Помилка завантаження статистики")


