@bot.callback_query_handler(func=lambda c: c.data in [
    "stars_admin_pending", "stars_admin_last", "stars_admin_stats", "stars_admin_toggle", "stars_admin_set_min"
])
def stars_admin_panel_callbacks(call):
    if not is_admin(call.from_user.id):
        return
    from telebot.types import InlineKeyboardMarkup, InlineKeyboardButton
    try:
        if call.data == "stars_admin_toggle":
            settings = get_stars_settings()
            update_stars_settings(enabled=not settings.get('enabled', True))
            bot.answer_callback_query(call.id, "Статус змінено")
            return stars_admin_panel_command(call.message)

        if call.data == "stars_admin_stats":
            return stars_stats_handler(call.message)

        if call.data == "stars_admin_set_min":
            msg = bot.send_message(call.message.chat.id, "Введіть новий мінімум Stars (ціле число):")
            return bot.register_next_step_handler(msg, stars_admin_set_min_input)

        # Lists
        from database import _db
        with _db() as con:
            if call.data == "stars_admin_pending":
                rows = con.execute(
                    "SELECT id, user_id, stars_amount, uah_amount, status, timestamp FROM stars_transactions WHERE status='pending' ORDER BY id DESC LIMIT 20"
                ).fetchall() or []
                title = "⏳ Очікують"
            else:
                rows = con.execute(
                    "SELECT id, user_id, stars_amount, uah_amount, status, timestamp FROM stars_transactions ORDER BY id DESC LIMIT 10"
                ).fetchall() or []
                title = "🕒 Останні 10"

        import time
        lines = [f"{title}", ""]
        kb = InlineKeyboardMarkup()
        for r in rows:
            rid, uid, s_amt, u_amt, st, ts = r
            tstr = time.strftime('%d.%m %H:%M', time.localtime(int(ts or 0)))
            lines.append(f"• #{rid} | {tstr} | UID {uid} | {int(s_amt)} XTR → {format_currency(u_amt)}₴ | {st}")
            kb.add(InlineKeyboardButton(f"🔎 Відкрити #{rid}", callback_data=f"stars_tx:{rid}"))
        kb.add(InlineKeyboardButton("⬅️ Назад", callback_data="panel"))

        text = "\n".join(lines) or (title + "\nНемає записів")
        try:
            bot.edit_message_text(text, call.message.chat.id, call.message.message_id, reply_markup=kb)
        except Exception:
            bot.send_message(call.message.chat.id, text, reply_markup=kb)
    except Exception as e:
        print(f"[stars_admin_cb] error: {e}")
        bot.answer_callback_query(call.id, "❌ Помилка", show_alert=True)


def render_stars_tx_detail(chat_id, tx_id, message_id=None):
    """Рендерить картку транзакції з кнопками дій"""
    try:
        from telebot.types import InlineKeyboardMarkup, InlineKeyboardButton
        from database import _db
        with _db() as con:
            row = con.execute(
                "SELECT id, user_id, stars_amount, uah_amount, telegram_charge_id, provider_payment_charge_id, status, timestamp FROM stars_transactions WHERE id=?",
                (tx_id,)
            ).fetchone()
        if not row:
            return bot.send_message(chat_id, "❌ Транзакцію не знайдено")
        rid, uid, s_amt, u_amt, tg_charge, prov_charge, status, ts = row
        import time
        tstr = time.strftime('%d.%m.%Y %H:%M', time.localtime(int(ts or 0)))
        lines = [
            f"🧾 <b>Транзакція #{rid}</b>",
            f"👤 UID: <code>{uid}</code>",
            f"🌟 Stars: <b>{int(s_amt)}</b>",
            f"💰 UAH: <b>{format_currency(u_amt)}</b>",
            f"📅 Час: {tstr}",
            f"🏷️ Статус: <b>{status}</b>",
            f"🆔 tg_charge: <code>{tg_charge or '—'}</code>",
        ]
        text = "\n".join(lines)
        kb = InlineKeyboardMarkup(row_width=2)
        if status == 'pending':
            kb.add(
                InlineKeyboardButton("✅ Зарахувати", callback_data=f"stars_tx_credit:{rid}"),
                InlineKeyboardButton("❌ Скасувати", callback_data=f"stars_tx_cancel:{rid}"),
            )
        if status == 'completed' and tg_charge:
            kb.add(InlineKeyboardButton("↩️ Refund", callback_data=f"stars_tx_refund:{rid}"))
        kb.add(InlineKeyboardButton("⬅️ Назад", callback_data="stars_admin_last"))

        if message_id:
            try:
                bot.edit_message_text(text, chat_id, message_id, reply_markup=kb, parse_mode="HTML")
            except Exception:
                bot.send_message(chat_id, text, reply_markup=kb, parse_mode="HTML")
        else:
            bot.send_message(chat_id, text, reply_markup=kb, parse_mode="HTML")
    except Exception as e:
        print(f"[stars_tx_detail] error: {e}")
        bot.send_message(chat_id, "❌ Помилка відображення транзакції")


@bot.callback_query_handler(func=lambda c: c.data.startswith("stars_tx:"))
def stars_tx_open(call):
    if not is_admin(call.from_user.id):
        return
    try:
        tx_id = int(call.data.split(":")[1])
        render_stars_tx_detail(call.message.chat.id, tx_id, message_id=call.message.message_id)
    except Exception as e:
        print(f"[stars_tx_open] error: {e}")
        bot.answer_callback_query(call.id, "❌ Помилка", show_alert=True)


@bot.callback_query_handler(func=lambda c: c.data.startswith("stars_tx_credit:"))
def stars_tx_credit(call):
    if not is_admin(call.from_user.id):
        return
    try:
        tx_id = int(call.data.split(":")[1])
        from database import _db
        with _db() as con:
            row = con.execute("SELECT user_id, uah_amount, status FROM stars_transactions WHERE id=?", (tx_id,)).fetchone()
        if not row:
            return bot.answer_callback_query(call.id, "Не знайдено")
        uid, uah_amount, status = row
        if status == 'completed':
            bot.answer_callback_query(call.id, "Вже зараховано")
        else:
            from database import check_deposit_tasks, add_deposit
            add_balance(uid, float(uah_amount), "stars_deposit", f"Ручне зарахування Stars tx #{tx_id}")
            # Обновляем сумму депозитов (только реальная сумма пополнения)
            add_deposit(uid, float(uah_amount))
            
            # Перевіряємо завдання типу deposit
            check_deposit_tasks(uid, float(uah_amount))
            update_stars_transaction(tx_id, status='completed')
            bot.answer_callback_query(call.id, "Зараховано")
        render_stars_tx_detail(call.message.chat.id, tx_id, message_id=call.message.message_id)
    except Exception as e:
        print(f"[stars_tx_credit] error: {e}")
        bot.answer_callback_query(call.id, "❌ Помилка", show_alert=True)


@bot.callback_query_handler(func=lambda c: c.data.startswith("stars_tx_cancel:"))
def stars_tx_cancel(call):
    if not is_admin(call.from_user.id):
        return
    try:
        tx_id = int(call.data.split(":")[1])
        update_stars_transaction(tx_id, status='cancelled')
        bot.answer_callback_query(call.id, "Скасовано")
        render_stars_tx_detail(call.message.chat.id, tx_id, message_id=call.message.message_id)
    except Exception as e:
        print(f"[stars_tx_cancel] error: {e}")
        bot.answer_callback_query(call.id, "❌ Помилка", show_alert=True)


@bot.callback_query_handler(func=lambda c: c.data.startswith("stars_tx_refund:"))
def stars_tx_refund(call):
    if not is_admin(call.from_user.id):
        return
    try:
        tx_id = int(call.data.split(":")[1])
        from database import _db
        with _db() as con:
            row = con.execute("SELECT user_id, telegram_charge_id, status FROM stars_transactions WHERE id=?", (tx_id,)).fetchone()
        if not row:
            return bot.answer_callback_query(call.id, "Не знайдено")
        uid, tg_charge, status = row
        if status != 'completed' or not tg_charge:
            return bot.answer_callback_query(call.id, "Немає що повертати")
        # Викликаємо Bot API refundStarPayment напряму
        import requests
        url = f"https://api.telegram.org/bot{bot.token}/refundStarPayment"
        resp = requests.post(url, json={"user_id": uid, "telegram_payment_charge_id": tg_charge}, timeout=15)
        ok = False
        try:
            data = resp.json()
            ok = bool(data.get('ok'))
        except Exception:
            ok = False
        if ok:
            update_stars_transaction(tx_id, status='refunded')
            bot.answer_callback_query(call.id, "Refund виконано")
        else:
            bot.answer_callback_query(call.id, "Refund не вдався", show_alert=True)
        render_stars_tx_detail(call.message.chat.id, tx_id, message_id=call.message.message_id)
    except Exception as e:
        print(f"[stars_tx_refund] error: {e}")
        bot.answer_callback_query(call.id, "❌ Помилка", show_alert=True)


def stars_admin_set_min_input(message):
    """Ручне встановлення мінімуму Stars через інлайн‑панель"""
    if not is_admin(message.from_user.id):
        return
    try:
        val = int((message.text or '').strip())
        if val <= 0:
            return bot.reply_to(message, "❌ Мінімум має бути > 0")
        update_stars_settings(min_deposit=val)
        bot.reply_to(message, f"✅ Мінімальний депозит встановлено: {val} Stars")
    except Exception as e:
        print(f"[stars_admin_set_min_input] error: {e}")
        bot.reply_to(message, "❌ Помилка встановлення мінімуму")



def get_user_balance_history(user_id, limit=20):
    """Получает историю изменений баланса пользователя"""
    try:
        from database import _db
        with _db() as con:
            cursor = con.execute("""
                SELECT delta, balance_before, balance_after, reason, details, created_at
                FROM balance_ledger 
                WHERE user_id = ? 
                ORDER BY created_at DESC 
                LIMIT ?
            """, (user_id, limit))
            return cursor.fetchall()
    except Exception as e:
        print(f"[balance_history] error: {e}")
        return []

