@bot.message_handler(commands=['cryptobot_currencies'])
def cryptobot_currencies_handler(message):
    """Встановлення підтримуваних валют CryptoBot"""
    if not is_admin(message.from_user.id):
        return
    
    try:
        currencies_text = message.text.split(' ', 1)[1] if len(message.text.split()) > 1 else None
        if not currencies_text:
            bot.reply_to(message, "❌ Введіть валюти: /cryptobot_currencies BTC,ETH,USDT,USDC")
            return
        
        currencies = [c.strip().upper() for c in currencies_text.split(',')]
        valid_currencies = ['BTC', 'ETH', 'USDT', 'USDC', 'LTC', 'BCH', 'XRP']
        
        for currency in currencies:
            if currency not in valid_currencies:
                bot.reply_to(message, f"❌ Невідома валюта: {currency}. Доступні: {', '.join(valid_currencies)}")
                return
        
        update_cryptobot_settings(supported_currencies=currencies)
        bot.reply_to(message, f"✅ Валюти встановлено: {', '.join(currencies)}")
    except Exception as e:
        print(f"[cryptobot_currencies] error: {e}")
        bot.reply_to(message, "❌ Помилка встановлення валют")

