def format_balance_history(history):
    """Форматирует историю баланса для отображения"""
    if not history:
        return "Історія транзакцій порожня"
    
    lines = ["📊 <b>Історія балансу:</b>"]
    
    for delta, before, after, reason, details, timestamp in history:
        try:
            import time
            dt = time.strftime('%d.%m.%Y %H:%M', time.localtime(timestamp))
        except:
            dt = str(timestamp)
        
        # Локализация причин
        reason_map = {
            'referral_bonus': 'Реферальний бонус',
            'withdraw': 'Вивід коштів',
            'account_transfer': 'Поповнення',
            'stars_deposit': 'Поповнення Stars',
            'garden_level_up': 'Підвищення рівня саду',
            'buy_tree': 'Покупка дерева',
            'sell_fruit_income': 'Продаж фруктів',
            'admin_chat_gift': 'Адмін (чат)',
            'admin_chat_penalty': 'Адмін штраф (чат)',
            'pvp_win': 'Перемога в {game_type} PvP',
            'pvp_draw': 'Нічия в {game_type} PvP',
            'pvp_timeout': 'PvP таймаут'
        }
        
        reason_text = reason_map.get(reason, reason or 'Неизвестно')
        
        sign = "+" if delta > 0 else ""
        lines.append(f"• <b>{dt}</b> — <b>{reason_text}</b>")
        lines.append(f"  💰 {sign}{delta:.2f}₴ ({before:.2f} → {after:.2f}₴)")
        if details:
            lines.append(f"  📝 {details}")
        lines.append("")
    
    return "\n".join(lines)

