@bot.message_handler(commands=['user_ledger'])
def user_ledger_handler(message):
    """Показывает леджер пользователя (админ-команда)"""
    if not is_admin(message.from_user.id):
        return
    
    try:
        args = message.text.split()
        if len(args) != 2:
            bot.send_message(message.chat.id, "❌ Використання: /user_ledger [user_id]")
            return
        
        user_id = int(args[1])
        history = get_user_balance_history(user_id, 30)
        
        if not history:
            bot.send_message(message.chat.id, f"📊 Історія користувача {user_id} порожня")
            return
        
        text = f"📊 <b>Леджер користувача {user_id}:</b>\n\n"
        text += format_balance_history(history)
        
        if len(text) > 4000:
            # Разбиваем на части если слишком длинно
            parts = [text[i:i+4000] for i in range(0, len(text), 4000)]
            for part in parts:
                bot.send_message(message.chat.id, part, parse_mode="HTML")
        else:
            bot.send_message(message.chat.id, text, parse_mode="HTML")
        
    except ValueError:
        bot.send_message(message.chat.id, "❌ Невірний формат user_id")
    except Exception as e:
        print(f"[user_ledger] error: {e}")
        bot.send_message(message.chat.id, "❌ Помилка завантаження леджера")



def parse_user_identifier(text):
    """Парсит идентификатор пользователя (@username или user_id)"""
    try:
        text = text.strip()
        if text.startswith('@'):
            # @username - нужно найти user_id по username
            username = text[1:]
            from database import get_user_by_username
            user_id = get_user_by_username(username)
            if user_id:
                return user_id, username
            else:
                return None, f"Пользователь @{username} не найден"
        else:
            # user_id
            user_id = int(text)
            return user_id, str(user_id)
    except ValueError:
        return None, "Неверный формат ID пользователя"
    except Exception as e:
        return None, f"Помилка: {e}"

def notify_user_balance_change(user_id, amount, reason, details, admin_name):
    """Отправляет уведомление пользователю об изменении баланса"""
    try:
        if amount > 0:
            emoji = "💰"
            action = "начислено"
        else:
            emoji = "💸"
            action = "списано"
        
        text = f"""{emoji} <b>Изменение баланса</b>

{action.title()}: <b>{abs(amount):.2f}₴</b>
Причина: {reason}
Детали: {details}
Админ: {admin_name}

Спасибо за использование Palmaron Bot!"""
        
        bot.send_message(user_id, text, parse_mode="HTML")
        
    except Exception as e:
        print(f"[notify_user] error: {e}")

def notify_admin_action(admin_id, action_text, user_id, username):
    """Уведомляет админа об успешном выполнении действия"""
    try:
        text = (
            f"✅ <b>Адмін-дію виконано</b>\n\n"
            f"{action_text}\n\n"
            f"👤 Користувач: {username}\n"
            f"🆔 ID: {user_id}"
        )
        bot.send_message(admin_id, text, parse_mode="HTML")
    except Exception as e:
        print(f"[notify_admin] error: {e}")



@bot.message_handler(commands=['give'])
def give_balance_command(message):
    """Команда /give для начисления баланса"""
    if not is_admin(message.from_user.id):
        return
    
    try:
        args = message.text.split()
        if len(args) != 3:
            bot.send_message(message.chat.id, "❌ Використання: /give [user] [amount]\\nПриклад: /give @username 100 або /give 123456 100")
            return
        
        user_id, username = parse_user_identifier(args[1])
        if not user_id:
            bot.send_message(message.chat.id, f"❌ {username}")
            return
        
        try:
            amount = float(args[2])
            if amount <= 0:
                bot.send_message(message.chat.id, "❌ Сума повинна бути більше 0")
                return
        except ValueError:
            bot.send_message(message.chat.id, "❌ Невірний формат суми")
            return
        
        # Начисляем баланс
        add_balance(user_id, amount, reason="admin_chat_gift", details=f"Нарахування адміном {message.from_user.first_name}")
        
        # Уведомляем пользователя
        notify_user_balance_change(user_id, amount, "Подарунок від адміністратора", f"Нарахування адміном {message.from_user.first_name}", message.from_user.first_name)
        
        # Уведомляем админа
        notify_admin_action(message.from_user.id, f"💰 Начислено {amount:.2f}₴", user_id, username)
        
        # Удаляем команду из чата
        try:
            bot.delete_message(message.chat.id, message.message_id)
        except:
            pass
        
    except Exception as e:
        print(f"[give_command] error: {e}")
        bot.send_message(message.chat.id, "❌ Помилка виконання команди")

