@bot.message_handler(commands=['tree'])
def give_tree_command(message):
    """Команда /tree для выдачи дерева"""
    if not is_admin(message.from_user.id):
        return
    
    try:
        args = message.text.split()
        if len(args) != 4:
            bot.send_message(message.chat.id, "❌ Використання: /tree [user] [tree_type] [count]\\nПриклад: /tree @username apple 3")
            return
        
        user_id, username = parse_user_identifier(args[1])
        if not user_id:
            bot.send_message(message.chat.id, f"❌ {username}")
            return
        
        tree_type = args[2].lower()
        if tree_type not in ['apple', 'pear', 'cherry', 'plum']:
            bot.send_message(message.chat.id, "❌ Невірний тип дерева. Доступні: apple, pear, cherry, plum")
            return
        
        try:
            count = int(args[3])
            if count <= 0:
                bot.send_message(message.chat.id, "❌ Кількість повинна бути більше 0")
                return
        except ValueError:
            bot.send_message(message.chat.id, "❌ Невірний формат кількості")
            return
        
        # Выдаем дерево
        from database import give_user_tree
        give_user_tree(user_id, tree_type, count)
        
        # Уведомляем пользователя
        try:
            text = (
                f"🌳 <b>Отримано дерево</b>\\n\\n"
                f"Тип: {tree_type}\\n"
                f"Кількість: {count}\\n"
                f"Видано адміном: {message.from_user.first_name}"
            )
            bot.send_message(user_id, text, parse_mode="HTML")
        except:
            pass
        
        # Уведомляем админа
        notify_admin_action(message.from_user.id, f"🌳 Выдано {count} деревьев {tree_type}", user_id, username)
        
        # Удаляем команду из чата
        try:
            bot.delete_message(message.chat.id, message.message_id)
        except:
            pass
        
    except Exception as e:
        print(f"[tree_command] error: {e}")
        bot.send_message(message.chat.id, "❌ Помилка виконання команди")

