# ФУНКЦИИ ПЕРЕНЕСЕНЫ В handlers/referral_handlers.py



@bot.message_handler(commands=['ref_stats'])
def ref_stats_handler(message):
    """Админ-команда для детальной статистики рефералов"""
    if not is_admin(message.from_user.id):
        return
    
    try:
        top_referrers = get_top_referrers_with_earnings(10)
        
        if not top_referrers:
            bot.send_message(message.chat.id, "📊 Рефералів поки що немає")
            return
        
        text = "📊 <b>Детальна статистика рефералів</b>\n\n"
        
        for i, (user_id, name, ref_count, earnings) in enumerate(top_referrers, 1):
            text += f"{i}. <b>{name}</b> (ID: {user_id})\n"
            text += f"   👥 Запрошено: {ref_count}\n"
            text += f"   💰 Зароблено: {earnings:.2f}₴\n"
            if earnings > 0:
                avg_earning = earnings / ref_count if ref_count > 0 else 0
                text += f"   📈 Середній бонус: {avg_earning:.2f}₴\n"
            text += "\n"
        
        # Общая статистика
        total_refs = sum(ref_count for _, _, ref_count, _ in top_referrers)
        total_earnings = sum(earnings for _, _, _, earnings in top_referrers)
        
        text += "━━━━━━━━━━━━━━━━━━━━\n"
        text += "📈 <b>Загальна статистика:</b>\n"
        text += f"👥 Всього запрошено: {total_refs}\n"
        text += f"💰 Всього зароблено: {total_earnings:.2f}₴\n"
        text += f"📊 Середній бонус: {total_earnings/total_refs:.2f}₴" if total_refs > 0 else "📊 Середній бонус: 0₴"
        
        if len(text) > 4000:
            # Разбиваем на части если слишком длинно
            parts = [text[i:i+4000] for i in range(0, len(text), 4000)]
            for part in parts:
                bot.send_message(message.chat.id, part, parse_mode="HTML")
        else:
            bot.send_message(message.chat.id, text, parse_mode="HTML")
        
    except Exception as e:
        print(f"[ref_stats] error: {e}")
        bot.send_message(message.chat.id, "❌ Помилка завантаження статистики")



def format_garden_stat_value(value, stat_type):
    """Форматирует значение статистики сада с правильными единицами"""
    try:
        if stat_type in ['trees_count', 'harvest_count', 'watering_count']:
            # Количество - целые числа
            return f"{int(value)} шт"
        elif stat_type in ['income', 'expenses', 'profit', 'balance']:
            # Деньги - с валютой
            return f"{float(value):.2f}₴"
        elif stat_type in ['level', 'experience']:
            # Уровни - целые числа
            return f"{int(value)} рівень"
        elif stat_type in ['multiplier', 'bonus_percent']:
            # Проценты и множители
            return f"{float(value):.1f}%"
        else:
            # По умолчанию - как есть
            return str(value)
    except (ValueError, TypeError):
        return "0"

def get_garden_stats_labels():
    """Возвращает правильные лейблы для статистики сада"""
    return {
        'level': '🌱 Рівень саду',
        'trees_count': '🌳 Кількість дерев',
        'harvest_count': '🍎 Зібрано фруктів',
        'watering_count': '💧 Поливів',
        'income': '💰 Дохід від продажу',
        'expenses': '💸 Витрати на сад',
        'profit': '📈 Чистий прибуток',
        'balance': '💳 Баланс',
        'experience': '⭐ Досвід',
        'multiplier': '⚡ Множник доходу',
        'bonus_percent': '🎯 Бонусний відсоток'
    }

def format_garden_stats_display(stats_dict):
    """Форматирует статистику сада для красивого отображения"""
    labels = get_garden_stats_labels()
    
    lines = ["🌱 <b>Статистика саду</b>", ""]
    
    # Группируем статистику по категориям
    garden_stats = []
    money_stats = []
    other_stats = []
    
    for key, value in stats_dict.items():
        if key in ['income', 'expenses', 'profit', 'balance']:
            money_stats.append((key, value))
        elif key in ['level', 'trees_count', 'harvest_count', 'watering_count', 'experience']:
            garden_stats.append((key, value))
        else:
            other_stats.append((key, value))
    
    # Статистика сада
    if garden_stats:
        lines.append("🌿 <b>Основний прогрес:</b>")
        for key, value in garden_stats:
            label = labels.get(key, key)
            formatted_value = format_garden_stat_value(value, key)
            lines.append(f"   {label}: <b>{formatted_value}</b>")
        lines.append("")
    
    # Финансовая статистика
    if money_stats:
        lines.append("💰 <b>Фінанси:</b>")
        for key, value in money_stats:
            label = labels.get(key, key)
            formatted_value = format_garden_stat_value(value, key)
            lines.append(f"   {label}: <b>{formatted_value}</b>")
        lines.append("")
    
    # Дополнительная статистика
    if other_stats:
        lines.append("⚙️ <b>Додаткові показники:</b>")
        for key, value in other_stats:
            label = labels.get(key, key)
            formatted_value = format_garden_stat_value(value, key)
            lines.append(f"   {label}: <b>{formatted_value}</b>")
    
    return "\n".join(lines)



@bot.callback_query_handler(func=lambda c: c.data == "garden_stats")
def garden_stats_handler(call):
    """Обработчик статистики сада с детальной активностью"""
    uid = call.from_user.id
    
    # Проверка блокировки
    if check_user_block_before_action(call, bot):
        return
    
    # Проверка спама
    is_spam, spam_message = check_button_spam(uid, "garden_stats")
    if is_spam:
        bot.answer_callback_query(call.id, text=spam_message, show_alert=True)
        return
    
    bot.answer_callback_query(call.id)
    
    try:
        from database import get_user_garden_stats, get_garden_activity_log
        
        # Получаем основную статистику
        stats = get_user_garden_stats(uid)
        
        # Получаем лог активности (последние 20 записей)
        activity_log = get_garden_activity_log(uid, 20)
        
        text = "🌱 <b>Статистика саду</b>\n"
        text += "━━━━━━━━━━━━━━━━━\n\n"
        
        # Основная статистика
        if stats:
            text += "📊 <b>Основні показники:</b>\n"
            text += format_garden_stats_display(stats) + "\n\n"
        
        # Активность
        if activity_log:
            text += "📋 <b>Остання активність:</b>\n"
            
            # Группируем по типам
            tree_purchases = []
            booster_purchases = []
            harvests = []
            sales = []
            upgrades = []
            
            for activity in activity_log:
                if activity['activity_type'] == 'tree_buy':
                    tree_purchases.append(activity)
                elif activity['activity_type'] == 'booster_buy':
                    booster_purchases.append(activity)
                elif activity['activity_type'] == 'harvest':
                    harvests.append(activity)
                elif activity['activity_type'] == 'sale':
                    sales.append(activity)
                elif activity['activity_type'] == 'upgrade':
                    upgrades.append(activity)
            
            # Показываем последние покупки деревьев
            if tree_purchases:
                text += "\n🌳 <b>Останні покупки дерев:</b>\n"
                for activity in tree_purchases[:5]:
                    time_str = format_kiev_time(activity['timestamp'])
                    text += f"• {activity['item_name']} x{activity['quantity']} - {activity['cost']:.2f}₴ ({time_str})\n"
            
            # Показываем последние покупки бустеров
            if booster_purchases:
                text += "\n⚡ <b>Останні бустери:</b>\n"
                for activity in booster_purchases[:5]:
                    time_str = format_kiev_time(activity['timestamp'])
                    duration = activity['metadata'].get('duration', 'N/A')
                    text += f"• {activity['item_name']} - {activity['cost']:.2f}₴ ({duration}) ({time_str})\n"
            
            # Показываем последние сборы
            if harvests:
                text += "\n🍎 <b>Останні збори:</b>\n"
                for activity in harvests[:5]:
                    time_str = format_kiev_time(activity['timestamp'])
                    text += f"• {activity['item_name']} x{activity['quantity']} ({time_str})\n"
            
            # Показываем последние продажи
            if sales:
                text += "\n💰 <b>Останні продажі:</b>\n"
                for activity in sales[:5]:
                    time_str = format_kiev_time(activity['timestamp'])
                    text += f"• {activity['item_name']} x{activity['quantity']} - {activity['cost']:.2f}₴ ({time_str})\n"
            
            # Показываем последние апгрейды
            if upgrades:
                text += "\n⬆️ <b>Останні апгрейди:</b>\n"
                for activity in upgrades[:3]:
                    time_str = format_kiev_time(activity['timestamp'])
                    text += f"• {activity['item_name']} - {activity['cost']:.2f}₴ ({time_str})\n"
        else:
            text += "📋 <b>Активність:</b>\n"
            text += "Поки що немає записів активності в саду\n\n"
            text += "💡 <b>Поради:</b>\n"
            text += "• Купіть своє перше дерево\n"
            text += "• Використовуйте бустери для прискорення\n"
            text += "• Регулярно збирайте фрукти\n"
            text += "• Продавайте фрукти на біржі"
        
        # Добавляем кнопки
        keyboard = InlineKeyboardMarkup()
        keyboard.add(InlineKeyboardButton("🔄 Оновити", callback_data="garden_stats"))
        keyboard.add(InlineKeyboardButton("⬅️ Назад до саду", callback_data="garden_menu"))
        
        # Отправляем сообщение
        try:
            bot.edit_message_text(
                text,
                call.message.chat.id,
                call.message.message_id,
                reply_markup=keyboard,
                parse_mode="HTML"
            )
        except Exception:
            # Если не удалось отредактировать, отправляем новое
            bot.send_message(
                call.message.chat.id,
                text,
                reply_markup=keyboard,
                parse_mode="HTML"
            )
        
    except Exception as e:
        print(f"[garden_stats] error: {e}")
        bot.send_message(call.message.chat.id, "❌ Помилка завантаження статистики саду")

# === CRYPTOBOT АДМИН-МЕНЮ ===
def admin_cryptobot_menu(call):
    """Админ-меню для Crypto Pay"""
    if not is_admin(call.from_user.id):
        return bot.answer_callback_query(call.id, "Нема доступу", show_alert=True)
    
    try:
        settings = get_cryptobot_settings()
        status = settings.get('enabled', False)
        
        # Проверяем подключение к API
        api_status = "❌ Не подключено"
        if settings.get('api_key'):
            try:
                from cryptobot_api import CryptoPayAPI
                api = CryptoPayAPI(settings['api_key'], testnet=False)
                result = api.test_connection()
                if result.get('ok'):
                    api_status = f"✅ Подключено (App ID: {result.get('app_id')})"
                else:
                    api_status = f"❌ Ошибка: {result.get('error', 'Неизвестная ошибка')}"
            except Exception as e:
                api_status = f"❌ Ошибка: {str(e)}"
        
        text = f"""₿ <b>Адмін-панель Crypto Pay</b>

🔧 <b>Налаштування:</b>
• <b>Статус:</b> {'✅ Увімкнено' if status else '❌ Вимкнено'}
• <b>Курс:</b> {settings.get('exchange_rate', 0.025)} USD за 1₴
• <b>Мінімум:</b> {settings.get('min_deposit', 10)}₴
• <b>Комісія:</b> {settings.get('admin_fee_percent', 2)}%
• <b>Валюти:</b> {', '.join(settings.get('supported_currencies', ['BTC', 'ETH', 'USDT', 'USDC']))}

📊 <b>API статус:</b>
• <b>Подключение:</b> {api_status}

🔗 <b>Документация:</b>
• <a href="https://help.send.tg/en/articles/10279948-crypto-pay-api">Crypto Pay API</a>
• <a href="https://t.me/CryptoBot">@CryptoBot</a> (Mainnet)
• <a href="https://t.me/CryptoTestnetBot">@CryptoTestnetBot</a> (Testnet)"""
        
        kb = InlineKeyboardMarkup(row_width=2)
        kb.add(
            InlineKeyboardButton(f"{'❌ Вимкнути' if status else '✅ Увімкнути'}", callback_data="cryptobot_toggle_btn"),
            InlineKeyboardButton("🔧 Налаштування", callback_data="cryptobot_admin_settings")
        )
        kb.add(
            InlineKeyboardButton("🔑 API ключ", callback_data="cryptobot_set_api")
        )
        kb.add(
            InlineKeyboardButton("💸 Мінімум", callback_data="cryptobot_set_min"),
            InlineKeyboardButton("📊 Комісія", callback_data="cryptobot_set_fee")
        )
        kb.add(
            InlineKeyboardButton("💱 Валюти", callback_data="cryptobot_set_currencies"),
            InlineKeyboardButton("🔄 Тест", callback_data="cryptobot_admin_test")
        )
        kb.add(
            InlineKeyboardButton("📊 Статистика", callback_data="cryptobot_admin_stats"),
            InlineKeyboardButton("⏳ Очікуючі", callback_data="cryptobot_admin_pending")
        )
        kb.add(
            InlineKeyboardButton("⬅️ Назад", callback_data="panel")
        )
        
        try:
            bot.edit_message_text(
                text,
                call.message.chat.id,
                call.message.message_id,
                reply_markup=kb,
                parse_mode="HTML"
            )
        except Exception as edit_error:
            print(f"[admin_cryptobot_menu] edit error: {edit_error}")
            # Fallback: send new message if edit fails
            bot.send_message(
                call.message.chat.id,
                text,
                reply_markup=kb,
                parse_mode="HTML"
            )
        
    except Exception as e:
        print(f"[admin_cryptobot_menu] error: {e}")
        import traceback
        traceback.print_exc()
        bot.answer_callback_query(call.id, f"❌ Помилка завантаження: {str(e)}", show_alert=True)

def cryptobot_toggle_btn(call):
    """Переключение Crypto Pay вкл/выкл"""
    if not is_admin(call.from_user.id):
        return bot.answer_callback_query(call.id, "Нема доступу", show_alert=True)
    
    try:
        settings = get_cryptobot_settings()
        new_status = not settings.get('enabled', False)
        update_cryptobot_settings(enabled=new_status)
        bot.answer_callback_query(call.id, f"✅ Crypto Pay {'увімкнено' if new_status else 'вимкнено'}")
    except Exception as e:
        bot.answer_callback_query(call.id, "❌ Помилка", show_alert=True)
    return admin_cryptobot_menu(call)

