def cryptobot_admin_test_handler(call):
    """Тестирование подключения через кнопку"""
    if not is_admin(call.from_user.id):
        return bot.answer_callback_query(call.id, "Немає доступу", show_alert=True)
    
    try:
        from cryptobot_api import CryptoPayAPI
        settings = get_cryptobot_settings()
        
        if not settings.get('api_key'):
            bot.answer_callback_query(call.id, "❌ API ключ не установлен", show_alert=True)
            return
        
        # Test mainnet
        api_mainnet = CryptoPayAPI(settings['api_key'], testnet=False)
        result_mainnet = api_mainnet.test_connection()
        
        # Test testnet
        api_testnet = CryptoPayAPI(settings['api_key'], testnet=True)
        result_testnet = api_testnet.test_connection()
        
        response = "🔧 <b>Результаты тестирования Crypto Pay API:</b>\n\n"
        
        if result_mainnet.get('ok'):
            response += f"✅ <b>Mainnet:</b> Подключено\n"
            response += f"📱 App ID: {result_mainnet.get('app_id')}\n"
            response += f"📝 Название: {result_mainnet.get('name')}\n"
            response += f"🤖 Бот: {result_mainnet.get('payment_processing_bot_username')}\n\n"
        else:
            response += f"❌ <b>Mainnet:</b> {result_mainnet.get('error', 'Ошибка подключения')}\n\n"
        
        if result_testnet.get('ok'):
            response += f"✅ <b>Testnet:</b> Подключено\n"
            response += f"📱 App ID: {result_testnet.get('app_id')}\n"
            response += f"📝 Название: {result_testnet.get('name')}\n"
            response += f"🤖 Бот: {result_testnet.get('payment_processing_bot_username')}\n"
        else:
            response += f"❌ <b>Testnet:</b> {result_testnet.get('error', 'Ошибка подключения')}\n"
        
        # Add current settings
        response += f"\n🔧 <b>Текущие настройки:</b>\n"
        response += f"• Курс: {settings.get('exchange_rate', 0.025)} USD за 1₴\n"
        response += f"• Минимум: {settings.get('min_deposit', 10)}₴\n"
        response += f"• Валюты: {', '.join(settings.get('supported_currencies', ['USDT', 'TON', 'BTC']))}\n"
        response += f"• Комиссия: {settings.get('admin_fee_percent', 2)}%"
        
        kb = InlineKeyboardMarkup()
        kb.add(InlineKeyboardButton("⬅️ Назад", callback_data="admin_cryptobot_menu"))
        
        bot.edit_message_text(
            call.message.chat.id,
            call.message.message_id,
            response,
            reply_markup=kb,
            parse_mode="HTML"
        )
            
    except Exception as e:
        print(f"[cryptobot_admin_test] error: {e}")
        bot.answer_callback_query(call.id, f"❌ Ошибка тестирования: {str(e)}", show_alert=True)

def cryptobot_change_params(call):
    """Изменение параметров CryptoBot"""
    if not is_admin(call.from_user.id):
        return bot.answer_callback_query(call.id)
    
    kind = call.data.split('_')[-1]
    
    if kind == "rate":
        bot.answer_callback_query(call.id, "Використовуйте команду: /cryptobot_rate [значення]")
    elif kind == "min":
        bot.answer_callback_query(call.id, "Використовуйте команду: /cryptobot_min [значення]")
    elif kind == "fee":
        bot.answer_callback_query(call.id, "Використовуйте команду: /cryptobot_fee [значення]")
    elif kind == "currencies":
        bot.answer_callback_query(call.id, "Використовуйте команду: /cryptobot_currencies [BTC,ETH,USDT]")

# === ОБЩИЙ ОБРАБОТЧИК КОМАНД ===
@bot.message_handler(func=lambda message: message.text and message.text.startswith('/'))
def general_command_handler(message):
    """Общий обработчик команд"""
    try:
        text = (message.text or "").strip()
        if not text.startswith('/'):
            return
        
        cmd = text.split()[0].lower()
        mapping = {
            '/stars_admin': stars_admin_handler,
            '/stars_rate': stars_rate_handler,
            '/stars_min': stars_min_handler,
            '/stars_fee': stars_fee_handler,
            '/stars_toggle': stars_toggle_handler,
            '/stars_stats': stars_stats_handler,
            '/cryptobot_admin': cryptobot_admin_handler,
            '/cryptobot_token': cryptobot_token_handler,
            '/cryptobot_api': cryptobot_api_handler,
            '/cryptobot_rate': cryptobot_rate_handler,
            '/cryptobot_min': cryptobot_min_handler,
            '/cryptobot_fee': cryptobot_fee_handler,
            '/cryptobot_toggle': cryptobot_toggle_handler,
            '/cryptobot_currencies': cryptobot_currencies_handler,
            '/cryptobot_test': cryptobot_test_handler,
            '/cryptobot_webhook': cryptobot_webhook_handler,
            '/stars_payout': stars_payout_handler,
        }
        
        handler = mapping.get(cmd)
        if handler:
            try:
                # Очищаем pending next_step handlers
                bot.clear_step_handler_by_chat_id(message.chat.id)
            except Exception:
                pass
            handler(message)
            return True
        return False
    except Exception as e:
        print(f"[general_command_handler] error: {e}")
        return False

