    try:
        import random, time
        from database import get_game_setting, get_all_user_ids, get_all_admins

        def _send_soft_reminder_to_user(uid: int):
            try:
                # Лишаємо лише амбасадорське повідомлення (без зайвих текстів)
                text = "💎 Додайте @palmaron_bot у нік та активуйте статус амбасадора: швидкі виводи без комісії і пріоритетна обробка!"
                bot.send_message(uid, text)
            except Exception:
                pass

        def _reminders_report_to_admins(sent_count: int, failed_count: int):
            try:
                admins = get_all_admins() or []
                for aid in admins:
                    try:
                        bot.send_message(
                            aid,
                            (
                                "📣 <b>Звіт розсилки нагадувань</b>\n"
                                "━━━━━━━━━━━━━━━━━\n"
                                f"✅ Успішно відправлено: <b>{sent_count}</b>\n"
                                f"❌ Не доставлено: <b>{failed_count}</b>\n"
                                "\n💡 Зміст: мотиваційні поради щодо підвищення рівня та статусу амбасадора (@palmaron_bot)."
                            ),
                            parse_mode="HTML"
                        )
                    except Exception:
                        pass
            except Exception:
                pass

        def _soft_reminders_loop():
            while True:
                try:
                    try:
                        en = get_game_setting('auto_reminders_enabled', '1') == '1'
                        if not en:
                            time.sleep(3600)
                            continue
                    except Exception:
                        pass
                    try:
                        iv_hours = int(get_game_setting('auto_reminders_interval_hours', '6'))
                    except Exception:
                        iv_hours = 6
                    iv_hours = max(6, min(iv_hours, 168))
                    # Анти-спам при рестарті: не відправляти частіше ніж раз на інтервал
                    try:
                        from database import get_game_setting as _ggs, set_game_setting as _sgs
                        import time as _t
                        last_ts = int(_ggs('auto_reminders_last_ts', '0') or '0')
                        now_ts = int(_t.time())
                        if now_ts < last_ts + iv_hours * 3600:
                            # Спимо до завершення інтервалу перед наступною спробою
                            sleep_s = max(60, (last_ts + iv_hours * 3600) - now_ts)
                            _t.sleep(sleep_s)
                            continue
                        _sgs('auto_reminders_last_ts', str(now_ts))
                    except Exception:
                        pass
                    # Сегментація одержувачів
                    try:
                        seg = get_game_setting('auto_reminders_segment', 'all')
                    except Exception:
                        seg = 'all'
                    if seg == 'non_ambassador':
                        from database import get_non_ambassador_user_ids
                        user_ids = get_non_ambassador_user_ids()
                    elif seg == 'low_level':
                        from database import get_user_ids_below_level, get_game_setting as _get
                        try:
                            mx = int(_get('auto_reminders_low_level_max', '1'))
                        except Exception:
                            mx = 1
                        user_ids = get_user_ids_below_level(mx)
                    else:
                        user_ids = get_all_user_ids()
                    sent = 0
                    failed = 0
                    for uid in user_ids:
                        try:
                            time.sleep(random.uniform(0.1, 0.4))
                            _send_soft_reminder_to_user(uid)
                            sent += 1
                        except Exception:
                            failed += 1
                    _reminders_report_to_admins(sent, failed)
                    time.sleep(iv_hours * 3600)
                except Exception:
                    time.sleep(3600)

        try:
            th = threading.Thread(target=_soft_reminders_loop, name="soft-reminders", daemon=True)
            th.start()
        except Exception:
            pass

        # Фоновий цикл автополиву для користувачів з активним бустером autowater
        def _auto_watering_loop():
            import time as _t
            from database import get_all_user_ids, get_active_boosters
            from database import get_user_trees_with_watering, water_tree
            while True:
                try:
                    uids = get_all_user_ids()
                    for uid in uids:
                        try:
                            boosts = get_active_boosters(uid)
                            if not any(bt == 'autowater' for bt, _ in boosts):
                                continue
                            trees = get_user_trees_with_watering(uid) or []
                            watered_any = False
                            for t in trees:
                                ws = t.get('watering_status') or {}
                                wl = ws.get('water_level', 100)
                                iw = ws.get('is_withered', False)
                                if iw or wl < 20:
                                    ok, msg = water_tree(uid, t['tree_type'])
                                    if ok:
                                        watered_any = True
                            if watered_any:
                                try:
                                    bot.send_message(uid, "💧 Автополив: ваші дерева полито автоматично")
                                except Exception:
                                    pass
                            _t.sleep(0.05)
                        except Exception:
                            pass
                    # інтервал перевірки
                    _t.sleep(120)
                except Exception:
                    _t.sleep(300)
        try:
            th2 = threading.Thread(target=_auto_watering_loop, name="auto-watering", daemon=True)
            th2.start()
        except Exception:
            pass
    except Exception:
        pass

    # Планувальник щоденних подій (2–3 рази/день)
    def _start_random_event_once():
        try:
            import random, time
            choices = [
                ('storm', {'dur': 15, 'penalty': -0.05, 'shelter_cost': 50, 'mult': 0.05, 'cap': 20, 'limit_user': 1}),
                ('drought', {'dur': 20, 'penalty': -0.05, 'water_cost': 40, 'fert_chance': 0.10, 'limit_user': 1}),
                ('pests', {'dur': 12, 'loss': 0.02, 'treat_cost': 40, 'limit_user': 1}),
                ('rush', {'dur': 10, 'mult': 0.15, 'limit_user': 2}),
                ('golden', {'dur': 10, 'chance': 0.05, 'reward': 50, 'limit_user': 1}),
                ('buyer', {'dur': 15, 'bonus_price': 0.08, 'cap_qty': 200}),
                ('market', {'dur': 20, 'fee': 0.12}),
            ]
            # Фільтр увімкнених типів
            try:
                from database import get_game_setting
                enabled = []
                for t,p in choices:
                    if get_game_setting(f'auto_event_{t}', '1') == '1':
                        enabled.append((t,p))
                if enabled:
                    choices = enabled
            except Exception:
                pass
            etype, params = random.choice(choices)
            from database import create_event
            eid = create_event(etype, params, int(params.get('dur', 10)), created_by=0, chat_id=None, start_in_minutes=0)
            evt = _get_active_event(etype)
            if evt and evt['id'] == eid:
                _broadcast_event_announcement(evt)
        except Exception:
            pass

    def _auto_events_loop():
        import threading, time, random
        # Швидкий старт: першу подію запускаємо через 2–5 хв після запуску
        try:
            time.sleep(random.randint(120, 300))
            _start_random_event_once()
        except Exception:
            pass
        while True:
            try:
                # Авто-вимикач через налаштування
                try:
                    from database import get_game_setting
                    if get_game_setting('auto_events_enabled', '1') != '1':
                        time.sleep(3600)
                        continue
                except Exception:
                    pass
                # План: 3 події на день (приблизно кожні 8 годин ± розкид)
                base_interval = 8 * 3600
                jitter = random.randint(-1800, 1800)  # ±30 хв
                wait_s = max(3600, base_interval + jitter)
                time.sleep(wait_s)
                _start_random_event_once()
            except Exception:
                # у разі помилки не зупиняти цикл
                time.sleep(3600)

    try:
        import threading
        t = threading.Thread(target=_auto_events_loop, daemon=True)
        t.start()
    except Exception:
        pass

