    # Глобальне оновлення активності для callback'ів (не блокує інші хендлери)
    @bot.callback_query_handler(func=lambda c: not (getattr(c, 'data', '') or '').startswith('event_'))
    def __touch_activity_callback(call):
        try:
            from database import update_user_activity, is_user_blocked, get_user_block_info
            import time
            # Глобальна перевірка підписки для ВСІХ callback'ів (крім verify_subscription)
            try:
                if getattr(call, 'data', None) != 'verify_subscription':
                    ok = check_subscription_before_action(call, bot)
                    if not ok:
                        return
            except Exception:
                pass
            
            # Перевіряємо чи заблокований користувач
            if is_user_blocked(call.from_user.id):
                block_info = get_user_block_info(call.from_user.id)
                if block_info:
                    block_type = "канал" if block_info[2] == 'channel_leave' else "чат"
                    block_text = (
                        f"🚫 <b>ДОСТУП ЗАБЛОКОВАНО!</b>\n\n"
                        f"❌ <b>Причина:</b> Вихід з обов'язкового {block_type}\n"
                        f"📅 <b>Дата блокування:</b> {time.strftime('%d.%m.%Y %H:%M', time.localtime(int(block_info[6])))}\n\n"
                        f"💡 <b>Що робити:</b>\n"
                        f"• Поверніться в {block_type}: {block_info[5]}\n"
                        f"• Зверніться до адміністратора\n"
                        f"• Очікуйте розблокування"
                    )
                    bot.answer_callback_query(call.id, "🚫 Доступ заблоковано", show_alert=True)
                    bot.send_message(call.message.chat.id, block_text, parse_mode="HTML")
                return
            
            update_user_activity(call.from_user.id)
            # Ambassador status auto-detect and notify on change
            try:
                from database import update_ambassador_flag_from_profile, get_all_admins, get_user
                changed, active = update_ambassador_flag_from_profile(call.from_user.id)
                if changed:
                    try:
                        user = get_user(call.from_user.id)
                        user_name = user[1] if user else str(call.from_user.id)
                        username = user[8] if user and len(user) > 8 else None
                        mention = f"@{username}" if username else f"tg://user?id={call.from_user.id}"
                        status_text = "АКТИВОВАНО 0% комісію (амбасадор)" if active else "ДЕАКТИВОВАНО статус амбасадора (повернення комісії)"
                        for admin_id in (get_all_admins() or []):
                            try:
                                bot.send_message(admin_id, f"💎 Амбасадор: {status_text}\n👤 Користувач: <a href='{mention}'>{str(user_name).replace('<','&lt;').replace('>','&gt;')}</a>", parse_mode="HTML")
                            except Exception:
                                pass
                        try:
                            if active:
                                bot.send_message(call.from_user.id, "💎 Вітаємо! У вас активовано статус амбасадора: швидкі виводи без комісії та пріоритет! ✨")
                            else:
                                bot.send_message(call.from_user.id, "ℹ️ Ваш статус амбасадора вимкнено. Вивід знову з комісією. Додайте @palmaron_bot у нік, щоб активувати.")
                        except Exception:
                            pass
                    except Exception:
                        pass
            except Exception:
                pass
        except Exception:
            pass
        return

