# ОРИГИНАЛЬНЫЙ ОБРАБОТЧИК С ДЕКОРАТОРАМИ (ВРЕМЕННО ОТКЛЮЧЕН - используется обработчик выше)
@bot.callback_query_handler(func=lambda c: c.data == "office_menu" and False)  # ОТКЛЮЧЕН
@ban_check
@subscription_required  
@freeze_check
def office_menu_handler(call):
    # Логирование на самом верхнем уровне
    print(f"[DEBUG] office_menu_handler FUNCTION CALLED for user {call.from_user.id if hasattr(call, 'from_user') else 'unknown'}")
    """Главное меню инвестиционного офиса"""
    try:
        print(f"[DEBUG] office_menu_handler called for user {call.from_user.id}")
        
        # Импорты в начале
        from database import get_user_office, calculate_office_profit, get_user_office_employees
        from office_models import EMPLOYEE_TYPES
        
        user_id = call.from_user.id
        
        # Проверка доступности кнопки (для не-админов)
        if not is_admin(user_id) and is_button_disabled("office_menu"):
            message = get_button_message("office_menu")
            safe_answer_callback_query(call, text=message, show_alert=True)
            return
        
        # Перевірка спаму
        is_spam, spam_message = check_button_spam(user_id, "office_menu")
        if is_spam:
            safe_answer_callback_query(call, text=spam_message, show_alert=True)
            return
        
        safe_answer_callback_query(call)
        
        # Рассчитываем прибыль перед показом меню
        calculate_office_profit(user_id)
        office = get_user_office(user_id)
        
        # Подсчитываем работников по типам
        employees = get_user_office_employees(user_id)
        employee_counts = {}
        for emp_type in [e['type'] for e in EMPLOYEE_TYPES]:
            employee_counts[emp_type] = sum(1 for e in employees if e['type'] == emp_type)
        
        kb = InlineKeyboardMarkup(row_width=1)
        kb.add(
            InlineKeyboardButton("👑 | Придбання працівників", callback_data="office_agency"),
            InlineKeyboardButton("🏢 | Інформація офісу", callback_data="office_info"),
            InlineKeyboardButton("🏆 | Топ 10 Найприбутковіших", callback_data="office_top"),
        )
        kb.add(InlineKeyboardButton("⬅️ Назад", callback_data="back_home"))
        
        msg = (
            "💼 <b>Вітаємо! Ви увійшли в меню управління вашим офісом.</b>\n\n"
            "• Розпочати або продовжити свою інвестицію\n"
            "• Придбати працівників в агенції для запуску роботи офісу\n"
            "• Після найму працівників — очікуйте на прибуток та в будь-який момент заберіть його на головний баланс\n"
            "• Переглянути детальну інформацію про працівників у відповідному меню нижче\n"
            "• Отримати розширену інформацію про ваш офіс також у відповідному розділі\n"
            "• Є питання? — Завжди можете звернутися в підтримку або запитати в чаті!"
        )
        
        try:
            send_banner_with_caption(
                call.message.chat.id, 
                "Інвестиційний офіс", 
                "💼", 
                msg, 
                reply_markup=kb, 
                parse_mode="HTML",
                subtitle=f"Доступно: {office['available_profit']:.2f}₴ | Всього: {office['total_profit']:.2f}₴"
            )
        except Exception as e:
            # Если не удалось отправить с баннером, отправляем обычное сообщение
            try:
                bot.send_message(call.message.chat.id, msg, reply_markup=kb, parse_mode="HTML")
            except Exception as e2:
                # Если и это не сработало, отправляем простой ответ
                bot.answer_callback_query(call.id, "❌ Помилка відображення меню", show_alert=True)
                import traceback
                print(f"[ERROR] office_menu_handler error: {e}")
                print(f"[ERROR] office_menu_handler error2: {e2}")
                traceback.print_exc()
    except Exception as e:
        # Общая обработка ошибок
        import traceback
        print(f"[ERROR] office_menu_handler general error: {e}")
        traceback.print_exc()
        try:
            safe_answer_callback_query(call, text="❌ Помилка відкриття меню офісу", show_alert=True)
        except:
            pass

@bot.callback_query_handler(func=lambda c: c.data == "office_agency")
@freeze_check
@subscription_required
@ban_check
@answer_callback_first
def office_agency_handler(call):
    """Меню агентства - покупка работников"""
    # Логируем САМОЕ ПЕРВОЕ, что может быть выполнено
    import sys
    print(f"[DEBUG] ===== office_agency_handler START для user {call.from_user.id if hasattr(call, 'from_user') else 'NO_USER'} =====", file=sys.stderr, flush=True)
    print(f"[DEBUG] ===== office_agency_handler START для user {call.from_user.id if hasattr(call, 'from_user') else 'NO_USER'} =====", flush=True)
    user_id = call.from_user.id
    
    # Всегда отвечаем на callback_query в начале
    try:
        bot.answer_callback_query(call.id, text="", show_alert=False)
        print(f"[DEBUG] office_agency_handler: callback_query отвечен")
    except Exception as e:
        print(f"[ERROR] office_agency_handler: Failed to answer callback_query: {e}")
    
    # Перевірка чи кнопка відключена (тільки для не-адмінів)
    if not is_admin(user_id) and is_button_disabled("office_menu"):
        message = get_button_message("office_menu")
        if not message:
            message = "⚠️ Ця функція тимчасово недоступна. Ми працюємо над її покращенням!"
        try:
            bot.answer_callback_query(call.id, text=message, show_alert=True)
        except:
            pass
        print(f"[DEBUG] office_agency_handler: кнопка отключена, возвращаемся")
        return
    
    try:
        from office_models import EMPLOYEE_TYPES, get_employee_max_count
        from database import get_user_office_employees
        from telebot.types import InlineKeyboardMarkup, InlineKeyboardButton
        
        print(f"[DEBUG] office_agency_handler: получаем данные о работниках")
        employees = get_user_office_employees(user_id)
        # Подсчитываем количество работников каждого типа
        employee_counts = {}
        for emp in employees:
            emp_type = emp['type']
            employee_counts[emp_type] = employee_counts.get(emp_type, 0) + 1
        
        print(f"[DEBUG] office_agency_handler: создаем клавиатуру")
        kb = InlineKeyboardMarkup(row_width=1)
        for emp in EMPLOYEE_TYPES:
            emp_type = emp['type']
            current_count = employee_counts.get(emp_type, 0)
            max_count = get_employee_max_count(emp_type)
            
            # Проверяем, достигнут ли лимит
            if current_count >= max_count:
                button_text = f"✅ {emp['emoji']} | {emp['name_uk']} ({current_count}/{max_count})"
                callback_data = "office_employee_already_hired"
            else:
                button_text = f"{emp['emoji']} | {emp['name_uk']} ({current_count}/{max_count})"
                callback_data = f"office_employee_info:{emp_type}"
            kb.add(InlineKeyboardButton(button_text, callback_data=callback_data))
        
        kb.add(InlineKeyboardButton("⬅️ BACK | Повернутись в офіс", callback_data="office_menu"))
        
        msg = (
            "💼 <b>Вітаємо! Ви потрапили до головного меню Агенції.</b>\n\n"
            "💡 Тут ви можете найняти працівників для вашого Інвестиційного Офісу.\n\n"
            f"👥 У наявності {len(EMPLOYEE_TYPES)} типів працівників:\n\n"
        )
        
        for i, emp in enumerate(EMPLOYEE_TYPES, 1):
            emp_type = emp['type']
            current_count = employee_counts.get(emp_type, 0)
            max_count = get_employee_max_count(emp_type)
            status = "✅" if current_count >= max_count else "📋"
            msg += (
                f"{i}. {status} {emp['emoji']} <b>{emp['name_uk']}</b> ({current_count}/{max_count})\n"
                f"{emp['color']} {emp['description']}\n\n"
            )
        
        msg += (
            "📄 Натисніть на працівника, щоб переглянути детальнішу інформацію та найняти його."
        )
        
        print(f"[DEBUG] office_agency_handler: отправляем сообщение пользователю {user_id}, chat_id={call.message.chat.id}")
        print(f"[DEBUG] office_agency_handler: длина сообщения={len(msg)}, кнопок={len(kb.keyboard)}")
        
        # Пробуем отправить сообщение несколькими способами
        success = False
        try:
            result = edit_or_send(call, msg, reply_markup=kb, parse_mode="HTML")
            if result:
                print(f"[DEBUG] office_agency_handler: сообщение отправлено через edit_or_send успешно")
                success = True
            else:
                print(f"[WARNING] office_agency_handler: edit_or_send вернул None")
        except Exception as e:
            print(f"[ERROR] office_agency_handler: ошибка в edit_or_send: {e}")
            import traceback
            traceback.print_exc()
        
        if not success:
            # Пробуем напрямую отправить сообщение
            try:
                print(f"[DEBUG] office_agency_handler: пытаемся отправить через bot.send_message")
                bot.send_message(call.message.chat.id, msg, reply_markup=kb, parse_mode="HTML")
                print(f"[DEBUG] office_agency_handler: сообщение отправлено через bot.send_message успешно")
                success = True
            except Exception as e2:
                print(f"[ERROR] office_agency_handler: ошибка отправки через bot.send_message: {e2}")
                import traceback
                traceback.print_exc()
                try:
                    bot.answer_callback_query(call.id, "❌ Помилка відображення меню", show_alert=True)
                except:
                    pass
        
        print(f"[DEBUG] ===== office_agency_handler END для user {user_id}, success={success} =====")
        
    except Exception as e:
        print(f"[ERROR] office_agency_handler: общая ошибка: {e}")
        import traceback
        traceback.print_exc()
        try:
            bot.answer_callback_query(call.id, "❌ Помилка відкриття меню агентства", show_alert=True)
        except:
            pass

@bot.callback_query_handler(func=lambda c: c.data.startswith("office_employee_info:"))
@freeze_check
@subscription_required
@ban_check
@answer_callback_first
def office_employee_info_handler(call):
    """Информация о конкретном работнике и возможность найма"""
    user_id = call.from_user.id
    
    # Перевірка чи кнопка відключена (тільки для не-адмінів)
    if not is_admin(user_id) and is_button_disabled("office_menu"):
        message = get_button_message("office_menu")
        if not message:
            message = "⚠️ Ця функція тимчасово недоступна. Ми працюємо над її покращенням!"
        safe_answer_callback_query(call, text=message, show_alert=True)
        return
    
    try:
        employee_type = call.data.split(":")[1]
    except (ValueError, IndexError):
        return bot.answer_callback_query(call.id, "❌ Помилка", show_alert=True)
    
    safe_answer_callback_query(call)
    
    from office_models import get_employee_by_type, get_employee_price, get_employee_daily_profit, get_employee_max_count
    from database import get_user_office_employees, get_user
    
    employee = get_employee_by_type(employee_type)
    if not employee:
        return bot.answer_callback_query(call.id, "❌ Працівник не знайдено", show_alert=True)
    
    # Проверяем текущее количество работников этого типа
    employees = get_user_office_employees(user_id)
    current_count = sum(1 for e in employees if e['type'] == employee_type)
    max_count = get_employee_max_count(employee_type)
    can_hire_more = current_count < max_count
    
    # Проверяем баланс
    user = get_user(user_id)
    balance = float(user[2] if isinstance(user, tuple) else user.get('balance', 0))
    price = get_employee_price(employee_type)
    can_afford = balance >= price
    
    kb = InlineKeyboardMarkup(row_width=1)
    if not can_hire_more:
        kb.add(InlineKeyboardButton(f"✅ Досягнуто ліміт ({current_count}/{max_count})", callback_data="office_employee_already_hired"))
    elif can_afford:
        kb.add(InlineKeyboardButton(f"💎 Купити {employee['name_uk'].lower()} / {price:.0f}₴", callback_data=f"office_buy_employee:{employee_type}"))
    else:
        kb.add(InlineKeyboardButton(f"❌ Недостатньо коштів ({price:.0f}₴)", callback_data="office_insufficient_funds"))
    
    kb.add(InlineKeyboardButton("⬅️ Назад", callback_data="office_agency"))
    
    daily_profit = get_employee_daily_profit(employee_type)
    
    # Формируем сообщение с учетом лимитов
    limit_info = f"Можна найняти: {max_count - current_count} з {max_count}"
    if current_count > 0:
        limit_info = f"Вже найнято: {current_count}/{max_count} | {limit_info}"
    
    msg = (
        f"💼 <b>{employee['name_uk']}</b>\n\n"
        f"{employee['story']}\n\n"
        f"📊 <b>Характеристики:</b>\n"
        f"💰 Ціна: {price:.0f}₴\n"
        f"⭐ Щоденний прибуток: {daily_profit:.2f}₴/день\n"
        f"📈 {limit_info}\n\n"
        f"💡 Натисніть кнопку нижче, щоб найняти {employee['name_uk'].lower()}."
    )
    
    print(f"[DEBUG] office_employee_info_handler: отправляем сообщение пользователю {user_id}")
    try:
        edit_or_send(call, msg, reply_markup=kb, parse_mode="HTML")
        print(f"[DEBUG] office_employee_info_handler: сообщение отправлено успешно")
    except Exception as e:
        print(f"[ERROR] office_employee_info_handler: ошибка отправки сообщения: {e}")
        import traceback
        traceback.print_exc()
        try:
            bot.answer_callback_query(call.id, "❌ Помилка відображення", show_alert=True)
        except:
            pass

@bot.callback_query_handler(func=lambda c: c.data.startswith("office_buy_employee:"))
@freeze_check
@subscription_required
@ban_check
@answer_callback_first
def office_buy_employee_handler(call):
    """Покупка работника"""
    user_id = call.from_user.id
    
    # Перевірка чи кнопка відключена (тільки для не-адмінів)
    if not is_admin(user_id) and is_button_disabled("office_menu"):
        message = get_button_message("office_menu")
        if not message:
            message = "⚠️ Ця функція тимчасово недоступна. Ми працюємо над її покращенням!"
        safe_answer_callback_query(call, text=message, show_alert=True)
        return
    
    try:
        employee_type = call.data.split(":")[1]
    except (ValueError, IndexError):
        return bot.answer_callback_query(call.id, "❌ Помилка", show_alert=True)
    
    from office_models import get_employee_by_type, get_employee_price
    from database import get_user, hire_office_employee, add_balance
    
    employee = get_employee_by_type(employee_type)
    if not employee:
        return bot.answer_callback_query(call.id, "❌ Працівник не знайдено", show_alert=True)
    
    price = get_employee_price(employee_type)
    
    # Проверяем баланс
    user = get_user(user_id)
    balance = float(user[2] if isinstance(user, tuple) else user.get('balance', 0))
    
    if balance < price:
        return bot.answer_callback_query(call.id, f"❌ Недостатньо коштів. Потрібно {price:.0f}₴", show_alert=True)
    
    # Пытаемся нанять работника
    success, message = hire_office_employee(user_id, employee_type)
    
    if not success:
        return bot.answer_callback_query(call.id, message, show_alert=True)
    
    # Списываем деньги
    add_balance(user_id, -price, reason="office_hire", details=f"Найм {employee['name_uk']}")
    
    bot.answer_callback_query(call.id, f"✅ {employee['name_uk']} успішно найнято!", show_alert=True)
    
    # Возвращаемся в меню агентства
    call.data = "office_agency"
    office_agency_handler(call)

@bot.callback_query_handler(func=lambda c: c.data == "office_info")
@freeze_check
@subscription_required
@ban_check
@answer_callback_first
def office_info_handler(call):
    """Информация об офисе пользователя"""
    print(f"[DEBUG] office_info_handler CALLED for user {call.from_user.id}")
    user_id = call.from_user.id
    
    # Всегда отвечаем на callback_query в начале
    try:
        bot.answer_callback_query(call.id, text="", show_alert=False)
    except Exception as e:
        print(f"[DEBUG] Failed to answer callback_query: {e}")
    
    # Перевірка чи кнопка відключена (тільки для не-адмінів)
    if not is_admin(user_id) and is_button_disabled("office_menu"):
        message = get_button_message("office_menu")
        if not message:
            message = "⚠️ Ця функція тимчасово недоступна. Ми працюємо над її покращенням!"
        # Ответ уже отправлен в начале функции, но отправляем с сообщением
        try:
            bot.answer_callback_query(call.id, text=message, show_alert=True)
        except:
            pass
        return
    
    from database import get_user_office, get_user_office_employees, calculate_office_profit
    from office_models import get_employee_by_type, EMPLOYEE_TYPES, get_employee_max_count
    from utils import get_user_name
    
    # Рассчитываем прибыль перед показом
    calculate_office_profit(user_id)
    office = get_user_office(user_id)
    employees = get_user_office_employees(user_id)
    
    # Подсчитываем работников по типам
    employee_counts = {}
    for emp_type in [e['type'] for e in EMPLOYEE_TYPES]:
        count = sum(1 for e in employees if e['type'] == emp_type)
        employee_counts[emp_type] = count
    
    user_name = get_user_name(user_id)
    
    kb = InlineKeyboardMarkup(row_width=1)
    if office['available_profit'] > 0:
        kb.add(InlineKeyboardButton("💎 | Забрати прибуток з офісу", callback_data="office_withdraw_profit"))
    kb.add(InlineKeyboardButton("📎 | Оновити статистику", callback_data="office_info"))
    kb.add(InlineKeyboardButton("⬅️ BACK | Повернутись в офіс", callback_data="office_menu"))
    
    # Формируем список работников с учетом лимитов
    staff_info = []
    total_employees = 0
    for emp in EMPLOYEE_TYPES:
        count = employee_counts.get(emp['type'], 0)
        max_count = get_employee_max_count(emp['type'])
        total_employees += count
        status = "✅" if count >= max_count else "📋"
        staff_info.append(f"{status} {emp['emoji']} {emp['name_uk']}: {count}/{max_count}")
    
    msg = (
        f"💼 <b>ІНФОРМАЦІЯ ПРО ВАШ ОФІС</b>\n\n"
        f"👤 Власник офісу: {user_name}\n"
        f"👥 Всього працівників: {total_employees}\n\n"
        f"📋 <b>Ваш персонал:</b>\n"
        f"{chr(10).join(staff_info)}\n\n"
        f"💵 Доступний прибуток до збирання зарплатні:\n"
        f"<b>{office['available_profit']:.2f} ₴</b>\n\n"
        f"💰 Загальний прибуток вашого офісу за весь час:\n"
        f"<b>{office['total_profit']:.2f} ₴</b>"
    )
    
    print(f"[DEBUG] office_info_handler: отправляем сообщение пользователю {user_id}")
    try:
        edit_or_send(call, msg, reply_markup=kb, parse_mode="HTML")
        print(f"[DEBUG] office_info_handler: сообщение отправлено успешно")
    except Exception as e:
        print(f"[ERROR] office_info_handler: ошибка отправки сообщения: {e}")
        import traceback
        traceback.print_exc()
        try:
            bot.answer_callback_query(call.id, "❌ Помилка відображення", show_alert=True)
        except:
            pass

