@bot.callback_query_handler(func=lambda c: c.data == "office_confirm_withdraw")
@freeze_check
@subscription_required
@ban_check
@answer_callback_first
def office_confirm_withdraw_handler(call):
    """Подтвержденное снятие прибыли"""
    user_id = call.from_user.id
    
    # Перевірка чи кнопка відключена (тільки для не-адмінів)
    if not is_admin(user_id) and is_button_disabled("office_menu"):
        message = get_button_message("office_menu")
        if not message:
            message = "⚠️ Ця функція тимчасово недоступна. Ми працюємо над її покращенням!"
        safe_answer_callback_query(call, text=message, show_alert=True)
        return
    
    from database import withdraw_office_profit, calculate_office_profit, add_balance
    from utils import get_user_name
    
    # Рассчитываем прибыль перед снятием
    calculate_office_profit(user_id)
    
    success, profit, message = withdraw_office_profit(user_id)
    
    if not success:
        return bot.answer_callback_query(call.id, message, show_alert=True)
    
    # Зачисляем прибыль на баланс
    add_balance(user_id, profit, reason="office_withdraw", details="Зарплатня з офісу")
    
    user_name = get_user_name(user_id)
    
    # Отправляем сообщение об успехе
    success_msg = (
        f"🔺 Success 🍍 CEO @palmaronofficial Ваш баланс було змінено {profit:.2f}!\n\n"
        f"❤️ Приємного користування ботом"
    )
    bot.send_message(call.message.chat.id, success_msg, parse_mode="HTML")
    
    # Отправляем детальную информацию
    detail_msg = (
        f"💼 Зарплатня ваших працівників успішно зарахована на ваш Бюджет боту! 💰\n\n"
        f"📊 Інформація щодо працівників:\n"
        f"🍁 Менеджери, брокери та спеціалісти залишили офіс у зв'язку з завершенням повного терміну оренди.\n\n"
        f"🔥 Загальний дохід офісу, зароблений працівниками:\n"
        f"🔺 Тотал {profit:.2f}₴"
    )
    bot.send_message(call.message.chat.id, detail_msg, parse_mode="HTML")
    
    # Возвращаемся к информации об офисе
    call.data = "office_info"
    office_info_handler(call)

